window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-026.json"] = [{"name":"斑背拟霸鹟","english_name":"Mottle-backed Elaenia","scientific_name":"Elaenia gigas","overview":"斑背拟霸鹟（英文名：Mottle-backed Elaenia，学名：Elaenia gigas），是雀形目霸鹟科拟霸鹟属的鸟类。显著特征为独特的冠羽和黄白色的腹部，主要分布于南美洲的哥伦比亚南部至玻利维亚西部一带，偏好轻林地带，如过度生长的空地、森林边缘和河岛等。","appearance":"斑背拟霸鹟体长约18厘米，体型较大，拥有突出的分叉状冠羽和显著的白色头冠斑块，常呈现出角状外观。上体橄榄棕色，眼环隐约可见，背部淡绿橄榄色边缘，有时形成斑驳或条纹效果；翅膀暗色，具有两道白色翼带，飞羽边缘白色，尾部暗色；喉部灰色，胸部和侧翼略带橄榄色条纹或云纹，腹部和下尾覆羽呈浅黄色；虹膜深褐色；喙黑色，下颚基部淡粉色；腿黑色。雌雄外观相似，雌鸟稍小。幼鸟特征未详述。","call":"频繁发出类似马丁的‘direet’叫声和尖锐的‘pert-chéér’声；黎明时分的歌声为‘wurdit’或‘purdip’，会连续不断地从低矮树顶或灌木丛中发出。","habits":"斑背拟霸鹟栖息于南美东部安第斯山脉的轻林地带，包括过度生长的空地、森林边缘和河岛。以昆虫和小型果实为食，常在明显枝干上直立栖息，其独特的冠羽几乎总是竖起，显得活跃而兴奋。捕食时，它会在3至20米的高度进行短暂的空中突袭，也会悬停采食。","breeding":"繁殖季节在10月至11月期间，雄鸟的生殖器会增大。在厄瓜多尔的一次观察中，发现了一个位于15米高的Piptocoma discolor树冠中的巢穴，巢穴由交错缠绕的浅色根须构成，呈圆筒状，没有明显的内部衬垫和外部装饰，其中有两个雏鸟。除此之外，关于繁殖的其他信息尚不明确。","identification":"与其他拟霸鹟相比，斑背拟霸鹟的显著特征在于其大型的分叉状冠羽和白色头冠斑块，背部淡绿色边缘可能呈现斑驳或条纹效果，以及黄色腹部。","protection":"IUCN：LC（无危）。虽然全球范围内并不受威胁，但在部分地区仍属稀有至局部常见。在哥伦比亚的Tinigua国家公园、厄瓜多尔的Podocarpus国家公园以及Kapawi和Yuturi旅馆附近，以及秘鲁的Manu国家公园和生物圈保护区均有分布。可能因森林砍伐而扩大了其分布范围。","distribution":"斑背拟霸鹟的繁殖区域主要集中在南美的哥伦比亚南部至玻利维亚西部一带，包括哥伦比亚、厄瓜多尔、秘鲁和玻利维亚的部分地区。","other":"无"},{"name":"淡褐拟霸鹟","english_name":"Brownish Elaenia","scientific_name":"Elaenia pelzelni","overview":"淡褐拟霸鹟（英文名：Brownish Elaenia，学名：Elaenia pelzelni），是雀形目霸鹟科拟霸鹟属的鸟类。广泛分布在南美洲的亚马逊河流域，包括巴西、秘鲁北部、哥伦比亚边境以及玻利维亚。该鸟以沿亚马逊河及其支流如Xingu、Iriri、Madeira和Juruá河流的低地森林为栖息地。","appearance":"体长约18厘米，是一种中等大小的拟霸鹟。全身呈淡褐色，背部略显暗淡，耳羽和面部颜色稍浅。头顶有一片白色冠斑，通常半隐藏。上体颜色均匀，呈淡褐色，翅膀较背部更暗，呈暗褐色，翼羽边缘有三道明显的棕色白边翼纹，飞羽边缘泛白。尾巴长而呈暗褐色。喉部白色，下体颜色较淡，胸腹部带有淡褐色调，尾下覆羽有时略带褐色。虹膜深棕色，上喙黑色，下喙基部粉红色，尖端黑色，跗跖黑色。雌鸟缺少冠斑。幼鸟翅膀羽毛更白，翼纹偏红，翼下覆羽和尾上覆羽呈黄褐色，尾羽末端较淡。","call":"叫声多样，包括低沉的双音节'chick-ert'，其中第一个音节略高，清晰的'chick-urp'或'per-cheet'，第二个音节更高，重复的清澈'whit'声和高音金属质感的'chick-eep'。","habits":"生活在沿宽阔低地河流的森林中，包括老的河岛。站立姿势挺拔，从低至高的树冠层都有其身影，较为警觉。食性尚不明，但推测可能以昆虫和果实为主，特别是在Cecropia果上可能有较高依赖性。","identification":"独特的大型淡褐色拟霸鹟，雄鸟头部、耳羽和面部颜色偏淡，与雌鸟的区别在于雄鸟有半隐蔽的白色冠斑。幼鸟的翼纹和下体颜色与成鸟有明显差异。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的亚马逊河流域，包括巴西的Xingu、Iriri、Madeira和Juruá河流，秘鲁的Marañón河流，以及巴西-哥伦比亚边境的亚马逊河流域。"},{"name":"纯色冠拟霸鹟","english_name":"Plain-crested Elaenia","scientific_name":"Elaenia cristata","overview":"纯色冠拟霸鹟（英文名：Plain-crested Elaenia，学名：Elaenia cristata），是雀形目霸鹟科拟霸鹟属的鸟类。中等体型、特征不明显的霸鹟科飞禽，其头部通常可见直立的冠羽而无白色标记。这种鸟主要分布在南美洲的东北部和东部，包括玻利维亚、巴西、哥伦比亚、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。","appearance":"该鸟拥有橄榄绿色的背部，灰白色的胸部，淡色腹部，以及两条翼纹。其最显著的特点在于头部的直立冠羽，但无白色斑点。雌雄鸟在外形上相似，幼鸟的特征可能略有不同，但具体细节需进一步观察。","call":"纯色冠拟霸鹟的鸣唱声为沙哑的“jer-jéhjeh”，叫声则较为柔和，类似于“wee”。鸣叫声是识别该物种的重要线索之一。","habits":"它们常栖息在散布着树木的开阔地带和草原林地中，偏好在灌木或树木的顶部直立栖息。纯色冠拟霸鹟主要以昆虫为食，具有一定的迁徙习性，但具体迁徙路线和范围尚需进一步研究。","breeding":"繁殖季节在巴西米纳斯吉拉斯州为8月至12月。巢穴由精细编织的苔藓制成，外覆地衣，内衬植物纤维，通常位于灌木叉间的高度约80至100厘米处。每窝产卵1至2枚，蛋壳呈淡奶油色，带有棕色斑点，平均尺寸约为19.8毫米×14.6毫米。孵化期大约为18至19天，雏鸟离巢时间约为17至19天。一项在米纳斯吉拉斯州的研究显示，繁殖成功率约为33%。","identification":"与其他Elaenia属物种非常相似，但通过其沙哑的鸣唱声和柔软的叫声，以及橄榄绿的背部、灰白的胸部和淡色腹部，可进行有效区分。此外，其独特的直立冠羽也是辨识的关键。","protection":"IUCN：LC（无危）","distribution":"纯色冠拟霸鹟广泛分布于南美洲的东北部和东部，包括玻利维亚、巴西、哥伦比亚、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。在这些国家的干燥森林地区均有发现，尤其在一些国家公园和保护区，如委内瑞拉的奥里诺科卡西亚雷生物圈保护区、玻利维亚的诺埃尔肯普夫梅尔卡多国家公园、巴西的EMBRAPA实验站和塞拉达卡纳斯特拉国家公园，以及秘鲁的马努国家公园和生物圈保护区。","other":"尽管其栖息地受到火灾、牛群啃食、选择性伐木和刀耕火种农业的威胁，但由于物种分布范围广阔，且存在于多个国家公园和保护区中，目前全球范围内并不受严重威胁。"},{"name":"小拟霸鹟","english_name":"Lesser Elaenia","scientific_name":"Elaenia chiriquensis","overview":"小拟霸鹟（英文名：Lesser Elaenia，学名：Elaenia chiriquensis），是雀形目霸鹟科拟霸鹟属的鸟类。上体橄榄褐色，喉部淡灰色，腹部淡黄色，具白色翼斑。分布于中美洲至南美洲东北部，包括阿根廷、玻利维亚、巴西等地。其自然栖息地为干燥草原、季节性湿地及严重退化的前森林。","appearance":"小拟霸鹟长约13.5至14厘米，重11.5至22.1克。头部及上体呈灰橄榄色，冠羽稍长形成方形顶冠，半隐的白色冠斑。面颊略淡于上体，具窄白眼环；翅膀和尾巴暗色，翼覆羽尖端白色形成两道宽翼斑，飞羽边缘泛白；喉部灰色，胸部变为灰橄榄色，其余下体淡黄色；虹膜深棕色；喙黑色，下颚基部粉红色；腿黑色。雄雌相似，幼鸟未详述。","call":"最常发出清脆、口哨般的‘weeééa’声，还有其他如‘beer-ta’、‘chí-bur’或‘jwebu’的叫声，以及较长的‘freee’声。黎明歌声为‘tse-rwee...tse-rwee...tse-rwee-gr-gr-wee’，声音被认为比黄腹拟霸鹟更柔和、哀怨。","habits":"小拟霸鹟栖息于开放地带，如干燥灌木丛、河边岛屿灌木丛、草地上散生的灌木和树木、开阔林地、次生林、种植园和带树篱的耕作区。常见于热带和上热带区域，局部可达海拔2000米，最高记录在委内瑞拉达到3000米。它可能在亚马逊地区存在迁徙或居民群体，那些在巴西南部繁殖的个体似乎在南半球冬季向北迁移。","breeding":"繁殖季从哥斯达黎加的3月开始，在巴拿马中部为1月中旬至4月，偶尔到7月。在哥伦比亚北部为3月至7月，在特立尼达岛为4月至6月。筑巢由雌鸟独自完成，巢为小杯状，由植物纤维、叶片和苔藓构成，内部铺有少量羽毛，位于灌木或树木1至4米高处。一窝产卵1至4枚，卵淡白色或浅粉色，带有棕色或红色斑点，平均大小约18.6毫米×14.5毫米。孵化期14至15天，雏鸟由双亲喂养，离巢期15至16天。","identification":"与黄腹拟霸鹟相比，小拟霸鹟具有较短的顶冠，下方颜色较少黄色；而白冠拟霸鹟的白色顶冠更多，眼环不那么明显，腹部白色，喉咙和胸部淡灰色，翼斑常带黄或橄榄色而非纯白。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲东北部，包括哥斯达黎加至阿根廷东北部，常见于国家公园和其他保护区。在亚马逊南部的分布范围被认为比之前想象的更广泛，但由于适宜栖息地相对稀缺，自然分布呈碎片化。","other":"小拟霸鹟在某些地区被认为是重要的热带果树种子传播者，例如在委内瑞拉的萨瓦纳地区。"},{"name":"灰胸小拟霸鹟","english_name":"Coopmans's Elaenia","scientific_name":"Elaenia brachyptera","overview":"灰胸小拟霸鹟（英文名：Coopmans's Elaenia，学名：Elaenia brachyptera），是雀形目霸鹟科拟霸鹟属的鸟类。分布于南美的哥伦比亚西南部和厄瓜多尔西北部。该鸟种在2016年之前被认为是小拟霸鹟的一个亚种。其生境多样，包括干燥的草原、季节性湿润的低地草地和重度退化的前森林。","appearance":"灰胸小拟霸鹟体型小，约13.5厘米，外表朴素，上体呈灰褐色，翼上有明显的白色条纹，腹部淡黄色。头部羽毛有时会竖起形成方形的冠状结构，偶尔露出白色的冠斑，眼周有模糊的白色环。与黄腹拟霸鹟相比略小，下腹部颜色不如岭拟霸鹟鲜亮黄色。","call":"该鸟的鸣唱包括尖锐的哨声、短促的颤音和类似拨弦的颤鸣，其中晨歌被描述为高音的'tsee...tsee...chee-wee'，而另一版本的晨歌在厄瓜多尔东部山麓地带则为'wit...wit...weedeew'。","habits":"生活在半开放的生境和林间空地，包括较轻的林地，海拔高度在700至2800米之间。食性和觅食行为尚无确切报告，但可能与它先前被归类的拟霸鹟相似。","breeding":"关于繁殖行为的具体信息缺失。","identification":"与岭拟霸鹟难以区分，但前者具有更蓬松或方正的冠状结构，喙较短，上体和胸部颜色略深，腹部黄色较少。与小拟霸鹟相比，有更高的鸣叫声和独特的连贯颤音。","protection":"IUCN：LC（无危）","distribution":"分布于安第斯山脉西部的哥伦比亚纳里诺省和厄瓜多尔西北部，以及厄瓜多尔东部的安第斯山脉东侧，可能延伸至哥伦比亚南部和秘鲁东北部。","other":"2016年以前，灰胸小拟霸鹟被视为小拟霸鹟的一个亚种。"},{"name":"棕顶拟霸鹟","english_name":"Rufous-crowned Elaenia","scientific_name":"Elaenia ruficeps","overview":"棕顶拟霸鹟（英文名：Rufous-crowned Elaenia，学名：Elaenia ruficeps），是雀形目霸鹟科拟霸鹟属的小型鸟类，以沙质土壤上的稀树草原为栖息地，分布局限于南美洲北部，包括哥伦比亚东南部、委内瑞拉东南部、圭亚那、苏里南、法属圭亚那及巴西北部。其最显著的外部特征是头部后方隐约可见的棕红色斑块。","appearance":"体长约14.5厘米，体重约19克，是一种小型拟霸鹟。具有独特的羽色和轻微的冠羽。头部上方和背部为深橄榄棕色，翅膀较暗呈灰褐色，有两条模糊的白色翼带，边缘颜色较浅。下体主要为淡黄色，喉部、胸部和两侧有模糊的灰色橄榄色斑纹，腹部和下尾覆羽为不带条纹的淡黄色。眼睛深棕色，喙黑色，下颌基部有淡粉色，腿黑色。雌雄相似，幼鸟未详述。","call":"发出一两个奇特、沙哑的吼叫声，一对中的个体常彼此呼应。","habits":"栖息于低海拔的热带湿润森林和干燥灌木丛，通常成对活动，栖息于灌木或小树上，频繁地飞扑到树叶间捕食昆虫。不与其他物种混群。","breeding":"未提供具体繁殖信息。","identification":"与其他Elaenia属成员的区别在于模糊的下体条纹、相对不明显的翼带以及缺乏明显的冠羽。在适宜的生境中，它是唯一具有清晰白色下体的类似大小的鵙科鸟。","protection":"IUCN状态未知。","distribution":"分布于南美洲北部，包括哥伦比亚东南部、委内瑞拉东南部、圭亚那、苏里南、法属圭亚那及巴西北部亚马逊雨林区域。","other":"在合适的生境中可能相当常见。"},{"name":"山拟霸鹟","english_name":"Mountain Elaenia","scientific_name":"Elaenia frantzii","overview":"山拟霸鹟（英文名：Mountain Elaenia，学名：Elaenia frantzii），是雀形目霸鹟科拟霸鹟属的鸟类。小型的拟霸鹟属鸟类。此鸟以德国自然学家Alexander von Frantzius命名。主要分布于中美洲至南美洲的高山区，包括危地马拉至哥伦比亚和委内瑞拉。","appearance":"山拟霸鹟长约14至15厘米，重约17至20克。其上部羽毛呈暗淡的橄榄色，具有一圈窄白眼环。翅膀颜色较暗，边缘有黄色羽毛，形成两道偏白色翼纹。喉咙和胸部为灰黄色，腹部变为淡黄色。性别相似，但幼鸟上部颜色更深，下部更浅，翼纹更为明亮。","call":"山拟霸鹟发出拖长的'peeeeur'叫声，比槲寄生霸鹟的叫声长，且有重复的'd’weet d’weet'歌声。","habits":"山拟霸鹟在湿山林中活动，特别是在林缘、空地、次生林、半开放地带或有树木的牧场。繁殖季节之外通常独居。冬季会下降到600米的低海拔，可能进行季节性移动。","breeding":"繁殖期在1200至2900米的高海拔，筑巢由雌鸟完成，使用苔藓、地衣和植物纤维构成杯状巢，位于树或竹子上的2至15米高处。产2枚带有肉桂斑点的白色蛋，由雌鸟孵化约15至16天。","identification":"山拟霸鹟头部圆润，无冠羽，与较大的黄腹拟霸鹟相比，体型较小，腹部颜色更浅。年轻个体翼纹更亮。","protection":"IUCN状态未知。","distribution":"分布于中美洲至南美洲的高山区，具体包括危地马拉至哥伦比亚和委内瑞拉。冬季可降至600米的低海拔。"},{"name":"高原拟霸鹟","english_name":"Highland Elaenia","scientific_name":"Elaenia obscura","overview":"高原拟霸鹟（英文名：Highland Elaenia，学名：Elaenia obscura），是雀形目霸鹟科拟霸鹟属的中型飞禽，主要分布在南美洲的东南厄瓜多尔至玻利维亚和阿根廷西北部。其显著特征为橄榄色背部，灰白色喉部和黄腹心，具两道淡色翼纹。","appearance":"体型中等，头部较小，尾长。上体统一呈暗灰橄榄色，喉部淡黄色渐变为胸部和侧身的淡橄榄色，腹部显淡黄色。具两条淡黄色翼纹，尾端在新鲜时呈白色。眼环狭窄而白色，喙黑，下颚基部粉红，腿黑色。雌雄相似，雌鸟略小。幼鸟上体暗红棕色，下体污灰白色。","call":"鸣声包含类似‘weehr-drrrr-whee’的短语，由滑音哨声、颤音和再次滑音哨声组成。有时伴有快速低沉的‘burrrr’或‘burrreep’声，以及上升的粗糙‘tch’DJREEE’或‘pup pup pup’音符。","habits":"栖息于湿润森林边缘和次生林，包括干燥森林和矮小的云雾林，常见于森林碎片和年轻的次生林小片。主要活动于海拔1700至3000米，偶尔下降至1400米。以昆虫和浆果为食，常单独站立于树冠高处，活跃于日间。","breeding":"繁殖季节在玻利维亚为10月至2月，阿根廷西北部主要在12月至1月。巢为简单整洁的杯状，直径约8至9厘米，高度5至6厘米，装饰有苔藓和地衣，内部铺有羽毛。每次产卵两个，白色带红褐色和紫罗兰色斑点。","identification":"与岭拟霸鹟相比，体型明显较大，少有羽冠，通常有明显的白色冠斑和更显眼的白色眼环。","protection":"IUCN：LC（无危）。在某些地区罕见，但在保护区中较为常见。","distribution":"分布于南美东南厄瓜多尔至玻利维亚和阿根廷西北部，包括安第斯山脉东坡。"},{"name":"中美拟霸鹟","english_name":"Great Elaenia","scientific_name":"Elaenia dayi","overview":"中美拟霸鹟（英文名：Great Elaenia，学名：Elaenia dayi），是雀形目霸鹟科拟霸鹟属的鸟类，主要分布于南美洲的特普伊山脉高海拔地区，包括委内瑞拉和巴西北部，可能延伸至圭亚那。","appearance":"体型较大，长约20厘米，体重29至40克。头部圆润，顶冠略显，缺乏明显的冠羽。上体呈深灰褐色，头顶更暗，具断续的白色眼圈；两翼有淡白色翼带，尾部呈暗色；下体多为淡橄榄灰色，喉部稍浅，腹部渐变为淡黄色；虹膜深棕色，喙小而黑，下颚基部色浅，腿黑色。雌雄相似，雌鸟略小。幼鸟特征未详述。tyleri亚种比指名亚种大，auyantepui亚种较小且颜色更深。","call":"鸣声响亮多变，常见的一种叫声为“SQUEE’ch’ch’ch-cheet-cheet”，兼具鼻音和叽叽喳喳的特点。","habits":"通常单独或成对出现，偏好栖息于小树或灌木的顶部。生境包括灌丛、森林边缘及带有小树的草原。活动范围广泛，从低地到高山均有分布。","breeding":"繁殖记录缺失，但在二月于Auyán-tepui采集的个体显示处于繁殖状态。","identification":"与黑嘴鸫相比，后者缺乏翼带且喙较长。","protection":"IUCN：LC（无危）","distribution":"分布于南美的特普伊山脉，包括委内瑞拉和巴西北部，潜在分布于圭亚那。"},{"name":"岭拟霸鹟","english_name":"Sierran Elaenia","scientific_name":"Elaenia pallatangae","overview":"岭拟霸鹟（英文名：Sierran Elaenia，学名：Elaenia pallatangae），是雀形目霸鹟科拟霸鹟属的鸟类。南美洲特有，主要分布在哥伦比亚至玻利维亚一带的山地森林中，以其橄榄灰上部和淡黄色下部为显著特征。","appearance":"岭拟霸鹟体长约14至14.5厘米，体重约12.3至17.5克。头部圆润，无明显羽冠，但具有一条狭窄的白色冠纹通常可见。上体橄榄色，眼环和眼周带有黄绿色，面部比上部更显黄色。翅膀和尾巴颜色较暗，有两道显眼的黄白色翼带（在旧羽中几乎不可见）。下巴白色，下喉和胸部黄橄榄色，腹部和下尾覆羽变为淡黄色。虹膜深棕色，喙黑色，下颚基部淡粉红色，腿黑色。雌雄相似，雌鸟略小。幼鸟的冠斑可能较小或缺失。种族intensa下部颜色更加鲜艳，冠部颜色接近背部颜色。","call":"日间鸣唱为尖锐清澈、升降调的‘wheeu’声，与白冠拟霸鹟类似但缺少模糊质感，偶尔夹杂着喷嚏般的‘tjrr’声。黎明时的鸣唱为‘chrewee...chrewee...chrewee-krrr...chrewee...’（在厄瓜多尔、秘鲁和玻利维亚）。叫声包括短促的‘whit！’，更模糊的‘wheer！’和低沉下滑的‘wheer-up’。","habits":"以昆虫为主食，也会大量食用槲寄生（Loranthaceae）和Melastomes科的果实，以及Rubus（蔷薇科）和Coriaria（Coriariaceae）科的果实。相比同类物种，岭拟霸鹟显得更为不活跃和低调，长时间安静地站立于各种高度，从林下层到树冠，主要活动范围在地面以上3至7米。常加入混合物种群。在树叶中捕食昆虫。","breeding":"繁殖季节在哥伦比亚为1月至8月，秘鲁为5月、10月至12月，期间观察到幼鸟出巢的情况（厄瓜多尔为11月，秘鲁为6月、7月和9月）。巢为整洁但体积较大的杯状，建在灌木丛中的分叉处，离地面约1米高（秘鲁）。一窝产两枚白色的蛋，上面有非常稀疏的褐色和灰色斑点；孵化和离巢时间未被记录。","identification":"与山拟霸鹟的区别在于白色冠纹和更黄的下部；与白冠拟霸鹟和小嘴拟霸鹟的区别在于下部更黄的色泽。","protection":"IUCN：LC（无危）","distribution":"南美洲：哥伦比亚至玻利维亚，包括巴西、圭亚那、委内瑞拉等地。栖息于亚热带或热带湿润的山地森林以及严重退化的前森林区域。","other":"已知存在五种亚种，其中E. p. olivina和E. p. davidwillardi因遗传差异较大，一些权威机构将其视为独立物种——黄腹岭拟霸鹟。"},{"name":"黄腹岭拟霸鹟","english_name":"Tepui Elaenia","scientific_name":"Elaenia olivina","overview":"黄腹岭拟霸鹟（英文名：Tepui Elaenia，学名：Elaenia olivina），是雀形目霸鹟科拟霸鹟属的鸟类。拥有橄榄灰的上体与淡黄色的下体，独特的白色翼纹和通常扁平的小型冠羽。在委内瑞拉南部、东南部以及圭亚那均有分布，常栖息于湿润的山地森林及其边缘。","appearance":"这种小型的拟霸鹟长约14.5至14.7厘米，体重介于14.9至20.4克之间。头部略呈圆形，顶部有轻微的冠状突起，通常可见一条狭窄的白色头带。背部为深橄榄棕色，眼圈呈窄黄白色，翅膀上有两道白色的翼斑，内侧飞羽边缘泛黄，三级飞羽广泛镶白边。下体呈黄色，喉咙、胸部和两侧带有明显的橄榄色洗涤，腹部中央黄色明显。虹膜为深棕色，喙黑色，基部粉色，跗跖黑色。相较于黄腹拟霸鹟、小拟霸鹟和纯色冠拟霸鹟，本种颜色更深，更偏黄色。","call":"其鸣叫特征尚不十分清楚，但据观察，日间鸣唱由不规则的尖锐音符组成，如“chi-tree-trew...tree-trew...chip...”。叫声类似山拟霸鹟的“pfeééu”，或是更为柔和的下降音调“pieuw”。","habits":"栖息于海拔950至2400米的湿润山地森林边界，以及周边的矮化山地灌木丛和岩石空地；偶尔出现在以梅拉斯托梅科植物为主的次生林中。长时间静止站立于树冠至下层林间的各种高度，经常加入混种群落。以昆虫和果实为主食，尤其是梅拉斯托梅科植物的果实。通过在叶间捕食的方式获取昆虫。","breeding":"在委内瑞拉的1月至4月期间，观察到部分个体有生殖腺肿大的迹象，提示可能在此期间繁殖。目前关于繁殖行为的具体信息不足。","identification":"与黄腹拟霸鹟、小拟霸鹟和纯色冠拟霸鹟相比，黄腹岭拟霸鹟颜色更深，更偏黄色，且体型稍大，最明显体现在喙部。叫声也有显著差异，但具体细节需参考录音资料。","protection":"IUCN：LC（无危）。在委内瑞拉的某些地区，如Cerro de la Neblina，黄腹岭拟霸鹟的数量相对较多，甚至丰富。在委内瑞拉的Canaíma国家公园有所分布，但在巴西和圭亚那的分布情况信息匮乏。","distribution":"主要分布在南美洲的特普伊山脉，包括委内瑞拉南部、东南部以及圭亚那。在委内瑞拉的分布较为广泛，而在巴西仅限于Serra Parima、Cerro Uei-Tepui和Cerro Urutani三地，以及圭亚那的部分区域。","other":"最近的研究认为，黄腹岭拟霸鹟与岭拟霸鹟并非同种，两者在颜色、体型和叫声上存在差异。"},{"name":"安岛拟霸鹟","english_name":"Greater Antillean Elaenia","scientific_name":"Elaenia fallax","overview":"安岛拟霸鹟（英文名：Blue Mountain Elaenia，学名：Elaenia fallax），是雀形目霸鹟科拟霸鹟属的小型鸟类，牙买加特有中型霸鹟，主要栖息于海拔500–2000米的潮湿山地常绿林与林缘灌丛。羽色暗橄榄褐，具两条白色翼斑及隐蔽的白色小冠斑，繁殖期5–7月，营苔藓杯巢于灌丛至树冠，IUCN评定为无危。","appearance":"体长15厘米，体重约14克。外形矮胖，头略具小冠。成鸟头至上背均匀暗橄榄褐，通常被遮盖的白色小冠斑仅近距离可见；过眼纹模糊，眼前与眼后各有一淡黄白小斑，形成短而不显的超眉线。翼覆羽及三级飞羽外缘淡绿白，形成两道鲜明白色翼斑；三级飞羽外缘宽而淡黄。尾略凹，外侧羽端近半透明。喉及下体淡黄，胸带灰绿或灰褐并具轻微纵纹。嘴黑色上喙，下喙基部粉红，端部黑色；虹膜深褐；脚黑色。幼鸟缺冠斑，上体更灰，下体更淡。","call":"繁殖季白天歌声为连续的tseerrr-che-wit-che-wit……及简化的che-wit；另有悠长下滑的哀怨哨音。非繁殖季相对安静。","habits":"留鸟但作短距离垂直迁移：繁殖期集中于东部山地（蓝山、波特罗亚尔山及圣安德鲁高丘），非繁殖季扩散至全岛低地林缘及散树开阔地。常单独或成对活动，亦加入混合鸟群，自林下层至树冠层觅食，自栖处飞扑昆虫或悬停啄取果实，食物以昆虫及小果实为主。","breeding":"繁殖期5–7月，筑巢期可延至6月下旬，求偶延续到7月。巢为厚重苔藓杯状，内衬大量羽毛，筑于灌丛至大树的低处到高枝。每窝2枚卵，卵淡粉红并具稀疏斑点，大小约18.8×14.5毫米。孵化期及育雏细节尚未记录。","identification":"与同域唯一的elaenia——牙买加伊拉鹟相比，本种具明显两条白色翼斑及绿色冠部（后者无翼斑，冠部石板灰）。与岛上三种Myiarchus属霸鹟相比体型明显更小，嘴更短。","protection":"IUCN: LC（无危）。为牙买加特有鸟类区系成员，局部常见。原始林覆盖率已下降约75%，残存多为次生林，且受飓风、农药、造林及城市化等威胁；部分繁殖地位于蓝山与约翰克罗国家公园内，但经费不足导致保护力度有限。","distribution":"繁殖区：牙买加东部山地（蓝山、波特罗亚尔山、圣安德鲁高丘）。非繁殖期可扩散至全岛低地。","other":"海地拟霸鹟曾为本种亚种，现已分拆独立。"},{"name":"巴西拟霸鹟","english_name":"Small-headed Elaenia","scientific_name":"Elaenia sordida","overview":"巴西拟霸鹟（英文名：Small-headed Elaenia，学名：Elaenia sordida），是雀形目霸鹟科拟霸鹟属的鸟类。分布于南美洲东南部，包括巴西东南部、巴拉圭东部和阿根廷东北部。该鸟种自高原拟霸鹟分离独立成种，适应多种生境。","appearance":"中等体型的霸鹟，头部较小，尾巴较长。上体主要呈橄榄棕色，喉咙和侧腹为淡灰色，腹部中央有黄色斑点。具有两条浅色翼带。两性相似，幼鸟上体暗赤褐色，下体脏灰白色。","call":"鸣唱为简单重复的‘wee-krrr-ee-krrree’，与绿拟霸鹟相似，但不同于高原拟霸鹟的复杂鸣唱，且音符频率较低。","habits":"栖息于湿润森林边缘和次生林地，包括沿海restinga。活动范围从海平面到2000米高程。以昆虫（如膜翅目）和果实为食，如Schinus terebinthifolius等植物果实。一般认为是留鸟，但在巴西巴伊亚州的单个记录可能涉及季节外的游荡。","breeding":"筑巢时间为10月中旬、12月底和2月初，巢位于1.2米高的灌木垂直叉枝上，巢杯直径80-90毫米，深50-60毫米，由干草花序构成，通常含2枚蛋，颜色为白色至粉红色，带有肉桂色条纹/斑点。","identification":"与高原拟霸鹟相比，体型略大，颜色更深、更橄榄色，背部与头部对比不明显，下体颜色更灰。腿脚和喙黑色，眼睛棕色。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东南部（从马托格罗索州南部东至米纳斯吉拉斯州，局部至巴伊亚州中部，南至里约热内卢和里奥格兰德州），巴拉圭东部，阿根廷东北部及乌拉圭极北端。","other":"接受扰动和破碎的生境，常见于巴西的多个保护区，如塞拉达卡纳斯特拉国家公园、因特瓦莱斯州立公园和沃尔塔韦尔哈保护区。"},{"name":"黄腹小霸鹟","english_name":"Yellow-bellied Tyrannulet","scientific_name":"Ornithion semiflavum","overview":"黄腹小霸鹟（英文名：Yellow-bellied Tyrannulet，学名：Ornithion semiflavum），是雀形目霸鹟科白眼先小霸鹟属的鸟类。小型热带森林飞禽，主要分布在中美洲，从墨西哥东南部至巴拿马西部，包括了墨西哥的Veracruz、Oaxaca、Tabasco、Chiapas等地，以及Guatemala、Belize、Honduras、Nicaragua、Costa Rica和Panama的Chiriquí西部。","appearance":"这种小鸟体型微小，尾巴短粗，大部分时间在树冠层活动，容易被忽视。它的腹部呈黄色，拥有明显的白色眉纹，喙短而结实。它在树冠中跳跃攀爬，尤其在小枝条和藤蔓间穿梭，善于在叶子下寻找昆虫。","call":"其鸣叫声和歌声是哀怨的笛音，既可以单独发出，也可以连成一串下降的序列。","habits":"黄腹小霸鹟偏好生活在湿润的热带森林中，偶尔会下降到森林边缘较低的位置。它们以昆虫为食，活动范围通常在树冠层。","identification":"与其他类似的小型鸟类相比，黄腹小霸鹟的黄色腹部、白色眉纹和短粗的喙是辨识的关键特征。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥的东南部（Veracruz、Oaxaca、Tabasco、Chiapas）到巴拿马的西部（Chiriquí），包括Guatemala、Belize、Honduras、Nicaragua、Costa Rica等地。"},{"name":"褐顶小霸鹟","english_name":"Brown-capped Tyrannulet","scientific_name":"Ornithion brunneicapillus","overview":"褐顶小霸鹟（英文名：Brown-capped Tyrannulet，学名：Ornithion brunneicapillus），是雀形目霸鹟科白眼先小霸鹟属的鸟类。体型微小，以黄色腹部和环绕额部的白色眉纹为显著特征，无翼带。分布于中美洲至南美洲西北部，包括哥斯达黎加、哥伦比亚、厄瓜多尔、巴拿马和委内瑞拉。","appearance":"这是一种非常小巧的短尾飞虫捕食者，体羽下方呈黄色，具有一条独特的白色眉纹，环绕额头。头部冠羽为棕色，区别于其相似种黄腹小霸鹟的灰色冠羽。体型娇小，容易被忽视，尤其是在森林树冠层中。","call":"鸣声独特，一系列哀婉清脆的哨音，音调逐渐下降，易于识别。","habits":"通常单独或成对出现，偏好栖息于森林树冠层，由于其体型微小，不易被发现。有时会加入混种群鸟群。","identification":"与黄腹小霸鹟极为相似，但可通过其棕色的冠羽加以区分。此外，其鸣声也是辨识的重要依据。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加南部，南至哥伦比亚西部和北部，厄瓜多尔西北部，以及委内瑞拉西北部和东北部。最近记录显示在尼加拉瓜南部也有分布。"},{"name":"白眼先小霸鹟","english_name":"White-lored Tyrannulet","scientific_name":"Ornithion inerme","overview":"白眼先小霸鹟（英文名：White-lored Tyrannulet，学名：Ornithion inerme），是雀形目霸鹟科白眼先小霸鹟属的鸟类。小型霸鹟科鸟类，1858年首次命名。最显著的特征是拥有明亮的白色眼纹，从喙基部延伸至眼睛上方和后方，以及独特的白色翼斑。主要栖息于亚马逊雨林和巴西东部的热带湿润森林地带。","appearance":"体型小巧，橄榄色背部，灰色头部，翼上有鲜明的白色或淡黄色条纹，形成明显的翼斑。喉部和胸部为白色或浅灰色，下腹部略带黄色。成鸟性别相似，头部灰色，其余上体呈中绿色。幼鸟的翼斑为橙黄色，其他特征与成鸟相似。","call":"鸣声为一系列四到五个尖锐的音符，音调逐渐加速：'pweee, pweet, weeet, weeet, weet'。","habits":"通常单独或成对出现在成熟雨林的树冠层，喜欢在森林边缘活动。以捕食树叶上的昆虫为生，常加入混合觅食群。在树冠层较为隐蔽，不易被视觉发现。","breeding":"具体繁殖信息未知。","identification":"通过白色的超眉线和由翼覆羽上的白色斑点形成的翼斑来区分。与细脚小霸鹟和Tolmomyias类的霸鹟相比，白眼先小霸鹟具有更清晰的面部图案和暗橄榄色的羽毛。","protection":"IUCN状态未提及，具体保护级别需查阅最新资料。","distribution":"广泛分布于亚马逊地区，包括巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉等地的热带雨林。","other":"由于其隐蔽的生活习性，更多时候通过声音而非视觉被发现。"},{"name":"北无须小霸鹟","english_name":"Northern Beardless Tyrannulet","scientific_name":"Camptostoma imberbe","overview":"北无须小霸鹟（英文名：Northern Beardless Tyrannulet，学名：Camptostoma imberbe），是雀形目霸鹟科无须小霸鹟属的小型鸟类。1857年被首次命名。这种鸟主要分布在中美洲，从美国中南部和西南部，经过墨西哥直至哥斯达黎加西北部，包括墨西哥的科苏梅尔岛。其特征包括暗棕色的头部、灰绿色的上身渐变为臀部的淡色，以及黄色的腹部。","appearance":"北无须小霸鹟的体型小巧，全长约10.2厘米，体重仅7.5克。头部呈暗褐色，具有可竖立的冠羽和浅色的眼眉纹。上半身为灰绿色，逐渐变淡至臀部。翅膀呈棕色，边缘有黄色羽毛，带有两道白色翼斑。尾巴为棕色，喉咙灰色，胸部黄绿色，腹部黄色。喙呈粉红色。性别相似，但在亮度上，尤其是翼斑部分，通常不如其近亲南无须小霸鹟那样鲜艳。幼鸟与成鸟相似，但翼斑更宽，呈肉桂色。","call":"北无须小霸鹟的叫声为响亮的口哨声“Fleeeeeerrr”，有时会断开成“fleeer-it”或“flee-flee-flee-flee”。这是一种系列下降的哀婉哨音。","habits":"北无须小霸鹟栖息于轻型森林、农田和树丛花园中。它们活跃地以昆虫、蜘蛛和浆果为食，觅食方式类似莺或叶鹎，而不是典型的飞扑捕食。它们在树杈处筑巢，巢由植物纤维或叶子制成，侧面有入口。","breeding":"繁殖期中，雌鸟会筑造一个圆顶状的巢，通常位于树叉上，巢内有两个带有红褐色和淡紫色斑点的白色蛋，主要在较大的一端。孵化期约为14至15天，再过17天左右小鸟就会离巢。","identification":"与南无须小霸鹟相比，北无须小霸鹟的翼斑不那么显眼，两者在哥斯达黎加西北部有重叠分布，但并不杂交。此外，北无须小霸鹟的叫声和求偶行为也可用于辨识。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括美国的东南部、西南部，墨西哥至哥斯达黎加西北部，以及墨西哥的科苏梅尔岛。非繁殖季节的分布信息未详。","other":"北无须小霸鹟的巢有时隐藏在帐篷毛虫网或蜘蛛网中，或藏于球苔藓丛或胭脂树种子荚之间，以及杜松针簇中。"},{"name":"南无须小霸鹟","english_name":"Southern Beardless Tyrannulet","scientific_name":"Camptostoma obsoletum","overview":"南无须小霸鹟（英文名：Southern Beardless Tyrannulet，学名：Camptostoma obsoletum），是雀形目霸鹟科无须小霸鹟属的小型鸟类。常见于中美洲至南美洲阿根廷，分布广泛，从哥斯达黎加至乌拉圭。其最显著的特征是拥有一个短而弯曲的喙，头顶有一簇蓬松的羽毛，脸部无须，羽毛颜色朴素，且随地理区域而异。","appearance":"体长约9.5至10.5厘米，体重7至9克。头部呈暗棕色或灰色，顶冠可竖立形成小冠羽，上体灰绿色，背部较淡，翼部棕色带黄色边缘，有两道白色、黄色或肉桂色的翼纹。尾巴通常微翘，喉部灰色，胸部黄绿色，腹部黄色。喙部黑色，下颚基部呈淡色。雌雄相似，亚成鸟比成鸟更暗淡，翼纹色彩较弱。","call":"叫声为高亢的哨音，\"fleeeeer\"，音调起伏，有时尾音为\"fleeeeee-pit-pit\"；还有下降的清晰低音序列，\"fleee, flee-fleew-fleew\"。求偶时，冠羽竖立，尾巴快速摆动，发出激动的混合叫声。","habits":"栖息于各种灌木环境，包括仙人掌沙漠、干旱的荆棘灌木丛、落叶林、林缘地带、城市公园等，通常避开热带雨林内部，但偶尔出现在雨林边缘或沼泽森林。以昆虫、蜘蛛和浆果为主食，如槲寄生（Loranthaceae）的小果实。单独或成对活动，偶尔加入混群觅食。通过积极的跳跃式捕食，快速在树枝间穿梭，偶尔悬停捕食。","breeding":"繁殖期在中美洲和委内瑞拉为12月至3月，在特立尼达岛为2月至4月，其他地区有所不同。巢由雌鸟单独建造，为球形，侧面有入口，装饰有叶子、草、苔藓等，内部铺垫细软材料。巢距地面1至30米，藏匿良好，常建在藤蔓或树枝间。每窝产卵通常为2枚，偶尔3枚，孵化期约14至15天，幼鸟由双亲共同喂养，离巢期约17天。","identification":"与北方近亲北无须小霸鹟相比，本物种的翼纹更为鲜明，颜色差异明显。在湿润地区的亚种颜色更绿，腹部纯黄色，而干旱地区的亚种颜色更灰，腹部颜色较暗。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，自哥斯达黎加向南延伸至乌拉圭。在低地至海拔约2000米的地区最为常见，局部可达2800米，罕见情况下至3120米。在广泛的范围内，它存在于多个国家公园和其他保护区。","other":"偏好灌木、轻度林地和半开放的栖息地，这使得它比许多其他霸鹟科鸟类更能抵抗森林退化和干扰的影响。能够在转化后的环境中生存。"},{"name":"平原霸鹟","english_name":"Suiriri Flycatcher","scientific_name":"Suiriri suiriri","overview":"平原霸鹟（英文名：Suiriri Flycatcher，学名：Suiriri suiriri），是雀形目霸鹟科平原霸鹟属的鸟类。小型霸鹟，具有灰色头部，橄榄褐色背部，黑色尾巴和两条灰色翼带。亚种在臀部颜色（黄色或棕色）和腹部颜色（淡黄色或白色）上有所差异。常见于南美洲中南部的草原和半开放地带，避开亚马逊雨林等湿润环境。其叫声独特，由一系列‘pi-chew’音符组成。","appearance":"成年鸟体长15.5至16厘米，体重11.5至16克（指名亚种），burmeisteri亚种体型稍大，可达18.5至21克。头部和背部主要呈灰色，具小白眉斑和短眉纹；翅膀和尾巴较暗，有明显的灰白色翼带和次级飞羽边缘，尾羽外缘淡色，尾尖明显。全身下方几乎全白，胸部略显暗色。眼睛深棕色，喙和腿黑色。雌雄外观相似。burmeisteri亚种背部更偏橄榄色，翼纹更黄，臀部和尾基部淡黄色，喉咙白色，胸部淡灰色，下腹和尾下覆羽淡黄色。","call":"鸣唱为一系列类似打喷嚏的‘pi-chew’音符，雄鸟和雌鸟的歌声有所不同，雌鸟发出的声音更高频和更大声，且间隔较大。","habits":"栖息于查科和开阔的林地，最高海拔可达3000米。在玻利维安安第斯山脉全年可见。burmeisteri亚种限于开阔的cerrado和带有散落高灌木的campo（'campo sujo'）。以昆虫和其他节肢动物为食，偶尔吃小果实，如Curatella americana。捕食方式包括从树冠直接掠食和悬停捕食，也会从树上1至2米处飞扑捕捉昆虫。","breeding":"繁殖季节在阿根廷为10月至12月。巢为杯状，由羊毛、蜘蛛网和苔藓构成，放置在树叉中，离地面3至6.5米。每窝产3枚蛋，孵化和雏鸟成长期未详细记录。已知受紫辉牛鹂的寄生。","identification":"与Chapada霸鹟的区别在于后者有白色臀部，黄色腹部，宽白尾尖，以及不同的歌声和展示行为。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲中部和南部，包括北部阿根廷、乌拉圭、巴拉圭、玻利维亚东部、巴西大部分东部地区，以及圭亚那南部、阿帕马州和亚马逊河下游附近，以及马德拉河中央部分的零星地区。在亚马逊雨林周围干燥的林地和草原中可见。","other":"曾被分为两个物种：Chaco霸鹟和Campo霸鹟，但现在认为是同一物种的不同亚种。"},{"name":"高地霸鹟","english_name":"Chapada Flycatcher","scientific_name":"Guyramemua affine","overview":"高地霸鹟（英文名：Chapada Flycatcher，学名：Guyramemua affine），是雀形目霸鹟科Guyramemua的鸟类。中等体型的鸟类，拥有灰色头部、橄榄绿色背部和黄色腹部，分布于南美洲巴西中南部和东部玻利维亚的干草原地带。","appearance":"高地霸鹟体长约16厘米，重约21至23克。头顶和背部呈中等灰色，略带橄榄色；眉纹和上眼线白色；翅膀和尾巴颜色较深，翼上有明显的灰白色翼斑，次级飞羽边缘白色；尾部短而宽，尾羽有浅色外缘和明显的白色尖端；下喉至胸部白色，腹部和尾下覆羽纯黄色；虹膜棕色；喙黑色；腿为中灰色。","call":"雄鸟和雌性高地霸鹟在二重唱中发出不同的歌声，雄鸟发出响亮的成对音节，类似\"where where, whooz it\"，雌鸟则发出响亮的颤音，通常以一两个\"whur\"音符开始。雌鸟的联络叫声为2至3音节，\"zhuwheep\"或\"zhuwheep-oo\"。","habits":"生活在开阔的林木稀树草原，常成对出现。主要以小节肢动物和水果为食，通常在树木的中上层枝条觅食，偶尔下降到灌木或地面。捕食方式包括从枝叶表面猎取猎物，以及飞扑至植被中悬停捕获节肢动物或果实。比更为活跃。","identification":"高地霸鹟与平原霸鹟的区别在于前者腹部为黄色且尾尖较宽白，后者嘴较长且腹部为白色；此外，高地霸鹟背部颜色更深绿，胸部白色较少，臀部和尾上覆羽颜色较淡。","protection":"IUCN：NT（近危）","distribution":"高地霸鹟主要分布在巴西中南部（马兰昂、托坎廷斯、马托格罗索、戈亚斯、米纳斯吉拉斯、南马托格罗索）和玻利维亚东部圣克鲁斯地区。在巴西，常见于草地和分散树木的灌木丛生区，如查帕达多斯吉马拉埃斯国家公园附近的阿瓜弗里亚路的前几公里，以及库亚巴附近科西波杜奥罗路上较为茂密的cerrado。","other":"最大威胁来自于栖息地转换为桉树（Eucalyptus）和松树（Pinus）种植园，畜牧业，以及大规模的农作物种植，如大豆、水稻和其他出口作物。"},{"name":"白喉姬霸鹟","english_name":"White-throated Tyrannulet","scientific_name":"Mecocerculus leucophrys","overview":"白喉姬霸鹟（英文名：White-throated Tyrannulet，学名：Mecocerculus leucophrys），是雀形目霸鹟科幽霸鹟属的小型鸟类。其显著特征为醒目的白色喉咙，常见于海拔2,800至3,500米的山区森林，有时会降至更低的高度。在南美洲，从委内瑞拉至阿根廷北部广泛分布。","appearance":"体长11至14厘米，体重8至11克。成鸟上体橄榄灰，头顶较暗；眼先和眉纹纯白，脸颊深色，耳羽带有白色羽毛；翅膀呈棕黑色，有两道明显的宽翼斑，颜色从肉桂色到黄白色不等；尾巴暗褐色；喉咙白色，延伸至耳羽后方，胸部中央有窄灰色胸带，两侧较宽，其余下体中黄色。雌雄外观相似，幼鸟特征未详述。不同亚种在大小、色泽、翼斑颜色和腹部色调上有细微差异。","habits":"通常成对或小群体出现在混合物种群中，活跃于森林边缘和灌木丛生地带。偏好湿润的亚热带或热带山地森林。","identification":"以其独特的白色喉咙和翼斑颜色区分于其他同类。不同的亚种在体色和翼斑色调上存在差异。","distribution":"分布于南美洲，包括委内瑞拉至阿根廷北部，覆盖巴西、玻利维亚、哥伦比亚、厄瓜多尔和秘鲁。"},{"name":"白尾姬霸鹟","english_name":"White-tailed Tyrannulet","scientific_name":"Mecocerculus poecilocercus","overview":"白尾姬霸鹟（英文名：White-tailed Tyrannulet，学名：Mecocerculus poecilocercus），是雀形目霸鹟科幽霸鹟属的小型鸟类。体型小巧、颜色淡雅且活跃的鸟种，具有独特的白色尾部，常在南美洲哥伦比亚至秘鲁的云雾森林及边缘地带被发现，海拔高度约在1,500至2,500米之间。","appearance":"该鸟种体型较小，羽毛颜色朴素，没有鲜艳色彩，最显著的特征是其大胆的白色眉纹、浅黄色臀部和两条偏白色的翼带。它的喙小而精致，尾巴经常轻微上翘，呈现出水平的站立姿态。白尾姬霸鹟在飞行时动作敏捷，通常在树冠层活动。","call":"它的叫声是一连串三到四个清脆、音调下降的‘psee’音符，有时也会发出单个沙哑的音节。这些声音通常来自树冠层中的群鸟。","habits":"白尾姬霸鹟偏好生活在云雾森林及其边缘地带，常见于混合物种的鸟群中。它们主要栖息在树冠层，活动范围广泛，以昆虫为主要食物来源。","breeding":"关于白尾姬霸鹟的繁殖习性的详细信息有限，但一般而言，此类鸟种会在特定季节进行繁殖，通过筑巢来孵化蛋和育雏。","identification":"与白带姬霸鹟相似，但体型更小，栖息地海拔较低。白带姬霸鹟拥有更粗的白色眉纹、闪亮的白色翼带，以及整体上更为鲜明的羽毛对比度。","protection":"IUCN：LC（无危）","distribution":"分布于南美的安第斯山脉森林地带，北起哥伦比亚，南至秘鲁东部坡地（西坡至Piura，东坡至Cuzco）。"},{"name":"黄斑姬霸鹟","english_name":"Buff-banded Tyrannulet","scientific_name":"Mecocerculus hellmayri","overview":"黄斑姬霸鹟（英文名：Buff-banded Tyrannulet，学名：Mecocerculus hellmayri），是雀形目霸鹟科幽霸鹟属的鸟类。分布于南美的秘鲁东南部至阿根廷西北部，栖息于海拔中等的安第斯山脉东部斜坡上的湿润山地森林中。","appearance":"这是一种小型的林下层捕虫鸟，其特征包括绿色翼纹、淡灰色的冠顶和短尾巴。雌雄羽色相似，具体尺寸和羽毛颜色的变化需进一步观察确认。","call":"鸣声由两个高音、平直的“see”音符组成，声音较高且更细薄，容易与紫喉金翅雀混淆。","habits":"黄斑姬霸鹟更常被听到而非看到，它们经常出现在混合物种群中，活跃于中等海拔的湿润山地森林的次生林或热带湿润山地森林中。","breeding":"有关繁殖行为的具体信息未详，但基于同科鸟类推测，可能涉及筑巢、产卵和育雏的一系列复杂行为。","identification":"识别特征包括绿色翼纹、淡灰色冠顶和短尾巴，与紫喉歌雀的鸣叫相区别。","protection":"IUCN：LC（无危）","distribution":"分布于安第斯山脉，从秘鲁东南部（北普诺）向南至阿根廷西北部（胡胡伊省）。","other":"黄斑姬霸鹟通常在混合物种群中活动，其生态角色和行为值得进一步研究。"},{"name":"棕翅姬霸鹟","english_name":"Rufous-winged Tyrannulet","scientific_name":"Mecocerculus calopterus","overview":"棕翅姬霸鹟（英文名：Rufous-winged Tyrannulet，学名：Mecocerculus calopterus），是雀形目霸鹟科幽霸鹟属的鸟类。体型与莺相似，主要分布在南美洲的安第斯山脉和沿海丘陵地带，包括厄瓜多尔西部和东南部以及秘鲁北部。","appearance":"该鸟全长约11厘米，体重约10至11克。其上体为明亮的绿橄榄色，翅膀暗灰，具有两道纯白的翼带，翼缘呈亮丽的棕红色，仅基部附近和最内侧及最外侧飞羽边缘为黄色。头部为深灰色，有明显的白色眉纹，眼先至耳羽有一条宽黑线，下脸为白色，后方边界为黑色耳羽新月状图案。喉部和胸部为淡灰白色，腹部白色，下尾覆羽淡黄色。虹膜为棕色，喙长而细，黑色，腿为灰色。雄雌同形同色，幼鸟未详述。","call":"发出沙哑的双音节叫声，类似于'pur-chee'，有时会附加额外音节形成'pur-chee, chi-chi-chu'，亦会发出快速下降的强调音符串，如同'kew-ki-ke-ke-ku-ku'。","habits":"活跃于森林的中上层，可能参与混合物种群。其出现模式不稳定，可能在某些地点几个月内看似消失，对其迁移行为的研究尚不充分。","identification":"与Rufous-winged Antwren相似，但后者腹部有黄色，且冠部为灰色。区别在于棕翅姬霸鹟缺乏腹部的黄色，且冠部颜色不同。","distribution":"分布于安第斯山脉的西厄瓜多尔（自伊姆巴布拉省和萨莫拉钦奇佩省以南）和北秘鲁（南至兰巴耶克和圣马丁省）。"},{"name":"黄腹姬霸鹟","english_name":"Sulphur-bellied Tyrannulet","scientific_name":"Mecocerculus minor","overview":"黄腹姬霸鹟（英文名：Sulphur-bellied Tyrannulet，学名：Mecocerculus minor），是雀形目霸鹟科幽霸鹟属的鸟类。不常见的霸鹟科鸟类，分布于南美洲安第斯山脉从委内瑞拉西部至秘鲁北部。具有鲜明的黄色腹部，白色眉纹，灰冠，以及淡黄色翼纹。在亚热带森林及其边缘地带活动，海拔高度约在1600至2800米之间。","appearance":"这种鹦鹉状的黄腹姬霸鹟拥有亮丽的黄色腹部，薄白眉纹，淡黑色过眼纹，灰白色颊部逐渐变淡黄色。头部呈现中等灰色，与深橄榄色的背部形成鲜明对比。翅膀深色，带有两个宽阔的淡黄色条纹，飞羽边缘也是淡黄色（除基部）。尾部为暗橄榄色，边缘呈淡黄色。上喉部白色，向下渐变为深黄色，胸部为深橄榄色，腹部及尾下覆羽亮黄色。虹膜褐色，嘴细长尖锐，黑色，下颌基部浅色，腿为中灰色。雌雄外观相似，幼鸟似成鸟。","call":"会发出一系列尖锐的‘chew’音组成的吱吱声。","habits":"通常在树冠层或次冠层活动，栖息时倾向于水平姿态。成双或单独加入混群觅食，偏好亚热带湿润山地森林。","identification":"与须霸鹟相比，黄腹姬霸鹟在栖息时更倾向于水平位置，且具有独特的黄色腹部，白色眉纹，灰冠和淡黄色翼纹。","distribution":"分布于委内瑞拉西部、哥伦比亚东部、厄瓜多尔和秘鲁北部的安第斯山脉东部。"},{"name":"白斑姬霸鹟","english_name":"White-banded Tyrannulet","scientific_name":"Mecocerculus stictopterus","overview":"白斑姬霸鹟（英文名：White-banded Tyrannulet，学名：Mecocerculus stictopterus），是雀形目霸鹟科幽霸鹟属的鸟类。小型、淡色且活跃。其最显著的特征是一条粗厚的白色眉纹，翼上有明亮的白色翼带，头冠呈中灰色，背部为棕色。常水平栖息，尾巴相对较长且经常保持水平或轻微上翘。分布于南美洲安第斯山脉的委内瑞拉至玻利维亚，栖息于海拔约2,300至3,300米的亚热带和温带森林及其边缘。","appearance":"身长约为13厘米，体重8至11克。头部具有一条白色的眉纹，眼纹黑色，头冠为中灰色，与暗褐色橄榄色的背部形成对比。面部白色，后部边界模糊的灰褐色耳羽。翅膀暗灰褐色，有两条纯白的翼带，飞羽边缘（除基部附近）为亮黄色到橙黄色；尾部为暗橄榄色。喉咙和下体为灰白色，胸部和两侧略带灰色，腹部白色，尾下覆羽淡黄色。虹膜棕色；喙长而细，黑色，下喙基部有时为淡粉色；腿灰色。雌雄相似，雌鸟平均体型略小。幼鸟特征未详述。不同亚种间差异较小：taeniopterus亚种背部比指名亚种稍浅且更绿，缺乏褐色调，头冠较浅的灰色，胸部灰色较浅，二级飞羽的橙黄色不太明显；albocaudatus亚种最外侧一对尾羽为淡黄白色。","call":"发出独特的尖锐上升的‘squeeyh’叫声，有时会连续发出，偶尔夹杂着快速的颤音，先升后降；黎明时的鸣唱是这些叫声的混合，其间穿插着更尖锐的音符。","habits":"通常在树冠或次树冠层中活泼地穿梭，常出现在混合物种的鸟群中。偏好亚热带和温带的湿润山地森林。","identification":"与白尾姬霸鹟相比，体型更大，栖息海拔更高；白尾姬霸鹟的白色眉纹较窄，翼带为偏白色，整体羽色较暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的委内瑞拉至玻利维亚，主要栖息于亚热带和温带的湿润山地森林。"},{"name":"黑冠雀霸鹟","english_name":"Black-crested Tit-Tyrant","scientific_name":"Anairetes nigrocristatus","overview":"黑冠雀霸鹟（英文名：Black-crested Tit-Tyrant，学名：Anairetes nigrocristatus），是雀形目霸鹟科雀霸鹟属的小型鸟类，分布于南美洲厄瓜多尔南部至秘鲁北部的安第斯山脉区域。雄鸟具有独特的黑色面部，黑白相间的条纹，以及突出的长冠羽。雌鸟和幼鸟较为灰暗，色彩对比不明显，冠羽较短。","appearance":"成年雄性黑冠雀霸鹟的头部中央羽毛显著延长，形成细长而分叉的冠羽，覆盖在其广阔的白色顶冠和颈背斑块之上；前额、整个脸部和下巴呈黑色；背部黑色，有狭窄的白色条纹；翅膀黑色，翼盖有宽大的白色尖端，形成两道醒目的翼带；次级飞羽边缘白色，仅基部例外，白色最宽处位于最内侧飞羽；尾羽黑色，边缘白色，白色部分最宽（11-18毫米）出现在最外侧一对尾羽上，其外侧羽毛亦为白色；喉咙、胸部和两侧有黑白相间的条纹，腹部和尾下覆羽为淡黄色；虹膜深棕色；喙鲜橙色，尖端黑色；腿黑色。雌鸟与雄鸟相似，但冠羽较短，头部前端颜色较暗，黑白图案淡化为灰白相间，喙主要为黑色，仅下颚基部为黄橙色。幼鸟冠羽更短，头部颜色较暗，背部模糊的黑色和淡橄榄色条纹，脸颊和眼圈淡黄色，下体污白色，胸部隐约有深褐色条纹，喙色暗，下颚基部粉红色。","call":"黑冠雀霸鹟的叫声包括尖锐的叫声和快速的颤音，常在灌木丛和轻树林中发出。","habits":"黑冠雀霸鹟栖息于亚热带或热带湿润的山地森林和高海拔的灌木地带。它们的活动范围广泛，善于在树枝间穿梭，以昆虫为主食。","breeding":"繁殖期、求偶、营巢、交配、产卵、孵化和育雏的具体细节尚需更多研究。","identification":"与黑冠雀霸鹟最相似的是黑白冠雀霸鹟，但黑冠雀霸鹟的尾羽末端白色部分更宽；此外，其分布范围更偏北。雌鸟和幼鸟可能与黄嘴雀霸鹟混淆，但黑冠雀霸鹟背部无棕色，腹部无黄色。","protection":"IUCN状态未知，未列入华盛顿公约(CITES)附录或中国国家重点保护野生动物名录。","distribution":"分布于南美极端南部的厄瓜多尔（Loja省南部）和秘鲁北部（从Cajamarca省向南至Ancash省东部和Huánuco省西部）。","other":"黑冠雀霸鹟所属的Anairetes属被认为与Mecocerculus和Serpophaga属关系最近，但缺乏确凿证据支持这一分类观点。"},{"name":"斑冠雀霸鹟","english_name":"Pied-crested Tit-Tyrant","scientific_name":"Anairetes reguloides","overview":"斑冠雀霸鹟（英文名：Pied-crested Tit-Tyrant，学名：Anairetes reguloides），是雀形目霸鹟科雀霸鹟属的小型活跃鸟类。分布于秘鲁中西部至智利西北部的沿海及高海拔地区，栖息于亚热带或热带湿润灌木丛和高海拔灌木丛中。","appearance":"斑冠雀霸鹟具有独特的分叉状冠羽，由伸长的侧冠羽毛和较短的中央羽毛组成，这是其属内独有的特征。雄鸟拥有醒目的黑白相间的羽毛，头部和喉部全黑，胸部和背部带有宽大的黑白条纹，腹部颜色从白色到淡黄色不等。雌鸟相似，但冠羽较短，暗色部分呈暗灰色而非黑色，喉部有细白纹。幼鸟的冠羽明显减小，上体深褐色，下体淡黄色，面部更平淡，有白色喉部，冠羽中的白色斑块显著。","habits":"斑冠雀霸鹟栖息于干燥至半干旱的灌木丛环境，活动范围广泛，从沿海的河岸灌木丛到海拔4000米的Polylepis森林均有分布。它在浓密的植被中积极觅食，以小型节肢动物为主食，通过停栖捕食或悬停捕食方式获取食物。","identification":"斑冠雀霸鹟与黑冠雀霸鹟最为相似，但两者体型大小和冠羽长度不同，黑冠雀霸鹟的尾羽下部白色尖端更为宽大。此外，幼鸟的识别需谨慎，特别是在多种Anairetes物种共存的区域，因为幼鸟的冠羽减小，羽毛颜色更暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲秘鲁中西部至智利西北部，包括沿海地区及高海拔地带。"},{"name":"灰胸雀霸鹟","english_name":"Ash-breasted Tit-Tyrant","scientific_name":"Anairetes alpinus","overview":"灰胸雀霸鹟（英文名：Ash-breasted Tit-Tyrant，学名：Anairetes alpinus），是雀形目霸鹟科雀霸鹟属的鸟类。小型霸鹟科雀霸鹟属鸟类，分布于南美的秘鲁和玻利维亚高海拔地区。该鸟以暗灰色为主调，具黑色翅膀和尾巴，白色翼纹和尾羽边缘，黄色腹部。","appearance":"灰胸雀霸鹟体型小巧，全长约13厘米，全身以柔和的灰色为主，背部模糊的黑色条纹，头部黑色，冠羽延长形成细长的叉状。翅膀黑色，两道显著的白色翼纹，内侧飞羽和次级飞羽边缘白色。尾巴上部黑色，下部大部分白色，腹部白色或极淡黄色。雌雄相似，无明显性别差异。","call":"灰胸雀霸鹟的叫声是一系列充满活力却略显烦躁的音符，通常被描述为“whew, pew, pew, pew, pew…”。","habits":"栖息于高海拔的Polylepis林地与灌木丛中，常见于陡峭的草坡或岩石山坡地带。常单独或成对活动，偶尔加入混种群。以昆虫为食，具体饮食细节未知。","breeding":"关于灰胸雀霸鹟的繁殖信息有限，其筑巢习性和繁殖周期尚待更多研究。","identification":"在灰胸雀霸鹟的分布范围内，它是唯一具有白色翼纹的小型灰色霸鹟。与之可能混淆的物种包括纯色栗臀雀和铅色岭雀鹀，但它们不具备灰胸雀霸鹟独特的白色翼纹和尾羽标记。","protection":"IUCN：EN（濒危）","distribution":"分布于南美洲的秘鲁和玻利维亚高海拔地区，具体位于3700至4600米的高安第斯山脉。","other":"灰胸雀霸鹟因Polylepis栖息地的丧失而面临严重威胁，其数量持续下降。"},{"name":"黄嘴雀霸鹟","english_name":"Yellow-billed Tit-Tyrant","scientific_name":"Anairetes flavirostris","overview":"黄嘴雀霸鹟（英文名：Yellow-billed Tit-Tyrant，学名：Anairetes flavirostris），是雀形目霸鹟科雀霸鹟属的小型鸟类，活跃于南美洲安第斯山脉干燥地区的灌木丛和杂草丛中，也局部出现在阿根廷低地。其显著特征为胸部大胆的黑色条纹和轻柔的黑色羽冠。","appearance":"这种小鸟通常成对活动，善于在灌木和杂草间跳跃，因此观察起来颇为困难。最明显的识别特征是胸部鲜明的黑条纹和飘逸的黑色羽冠。嘴基部呈现鲜亮的橙色，但在野外环境下较难观察到这一细节。","habits":"黄嘴雀霸鹟偏好栖息于亚热带或热带湿润的山地森林和高海拔的灌木地带。它们的活动范围广泛，涉及多个南美国家，包括阿根廷、玻利维亚、智利和秘鲁。","identification":"与同属的其他物种相比，黄嘴雀霸鹟的橙色嘴基和独特的胸部条纹是辨识的关键。此外，其特有的栖息环境和活动模式也有助于区分。","distribution":"黄嘴雀霸鹟的分布区域跨越南美洲西部、中南部和东南部，具体包括阿根廷、玻利维亚、智利和秘鲁等地的山地森林和高海拔灌木地带。"},{"name":"须雀霸鹟","english_name":"Tufted Tit-Tyrant","scientific_name":"Anairetes parulus","overview":"须雀霸鹟（英文名：Tufted Tit-Tyrant，学名：Anairetes parulus），是雀形目霸鹟科雀霸鹟属的小型鸟类。其显著特征为独特的黑色羽冠，眼睛呈淡黄色至奶油白色，喙黑色。分布于南美洲的安第斯山脉，从哥伦比亚南部至智利和阿根廷，亦见于智利中部低地及阿根廷北部巴塔哥尼亚。活跃于各种灌木丛、轻林区，乃至高海拔的Polylepis森林。","appearance":"须雀霸鹟体型小巧，平均长度9.5至11厘米，体重约6克。最引人注目的特征是其长而弯曲的黑色羽冠，常呈分叉状，仿佛拥有两根“小角”。头部黑色，具白色眉纹和眼后纹。背部灰褐色，翅膀和尾巴暗色，翼上有两条狭窄的白色翼带。腹部黄色，喉部和胸部为白色，布满深灰色至黑色条纹。腿脚黑色。雌雄相似，但雌鸟可能略小，羽冠稍短。幼鸟色泽较淡，羽冠更短，翼带带有黄褐色，无隐蔽的白色冠斑。","call":"具有响亮、高音的鸣叫声，包括快速的‘chuit-chuit-chuit-chuit-chuit-chidi-didi’歌曲和偶尔发出的缓慢系列‘chuit’单音。在成对觅食时，会发出‘perr-reet’的联系叫声。","habits":"栖息于上山森林和灌木丛，亦适应多种生境，如云雾林边缘、Polylepis树林、受干扰的湿润灌木丛、温带森林和干燥的荆棘灌木丛。主要以昆虫为食，偶尔食种子。活动范围广泛，从海平面到海拔4,200米皆可见其踪迹。成对或小家庭群觅食，有时加入混合物种觅食群。","breeding":"繁殖季节因地理位置而异，北方种群自1月至6月，南方种群自8月至1月。每年繁殖两次，巢筑于灌木或竹子旁，靠近溪流、空地或路径，呈杯状，由根纤维、苔藓、草和绒毛构成，内衬细小羽毛。每窝产2至3枚蛋，蛋色为乳黄色。","identification":"与黄嘴雀霸鹟相似，但下体条纹更细，翼带更窄，喙全黑，眼色鲜明。相较于弗南多斯雀霸鹟，体型更大，腹白，下体条纹更重。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲西部和南部，包括哥伦比亚、厄瓜多尔、秘鲁、玻利维亚、阿根廷和智利。在安第斯山脉北部主要限于山区，南部则扩展至沿海地区。","other":"须雀霸鹟有三个亚种：A. p. aequatorialis（哥伦比亚南部至阿根廷北部）、A. p. parulus（智利西部和阿根廷西南部至火地岛）和A. p. patagonicus（阿根廷西部）。"},{"name":"弗南多斯雀霸鹟","english_name":"Juan Fernandez Tit-Tyrant","scientific_name":"Anairetes fernandezianus","overview":"弗南多斯雀霸鹟（英文名：Juan Fernandez Tit-Tyrant，学名：Anairetes fernandezianus），是雀形目霸鹟科雀霸鹟属的特有种，仅分布于南美洲智利的胡安·费尔南德斯群岛的罗宾逊克鲁索岛。这较为罕见且数量正在下降的鸟类。","appearance":"弗南多斯雀霸鹟通常成对出现，活跃于残存的本土灌木丛和低矮林地中，主要栖息于高于城镇的海拔地带。它们具有明显的条纹胸部和瞪大的淡色眼睛，其细软的羽冠常常被压平。","habits":"弗南多斯雀霸鹟偏好在残存的本土灌木和低矮林地中活动，主要在高于城镇的海拔地带。它们通常成对出现，活跃于植被较低处，有时表现出好奇的行为。","identification":"其特征性的条纹胸部和突出的淡色眼睛，以及常被压平的细软羽冠，是辨识弗南多斯雀霸鹟的关键特征。","protection":"IUCN：EN（濒危）","distribution":"分布局限于南美洲智利的胡安·费尔南德斯群岛，特别是在罗宾逊克鲁索岛上。"},{"name":"敏雀霸鹟","english_name":"Agile Tit-Tyrant","scientific_name":"Uromyias agilis","appearance":"这是一种小型的、尾巴相对较长的霸鹟，其外观常常显得蓬乱，下方有杂乱的条纹，眉线模糊呈白色，面部有较暗的面具状斑纹。翅膀上无明显的翼带，腹部呈淡柠檬黄色，头顶有轻微的松散羽冠（通常平贴着）。","call":"会发出连续的颤音和兴奋的尖叫声。","habits":"常见于小规模群体，它们在林下层积极觅食，有时会跟随混合物种的鸟群。栖息于海拔约2,600至3,500米的温带灌木林及其边缘。","breeding":"在竹子的茎秆中筑巢，利用竹叶编织巢穴，巢内衬以其他鸟类的羽毛。","identification":"与相似种类相比，缺乏翼带，腹部颜色独特，且头部特征明显，有助于与其他物种区分开来。","distribution":"分布于委内瑞拉西部（梅里达、塔奇拉）、哥伦比亚东部与中部山脉，以及厄瓜多尔（西部至科托帕希，东部至洛哈东北部）。"},{"name":"无纹雀霸鹟","english_name":"Unstreaked Tit-Tyrant","scientific_name":"Uromyias agraphia","overview":"无纹雀霸鹟（英文名：Unstreaked Tit-Tyrant，学名：Uromyias agraphia），是雀形目霸鹟科敏雀霸鹟属的鸟类。原生于秘鲁安第斯山脉东坡，栖息于海拔2700至3100米的竹林边缘和森林下层。其外观似山雀，头部较大，常直立站立。","appearance":"体型小，上体呈暗褐色，具显著的白色眉纹，胸腹部淡灰色，略带斑点，腹部和臀部呈柠檬黄色。头部特征明显，黑色的眼线和冠羽，白色眉纹。雄雌相似，无显著性别差异。","call":"发出清脆的高音歌曲和断续的‘peep’叫声，有助于识别。","habits":"偏好高海拔的森林边缘环境，常见于竹林附近。以群居为主，频繁参与混合物种群体的觅食活动。主要食物来源为昆虫。","breeding":"具体繁殖习性资料有限，通常在春季繁殖，营巢于树洞或灌木丛中，由雌雄共同参与繁殖活动。","identification":"与敏雀霸鹟的区别在于，无纹雀霸鹟上体斑纹较少，眉纹颜色较淡，腹部更黄。两物种分布区域不重叠。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲秘鲁境内，尤其是安第斯山脉东坡的高海拔地区。","other":"与敏雀霸鹟有近缘关系，但在地理分布和生态位上有所区别。"},{"name":"灰姬霸鹟","english_name":"Torrent Tyrannulet","scientific_name":"Serpophaga cinerea","overview":"灰姬霸鹟（英文名：Torrent Tyrannulet，学名：Serpophaga cinerea），是雀形目霸鹟科灰姬霸鹟属的鸟类。独居于中美至南美快速流动的山溪旁，从哥斯达黎加延伸至玻利维亚北部及委内瑞拉西北部。其独特的小型体态和灰白色调的羽毛，使它在湍流中的岩石上格外显眼。","appearance":"成年灰姬霸鹟长约10至11.4厘米，体重约8克。雄鸟上身淡灰色，下身灰白渐变至喉部及腹部下方的纯白色。眼上方至头顶部黑色，冠羽隐匿白色斑块，翅膀与尾羽深黑。雌鸟头部略显灰暗，冠羽斑块缩小或消失，幼鸟具褐色顶冠，背部微黄，翼纹更宽泛呈黄色。","call":"鸣声为尖锐穿透的chip声，易于湍急水流的噪音中辨识；歌唱时重复其叫声或以seek开头，随后是一连串颤音ti,ti,ti,ti,ti,ti,。","habits":"栖息于海拔300至2200米的山溪岩石区，偏好湍急水域。其飞行低而直接，类似水雉，常在水面低飞。以昆虫为食，通过空中捕捉或在河岸植被及岩石上寻觅。","breeding":"筑杯状巢于水面上方至4米高的枝干，或岩石岸边，内部铺垫羽毛，外表覆盖苔藓，每次产卵两枚，颜色为浅黄或白色，无斑点。","identification":"与同类相比，灰姬霸鹟的灰白色调和独特的栖息环境使其易于识别。与亚马逊流域的河姬霸鹟和黑长尾霸鹟相比，体型更小，上体颜色更灰，翼尾色浅。","protection":"IUCN：LC（无危）","distribution":"繁殖于中美洲至南美洲，范围涵盖哥斯达黎加至玻利维亚，及委内瑞拉西北部。"},{"name":"河姬霸鹟","english_name":"River Tyrannulet","scientific_name":"Serpophaga hypoleuca","overview":"河姬霸鹟（英文名：River Tyrannulet，学名：Serpophaga hypoleuca），是雀形目霸鹟科灰姬霸鹟属的小型飞禽。常见于低地河流附近的岛屿或沿岸植被中。其最显著的外部特征是黑色、灰色和白色的羽毛搭配，体型较小，与黑长尾霸鹟相比更轻盈，后者常出现在高海拔的湍急河流旁。","appearance":"体长约10.5厘米，体重介于5.5至6.7克之间。河姬霸鹟拥有细长的身躯，头部以灰色为主，中央冠羽部分呈黑色并形成扁平的顶冠，遮掩住白色的冠斑。眼睛周围有白色眼圈，背部和翅膀呈现均匀的棕灰色，尾巴较长且暗淡。脸部下方、下巴及整个下体为白色，胸部略带浅灰色调。虹膜深棕色，喙黑色，腿呈深灰色。雌雄外观相似，幼鸟与成鸟无明显差异。不同亚种在颜色和大小上存在细微差别。","call":"兴奋时发出连续上升的颤音，前有两音节的短语，重音在第二个音节上，例如“chip-skéép-pf-t-t-t-t-t-t-t-et-et-et-chip-chip”或“d-d-d-r-r-re-re-re-reet？”。伴侣间的二重唱表现为快速的“p’dit-p’dit-p’dt”或“pikup, pikup, pikup”。觅食时还会发出微弱的“see-blik”或“pit-chick”声。","habits":"栖息于亚马逊盆地的河畔，偏好在河流走廊的亚热带或热带湿润灌木丛中活动。主要分布在南美洲的秘鲁、委内瑞拉和巴西，以及厄瓜多尔、哥伦比亚和玻利维亚的部分边境地区。河姬霸鹟沿着几大主要河流如亚马逊河、奥里诺科河、托坎廷斯河、阿鲁瓜亚河、欣古河、马代拉河和乌卡亚利河等生活，通常在河岸的灌木丛中穿梭觅食。","breeding":"具体繁殖信息未详述。","identification":"与黑长尾霸鹟相比，河姬霸鹟体型更小，下体颜色更浅。不同亚种间在颜色深浅和顶冠的大小上有区别，尤其是委内瑞拉亚种（venezuelana）比指名亚种更小，顶冠上的黑色较少，白冠斑较小，几乎无顶冠，喙较短。","protection":"IUCN状态未提及。","distribution":"河姬霸鹟主要分布于南美洲的亚马逊盆地，包括秘鲁、委内瑞拉、巴西，以及厄瓜多尔、哥伦比亚和玻利维亚的部分边境地区。其栖息地集中在亚马逊河、奥里诺科河、托坎廷斯河、阿鲁瓜亚河、欣古河、马代拉河和乌卡亚利河等河流走廊。"},{"name":"烟姬霸鹟","english_name":"Sooty Tyrannulet","scientific_name":"Serpophaga nigricans","overview":"烟姬霸鹟（英文名：Sooty Tyrannulet，学名：Serpophaga nigricans），是雀形目霸鹟科灰姬霸鹟属的鸟类。身长约12厘米，重约9克。羽毛呈深灰至棕灰色调，尾羽黑色，常见于南美洲的河流、溪流、池塘和湿地附近。其分布范围覆盖了玻利维亚南部、巴拉圭、巴西中南部、阿根廷中部及乌拉圭。","appearance":"烟姬霸鹟体型娇小，尾部较长，全身羽毛均匀暗灰至棕灰，头顶略深，半隐藏的白色冠纹。翅膀颜色较暗，有两道模糊的浅灰色翼带，最内侧飞羽边缘泛白至灰白。尾巴黑色，下颏白色，腹部淡灰比背部更浅，两胁后期染有棕色。虹膜深褐色，喙与腿均为黑色。雌雄相似，幼鸟描述未详。","call":"鸣唱由几个断续音符开始，随后是一连串较高音的甜美‘金丝雀般’音符。","habits":"栖息于亚热带或热带湿润灌木丛，偏好靠近水源如河流和沼泽地带。活跃于岩石或枝条间，极少落地，会空中掠食昆虫或水面捕食。常上下摆动尾部，有时扇动。","breeding":"繁殖季节在10月至12月，双亲共同筑巢，巢通常位于悬垂枝下，可能靠近桥梁等结构。巢由紧密的根和草构成，内部铺以羽毛，平均产卵三枚。关于孵化时间和幼鸟离巢时间未知。","identification":"与尤氏小霸鹟及灰姬霸鹟有亲缘关系，但具体辨识特征需依据外形、行为及分布区。","protection":"IUCN：LC（无危）","distribution":"分布于南美，包括玻利维亚南部、巴拉圭东部和巴西中南部至阿根廷中部和乌拉圭，以及自2010年起新记录的巴西托坎廷斯州。","other":"在多个国家公园和其他保护区中均有发现，如巴拉圭的Ybycuí国家公园，巴西的Aparados da Serra、Iguaçu和Serra da Canastra国家公园，以及阿根廷的Iguazú国家公园和San Juan de Poriahú私人保护区。"},{"name":"白冠姬霸鹟","english_name":"White-crested Tyrannulet","scientific_name":"Serpophaga subcristata","overview":"白冠姬霸鹟（英文名：White-crested Tyrannulet，学名：Serpophaga subcristata），是雀形目霸鹟科灰姬霸鹟属的鸟类。小型霸鹟科鸟类，分布于南美洲的阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭的林地和开阔地带，带有散生灌木和树木。其近亲为白腹姬霸鹟，但白冠姬霸鹟的腹部呈黄色。新描述的灰冠姬霸鹟与其极其相似，长时间被混淆，通常需通过声音来区分。","appearance":"成鸟具细长的白色眉纹，从喙延伸至眼后方，有淡色眼环，灰色橄榄色上身，头部和颈背更显纯灰色，中央顶冠有数根黑色羽毛部分遮盖着白色的冠状条纹；双翼暗至黑色，有两道明显白色至淡黄褐色的翼带，尾巴暗色，外侧尾羽边缘白色；面部灰白，下巴和喉咙白色，胸部灰色，腹部强烈泛黄。幼鸟翼带黄褐色，顶冠极少或无白色。成鸟体长11厘米，体重6-8.6克。","call":"快速的干裂声，尖锐的“pip, wi-di-dit”声，以及一系列较长的啾啾声和颤音。清晨时，发出柔和而欢快、几乎机械般的声音，如“psee psee psee-e-e-e-e-e-e”，每3-4秒重复一次。","habits":"偏好开放生境，如灌丛、杂草丛生的空地、林缘，不在成熟森林内部发现。迁徙模式部分已知，一些群体离开繁殖地，另一些仅下降到较低海拔。活动于低地热带森林边缘、落叶林、画廊森林、荆棘森林、高大的半干旱山地灌木、草原、花园和种植园，甚至农业区的围栏线旁。","breeding":"繁殖季节在巴西和阿根廷为8月至次年1月，筑巢由双方共同完成，持续4-7天，巢为紧凑的开放式杯状，直径5.5-6厘米，内部直径3.5厘米，高度5.5厘米，由草茎和其他植物纤维构成，装饰以蜘蛛卵囊和苔藓，内部大量铺垫羽毛。每窝产2枚乳白色蛋，偶尔3枚，由双方轮流孵卵，孵化期13-15天。","identification":"与灰冠姬霸鹟极为相似，区别主要依赖声音，白冠姬霸鹟腹部呈黄色，而灰冠姬霸鹟腹部可能为白色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的玻利维亚西部至阿根廷南部，巴西东部至乌拉圭，以及巴拉圭。在繁殖季节，向东南巴西沿海和乌拉圭迁徙。","other":"尽管其分类地位曾有争议，但现在认为与是同一物种，主要依据是相似的鸣叫声、最近的分化时间和微小的形态差异。"},{"name":"白腹姬霸鹟","english_name":"White-bellied Tyrannulet","scientific_name":"Serpophaga munda","overview":"白腹姬霸鹟（英文名：White-bellied Tyrannulet，学名：Serpophaga munda），是雀形目霸鹟科灰姬霸鹟属的鸟类。小型霸鹟科鸟类，与白冠姬霸鹟关系密切，外观相似，但上部羽毛更偏灰色，腹部呈白色，缺乏黄色色调。分布于阿根廷西部、查科、蒙特沙漠及埃斯皮纳尔部分地区，向南至玻利维亚南部。冬季迁徙至东部，与白冠姬霸鹟共同生活，直至乌拉圭。","appearance":"体长约11.5厘米，体重4.5至9克。具有灰色和白色的特征，眉纹细长，从喙延伸至眼后，具断续的白色眼环，淡色眼线；冠羽和颈项纯灰色，几根黑色中央冠羽遮掩着白色冠纹，其余部分为灰色，仅略带橄榄色光泽；翅膀暗至黑色，两道白色翼纹明显，多数飞羽外缘宽幅白色至淡黄色；尾巴暗色，最外侧尾羽外缘白色；脸部灰白色，颏和喉部白色，胸浅灰色，腹部和下腹部白色，有时微泛乳黄色；虹膜深棕色；喙细长，黑色；腿灰色。雌雄同形，雌鸟稍小。幼鸟翼纹呈黄褐色，冠羽缺少白色。","call":"鸣唱为柔和的机械式颤音，开始时有几个引子音节，‘psee-psee-e-e-e-e-e-e-e-e-e-e-e’，比白冠姬霸鹟略高、快且长，每3秒重复一次，日出时最为频繁，巡逻领地时也会几乎同样频繁地发出。还有较慢、节奏感强的‘tsi, tsu-tsu, tsu-tsu, tsu-tsu’和其他杂乱的叽喳声。","habits":"白腹姬霸鹟偏好干旱灌木丛生地带，如荆棘林和落叶林，海拔可达2900米。非繁殖季节，出现在查科和多种灌木及开阔地带，包括农田。冬季迁移到较低海拔，北移至查科和巴塔哥尼亚低地，部分个体甚至到达巴西东南部沿海和乌拉圭。以昆虫为食，活跃于灌木边缘，短暂停留，常展示冠羽。","breeding":"繁殖期为9月至1月，巢由双亲共建，耗时4至7天。巢建于树干水平或倾斜枝条的交叉点，通常被茂密的覆盖物和荆棘包围，尤其偏爱chañar树或其他荆棘灌木。巢为紧密构造的开放杯状，直径5.5厘米，内径3.5厘米，高度5.5厘米，由草茎和其他植物纤维制成，装饰有蜘蛛卵囊和地衣，内部大量铺垫羽毛，曾观察到几乎全部为鸵鸟科羽毛。产卵2至3枚，颜色为奶油白色。双亲轮流孵卵，孵化期13至15天。双亲共同喂养雏鸟，育雏期13至14天。","identification":"与白冠姬霸鹟的区别在于上体颜色更偏灰色，腹部白色，缺乏黄色色调。鸣叫声也有细微差异，白腹姬霸鹟的声音更高、更快、更长。","protection":"IUCN：LC（无危）","distribution":"繁殖于玻利维亚西部安第斯山脉（自拉巴斯向南）和阿根廷西部（至内乌肯和里奥内格罗西部）；冬季迁徙至东部，最远抵达巴西东南部沿海和乌拉圭，以及北至玻利维亚东北部（圣克鲁斯省）。","other":"关于其分类地位存在争议，曾被认为是白冠姬霸鹟的亚种，但两者在羽毛、声音上有细微差别，且在阿根廷的分布呈狭缝状邻接，有有限的杂交现象。"},{"name":"灰冠姬霸鹟","english_name":"Straneck's Tyrannulet","scientific_name":"Serpophaga griseicapilla","overview":"灰冠姬霸鹟（英文名：Straneck's Tyrannulet，学名：Serpophaga griseicapilla），是雀形目霸鹟科灰姬霸鹟属的小型鸟类。主要分布在南美洲中南部的林地和开阔地带，具有散生灌木和树木的环境，确切的分布细节尚待澄清。在阿根廷繁殖，可能也在玻利维亚繁殖。除上述国家外，还被记录为非繁殖季节的访客出现在巴拉圭，以及巴西和乌拉圭（其在后两国的出现是否为规律性的非繁殖访客还是仅限于偶然到访，目前尚不清楚）。","appearance":"体长约9-10.7厘米，体重约4.4-7.5克。头部呈灰色，眼纹较暗；冠羽可能有少量黑色羽毛，基部隐藏着白色。眉纹对比明显，眼下方有白色新月状斑块。上体颜色从灰色渐变为橄榄色或橄榄褐色。翼上有两道明显的条纹，由棕色灰羽尖形成。尾羽深灰褐色，新鲜时有浅色边缘。下体从喉咙至胸部逐渐染黄，腹部淡黄色，胸侧略带灰色调。虹膜榛色至深棕色，喙和腿黑色。","call":"全年都会发出高音但传播不远的叫声“twie tirrrrrrrrrrrrrrrrrr”，有时单独发出第一或第二部分；在警戒时刻，会发出更有力、高音的“tie...tie...tie...”，通常为3-5个音节。","habits":"迁徙性鸟类。非繁殖季节，通过阿根廷东北部和东部迁徙（从米西奥内斯至布宜诺斯艾利斯），并北移至玻利维亚，可能在那里繁殖，以及到巴拉圭。单个记录显示，它也可能出现在巴西极南部和乌拉圭，但其状态尚不明确。","breeding":"在阿根廷的内乌肯省，巢穴在11月第一周准备好迎接产卵，位于地面以上1.2米处，处于以Prosopidastrum angusticarpum为主的灌木丛中。","identification":"外观上与白冠姬霸鹟极为相似，但叫声独特且尾巴较短。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括南美洲的阿根廷中西部和西北部。非繁殖区域涉及玻利维亚、阿根廷北部、乌拉圭西部、巴拉圭以及巴西（状态不明）。","other":"曾有一段时间，由于分类学上的混乱，该物种错误地使用了科学名称Serpophaga griseiceps，这是白腹姬霸鹟的次级同义词。直到2007年，灰冠姬霸鹟才正式获得其科学名称，尽管自上世纪90年代初以来人们已知晓其存在。"},{"name":"灰色小霸鹟","english_name":"Mouse-colored Tyrannulet","scientific_name":"Phaeomyias murina","overview":"灰色小霸鹟已删除（英文名：Mouse-colored Tyrannulet，学名：Phaeomyias murina），是雀形目霸鹟科灰色小霸鹟属的小型鸟类。广泛分布于南美洲热带和亚热带的灌木丛和林地中，但在大陆最南端、高海拔安第斯山脉及密集雨林中罕见。尽管普遍常见，其小巧体型和不起眼的羽毛色彩常使它被忽视，或仅被视为普通霸鹟的一员。","appearance":"该鸟体长约为10厘米，整体呈现淡灰褐色，上体颜色较深，下体较浅，具有一些不显眼的条纹。头部圆形，喙尖而细长，适于捕食昆虫。雌雄鸟外观相似，幼鸟可能具有更为柔和的色彩。","call":"其鸣叫声独特，有助于在视觉难以分辨的情况下进行物种识别。具体声音特点需参照专业音频资料。","habits":"偏好灌木丛生和树林边缘地带，活动范围广泛，不局限于特定纬度或海拔。它是一种非迁徙性的鸟类，全年在相同区域内活动。以昆虫为食，善于空中捕猎，飞行敏捷。","breeding":"繁殖季节内，会进行求偶展示，营巢于灌木或低矮树木中，使用干草和苔藓筑巢。每次产卵数量通常为2至3枚，由双亲共同孵化和育雏。","identification":"与白腹灰色小霸鹟和科岛霸鹟极为相似，但通过其独特的鸣叫声可以进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲大部分地区，自哥伦比亚南部至阿根廷北部，包括巴西、秘鲁、玻利维亚和巴拉圭等地。","other":"历史上曾与白腹灰色小霸鹟和科岛霸鹟被视为同一物种，后经研究确认为独立物种。"},{"name":"白腹灰色小霸鹟","english_name":"Tumbesian Tyrannulet","scientific_name":"Nesotriccus tumbezanus","overview":"白腹灰色小霸鹟（英文名：Tumbesian Tyrannulet，学名：Nesotriccus tumbezanus），是雀形目霸鹟科科岛霸鹟属的鸟类。是南美洲特有种，常见于厄瓜多尔西南部和秘鲁西北部的沙漠灌木丛及森林地带。其体型小巧，外表朴素，容易被忽视，常与其它几种小霸鹟混淆，尤其是与灰色小霸鹟。名称源于秘鲁西北部城市Tumbes。","appearance":"该鸟体色以灰褐为主，缺乏黄色调，翼上有棕色条纹，眼周有一圈淡色斑纹。头部圆润，无明显的冠羽，这有助于将其与南无须小霸鹟和灰白小霸鹟区分开来。与马谷白腹灰色小霸鹟极为相似，两者的区别非常细微，通常通过分布区域来区分。","call":"鸣声短促而突然，包括快速的“widichit！”和“peedit！”叫声，以及各种尖锐的吱吱声和沙哑声，与马谷白腹灰色小霸鹟的鸣声有所区别。","habits":"偏好居住在干燥森林和沙漠灌木丛中，主要分布在厄瓜多尔西南部和秘鲁西北部。尽管在其有限的分布范围内较为常见，但因体型小且外表不起眼，容易被忽略。活动范围包括西部低地至安第斯山脉较低的山麓。","identification":"与马谷白腹灰色小霸鹟极为相似，但两者的分布范围不同，马谷白腹灰色小霸鹟不在其区域内。鸣叫声也有差异，白腹灰色小霸鹟的叫声更短促。","protection":"IUCN：LC（无危）","distribution":"分布于南美，具体为厄瓜多尔西南部和秘鲁西北部，主要栖息于沙漠灌木丛及森林地带。"},{"name":"科岛霸鹟","english_name":"Cocos Tyrannulet","scientific_name":"Nesotriccus ridgwayi","overview":"科岛霸鹟（英文名：Cocos Tyrannulet，学名：Nesotriccus ridgwayi），是雀形目霸鹟科科岛霸鹟属的鸟类。小型、色彩朴素，仅分布于太平洋中的科科斯岛，位于哥斯达黎加西南约300英里处。该鸟种是科岛特有种。","appearance":"成年科岛霸鹟长约11厘米，体重约11克。上部羽毛颜色从灰橄榄色到深棕色橄榄色不等，头部与背部颜色相似，具有一条微弱的较浅眉纹；翅膀和尾巴呈暗灰色，有两条黄色的翼带和淡黄褐色的飞羽边缘；下部羽毛从灰黄褐色到淡黄色，胸部带有棕色至橄榄色的色调。眼睛虹膜深棕色，上喙棕色至黑色，下喙白色、粉红色或浅角质色，尖端暗灰色；腿脚暗灰色。雄鸟和雌鸟外观相似，幼鸟颜色更偏棕色，翼带呈黄褐色至肉桂色。","call":"其典型鸣唱为一段短促、下降的喷嚏声。","habits":"科岛霸鹟栖息于湿润森林以及灌木丛和沼泽地带，偏好密集植被环境。","breeding":"具体繁殖信息未知。","identification":"通过其特有的灰橄榄色至深棕色橄榄色的上部羽毛，淡黄褐色的翼带和下部羽毛，以及独特的喷嚏声鸣唱，可以识别科岛霸鹟。","protection":"IUCN：VU（易危）","distribution":"仅分布于哥斯达黎加西南远海的科科斯岛。","other":"科岛霸鹟面临的最大威胁是外来物种，尤其是鼠类（Rattus）和猫，以及外来草食动物（如鹿、猪、山羊），这些物种破坏了其栖息地。"},{"name":"北灰色小霸鹟","english_name":"Northern Mouse-colored Tyrannulet","scientific_name":"Nesotriccus incomtus","overview":"北灰色小霸鹟（英文名：Northern Mouse-colored Tyrannulet，学名：Nesotriccus incomtus），是雀形目霸鹟科科岛霸鹟属的小型鸟类。分布于南美洲热带和亚热带地区的轻林和灌木丛中，从哥斯达黎加南部至巴拿马，穿过哥伦比亚和厄瓜多尔东北部，到达委内瑞拉、特立尼达和圭亚那。该物种较为常见，但由于体型小且羽毛颜色暗淡，容易被忽视。","appearance":"这是一种小型、色调沉闷的霸鹟，具有圆顶状的头部，无冠羽，长眼纹，以及明显的淡色翼条。雄雌相似，幼鸟的羽毛可能较成鸟更显柔和。整体上，北灰色小霸鹟的外观与其他几种类似的霸鹟非常接近。","call":"其典型鸣唱为嗡嗡的颤音，起初上升，然后突然在结尾处下降。","habits":"北灰色小霸鹟栖息于各种灌木和林地环境，避开高海拔的安第斯山脉和密集的雨林。它们在树冠层活动，以昆虫为主食。","breeding":"关于其繁殖生态的详细信息尚不充分，但与其他霸鹟类似，可能在树枝上筑巢，由雌雄共同参与繁殖过程。","identification":"与灰色小霸鹟非常相似，主要区别在于分布区域及可能的遗传差异，但在巴西中部地区，仅凭外观可能难以区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲南部的哥斯达黎加和巴拿马，向南延伸至南美洲北部的哥伦比亚、厄瓜多尔东北部、委内瑞拉、特立尼达和圭亚那。","other":"该物种最近从遗传学角度与灰色小霸鹟进行了区分，此前曾被视为同一物种的一部分。现为灰色小霸鹟亚种。"},{"name":"灰色小霸鹟","english_name":"Mouse-colored Tyrannulet","scientific_name":"Nesotriccus murinus","overview":"灰色小霸鹟（英文名：Mouse-colored Tyrannulet，学名：Nesotriccus murinus），是雀形目霸鹟科科岛霸鹟属的鸟类。小型、羽色朴素。体长约10.5–12厘米，重7–12.4克，羽色整体呈暗褐灰色，翼上有两道肉桂色至白色的翼斑。分布于安第斯山以东的秘鲁至巴西东南部及阿根廷东北部，栖息在干旱的低地灌丛、落叶林、干旱河谷林缘及次生灌丛，海拔可达2 400 米。典型鸣声为先升后降的嗡嗡颤音。","appearance":"成鸟雌雄同色。头顶圆润无冠，具长而明显的淡色眉纹和狭白眼圈，面喉淡灰白。上体暗褐灰色，翼及尾暗褐，两道翼斑新鲜时呈亮肉桂色，磨损后可近纯白。下体自胸至腹由灰白渐转淡黄，胸侧常带淡橄榄色细斑。嘴短粗、角质色，下嘴基部粉红；虹膜褐色；脚灰色。幼鸟羽色与成鸟相似。","call":"鸣唱为略带鼻音的短促颤音，先升后降，形如“tu-tu-tu-tu-tee!-Tr-trrp”，清晨常成对二重唱。日间鸣声为连续几次的上升短句。另有快速断续的“t-trrrrt”颤音及双音“tee-tep”叫。南群（指名亚种及wagae）清晨鸣声为3–5个沙哑短音的重复，类似部分拟霸鹟；白天鸣声则为更沙哑的上升音节。","habits":"栖息于干旱低地及低山灌丛、仙人掌灌丛、荆棘林、落叶林、河岸林缘、次生灌丛、公园及花园，海拔从海平面至2 400 米，但多低于1 000 米。繁殖后从高海拔向低地迁移；阿根廷、巴拉圭及巴西南部的种群在4月后北迁越冬于亚马逊盆地。常单独或成对在2–8 m高的枝叶间觅食，偶尔短暂加入混群；以向上飞啄、悬停啄食及栖枝啄食等方式捕捉昆虫，并大量取食槲寄生等浆果。","breeding":"繁殖期因地而异：巴拿马3–6月，哥伦比亚5–10月，巴西10–12月，阿根廷10–翌年4月。巢由雌鸟独力8天完成，为离地通常不足4 m的树枝叉上的开放杯状巢，由植物纤维、根、草茎、苔藓与蜘蛛丝构成，内外衬以羽毛；外径约6厘米，内径约4厘米。每窝2枚白色或淡粉白色卵，卵径15.7–18.4 毫米× 12–13.8 毫米，重0.8–1.3克。雌鸟单独孵卵14–17天；雏鸟留巢17天，双亲共同喂养，8–10天后开始加入浆果。","identification":"与北灰色小霸鹟（现仍未分拆）极为相似，野外区分需结合鸣声及遗传分析，巴西中部重叠区几乎无法仅凭外形区分。与同属的马谷白腹灰色小霸鹟和白腹灰色小霸鹟相比，本种体型较小，翼斑颜色较淡，鸣声结构不同。亚种间差异主要在于羽色深浅及下体黄色强度，指名亚种murinus与ignobilis无法区分，wagae则上体带最暗橄榄色、下体黄色更深、嘴略大。","protection":"IUCN: LC（无危）","distribution":"繁殖区：哥伦比亚北部及安第斯山区、委内瑞拉（除南部亚马逊州）、特立尼达及多巴哥、圭亚那、苏里南、法属圭亚那、厄瓜多尔东北部、秘鲁东部、玻利维亚北部及中部、巴西大部（亚马逊以南）、巴拉圭、阿根廷西北部及东北部（至拉里奥哈及查科省）。非繁殖区：巴西南部的种群冬季北迁至亚马逊盆地；玻利维亚高海拔种群冬季降至800 m以下；秘鲁东部及巴西东部种群多为留鸟。","other":"本种曾被视为广义的“灰色小霸鹟已删除”复合体（Nesotriccus murinus sensu lato）的一部分，与马谷白腹灰色小霸鹟、白腹灰色小霸鹟及科岛霸鹟存在复杂的分类修订，现依分子系统学研究独立成种。北灰色小霸鹟曾被分拆，但 Avilist 中仍属同种。"},{"name":"马谷白腹灰色小霸鹟","english_name":"Maranon Tyrannulet","scientific_name":"Nesotriccus maranonicus","overview":"马谷白腹灰色小霸鹟（英文名：Maranon Tyrannulet，学名：Nesotriccus maranonicus），是雀形目霸鹟科科岛霸鹟属的鸟类。小型霸鹟，分布于南美洲北部，具体包括厄瓜多尔南部和秘鲁北部的特定地区。","appearance":"这种鸟体型较小，整体呈现灰褐色，腹部可能带有微弱的黄色调。其头部圆润，没有羽冠，眼纹浅淡，翼上有棕色的翼带，这些特征有助于识别。与Tumbes Tyrannulet极为相似，两者曾被认为是同一种，统称为鼠色小霸鹟。","call":"其叫声独特，常发出上升的、嗡嗡的颤音，有时以尖锐的啾声结尾。","habits":"栖息于干燥和半湿润的森林及灌木丛中，适应多种灌木和树木环境。","identification":"尽管与Tumbes Tyrannulet非常相似，但分布区域常常是最有效的区分方式。Marañon Tyrannulet在安第斯山脉西部的较高海拔以及大陆分水岭东侧的内陆山谷中被发现。","distribution":"主要分布在南美洲北部，包括秘鲁东北部的Marañón Valley、Amazonas西部、Cajamarca东部和La Libertad东部。"},{"name":"黄小霸鹟","english_name":"Yellow Tyrannulet","scientific_name":"Capsiempis flaveola","overview":"黄小霸鹟（英文名：Yellow Tyrannulet，学名：Capsiempis flaveola），是雀形目霸鹟科黄小霸鹟属的小型鸟类。拥有亮丽的黄色羽毛，主要分布在中美洲的尼加拉瓜南部至南美洲的巴西东部，包括阿根廷东北部和巴西东南部。其独特的亮黄色外观和分布范围使其成为该地区特有的显著物种。","appearance":"黄小霸鹟长约10.5至11.4厘米，体重约8克，体态纤细，喙小巧，酷似微型的绿莺或林莺。上身呈橄榄绿色，下身则是鲜艳的黄色。头部有淡色或近白色的眉纹，翅膀和尾巴为暗褐色，边缘略带黄色，有两道黄色翼斑。雄雌相似，而幼鸟上身偏棕色，下身黄色较淡。叫声为柔和的'pewik'，二重奏式歌曲为节奏感强的'pee-tic-keek'。","call":"其鸣叫包括柔和的'pewik'声，以及富有节奏感的二重奏歌曲'pee-tic-keek'。","habits":"黄小霸鹟活跃于灌木丛、森林边缘、溪流旁的植被、密集的次生林以及多草的牧场或空地。它们通常以昆虫、蜘蛛和小型浆果为食，通过从树叶中捕获猎物或短距离飞翔捕食。","breeding":"繁殖季节，它们会在树、灌木或玉米植株上2至7米高的地方，用植物纤维和草叶搭建杯状巢穴，外部装饰有苔藓。典型的产卵数为两个白色蛋，偶尔带有轻微的红褐色斑点。","identification":"与其他小型霸鹟相比，黄小霸鹟拥有更明亮的黄色外观，以及独特的叫声和二重奏歌曲。","protection":"IUCN：LC（无危）。在许多国家公园和保护区广泛存在，如哥斯达黎加的Río Negro Jaguar Reserve和Tarcol Lodge，哥伦比亚的Río Claro Reserve和Tinigua National Park，厄瓜多尔的Machalilla National Park和Río Palenque Science Centre，秘鲁的Pacaya-Samiria National Reserve，巴拉圭的Caaguazú、San Rafael和Ybycuí National Parks，以及巴西的Iguaçu、Itatiaia、Serra da Canastra和Tapajós National Parks。由于其对转换栖息地和次生林的适应能力，预计未来不会受到威胁。","distribution":"分布于中美洲南部至南美洲东部，包括尼加拉瓜南部、阿根廷东北部、巴西东南部。"},{"name":"须多斑霸鹟","english_name":"Bearded Tachuri","scientific_name":"Polystictus pectoralis","overview":"须多斑霸鹟（英文名：Bearded Tachuri，学名：Polystictus pectoralis），是雀形目霸鹟科多斑霸鹟属的鸟类。1817年由Vieillot首次命名。拥有独特的面部花纹，雄鸟以黑色冠羽和脸部为显著特征，与棕色背部形成鲜明对比。主要栖息于南美洲的干燥草原和灌木丛生的稀树草原，包括乌拉圭、厄瓜多尔、马尔维纳斯群岛、哥伦比亚等国。","appearance":"雄性须多斑霸鹟具有醒目的面部特征，黑色冠羽下隐藏着白色羽毛，黑色脸部与棕色背部形成对比，可见锈色臀部和肉桂色下体。雌鸟则呈现棕色冠羽和淡色脸部，喉咙呈白色。体型较小，羽毛颜色随季节变化。","habits":"偏好原生草甸和带有分散灌木的干旱草原地带，偶尔出现在受干扰的植被中。活动范围通常限于低海拔地区，最高可达1300米。","breeding":"繁殖期在哥伦比亚东部为6月至7月，在阿根廷和巴西为9月至次年1月。可能实行一雄多雌制，关于雌鸟独自抚育幼鸟的猜测待证实。筑巢于灌木或蓟草中，距地面不足1米，巢由草、植物纤维、蓟绒毛和蜘蛛网构成。","identification":"与同属物种相比，须多斑霸鹟的黑色面部和棕色背部组合是其显著的识别特征。","protection":"IUCN：NT（近危）。在部分地区常见，但在多数国家被视为国家保护关注对象。在委内瑞拉数量下降，巴拉圭极度濒危，玻利维亚近期无确切记录。","distribution":"分布于南美洲，包括阿根廷、玻利维亚、巴西、哥伦比亚、法属圭亚那、圭亚那、苏里南、乌拉圭和委内瑞拉。在阿根廷的Córdoba省、巴西的Roraima州、哥伦比亚的Meta地区较为常见。"},{"name":"灰背多斑霸鹟","english_name":"Grey-backed Tachuri","scientific_name":"Polystictus superciliaris","overview":"灰背多斑霸鹟（英文名：Grey-backed Tachuri，学名：Polystictus superciliaris），是雀形目霸鹟科多斑霸鹟属的鸟类。小型罕见的霸鹟科鸟类，特有于巴西东南部。其最显著的特征是眼前有一块明显的白色斑块，以及一条短白眉线。头部呈灰色，背部为褐色灰色，胸部和侧身带有肉桂色晕染。","appearance":"灰背多斑霸鹟长约9.5厘米，体重约6克。具有短而明显的白眉纹和眼环；头顶灰色，羽毛较长，部分遮盖住白色的冠羽；上体呈褐色灰色；翅膀暗褐色，翼覆羽尖端和飞羽边缘略显淡棕色；尾巴暗色；下巴近白色，喉部至下体为中等粉红浅褐色，腹部下方渐变为白色；虹膜深棕色；喙和腿均为黑色。雌雄相似，但雌鸟体型略小于雄鸟。幼鸟腹部呈奶油色。","call":"其鸣唱为快速重复的‘pilrup-pilrup-pilrup’和‘fruirilrilrilril’，是一种微弱、快速、悦耳的颤音，起始音节略有口吃，随后音调稍升再逐渐减弱；还发出‘tee-kpuj’声和安静的接触叫声‘purp’。","habits":"栖息于岩石草原伴生灌木丛（campo rupestre）、废弃的灌木牧场、高海拔草地，以及云雾林边缘的灌木丛中；海拔高度介于900至2300米，多数位于1700米以下。全年留居于繁殖区。主要以昆虫为食，通常单独觅食，偶尔成对或三只一组活动。常攀附于垂直的茎干上，或停歇于低矮的灌木上，很少落地；主要采取飞扑捕食和停歇捕食的方式，经常返回相同的停歇点；飞行能力较弱。","breeding":"繁殖期在7月至9月。巢为小杯状，由根须和苔藓构成，安置于小灌木的分叉处。每窝产卵1至2枚；关于孵卵和幼鸟离巢的时间尚无具体数据。","identification":"灰背多斑霸鹟可通过其独特的白眉纹、眼前白色斑块以及灰顶、褐色灰色背部和肉桂色胸侧来识别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲巴西东南部的中央巴西山丘和高原地带以及大西洋森林山区，包括Serra do Espinhaço、Caraça国家公园、Serra da Canastra和Serra do Cipó国家公园。","other":"尽管面临生境丧失的威胁，灰背多斑霸鹟在部分降级的生境如废弃矿场仍能生存。"},{"name":"南美多拉霸鹟","english_name":"Dinelli's Doradito","scientific_name":"Pseudocolopteryx dinelliana","overview":"南美多拉霸鹟（英文名：Dinelli's Doradito，学名：Pseudocolopteryx dinelliana），是雀形目霸鹟科多拉霸鹟属的鸟类。主要栖息于阿根廷中部和北部的沼泽地带，非繁殖季节向北迁移。其名称纪念了阿根廷生物学家Luis Dinelli。","appearance":"小型黄褐色飞虫捕食者，具有棕色的顶冠和耳羽，与Subtropical, Warbling, 和Ticking Doraditos相似，但可通过声音最易区分。","habits":"栖息于亚热带或热带的干燥灌木丛、干燥低地草原和沼泽地带，非繁殖季节访问阿根廷北部、巴拉圭，可能还包括巴西西南部（马托格罗索杜苏尔州）和玻利维亚。","identification":"与Subtropical, Warbling, 和Ticking Doraditos相比，南美多拉霸鹟可通过声音、棕色顶冠和棕色耳羽区分开来。","protection":"IUCN：NT（近危）；受栖息地丧失威胁。","distribution":"分布于巴拉圭中部和巴西西南部至阿根廷中部，非繁殖季节向北迁至阿根廷北部、巴拉圭，可能还包括巴西西南部（马托格罗索杜苏尔州）和玻利维亚。"},{"name":"冠多拉霸鹟","english_name":"Crested Doradito","scientific_name":"Pseudocolopteryx sclateri","overview":"冠多拉霸鹟（英文名：Crested Doradito，学名：Pseudocolopteryx sclateri），是雀形目霸鹟科多拉霸鹟属的小型鸟类。其显著特征为明亮的黄色下体、蓬松的羽冠和三条翼纹。分布于南美洲的沼泽地带和泛滥草甸，覆盖了委内瑞拉、圭亚那、特立尼达岛、玻利维亚、巴西东部和南部、阿根廷东北部等地。","appearance":"体长约11厘米，体重介于6至9.9克之间。雄鸟具有独特的蓬松羽冠，上体呈淡橄榄色，延长的冠羽为黑色边缘带黄白色，半隐藏的黄色冠纹，背部有微妙的暗灰色条纹；两翼为淡橄榄色，两道翼纹和三级飞羽边缘呈暗淡的白色，特殊的一级飞羽P6和P7有凹陷和渐细的羽片；整个下体鲜亮的黄色。雌鸟较雄鸟颜色更淡，黑色羽冠边缘更宽的淡黄色（与头顶对比不明显），头部其余部分更浅，眉线非常淡的黄色，一级飞羽正常，下喙粉橙色。幼鸟类似雌鸟，但羽冠更短，更多赭色，较少黑色，下体非常淡。","call":"其鸣唱是一系列非常柔和而尖锐的‘tsik-tsik-tsee-lee’音符。","habits":"栖息于沼泽和泛滥的草甸，偏好植被茂盛的环境。","identification":"与其他Doradito种类相比，冠多拉霸鹟独有的特征是其羽冠和翼纹。","protection":"IUCN状态未知。","distribution":"分布于南美洲，包括委内瑞拉、圭亚那、特立尼达岛、玻利维亚、巴西东部和南部至阿根廷东北部。"},{"name":"亚热带多拉霸鹟","english_name":"Subtropical Doradito","scientific_name":"Pseudocolopteryx acutipennis","overview":"亚热带多拉霸鹟（英文名：Subtropical Doradito，学名：Pseudocolopteryx acutipennis），是雀形目霸鹟科多拉霸鹟属的鸟类。主要分布在南美洲的安第斯山脉，从哥伦比亚到阿根廷西北部。这种鸟以其鲜明的橄榄绿色上部和亮黄色下部而著称。","appearance":"雄性亚热带多拉霸鹟全身呈现亮丽的橄榄绿，头顶有短而蓬松的冠羽，翅膀橄榄棕色，边缘略带灰色，某些标本的翼覆羽尖端呈暗肉桂色，形成两道翼纹。尾部橄榄绿，下部鲜亮金黄。雌鸟与雄鸟的主要区别在于其初级飞羽外缘不凹陷。幼鸟嘴基部较淡，翼纹更为明显。","call":"发出一系列嗡嗡的、不规则的前奏音节，随后是短促的鼻音‘tzit-tzit-tzit t-konk’，觅食时会发出‘tzit’的叫声。","habits":"栖息于亚热带地区的沼泽、湿地和近水边的草地，通常在2200至3550米的高度活动，冬季可能降至低地。许多群体表现出迁徙行为，冬季会向亚马逊雨林和巴西沿海地带移动。","breeding":"繁殖期在12月至翌年4月，于玻利维亚高地。繁殖行为包括短暂飞行展示时的翼‘呼噜’声，可能是由凹陷的初级飞羽产生。巢为深杯状，以草或其他植物纤维制成，内部铺有羽毛，筑于湿地植被中。一窝产三枚蛋，孵化和离巢时间未被记录。","identification":"与拟莺多拉霸鹟相比，亚热带多拉霸鹟的上部更亮的橄榄色，下部更亮的黄色，头部没有红色调。雌鸟与雄鸟在外貌上差异不大，主要通过初级飞羽的形态区分。","protection":"IUCN：LC（无危）。在哥伦比亚和厄瓜多尔受到威胁（‘脆弱’和‘近危’），而在阿根廷南部（如萨尔塔和图库曼省）较为常见。其在北部的稀有性可能与湿地排水和过度放牧有关。在秘鲁的Tambopata-Candamo保护区和哥伦比亚的La Florida公园有记录。","distribution":"分布于南美洲，从哥伦比亚至阿根廷西北部，主要在安第斯山脉的亚热带区域。在繁殖季节，高度范围为2200至3550米，非繁殖季节则可能降至海拔700米以下。"},{"name":"拟莺多拉霸鹟","english_name":"Warbling Doradito","scientific_name":"Pseudocolopteryx flaviventris","overview":"拟莺多拉霸鹟（英文名：Warbling Doradito，学名：Pseudocolopteryx flaviventris），是雀形目霸鹟科多拉霸鹟属的鸟类。小型霸鹟科鸟类。其特征为上体橄榄褐色，下体鲜黄色，头部顶冠带有锈红色斑块。主要分布于南美洲的高草沼泽地带，尤其是在莎草丛生的湿地。该物种在阿根廷中东部、巴拉圭、乌拉圭和巴西南部均有分布。","appearance":"成年拟莺多拉霸鹟体长约11-11.7厘米，体重7-8克。雄鸟上体呈暗淡的橄榄褐色，顶冠锈红色，面部暗色，翅膀颜色与背部相似，翼羽尖端和边缘泛黄白色；尾巴暗橄榄褐色；全身下方亮黄色，喉部尤为鲜艳。虹膜为中棕色，喙纤细黑色，跗跖深灰色。雌鸟与雄鸟相似，但下颚基部粉红。幼鸟色泽较暗，翼羽边缘泛黄白色，下体亮黄白色，喉部略带灰，腹部乳黄色。","call":"鸣声为一系列柔和而略显断续的高音，先是机械式的短促叫声，随后是一连串4-8个较为悦耳的音符，如“chek, chek, chek, chek-chick-chick-chiquetik”。觅食时会发出“tek”叫声。","habits":"栖息于芦苇床、淡水沼泽、莎草湿地及周边的河岸植被中。偏好巴西南部由莎草科植物主导的高草和芦苇地带。海拔从海平面至500米。在南美洲南部的繁殖种群会在南半球冬季向北迁移，而在巴西南部则可能全年留驻，有繁殖记录。","breeding":"繁殖季为9月至次年1月。巢为细草或芦苇纤维编织的松散杯状，固定于垂直的沼泽植物上。每窝产2-4枚奶油黄色蛋，平均尺寸16-17.5mm x 12-13mm，平均孵化期约17天，平均离巢期约13天。巢存活率至离巢平均30天，分别为20%和60%，巢失败的主要原因是捕食，尤其在孵化期。","identification":"与南美多拉霸鹟相比，拟莺多拉霸鹟背部更偏橄榄色，而非褐色。叫声特征明显区别于其他多拉霸鹟。","protection":"IUCN：LC（无危）。在多个国家公园和自然保护区中可见，但在南美洲某些地区数量稀少。","distribution":"繁殖区位于阿根廷中东部、乌拉圭、巴西南部；非繁殖期分布北至巴拉圭。在巴西南部，主要出现在5月至9月间，但在里奥格兰德杜苏尔州被视为常住。","other":"与拟莺多拉霸鹟极为相似的物种是滴答多拉霸鹟，二者主要通过叫声区分。"},{"name":"滴答多拉霸鹟","english_name":"Ticking Doradito","scientific_name":"Pseudocolopteryx citreola","overview":"滴答多拉霸鹟（英文名：Ticking Doradito，学名：Pseudocolopteryx citreola），是雀形目霸鹟科多拉霸鹟属的小型鸟类。南美洲特有。其分布区域主要集中在智利中部（瓦尔帕莱索至洛斯里奥斯）和阿根廷中西部（从楚布特和里奥内格罗北至萨尔塔）。该鸟种以其独特的亮黄色腹部和橄榄棕色的上体而著称。","appearance":"滴答多拉霸鹟体型小巧，长约12.5厘米，体重在7.5至10克之间。上体呈橄榄棕色，头部颜色更深，更鲜艳；下体为柠檬黄色，两翼带有狭窄的肉桂色条纹。羽毛与先前认为同种的拟莺多拉霸鹟相似，但颜色更黄，体型略大，尤其是在喙和翅膀长度上。","call":"其鸣唱始于低沉的咔哒声，节奏逐渐加快，最终突然终止，如‘tick, tick, tick, tick-tick-tick-you’或‘tic tic tic tic tic tirik-tirik’，同时头部随每一声鸣叫快速上扬。","habits":"滴答多拉霸鹟栖息于淡水和微咸水沼泽，以及邻近的杂草植被中，常见于智利的流溪边湿地。它们也会出现在玉米田和杂草丛中，特别是在迁徙期间。活动范围从海拔300米至1300米，但在智利中部可降至海平面。","breeding":"繁殖数据有限，雄鸟在11月底至12月初处于繁殖状态。在智利，巢由芦苇和柳树种子构成，而在阿根廷，巢为锥形，由细根、干草和各种灌木枝条编织而成，用蛛网固定，离地面约65厘米。一窝产卵三枚，蛋壳淡奶油色，带有暗褐色斑点和条纹，大小约为16.2毫米×12.2毫米，重量0.64克。","identification":"在智利范围内，滴答多拉霸鹟的下体明亮黄色和上体的橄榄棕色，加上肉桂色的翼带，使其容易辨认。与东部安第斯山脉以东的类似物种相比，它的颜色更黄，体型更大。","protection":"IUCN：LC（无危）。在阿根廷中西部局部地区较为常见，但在智利一般被认为是稀少且分布局限。","distribution":"滴答多拉霸鹟主要分布于智利中部至阿根廷中西部，包括瓦尔帕莱索至洛斯里奥斯，以及从楚布特和里奥内格罗北至萨尔塔。在非繁殖季节会迁移到玻利维亚，且在阿根廷东部（如圣菲、恩特雷里奥斯和布宜诺斯艾利斯）定期非繁殖。"},{"name":"铜绿侏霸鹟","english_name":"Bronze-olive Pygmy Tyrant","scientific_name":"Pseudotriccus pelzelni","overview":"铜绿侏霸鹟（英文名：Bronze-olive Pygmy Tyrant，学名：Pseudotriccus pelzelni），是雀形目霸鹟科伪霸鹟属的小型鸟类。体型圆胖，主要分布在中美洲至南美洲的山地森林，如巴拿马、哥伦比亚、厄瓜多尔和秘鲁。其独特的橄榄色羽毛在不同光线下呈现铜绿色调。","appearance":"铜绿侏霸鹟体态小巧，全身覆盖着较深的橄榄色羽毛，胸部呈淡褐色，腹部则显黄色。在光线不佳的情况下，整体羽毛颜色显得较为单一，呈棕色。雄鸟、雌鸟和幼鸟的羽毛颜色相似，但在细节上可能有所差异。","call":"通过发出类似拍打声和翅膀振动的声音被发现，这成为其特有的识别标志。","habits":"偏好栖息在海拔700至2000米的山地森林下层，通常比另一物种——棕头侏霸鹟所处的高度更低。以昆虫为食，活动范围相对固定，常在低矮的树枝上安静停歇，然后突然出击捕捉猎物。","breeding":"关于其繁殖习性的详细信息尚不充分，但已知它们在特定季节内会在山地森林中筑巢繁殖。","identification":"与棕头侏霸鹟相比，铜绿侏霸鹟在海拔高度上有部分重叠，但可通过其橄榄色的羽毛和特有的鸣叫声来区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，具体包括巴拿马、哥伦比亚、厄瓜多尔和秘鲁的山地森林。"},{"name":"褐额侏霸鹟","english_name":"Hazel-fronted Pygmy Tyrant","scientific_name":"Pseudotriccus simplex","overview":"褐额侏霸鹟（英文名：Hazel-fronted Pygmy Tyrant，学名：Pseudotriccus simplex），是雀形目霸鹟科伪霸鹟属的小型鸟类。其羽毛以组合的黑色、棕色、白色、黄色和绿色构成，色调暗淡，仅少数具有亮丽色彩。分布于秘鲁东南部至玻利维亚西北部的亚热带或热带湿润山地森林。","appearance":"褐额侏霸鹟羽毛颜色单一，以暗褐色为主，成鸟头部带有微弱的锈色痕迹，这一特征在幼鸟中并不明显。体型小巧，长度约6.5-6.8厘米，体重在9-11克之间，拥有直立的冠羽。","call":"会发出尖细、高音的哨声和颤音，以及柔和的啪嗒声。","habits":"偏好栖息于低海拔的亚热带或热带湿润山地森林，有时在次生林边缘活动。以昆虫为主要食物来源，偶尔也会摄取果实或小型脊椎动物。","identification":"与幼年的棕头侏霸鹟相似，但缺乏锈色的翅膀和尾巴。与铜绿侏霸鹟的分布区域不重叠。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的秘鲁东南部（Madre de Dios, Puno）和玻利维亚西北部（La Paz, Cochabamba）。"},{"name":"棕头侏霸鹟","english_name":"Rufous-headed Pygmy Tyrant","scientific_name":"Pseudotriccus ruficeps","overview":"棕头侏霸鹟（英文名：Rufous-headed Pygmy Tyrant，学名：Pseudotriccus ruficeps），是雀形目霸鹟科伪霸鹟属的鸟类。独特而醒目的红褐色头部使其在亚热带和温带的云雾森林中极易识别，分布于安第斯山脉，自哥伦比亚中部至玻利维亚西部，海拔介于2000至3300米之间。","appearance":"成鸟体长约11厘米，重7-9克。头部、喉咙呈现鲜明的橙黄色，上体为深橄榄色，翅膀深黄褐色，羽缘宽而暗红褐色，营造出全面红褐色翅膀的视觉效果（在秘鲁中部更偏棕色）。尾羽暗红褐色，胸腹部分灰白，腹部中心和下尾覆羽乳黄色。虹膜暗褐色，上喙黑色，下喙大部淡黄色，腿灰色。雌雄外观相似。幼鸟以深橄榄色为主，翅膀红褐色，颏部白色，头部呈棕褐色，随着成长逐渐转变为成鸟的红褐色。","call":"具有响亮且爆发性的嗡嗡颤音，持续数秒，有时以'啪'声结尾；歌声更高调，先降后升，常伴有重复的喙啪声。","habits":"偏好亚热带或热带湿润山地森林环境，单个或成对出现在森林底层，通常在密林中活动，主要以树叶上的昆虫为食。","identification":"红褐色头部、翅膀和尾巴与橄榄色背部和胸部的鲜明对比，腹部略显苍白的黄色，使其在同属物种中独树一帜。","distribution":"分布于南美洲的哥伦比亚（中部和东部安第斯山脉，以及北部和南部的西坡），向南延伸至厄瓜多尔（最南至科托帕希），玻利维亚（拉巴斯和科恰班巴的东坡）。"},{"name":"环蚁鹨","english_name":"Ringed Antpipit","scientific_name":"Corythopis torquatus","overview":"环蚁鹨（英文名：Ringed Antpipit，学名：Corythopis torquatus），是雀形目霸鹟科蚁鹨属的鸟类。以独特的环状背颈斑而得名。这种小型鸟类体型中等至暗灰色，拥有白色胸部，其上分布着显眼的黑色纵纹。广泛分布于南美洲亚马逊盆地，包括巴西、圭亚那、哥伦比亚、秘鲁、玻利维亚以及委内瑞拉的奥里诺科河流域。","appearance":"环蚁鹨长约13.5至14厘米，重约15至18克。冠部呈灰褐色，具微弱的白色眉纹和眼后斑点；背部、翅膀和尾巴为深橄榄棕色；脸部为淡橄榄灰色，下巴和喉咙为白色；下体为白色，两胁略带灰橄榄色，明显的宽黑条纹始于几乎连续的上胸项圈，向下延伸至两侧，腹部和下尾覆羽无纹。翼内侧为暗灰色；虹膜为中等棕色、灰棕色或灰色；上喙为黑色，下喙基部黄色至粉红橙色，靠近基部为浅粉色；跗跖很长，颜色为淡灰色至粉灰。雌雄相似，雌鸟比雄鸟小。幼鸟的胸纹较少，颜色较浅且更偏棕色。亚种sarayacuensis平均比指名亚种小，冠部颜色与背部相同；anthoides亚种也较小，冠部为石板灰色。","call":"最常听到的是精心发出的下降式、清晰的双音节哨声，类似'peeew prayeur'，第二个音符先上升再降至第一个音符以下，有时会连发超过两个音符；觅食时经常发出喙响声，尤其是在受惊时。","habits":"环蚁鹨偏好生活在低地热带雨林的地面，常在成熟的森林地面上漫步，沿着树根和倒木行走，偶尔飞至林下植被捕捉昆虫。它的活动范围集中在亚马逊流域的低海拔森林。","identification":"环蚁鹨的辨识特征在于其独特的地面活动习性和外观，尤其是上胸的黑色条纹和环状背颈斑。与同属的南美蚁鹨在亚马逊盆地南部接近但不重叠的分布范围也是辨识点之一。","protection":"IUCN：LC（无危）","distribution":"环蚁鹨的分布区域覆盖了整个亚马逊盆地，包括巴西、圭亚那、哥伦比亚、厄瓜多尔、秘鲁、玻利维亚，以及委内瑞拉东部的奥里诺科河下游地区。此外，还出现在法属圭亚那、苏里南和圭亚那。在接近亚马逊盆地南部的西北部塞拉多地区，其分布接近但不与同属物种南美蚁鹨的范围重叠。"},{"name":"南美蚁鹨","english_name":"Southern Antpipit","scientific_name":"Corythopis delalandi","overview":"南美蚁鹨（英文名：Southern Antpipit，学名：Corythopis delalandi），是雀形目霸鹟科蚁鹨属的鸟类。体型中等，外观独特，主要在湿润森林和次生林的地面行走。其橄榄褐色背部、黄色喙、白色脸庞和腹部以及黑色胸带构成了显著特征。分布于南美洲，包括巴西南部、巴西南部大草原、巴拉圭、玻利维亚和阿根廷东北部。","appearance":"南美蚁鹨体长13.5至14厘米，体重14至18克。它拥有橄榄色上体，冠羽略显灰，带有淡白色眉纹和眼后纹；翅膀和尾巴与背部颜色相同；脸部呈淡灰橄榄色，下巴和喉咙奶油白；下体白色，侧翼微染灰橄榄色，有明显的宽黑条纹始于几乎连贯的胸环，向下延伸至侧翼，腹部和下尾覆羽无斑点；翼内衬白色；虹膜中至深棕色；上喙黑色，下喙基部黄色至粉橙色，口内橙黄色；腿长而色浅，灰粉色。与环蚁鹨相比，上体颜色更浅，橄榄色较淡，下巴和喉咙更奶油色，翼内衬白色而非暗灰色。雌雄相似，幼鸟与成鸟类似。","call":"最常发出的是精心递降的、清澈的六音节哨声，‘peee prayeur, pi-pi-peepit？’；在随机觅食时经常发出响亮的喙啪声，尤其是在受惊时。","habits":"南美蚁鹨栖息于森林地面，偏好生活在亚热带或热带湿润低地森林中。它们的活动范围覆盖了巴西南部、巴西南部大草原周边、玻利维亚东部、巴拉圭东部以及阿根廷东北部。其地理分布与另一种Corythopis属物种——环颈蚁鹨，在北部和西部大草原上没有交集，尽管其范围延伸至亚马逊盆地南部，进入西北部大草原。","identification":"与环蚁鹨相比，南美蚁鹨上体颜色更浅，橄榄色较淡，下巴和喉咙颜色更奶油，翼内衬白色而非暗灰色。两者分布范围几乎没有重叠。","distribution":"南美蚁鹨的分布范围包括玻利维亚东部和巴西中部至巴拉圭东部，巴西东南部以及阿根廷东北部和西北部。具体而言，其栖息于巴西东南部沿海山脉，从里约热内卢州中部向南延伸至圣保罗州中部。"},{"name":"褐顶丛霸鹟","english_name":"Fulvous-crowned Scrub Tyrant","scientific_name":"Euscarthmus meloryphus","overview":"褐顶丛霸鹟（英文名：Fulvous-crowned Scrub Tyrant，学名：Euscarthmus meloryphus），是雀形目霸鹟科棕侏霸鹟属的鸟类。体型微小的霸鹟，分布于南美地区，包括阿根廷、玻利维亚、巴西、哥伦比亚等地。该物种拥有独特的暗褐色冠羽，上部呈土黄色，下部近白色，栖息于干燥地带和散布树木的牧场，以地面附近的昆虫为食，其嘹亮的叫声常成为所在区域的背景声。","appearance":"褐顶丛霸鹟体型极小，体长约10至12厘米，雄雌相似，但雌鸟略小于雄鸟。头部具有一簇蓬松的明亮红褐色冠羽，面部为淡褐色，喉咙和胸部为灰白，身体两侧和腹部带有棕色色调，其余下体为奶油黄色。上身颜色较为暗淡，背部呈土黄褐色，翅膀和尾巴为暗褐色。","call":"褐顶丛霸鹟发出快速连续的‘sputtering’叫声，有时会形成二重唱，其叫声在南部分布区听起来像是‘rrrr-Ripeeo’。","habits":"褐顶丛霸鹟栖息于干燥的低地和山地灌木丛、过度放牧的牧场、干枯杂草田和荒地，以及干林边缘，海拔高度从海平面到约1000米。它们通常单独或成对活动，主要在密集的灌木丛中觅食，偶尔在地面上捕食昆虫。","breeding":"繁殖季节大约在10月至12月间，巢穴建于密集灌木丛中的细枝间，巢材包括死草、植物茎、藤蔓、树皮、地衣和种子绒毛，巢内通常有2至3枚蛋，颜色为乳白色，带有棕色、紫罗兰色和灰色斑点。","identification":"与褐脸丛霸鹟（学名：）的区别在于冠羽的颜色和分布区域，后者主要分布在厄瓜多尔和秘鲁的沿海坡地。","protection":"IUCN：LC（无危）","distribution":"褐顶丛霸鹟在南美洲有两个分离的分布群，一个位于南美最北部，包括哥伦比亚和委内瑞拉北部；另一个位于亚马逊盆地以南的干燥森林，覆盖了巴西东部、乌拉圭、巴拉圭东部、阿根廷北部和玻利维亚东部。","other":"近期研究发现，之前被认为是褐顶丛霸鹟亚种的褐脸丛霸鹟现已被提升为独立物种。"},{"name":"棕胁侏霸鹟","english_name":"Rufous-sided Scrub Tyrant","scientific_name":"Euscarthmus rufomarginatus","overview":"棕胁侏霸鹟（英文名：Rufous-sided Scrub Tyrant，学名：Euscarthmus rufomarginatus），是雀形目霸鹟科棕侏霸鹟属的鸟类。体型微小的飞禽。其特征为喉部白色与背部棕色形成鲜明对比，腹部呈黄色，两胁深暖赭色。分布于南美的苏里南、巴西东部、玻利维亚东北部及巴拉圭东部。","appearance":"该鸟体长11厘米，体重仅6克。上体均匀呈棕色，翼部较暗，覆羽尖端赭色，形成双翼条纹。尾长而暗淡，边缘赭色。脸部浅棕色，喉部白色，下体淡黄色，胸侧和两胁深暖赭色。雄雌相似，幼鸟特征未详述。","call":"拥有独特的鸣唱，一系列快速重复的嗡嗡声，如“tic, tic, tic, tiker-trrrrrk”。","habits":"偏好开放、保存良好的自然草原环境，散布着灌木丛。其活动范围和迁徙模式未详细记录。","breeding":"关于生长繁殖的信息未提供。","identification":"通过其独特的喉部白色、棕色背部、黄色腹部和深暖赭色的两胁来辨识，以及特有的鸣唱。","protection":"IUCN：LC（无危）。物种因生境丧失面临威胁，局部地区较为常见，但在其广阔分布区中，记录稀少。","distribution":"分布于南美，包括苏里南南部（Sipaliwini）、巴西东部至中部（Pará至Bahia，南至Mato Grosso），玻利维亚北部与东部，以及巴拉圭东北部（Zanja Morotí）。","other":"在巴西和苏里南的特定保护区中仍存在可观数量的种群，但生境破坏是其罕见的主要原因。"},{"name":"褐脸丛霸鹟","english_name":"Fulvous-faced Scrub Tyrant","scientific_name":"Euscarthmus fulviceps","overview":"褐脸丛霸鹟（英文名：Fulvous-faced Scrub Tyrant，学名：Euscarthmus fulviceps），是雀形目霸鹟科棕侏霸鹟属的鸟类。主要分布于南美洲的厄瓜多尔西南部和秘鲁西部的干燥灌木丛生地带。其最显著的特征是脸部和前额呈现亮丽的橙色。在干燥地带和散落着树木与灌木的牧场中觅食，通常靠近地面活动，很难被发现。尽管难以定位，一旦找到，这种鸟会显得相当亲近人，其快速、沙哑、喷溅式的叫声常常成为某些地区声音景观的一部分。羽毛虽具有一定的独特性，但色彩相对低调。成鸟上身呈栗褐色，下身从白色到黄色不等，脸部和前额有独特的橙色斑纹，形成面具般的外观。","appearance":"褐脸丛霸鹟是一种小型活跃的鸟类，身长约为10至10.5厘米。成鸟的上体大部分为栗褐色，翅膀和尾巴略显暗淡，带有两道明显的橙白色翼带。喉咙呈白色，胸部为浅奶油色，某些个体的胸部可能带有灰色橄榄色调，与更黄的腹部形成对比。脸部和前额有一片橙色斑纹，延伸至眼圈、耳羽、眉纹和前额，至少延伸至眼睛后面。喙部上颚为深棕色，下颚为淡粉色，脚为淡蓝灰色，足底为白色。幼鸟的描述尚未给出。","call":"褐脸丛霸鹟发出快速、沙哑、喷溅式的叫声，有时以二重唱的形式呈现，描述为“re-tr-tr-tr-tr-tr-treetrrrt…”或“wi-wi-w-DU-WIT”。叫声也可被描述为一系列尖锐的“tiri-dik”，“tiri-di'dik”，“tiridí-tiridí”或细长的管道音或气泡音，转录为“ptee-pee-pew”或“pitter-pittew”。","habits":"褐脸丛霸鹟居住在干燥的森林、灌木丛、次生林和杂草丛生的开阔地带。它们在低地和山麓地带活动，一般不超过1500米的高度，但在特定条件下可达到2000至2500米。它们倾向于在热带干燥森林的较低植被层中觅食，有时会加入混群。在较为开放的环境中，成鸟更有可能加入混群。","breeding":"褐脸丛霸鹟的繁殖季节主要集中在3月至6月间，在厄瓜多尔的西南部。它们的巢通常建在密集的灌木丛的外缘，或偶尔位于开阔地带的低矮草本植物丛中。巢为小而脆弱的开放式杯状结构，由干枯的小枝和植物茎组成，附着在薄枝和植物茎之间。每窝通常产两枚蛋，孵化期大约为14至15.5天。雏鸟孵化后24至36小时内，能在六天后蹲伏于巢中，九天后看起来几乎全身覆盖羽毛。","identification":"褐脸丛霸鹟在其分布范围内几乎无法混淆。与之相关的其他物种的辨识要点未提及。","protection":"IUCN：LC（无危）","distribution":"褐脸丛霸鹟分布在厄瓜多尔西南部，从埃斯梅拉达斯省向南，包括一些离岸岛屿，以及秘鲁西北部，从塔姆贝斯到利马。其分布还略微跨越秘鲁北部的安第斯山脉西部，进入上马兰翁河谷。","other":"最近的研究确认了褐脸丛霸鹟与褐顶丛霸鹟之间的系统发育差异，导致其再次被提升为独立物种地位。"},{"name":"灰白小霸鹟","english_name":"Grey-and-white Tyrannulet","scientific_name":"Pseudelaenia leucospodia","overview":"灰白小霸鹟（英文名：Grey-and-white Tyrannulet，学名：Pseudelaenia leucospodia），是雀形目霸鹟科灰白小霸鹟属的唯一物种。1877年由Taczanowski首次命名。这种小型飞禽主要分布于南美洲的厄瓜多尔西南部及秘鲁西北部的干旱低地和山麓地带，偏好沙漠灌丛和干燥森林环境。在伊莎贝拉岛（Isla de la Plata）较为常见。","appearance":"体长约12.5厘米，体重约10至11克。头部具有独特的白色眉纹和大块半隐匿的白色冠羽，冠羽边缘稍长，有时会分裂形成叉状。上体呈淡灰褐色，翅膀暗色，翼羽和覆羽边缘有狭窄的白色边线；尾巴灰色。脸部和整个下体为灰白色，两胁略带灰色，腹部奶油色。虹膜深棕色，喙黑色带褐色，下颚基部宽而粉红色，口角粉色；跗跖灰色。雄雌外观相似，幼鸟冠羽中的白色较少。","call":"经常发出干燥的吱吱声。","habits":"栖息于干旱的太平洋沿岸斜坡和海岸，活动范围包括厄瓜多尔西部（伊莎贝拉岛、普纳岛、瓜亚斯西部、洛哈南部）和秘鲁西北部（至安卡什省）。在树丛和灌木间活跃地穿梭，偏好沙漠灌丛和干燥森林环境。","identification":"与南无须小霸鹟类似，但可通过其白色的冠羽加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美的厄瓜多尔西南部（包括伊莎贝拉岛、普纳岛、瓜亚斯西部、洛哈南部）和秘鲁西北部（至安卡什省）。","other":"在厄瓜多尔的伊莎贝拉岛上较易发现，但在其他地区数量稀少。"},{"name":"小霸鹟","english_name":"Lesser Wagtail-Tyrant","scientific_name":"Stigmatura napensis","overview":"小霸鹟（英文名：Lesser Wagtail-Tyrant，学名：Stigmatura napensis），是雀形目霸鹟科鹡鸰霸鹟属的小型鸟类。仅见于亚马逊河流域岛屿，以黄色腹部和眉纹、翼及尾部白色斑块为显著特征。分布于南美洲的亚马逊河、奥里诺科河及其支流附近的岛屿上，包括哥伦比亚东南部、厄瓜多尔东部、秘鲁东北部和巴西西部。","appearance":"体长约13厘米，体重8至11.5克。拥有窄淡黄色眉纹，从喙延伸至眼后方，灰橄榄色背部，翅膀暗淡，中羽和大覆羽具宽白色条纹形成纵向翼斑，内侧飞羽边缘宽阔白色。尾巴长而略呈梯状，暗色，最外三对尾羽尖端有宽大的白色椭圆形斑点，外侧尾羽具白色外缘和宽阔的黄白色基部带，通常延伸至尾根。脸部淡黄色，喉部及整个下体中黄色，胸部略带橄榄绿至灰橄榄色调。虹膜深棕色，喙长且黑色，腿黑色。雌雄相似，雌鸟稍小于雄鸟。幼鸟特征未详述。","call":"发出柔和的哨音和哀怨的“wheeert？”或“weeeéé”，以及尖锐下降的咔哒声，如同弹跳球的声音，常以富有节奏感的二重唱形式呈现。一对鸟儿会进行生动的、断奏式的对唱，一只发出‘pfew skew’，另一只则唱出更响亮的‘du’ u’u’，同时每次叫声时都会翻动翅膀和尾巴向上前方。","habits":"栖息于早期演替植被，尤其在亚马逊大河流的岛屿上新形成的沙滩，有厚实的苔莎草和高草丛，以及零星的年轻树木。觅食时成对或家庭群体活动，积极移动，短暂停顿，尾巴通常翘起高于水平面，持续扇动露出宽大的白色尖端和黄白色的基部，翅膀轻微下垂。在灌木丛中的叶片、枝条和树皮上觅食昆虫，有时会降落到地面。","breeding":"繁殖季节不详，但在阿尔戈阿斯州的8月末见到卵，9月初见到巢中的雏鸟，1月在巴西北部观察到刚孵出的雏鸟。巢为杯状，由细枝和蛛丝构成，内部铺有柔软材料，隐藏于茂密的灌木叶中，高度从地面70厘米至1.5米不等。巢直径约40毫米，巢深25毫米，巢外高30毫米。每窝产卵2-3枚，卵呈白色，带有集中于较大一端的深褐色和紫色斑点，平均尺寸为17毫米×12毫米，平均重量1.2克。","identification":"与极为相似且共域的大霸鹟主要通过体型略小、尾基部白色、无暗色眼后斑以及最重要的是下体颜色较暗淡和背部颜色更深的特征来区分。雌雄相似，雌鸟体型略小。","protection":"IUCN：LC（无危）。在南美洲部分地区较为常见，但在亚马孙东部巴西似乎非常局部化。在厄瓜多尔，于1986年首次发现，沿纳波河上游至拉塞瓦洛奇奥地区常见。最近在委内瑞拉南部和哥伦比亚东部的奥里诺科河以及巴西北部的布兰科河被发现，可能在玻利维亚北部存在，但目前尚未有确切记录。","distribution":"分布于南美洲的亚马逊河、奥里诺科河及其支流附近的岛屿，具体包括哥伦比亚东南部、委内瑞拉西南部、厄瓜多尔东部、秘鲁东北部和巴西西部。","other":"在巴西Caatinga生物群系中，于适宜生境中数量合理，但其真实状态可能需要进一步澄清，因为现场观察者在该区域两个共存的Stigmatura物种之间存在混淆。"},{"name":"大霸鹟","english_name":"Greater Wagtail-Tyrant","scientific_name":"Stigmatura budytoides","overview":"大霸鹟（英文名：Greater Wagtail-Tyrant，学名：Stigmatura budytoides），是雀形目霸鹟科鹡鸰霸鹟属的鸟类。体型虽小却比近缘的较小霸鹟更为壮硕。分布于南美洲中南部，主要在玻利维亚东南部、巴拉圭西部、阿根廷中部和西北部的林地与灌木丛，以及巴西东北部的Caatinga地区。","appearance":"此鸟拥有橄榄灰色背部，黄色腹部，其最显著的特征为极长的白尖尾巴。翅膀上的白色斑块在不同亚种间有所差异。","call":"其鸣唱为快速的叽叽喳喳声。","habits":"偏好干燥的灌木丛地带、Chaco森林和河岸森林，于各层高度寻找食物。","identification":"与较小霸鹟相比，体型更大，尾巴更长，羽色差异明显。","distribution":"分布于南美洲的两个主要区域：一是玻利维亚东南部、巴拉圭西部、阿根廷中部和西北部；二是巴西东北部的Caatinga地区。"},{"name":"巴伊小霸鹟","english_name":"Bahia Wagtail-Tyrant","scientific_name":"Stigmatura bahiae","overview":"巴伊小霸鹟（英文名：Bahia Wagtail-Tyrant，学名：Stigmatura bahiae），是雀形目霸鹟科鹡鸰霸鹟属的小型、细长且尾部较长的鸟类，主要分布在巴西东部的干燥灌木丛中。其上体呈灰褐色，下体为淡黄色，眉纹明显，翅膀和尾巴有醒目的白色斑块。与大霸鹟相似，但体型略小，上体颜色偏棕，下体黄色较暗淡。","appearance":"巴伊小霸鹟上体灰褐，下体淡黄，具有明显的黄色眉纹。尾部长而窄，通常上翘，扇形展开并不断扇动，露出白色的尾尖和黄色基部。飞行时，翅膀展示出宽阔的纵向白色斑块。脸部淡黄色，喉咙和整个下体中黄色，胸部带有轻微的橄榄色到灰橄榄色的色调。雌雄相似，雌鸟比雄鸟略小。","call":"巴伊小霸鹟的叫声与其近亲相似，都是一系列响亮的颤音串，常以二重唱形式发出。但巴伊小霸鹟的歌声听起来更少干涩和嗡嗡声，包含了更多清晰的哨音。","habits":"巴伊小霸鹟主要生活在干燥的caatinga灌木丛中，低于约600米的高度。它可能以昆虫为主要食物来源，行为上与小霸鹟类似，成对或家庭群体活动，活跃地移动，短暂停顿。尾巴通常上翘，持续扇动。它会从栖息处觅食，偶尔也会悬停觅食，似乎比小霸鹟更频繁地降落地面觅食。","breeding":"关于其繁殖生态的信息非常有限。","identification":"与小霸鹟的区别在于上体颜色（淡暖棕色vs.淡灰色橄榄色）和下体颜色（奶油色vs.淡黄色），以及歌声的不同。与大霸鹟相比，体型较小，下体黄色较暗淡，背部更偏棕色。","protection":"IUCN：LC（无危）","distribution":"巴伊小霸鹟主要分布在南美洲巴西东南部，从Ceará和Rio Grande do Norte向南延伸至Bahia南部。","other":"巴伊小霸鹟与小霸鹟曾被认为是同一种，但基于遗传分化和一些细微的羽毛特征、歌声及生态差异，现已确定为独立物种。"},{"name":"稚小霸鹟","english_name":"Guatemalan Tyrannulet","scientific_name":"Zimmerius vilissimus","overview":"稚小霸鹟（英文名：Guatemalan Tyrannulet，学名：Zimmerius vilissimus），是雀形目霸鹟科南美小霸鹟属的鸟类。常见于中美洲高海拔地区，包括墨西哥南部、危地马拉、萨尔瓦多，可能还延伸到伯利兹。以食用槲寄生浆果及其它果实和昆虫为主食。","appearance":"稚小霸鹟上身呈橄榄绿色，头部顶部灰暗，具有一条中等长度的白色眉纹。翅膀上的初级、次级飞羽、覆羽边缘为黄色，且前缘更宽厚，无翼斑。下体偏白，胸部有模糊的淡色条纹，腹部和尾下覆羽微带黄绿色调。尾巴细长，略长于同类。两性相似，但幼鸟具有橄榄色的冠部，黄色眉纹，以及更宽而淡的翼缘。喙短而钝，黑色。","call":"稚小霸鹟的叫声是一声响亮的'pee-er'，黎明之歌则为哀婉的'yerd-dee, yerd-dee'。","habits":"生活在从低地到海拔2600米的湿润地带，偏好森林、次生林、牧场、有树木的种植园以及阴凉的花园。活动范围广泛，常单独或成对出现在树冠层，飞行特征活跃，以空中捕食为主，从栖息处短距离突袭获取食物。","breeding":"筑巢于2至15米高的位置，巢呈近似球形，侧入口，由苔藓构成，内部衬以植物纤维。巢可能建于苔藓中、垂挂的寄生根内，或在大树叶下，甚至可能利用黄橄榄色的黄橄榄鹟的垂挂巢。每窝通常产两枚带有红褐色斑点的淡白色蛋。雌鸟孵化期约14至15天，幼鸟再过17天左右离巢。","identification":"稚小霸鹟与槲小霸鹟极为相似，但稚小霸鹟体型略大，侧面和腹部橄榄黄色更为明显，眉纹更加突出，覆盖至喙基部。尾长相对更长，翼羽边缘的黄色更窄且不那么醒目。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，自墨西哥南部至萨尔瓦多，可能延伸至伯利兹。","other":"曾与槲小霸鹟被视为同一物种，直到近期才被认定为独立种。"},{"name":"槲小霸鹟","english_name":"Mistletoe Tyrannulet","scientific_name":"Zimmerius parvus","overview":"槲小霸鹟（英文名：Mistletoe Tyrannulet，学名：Zimmerius parvus），是雀形目霸鹟科南美小霸鹟属的鸟类。体型较小的霸鹟，以槲寄生的果实为主要食物来源，同时也会摄取昆虫，常见于中美洲和邻近的哥伦比亚部分地区。分布于森林、林缘、果园及树丛点缀的牧场等地，尤其在槲寄生生长丰富的环境中。槲小霸鹟通常出现在低地和山脚地带，其独特的翼羽标记——橄榄绿色的翅膀边缘镶嵌着黄色——使其易于识别。","appearance":"槲小霸鹟体长约11至12厘米，拥有灰色的冠羽，明亮的白色眉纹，橄榄绿色背部，以及显眼的黄边翼羽。翼羽的橄榄绿色部分被黄色边缘所包围，形成其独特外观。喙短而圆，尾部狭窄且较长，相较于其他小型霸鹟而言。雌雄外观相似，但幼鸟眼睛呈棕色，头部颜色更偏橄榄灰，翼羽边缘更宽且不那么明显，眉纹带有些许黄色色调。","call":"槲小霸鹟是一种频繁鸣叫的鸟类，常发出类似'peeyaik'、'pee-peeu'或'pee-yuip'的叫声，与厚嘴歌雀的叫声相似，声音哀婉。","habits":"槲小霸鹟栖息于湿润的常绿森林及其边缘，种植园和半开放的区域，只要有大型树木存在即可。它们活跃于森林的中上层，通常单独或成对出现。飞行特点灵活，活动范围广泛，以捕食节肢动物为主，同时也参与混合物种觅食群。它们在寻找猎物时会翘起尾巴快速移动。","breeding":"繁殖期间，槲小霸鹟会在缠结的植物或寄生植物中建造球状巢穴，由根须、苔藓和其他植物材料构成。每窝产2枚带有锈色斑点的白色卵。繁殖期、求偶、交配等具体细节尚未详述。","identification":"槲小霸鹟与稚小霸鹟相似，但体型更小，侧面和腹侧橄榄色和黄色不那么强烈。此外，槲小霸鹟的鸣叫声更为哀婉，且翼羽黄色边缘比稚小霸鹟更宽更明显。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的洪都拉斯至南美洲哥伦比亚的极西北部。主要栖息于中美洲东部的低地和山脚地带。","other":"槲小霸鹟曾被认为是Paltry Tyrannulet的一个亚种，但基于2013年发表的分子系统发育研究，现已确认为独立物种。"},{"name":"华丽小霸鹟","english_name":"Spectacled Tyrannulet","scientific_name":"Zimmerius improbus","overview":"华丽小霸鹟（英文名：Spectacled Tyrannulet，学名：Zimmerius improbus），是雀形目霸鹟科南美小霸鹟属的鸟类。小型的霸鹟科鸟类，常见于哥伦比亚东北部和委内瑞拉西部的中海拔森林地带，以小果实和昆虫为食，具有独特的翼部标记：橄榄绿色的次级飞羽边缘呈黄色，形成鲜明的黄色斑块。","appearance":"体型小巧，羽毛暗淡。成鸟头部为暗灰绿至背部转为绿色，冠部和颈背为暗灰色，眼上眉纹、眼周弧线白色，赋予其眼镜般的外观。翅膀覆羽和大部分飞羽边缘黄绿色，尾部窄而长，边缘黄色。胸部、腹部及尾下覆羽微黄，与白色喉咙形成对比，胸间有模糊的细纹。雌雄相似，但雌鸟略小。幼鸟色彩较暗淡，背部、眼周和腿脚颜色更深，且翅羽末端稍显苍白，似有翼斑，但成年后消失。","habits":"生活在森林、种植园和次生林的中上层，喜独行或成对出现。以浆果为主要食物来源，也捕食昆虫。活动范围广泛，遍布森林各层次。","identification":"与其他Zimmerius属物种的区别在于翼部的黄色边缘覆盖了次级飞羽的一半以上，形成独特的黄色斑块。与金脸小霸鹟相比，后者面部黄色，冠部绿色而非灰色。与Tolmomyias属的某些种类（如Yellow-olive Flycatcher）相比，体型较小，喙短而钝，眼周无环，喙型有异。","distribution":"分布于南美洲的委内瑞拉和哥伦比亚，具体包括两国的东北部和西部地区。"},{"name":"委内瑞拉小霸鹟","english_name":"Venezuelan Tyrannulet","scientific_name":"Zimmerius petersi","overview":"委内瑞拉小霸鹟（英文名：Venezuelan Tyrannulet，学名：Zimmerius petersi），是雀形目霸鹟科南美小霸鹟属的鸟类。色彩暗淡，主要栖息于森林、种植园及次生林的中上层，通常单独或成对出现。该物种以浆果为主食，具有独特的面部花纹，包括醒目的白色眉纹、深色脸颊和眼下的白色新月形斑块。","appearance":"委内瑞拉小霸鹟为小型霸鹟，体长约11.5至12厘米，橄榄绿色的背部，白色腹部，翼羽边缘有黄色镶边，喙短而圆。成鸟两性相似，头部呈暗灰石板色，具显著的白色眉纹，耳羽灰色，下颚有一条黑色细线，翅膀和尾羽的橄榄绿翼羽有黄色边缘，翼下白色，两侧略带黄色。幼鸟与成鸟相似，但冠部更偏橄榄色，翼和尾羽呈棕色。","call":"该鸟的叫声为哀怨的短促鸣声，频繁发出，易于通过叫声识别。","habits":"委内瑞拉小霸鹟栖息于多种森林环境，包括开放森林，常见于树冠层。它们主要以浆果为食，偶尔也会捕食昆虫。飞行特征不详，但根据其生态习性，推测其飞行灵活。","breeding":"关于委内瑞拉小霸鹟的繁殖信息有限，但它们可能在森林环境中筑巢，具体的繁殖季节、求偶行为、营巢、交配、产卵和育雏细节尚待研究。","identification":"与其他同属物种如华丽小霸鹟相比，委内瑞拉小霸鹟可通过其独特的翼羽黄色边缘和面部花纹加以区分。此外，它们的分布范围互不重叠。","protection":"IUCN：LC（无危）","distribution":"委内瑞拉小霸鹟主要分布在委内瑞拉北部的沿海山脉地区，具体包括北部的繁殖区域。","other":"曾与华丽小霸鹟被认为是同一种，但在2013年的一项分子系统发育研究后，两者被确认为独立物种。"},{"name":"玻利维亚小霸鹟","english_name":"Bolivian Tyrannulet","scientific_name":"Zimmerius bolivianus","overview":"玻利维亚小霸鹟（英文名：Bolivian Tyrannulet，学名：Zimmerius bolivianus），是雀形目霸鹟科南美小霸鹟属的鸟类。分布于秘鲁东南部和玻利维亚中部、西部。该鸟体型小巧，橄榄灰色淡雅，活跃于从山地森林到接近树线的高山森林和灌木丛。","appearance":"玻利维亚小霸鹟体色为浅橄榄灰，腹部极淡。头部直立，眼圈淡色，翼上无条纹。雌雄成鸟外观相似，幼鸟细节可能略有差异。","call":"其叫声为单一下降的哨音。","habits":"栖息于从山地森林到接近树线的高山森林和灌木丛，分布海拔范围广泛。具体觅食行为和食物种类未详述。","breeding":"关于繁殖习性的详细信息未提供。","identification":"与红嘴小霸鹟在较低海拔区有重叠，可通过玻利维亚小霸鹟的淡色腹部来区分，而红嘴小霸鹟的腹部为黄色。","protection":"IUCN：LC（无危）","distribution":"分布于南美，包括秘鲁的中南部（阿亚库乔、库斯科、马德雷德迪奥斯、普诺）至玻利维亚中部（拉巴斯、科恰班巴）。"},{"name":"红嘴小霸鹟","english_name":"Red-billed Tyrannulet","scientific_name":"Zimmerius cinereicapilla","overview":"红嘴小霸鹟（英文名：Red-billed Tyrannulet，学名：Zimmerius cinereicapilla），是雀形目霸鹟科南美小霸鹟属的鸟类。体型小巧的霸鹟科鸟类，分布于南美洲的安第斯山脉东坡，主要见于厄瓜多尔、秘鲁和玻利维亚的山区森林中。其最显著的特征是带有紫红色下喙的灰头黄橄榄色外观。","appearance":"红嘴小霸鹟体长约为11.5至12厘米，上部为黄橄榄色，头部呈淡灰色或暗橄榄色，喉部为白色，胸部为橄榄黄色，腹部更显明亮黄色。其翼羽边缘微黄，但不形成明显的翼斑。下喙紫红，上喙暗灰或暗灰黑色，虹膜淡黄色或乳白色。雌雄羽毛相似，幼鸟尚未描述。","call":"红嘴小霸鹟发出柔和的哨声和吱吱声，有时单独鸣叫，有时快速连串发出，叫声清脆悦耳。","habits":"栖息于海拔750至1200米的湿润森林中，常见于林冠层，偏好开阔地带的树木高处。以昆虫为食，活动范围广泛，飞行敏捷。","breeding":"关于红嘴小霸鹟的繁殖信息尚不详尽，其繁殖期、筑巢、交配等细节有待进一步研究。","identification":"红嘴小霸鹟与绿头小霸鹟(Zimmerius villlarejoi)相似，但后者冠部为橄榄色，体型更小，叫声不同。与细脚小霸鹟和玻利维亚小霸鹟的区别在于冠部颜色、喙色及叫声。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于南美的安第斯山脉东侧，包括厄瓜多尔、秘鲁北部至中部和玻利维亚北部。"},{"name":"绿头小霸鹟","english_name":"Mishana Tyrannulet","scientific_name":"Zimmerius villarejoi","overview":"绿头小霸鹟（英文名：Mishana Tyrannulet，学名：Zimmerius villarejoi），是雀形目霸鹟科南美小霸鹟属的小型霸鹟。其分布局限于秘鲁东北部的两个地理隔离区域，一是在伊基托斯附近的白砂森林，二是在Moyobamba和Tarapoto附近的安第斯山麓。该鸟种的发现归功于José Álvarez Alonso，他在1990年代首次对秘鲁的白砂森林进行了认真的鸟类学探索。","appearance":"绿头小霸鹟体型小巧，全身主要呈黄橄榄色，拥有淡色的喙和眼，翅膀羽毛边缘泛黄。头部略显暗淡，与红嘴小霸鹟相比体型更小，而与短嘴绿头小霸鹟相比叫声更高亢。成鸟两性相似，上体一般为橄榄色，面部两侧稍带绿色，翅膀呈暗黑色，翼羽边缘和尖端为硫磺黄色，次级飞羽和外侧初级飞羽边缘亦为硫磺黄色。尾巴灰暗，边缘为橄榄绿色。喉咙呈淡绿橄榄色，胸部渐变为橄榄黄色，腹部和尾下覆羽为硫磺黄色。幼鸟特征尚未描述。","call":"绿头小霸鹟的鸣叫特征为高音哨声，通常单独或成对发出，低地地区的叫声带有沙哑质感。叫声是区分它与近似种红嘴小霸鹟的重要依据。","habits":"绿头小霸鹟栖息于森林冠层，偏好潮湿的低地森林环境。其饮食以昆虫和水果为主，有证据表明它们也可能食用种子。觅食活动主要在树冠进行，寻找种子和小型节肢动物。","identification":"与细脚小霸鹟和黄顶小霸鹟的区别在于头部和脸部的素色以及红色的喙。与红嘴小霸鹟的区别在于头部颜色（非灰色）和体型较小，以及声音的差异。短嘴绿头小霸鹟与绿头小霸鹟最为相似，但体型略小，叫声更低沉。","protection":"IUCN：LC（无危）","distribution":"绿头小霸鹟主要分布在秘鲁北部，具体为伊基托斯附近的白砂森林和Moyobamba及Tarapoto附近的安第斯山麓。","other":"绿头小霸鹟的两个地理隔离种群可能代表不同的物种，这一假说尚待进一步研究证实。"},{"name":"短嘴绿头小霸鹟","english_name":"Chico's Tyrannulet","scientific_name":"Zimmerius chicomendesi","overview":"短嘴绿头小霸鹟（英文名：Chico's Tyrannulet，学名：Zimmerius chicomendesi），是雀形目霸鹟科南美小霸鹟属的鸟类。2013年由Bret Whitney等鸟类学家首次描述的物种，以纪念环保英雄Chico Mendes。该鸟种仅见于巴西玛代拉河至亚马孙州东南部的亚马逊白砂森林，其自然生境为亚热带或热带湿润山地森林。","appearance":"体长约10厘米，体重约5.5克。拥有橄榄绿色上体，从头部到尾上覆羽颜色一致，脸部、喉咙、胸部及两侧转为淡黄绿色，腹部和尾下覆羽明亮黄色。尾巴和翅膀呈暗黑色，边缘略带橄榄绿，翼下覆羽浅黄色。虹膜白色，喙基部棕红色，尖端粉红，腿脚黑色。雌雄羽毛相似，但雄鸟翅膀和尾巴较长，体重更重。","call":"最常听到的叫声为双音节的‘tweep-tweep’，偶尔为单音或三音节，带有变奏和不同的抑扬顿挫。","habits":"主要以寄生植物Oryctanthus alveolatus的果实为食，这种植物同样对近缘种绿头小霸鹟至关重要。在与高大森林的过渡地带，可能因争夺寄生植物而被圭亚那小霸鹟排挤。通常成对出现，尚未记录其捕食节肢动物。","breeding":"关于繁殖信息目前暂无具体数据。","identification":"与绿头小霸鹟的区别在于体型相对较小，叫声不同。","protection":"IUCN：NT（近危）。物种分布范围狭小，受威胁于亚马逊森林的砍伐。部分栖息地已被划定为Campos Amazônicos国家公园。","distribution":"主要分布于巴西亚马逊州南部，玛代拉河至阿利普阿纳河之间，可能延伸至罗赖马州东北部和马托格罗索州西北部。","other":"面临的主要威胁来自于道路建设，特别是Transamazônica公路的铺设计划，这将对其栖息地造成不可逆转的破坏。"},{"name":"细脚小霸鹟","english_name":"Slender-footed Tyrannulet","scientific_name":"Zimmerius gracilipes","overview":"细脚小霸鹟（英文名：Slender-footed Tyrannulet，学名：Zimmerius gracilipes），是雀形目霸鹟科南美小霸鹟属的鸟类。分布于南美洲亚马逊雨林区域，包括委内瑞拉、哥伦比亚、厄瓜多尔、秘鲁、玻利维亚和巴西的西部亚马逊盆地。其外表呈现淡黄绿色，头部略显灰暗，翼缘泛黄，与灰冠霸鹟相似但体型更小，喙部更为小巧。","appearance":"成年细脚小霸鹟长约9至11.5厘米，体重6.6至9.5克。头部灰色，上体呈暗橄榄色，翅膀暗淡，翼羽边缘呈黄色，形成独特的暗色翼尖与黄色边缘的对比。喉部和脸部下方为淡黄白色，胸部逐渐变为暗橄榄黄色，腹部黄色。眼睛灰暗，喙小而圆，黑色，腿为深灰色。雌雄外观相似，雌鸟稍小。幼鸟特征未详述。","call":"其叫声通常是一系列轻柔的‘chwit’或‘what?’声，重复缓慢，有时整个白天都能听到，音调会因地区而异，亚马逊以北为柔和的上升哨音‘wheet’，亚马逊以南为较短的上升‘whit’。还有一种声音为四到五个上升的模糊音符‘chu, chu-chu-ree’，结尾突然升高。黎明时的歌声在秘鲁（gilvus亚种）为加速单调的‘chew-chu-chi’chi’音符，而在厄瓜多尔东部（指名亚种）则为类似becard的忧郁‘peeu, tri-ri-ri’。","habits":"主要栖息于雨林树冠层，以昆虫为主食，偶尔食用小型果实，特别喜爱槲寄生（Loranthaceae科）。觅食时高度活跃，通过站立捕食和飞扑捕食获取食物，常单独或成对活动，偶尔加入混合物种群。","breeding":"繁殖季节在哥伦比亚南部为6月，在秘鲁东南部为8月至12月。巢位于树上，高度可达35米，已知巢中至少有两个较大的雏鸟。在巴西发现一枚淡粉色带红棕色和灰色斑点的蛋，尺寸为20mm×13mm，可能属于本种或圭亚那小霸鹟。","identification":"与灰冠霸鹟相比，细脚小霸鹟体型更小，喙更小，眼色更深，通过这些特征可以将其区分开来。亚种之间可能存在颜色差异，gilvus亚种的下体色彩更为鲜亮。","protection":"IUCN：LC（无全球性威胁）。在许多国家公园和其他保护区中均有分布，包括委内瑞拉的奥里诺科-卡西基亚雷生物圈保护区、哥伦比亚的提尼瓜国家公园、厄瓜多尔的拉塞瓦和萨查旅馆附近（此处物种分布异常局部化）、秘鲁的阿尔帕哈约-米沙纳国家保护区、马努国家公园和生物圈保护区、塔博帕塔-坎达莫保留区、玻利维亚的马迪迪和诺埃尔·肯普夫·梅尔卡多国家公园以及皮隆·拉哈斯生物圈保护区，以及巴西的多个保护区。","distribution":"细脚小霸鹟主要分布在南美洲的亚马逊雨林区域，包括委内瑞拉、哥伦比亚、厄瓜多尔、秘鲁、玻利维亚和巴西的西部亚马逊盆地。","other":"直到最近，圭亚那小霸鹟仍被视为本种的一个亚种。"},{"name":"圭亚那小霸鹟","english_name":"Guianan Tyrannulet","scientific_name":"Zimmerius acer","overview":"圭亚那小霸鹟（英文名：Guianan Tyrannulet，学名：Zimmerius acer），是雀形目霸鹟科南美小霸鹟属的小型、不显眼的霸鹟。分布于亚马逊盆地东部及巴西东北部的森林地带。","appearance":"体型微小，长度约9至11.4厘米，体重5.7至11克。特征包括短喙、翼条纹和较长的尾巴。其脸和下喉几乎纯白色，下体淡黄色；喙和跗蹠通常全黑，眼睛灰色或深棕色。","call":"最常见叫声为干涩的双音节hiccup声，容易被忽视；黎明时的鸣唱为重复上升的颤音。","habits":"栖息于多种森林环境，包括原始雨林、次生雨林、低矮的沙土森林及河岸边缘。常在枝梢叶簇上停留，扑捉昆虫，也以小果实为食。活动高度多在海拔800米以下，但在委内瑞拉东南部记录到高达1400米。","breeding":"繁殖季节不明，但在苏里南有记录显示九月筑巢。巢为侧入口的圆顶状，高置于芒果树上，由新鲜苔藓、活的芒果花萼构成，内部密铺棉絮和兽毛，外部直径10厘米，高8厘米，内杯4x6厘米。产卵数为两枚，卵壳淡白，大端布满栗色和紫罗兰色斑点，平均尺寸15.1-16mm x 11.1-12.5mm，重约0.5克；孵化和离巢时间未知。","identification":"与前同种细脚小霸鹟相似，但脸和下喉近乎纯白，下体更淡黄；叫声区别明显，尤其是亚马逊河北部的个体，发出极短音符，音调下降，最高频率更高。","protection":"IUCN：LC（无危）。虽然不普遍但常见，由于栖息于树冠层，往往因声音而被发现。在多个国家公园和其他保护区内存在，包括巴西东北部的Tapacurá生态站、Pedra Talhada、Murici和Guaribas生物保护区，以及亚马逊东部的Cristalino丛林旅馆、Tapajós国家公园和Serra dos Carajás保护区群。城市森林区域也能频繁见到。","distribution":"分布于委内瑞拉东部和东南部、圭亚那和巴西东北部，包括亚马逊河盆地的东部区域。","other":"最近才从细脚小霸鹟中分离出来，成为一个独立物种。"},{"name":"金脸小霸鹟","english_name":"Golden-faced Tyrannulet","scientific_name":"Zimmerius chrysops","overview":"金脸小霸鹟（英文名：Golden-faced Tyrannulet，学名：Zimmerius chrysops），是雀形目霸鹟科南美小霸鹟属的小型鸟类。为小霸鹟属在安第斯山系分布最广的鸟种，自委内瑞拉西北部延伸至秘鲁北部，另在委内瑞拉东北部有一隔离种群（亚种 cumanensis）。其羽色以橄榄绿上体、黄色面部及淡色下体为典型，栖息于湿润森林及边缘。","appearance":"体长10.5–11.5厘米，体重7.7–10.6克。面部金色至亮黄色，眼深色。指名亚种额、眉纹及眶周鲜黄，上体亮橄榄绿；翼暗褐，覆羽及飞羽具鲜黄缘，形成暗色“楔”纹；尾暗褐；喉及下面部黄白，胸腹转淡白；喙小黑色；脚灰色。雌雄同色，雌略小。幼鸟尚无描述。亚种 cumanensis 下体带淡绿黄；亚种 minimus 体型明显更小。","call":"极善鸣叫，反复发出响亮哨音“pleeeeur”或“hueeer”；黎明时亦有“teer-tif”。另有哀婉“chu-dee-de-e-e”及缓慢4–5次重复的“cheee cheee cheee”。叫声具地理差异：cumanensis 为无泛音直线下滑哨音；委内瑞拉安第斯及佩里哈山脉为带泛音短促下滑音；哥伦比亚与厄瓜多尔大部为先升后降无泛音哀哨；哥伦比亚西部则为带泛音中部最强哨音。","habits":"留鸟。主要栖息于海拔500–2000米的湿润山地森林、林缘、次生林、半落叶林、咖啡园及花园，局部可达2700米。常成对或单独活动，随混群在林冠5–10米处觅食，偶尔悬停取食。食物以昆虫为主，兼食槲寄生等小型附生浆果。","breeding":"繁殖期长，哥伦比亚记录到4、6、9、11月筑巢，厄瓜多尔东部8月仍有繁殖。巢为侧面入口的圆顶状，多置于悬垂苔藓或树侧苔藓球中，距地5–12米，个别达45米。雌鸟单独筑巢，每窝2枚乳白底色带肝棕色斑的卵，平均17.2×13.4毫米，重约1.6克。孵化约17天，仅雌鸟承担；育雏期17–19天，双亲共同喂雏，成功率仅12%，92%失败由捕食导致。","identification":"与同属物种相比，金脸小霸鹟以黄色面部及亮橄榄上体为显著特征。与已独立成种的灰喉金脸小霸鹟可通过分布区及鸣声区分；亚种 cumanensis 下体淡绿黄，minimus 体型最小，二者未来可能提升为独立种。","protection":"IUCN: LC（无危）","distribution":"繁殖区：指名亚种 chrysops 见于委内瑞拉西北部安第斯山系及佩里哈山脉、哥伦比亚（除纳里尼奥省）、厄瓜多尔东部及秘鲁北部（至圣马丁省）；亚种 cumanensis 分布于委内瑞拉东北部（安索阿特吉、苏克雷、北莫纳加斯）；亚种 minimus 局限哥伦比亚北部圣玛尔塔山脉及北马格达莱纳。非繁殖区：全年留居，无迁徙记录。","other":"系统学研究表明，亚种 cumanensis 因鸣声独特几乎应被视为独立种，亚种 minimus 及指名亚种内部三群（委内瑞拉安第斯及佩里哈、哥伦比亚与厄瓜多尔安第斯、哥伦比亚西部安第斯）亦具潜在种级分化，仍需进一步声学与遗传研究确认。原归入本种的 flavidifrons 亚种（厄瓜多尔小霸鹟）现已归为秘鲁小霸鹟的亚种。"},{"name":"库氏小霸鹟","english_name":"Coopmans's Tyrannulet","scientific_name":"Zimmerius minimus","overview":"库氏小霸鹟（英文名：Coopmans's Tyrannulet，学名：Zimmerius minimus），是雀形目霸鹟科南美小霸鹟属的鸟类。分布于南美的哥伦比亚东北部及委内瑞拉北部。","appearance":"该物种的详细外形特征未提供。","call":"该物种的鸣叫特征未提供。","habits":"库氏小霸鹟的生活习性信息未详述。","breeding":"关于库氏小霸鹟的生长繁殖信息未提供。","identification":"该物种与其他近似物种的辨识要点未提供。","protection":"IUCN状态未提及。","distribution":"库氏小霸鹟分布在南美洲，具体包括哥伦比亚东北部和委内瑞拉北部。","other":"关于库氏小霸鹟的其他重要信息未提供。现为金脸小霸鹟亚种。"},{"name":"灰喉金脸小霸鹟","english_name":"Choco Tyrannulet","scientific_name":"Zimmerius albigularis","overview":"灰喉金脸小霸鹟（英文名：Choco Tyrannulet，学名：Zimmerius albigularis），是雀形目霸鹟科南美小霸鹟属的小型鸟类，常见于南美洲的厄瓜多尔西部和哥伦比亚西南部的森林地带。其显著特征为橄榄绿色的上体，淡灰色的腹部，黄色的眼圈和翼羽边缘。分布区域面临严重的栖息地破坏。","appearance":"体长约10.5至11.5厘米，体重约6.6至8.6克。上体呈深橄榄色，额头有黄色斑点，翼羽边缘和次级飞羽基部（除次级飞羽外）有黄色镶边，眼先暗色，耳羽呈金棕色，腹部偏白，侧身略带淡黄色，下腹及臀部为淡黄色。雌雄大小差异未知，幼鸟特征未详述。与金脸小霸鹟相似，但体型略小，喉部白色更为明显。","call":"日间叫声为短促的哨音，以强调的上升音结尾，但总体上波动，带有泛音，最大音量出现在音符的四分之三处。黎明歌曲与近缘种，尤其是金脸小霸鹟的区别尚未详细研究。","habits":"栖息于湿润的山前森林、边界、较老的次生林和咖啡种植园，甚至花园中。在厄瓜多尔，从近海平面到约1600米的高度均有记录，而在哥伦比亚南部有高达2500米的标本。觅食行为与近缘种类似，具体饮食细节未知。","identification":"与金脸小霸鹟非常相似，但灰喉金脸小霸鹟的喉部更白，体型稍小，黄色特征略显淡一些。通过声音确认身份最佳。","protection":"IUCN：LC（无危）。物种在多个保护区中，包括厄瓜多尔的Machalilla国家公园、Loma Alta生态保护区、Jatun Sacha Bilsa保护区和Río Palenque科学中心。哥伦比亚西部确切分布范围仍有待考证。","distribution":"繁殖区域：南美洲的厄瓜多尔西部至北瓜亚斯省，哥伦比亚西南部纳里诺省。在哥伦比亚，可能分布更北至Risaralda省的Tatamá国家公园，但需要更多研究确认。","other":"之前曾被视为金脸小霸鹟的同种，后基于分子和声学差异被划分为独立物种。"},{"name":"厄瓜多尔小霸鹟","english_name":"Loja Tyrannulet","scientific_name":"Zimmerius flavidifrons","overview":"厄瓜多尔小霸鹟（英文名：Loja Tyrannulet，学名：Zimmerius flavidifrons），是雀形目霸鹟科南美小霸鹟属的鸟类。主要分布于南美洲厄瓜多尔西南部地区。","appearance":"与秘鲁小霸鹟外形接近。","identification":"与同属的金脸小霸鹟曾经被认为是同一种，但现已确认为独立物种。","distribution":"主要分布在南美洲厄瓜多尔的西南部地区。","other":"现为秘鲁小霸鹟亚种。"},{"name":"秘鲁小霸鹟","english_name":"Peruvian Tyrannulet","scientific_name":"Zimmerius viridiflavus","overview":"秘鲁小霸鹟（英文名：Peruvian Tyrannulet，学名：Zimmerius viridiflavus），是雀形目霸鹟科南美小霸鹟属的鸟类。是南美西北部安第斯山地的特有小型霸鹟，曾被视为金脸小霸鹟的亚种。体长约12厘米，重9–10克，上体橄榄绿，翼羽具鲜黄绿边缘，头顶灰褐，具暗色眼纹及淡黄眉纹，胸腹淡黄偏橄榄，尾羽略翘。主要栖息于秘鲁与厄瓜多尔海拔1000–2500 m的云雾林冠层，以昆虫及浆果为食。该种包含两个单型亚种：指名亚种分布于秘鲁中部安第斯山脉，flavidifrons亚种分布于厄瓜多尔西南及秘鲁极西北。","appearance":"成鸟雌雄同色。头顶暗橄榄至灰橄榄，背部亮橄榄。具淡黄小髭纹及断环状淡黄眼环，耳羽亮橄榄带淡褐。翼羽暗褐色，覆羽、次级飞羽及初级飞羽基部外缘鲜黄绿，形成明显“楔形”黄斑；尾羽褐绿。喉淡黄，胸及胁橄榄黄并具鳞状橄榄斑，腹亮黄。虹膜中央灰至中褐，边缘棕褐。嘴短小，上嘴黑灰，下嘴中灰；腿黑灰至黑色。幼鸟未见描述。","call":"发出连续而快速的哨音短语“pee-diddle-wééo”，反复鸣唱。","habits":"留鸟，栖息于湿润山地森林及林缘，偶见于次生灌丛。通常单独或成对在森林冠层活动，常加入混合种觅食群。以跳跃及短飞方式在枝叶外缘觅食，站立时姿态水平，尾常略翘。以昆虫为主，亦取槲寄生科及其他小型浆果。通过停栖啄取和出击啄取两种方式获得食物。","breeding":"繁殖记录缺乏，生态细节尚待研究。","identification":"与金脸小霸鹟相比，本种面部黄色较淡，下体更偏橄榄黄而非纯白；与同属其他种的区别在于翼上黄色斑块更明显，面部及下体色调特征独特。两亚种中，flavidifrons分布于厄瓜多尔西南及秘鲁西北，指名亚种局限于秘鲁中部安第斯。","protection":"IUCN: LC（无危）。虽非全球性受胁种，但属于分布狭窄的安第斯山系特有种，部分区域因农业扩张及古柯种植导致森林减少，云雾林仍相对完好。","distribution":"繁殖区：秘鲁中部安第斯山脉（Huánuco、Junín、Ayacucho）及厄瓜多尔西南（Guayas南至Loja）并秘鲁极西北（Tumbes、Piura）。非繁殖区：全年留居，无迁徙记录。"},{"name":"杂色须霸鹟","english_name":"Variegated Bristle Tyrant","scientific_name":"Pogonotriccus poecilotis","overview":"杂色须霸鹟（英文名：Variegated Bristle Tyrant，学名：Pogonotriccus poecilotis），是雀形目霸鹟科须霸鹟属的小型鸟类。广泛分布于南美洲安第斯山脉，自委内瑞拉西北至秘鲁南部，主要栖息于海拔1500至2300米的湿润山地森林。其外观并不显眼，具有独特的栗色翼纹和双色喙，常被发现单独或成对活动。","appearance":"该鸟体型小，头顶呈石板灰色，脸颊上有黑色与白色构成的显著月牙形图案。上体橄榄绿色，翼上有两道醒目的栗色条纹。下体浅黄色，胸羽略带橄榄色调。雄雌相似，无明显差异。","call":"发出一系列高音的\"tsit\"声，有时以较长的\"tsee!\"结束。","habits":"栖息于中低层林区，常见于混合物种群中，以昆虫为主食，通过悬停捕食的方式觅食。活动范围涵盖南美安第斯山脉的特定海拔。","breeding":"关于繁殖行为的文献记载尚不充分，但已知会在特定季节进行繁殖，具体细节有待进一步研究。","identification":"与大理石面须霸鹟(Phylloscartes ophthalmicus)的区别在于，后者翼纹偏黄色而非栗色，且下体颜色更为明亮。同时，它与灰顶窄嘴霸鹟(Leptopogon supercilaris)也有区别，后者翼纹颜色通常为肉桂色或棕黄色，体型略大，喙全黑，面部对比度较低。","protection":"IUCN：LC（无危）","distribution":"分布于南美，包括哥伦比亚北部、委内瑞拉西北部至秘鲁南部，主要栖息于安第斯山脉东坡的湿润山地森林。","other":"杂色须霸鹟通常被视为单型种，尽管曾有来自委内瑞拉极西北部的独立亚种描述。"},{"name":"查氏姬霸鹟","english_name":"Chapman's Bristle Tyrant","scientific_name":"Pogonotriccus chapmani","overview":"查氏姬霸鹟（英文名：Chapman's Bristle Tyrant，学名：Pogonotriccus chapmani），是雀形目霸鹟科须霸鹟属的鸟类。体型小巧，外观上部橄榄绿，下部淡黄色，具明显的淡色翼纹和较长的尾巴。常见于南美洲委内瑞拉南部特普伊山脉的高海拔湿润森林，高度通常超过800米。","appearance":"身长12厘米，体重仅8克。上体呈暗淡的橄榄绿色，头顶略深；眉线淡白色，眼环白色，黑色眼线与耳羽相连形成锐利的黑色新月状图案；翅膀暗淡，两道淡黄色至淡褐色的翼纹，飞羽边缘颜色较浅；尾羽暗橄榄绿色；脸下部灰白相间，喉部和胸部橄榄黄色，其余下体淡黄色。虹膜棕色，喙短尖，黑色，下颚基部较淡黄色，腿灰色。雄雌相似，幼鸟描述未详。Duidae亚种比指名亚种更偏黄绿色，内侧次级飞羽尖端更深的淡褐色，飞羽边缘更黄，少带淡褐色。","call":"发出独特的下降音调的两到三声鸣叫，带有挤压质感，兴奋时可能发出高而细的颤音。","habits":"通常在湿润森林的高处活动，成对或小家庭群组，活跃地觅食，以昆虫为食，常在叶簇末端捕食。经常出现在混合物种的鸟群中。","breeding":"具体繁殖细节未知。","identification":"在其有限的分布范围内，与其他物种不容易混淆。","protection":"IUCN状态不明。","distribution":"南美洲委内瑞拉南部特普伊山脉的高海拔湿润森林。","other":"有时被归类在Phylloscartes属内。"},{"name":"纹脸须霸鹟","english_name":"Marble-faced Bristle Tyrant","scientific_name":"Pogonotriccus ophthalmicus","overview":"纹脸须霸鹟（英文名：Marble-faced Bristle Tyrant，学名：Pogonotriccus ophthalmicus），是雀形目霸鹟科须霸鹟属的小型鸟类。分布于南美洲，从委内瑞拉至玻利维亚的山地森林地带，约在海拔800至2200米之间。其特征是脸部具有大理石般的斑驳图案，以及黑色与白色的月牙状标记。","appearance":"纹脸须霸鹟体长约11.5厘米，体重约10至11克。头部冠部呈石板灰色，与鲜黄橄榄色的背部形成鲜明对比；眉线和眼上纹为白色，脸部混杂黑白色调，耳羽区至浅黄色，后方带有宽阔的黑色新月标记；翅膀暗淡，有两条翼带和飞羽边缘为浅橄榄黄至黄色，最内侧飞羽外缘宽幅泛黄；尾巴暗橄榄色；喉咙部分混杂灰白色，下体鲜黄，胸部深橄榄色浸染严重；虹膜棕色；喙全黑；腿灰色。雌雄相似，幼鸟比成鸟更暗淡。不同亚种主要在脸部、翅膀和下体的黄色强度上有所差异。","call":"鸣唱为略显微弱但爆发力强的高音颤音，以快速、轻微上升的颤音结尾，\"ju-ju-j-j-j tre-e-e-e-e-e- pit-pit\"；叫声为尖锐的\"ju-é\"或\"ts-rit\"。","habits":"通常单独或成对出现，常在森林的低至中层活动，有时跟随混合物种群。活动范围广泛，善于飞翔。","breeding":"巢穴为烤箱形状，由苔藓构成的球体，有一侧入口，背靠大树主干，高度约为7米，曾发现含有两枚蛋，一枚蛋尺寸为18.1mm×13.4mm，纯白色。在哥伦比亚，六月观察到筑巢行为，九月至十二月间在秘鲁发现家庭群体中包含幼鸟。","identification":"通过全黑的喙和黄色的翼带识别纹脸须霸鹟，与同属其他种类区分开来。","protection":"IUCN：LC（无危）。在某些地区稀少至局部常见。在哥伦比亚的Finca Merenberg（Huila）位于其海拔上限处较为罕见。在多个保护区中出现，包括委内瑞拉的Henri Pittier国家公园，哥伦比亚的Tambito自然保护区和Ucumarí区域公园，秘鲁的Machu Picchu历史保护区，以及玻利维亚的Pilón Lajas生物圈保护区和Madidi国家公园。","distribution":"分布于南美，从委内瑞拉至玻利维亚，包括哥伦比亚、厄瓜多尔、秘鲁等地的山地森林。"},{"name":"眼斑须霸鹟","english_name":"Spectacled Bristle Tyrant","scientific_name":"Pogonotriccus orbitalis","overview":"眼斑须霸鹟（英文名：Spectacled Bristle Tyrant，学名：Pogonotriccus orbitalis），是雀形目霸鹟科须霸鹟属的鸟类。小型的须霸鹟。具有独特的外观特征，分布于南美洲安第斯山脉的狭窄地带，大约在海拔500至1400米之间。","appearance":"体型小，长约11.5厘米，体重约8克。头部灰暗，脸侧和耳羽呈黄斑状，边缘隐约被黑色弧形纹环绕。上体橄榄色，翅膀深灰色，翼羽端部有明显的淡黄色斑点，形成两道弱黄色翼带。尾巴橄榄色，全身下部鲜黄色，胸部略带橄榄色调。虹膜棕色，喙长而尖，上喙黑色，下喙大部分白色至粉白色；腿灰色。雌雄相似，幼鸟特征未知。","call":"声音较为柔和，发出一系列起伏轻微的‘tic’音，有时单独发出。","habits":"栖息于安第斯山脉山脚下的森林中层和树冠层，偶尔加入混合物种的鸟群。其生活环境为亚热带或热带湿润的低地森林和山地森林。","identification":"通过其橙色的下喙和灰暗头部配合黄斑脸侧的特征进行辨识。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲安第斯山脉，从哥伦比亚南部至玻利维亚，具体包括哥伦比亚、厄瓜多尔、秘鲁和玻利维亚。"},{"name":"委内瑞拉须霸鹟","english_name":"Venezuelan Bristle Tyrant","scientific_name":"Pogonotriccus venezuelanus","overview":"委内瑞拉须霸鹟（英文名：Venezuelan Bristle Tyrant，学名：Pogonotriccus venezuelanus），是雀形目霸鹟科须霸鹟属的鸟类。是委内瑞拉特有的小型橄榄黄色霸鹟，显著特征包括黑色耳斑、灰色冠羽、粉红色下颚及醒目的黄白色翼带。性别相似，通常独居或成对出现，栖息于山区成熟湿润森林。","appearance":"体长约11.5厘米，体重约8-9克。头部灰色，眼圈黄白，脸部和耳羽有黄斑，上体橄榄色，双翅黑色，具两道明亮的黄色翼带，飞羽边缘及尖端呈淡黄色。尾巴橄榄色，喉部至腹部亮黄色，胸部略泛橄榄色。虹膜棕色，喙长而尖，上黑下白，腿灰色。幼鸟描述未知，成鸟性别外观一致。","call":"发出双重音调的叫声“che-dip”，以及高低起伏的快速颤音。","habits":"生活在海拔950-1400米的湿润山地森林，尤其是潮湿的苔藓云雾林。居民鸟，常单独或成对在混合物种群中觅食，站立姿态直立，尾巴垂直向下。通过短暂的向外或向上环状飞行捕获昆虫，或悬停在树叶下侧采食，之后迅速飞往新栖处。","breeding":"关于繁殖数据尚无具体信息，繁殖季节可能在1月至4月/5月之间。","identification":"与纹脸须霸鹟的区别在于后者翅膀覆羽对比不明显，翼带不突出，下颚灰色而非粉红，面部更为干净。","protection":"IUCN：NT（近危）","distribution":"分布于南美洲委内瑞拉北部，具体包括沿海山脉（从卡拉沃沃东至联邦区）和内陆山脉（阿鲁加州、米兰达州南部）。","other":"在Henri Pittier国家公园和其他保护区中较为常见，尽管在其小范围内仍有广泛的森林覆盖，但住宅区周围如加拉加斯等地的森林破坏严重。"},{"name":"哥伦比亚须霸鹟","english_name":"Antioquia Bristle Tyrant","scientific_name":"Pogonotriccus lanyoni","overview":"哥伦比亚须霸鹟（英文名：Antioquia Bristle Tyrant，学名：Pogonotriccus lanyoni），是雀形目霸鹟科须霸鹟属的鸟类。这一稀有物种仅在哥伦比亚安第斯山脉的少数地点被发现，尤其在中央山脉北部。该鸟种于1988年被正式描述，以美国鸟类学家Wesley Lanyon命名，其分布区因森林破坏而严重碎片化，被列为濒危物种。","appearance":"哥伦比亚须霸鹟体型较小，主要呈黄色，头部冠羽呈灰绿色，两翼具有宽大的黄色翼带，耳部可见模糊的黄灰色斑纹。上体橄榄绿色，下体鲜亮黄色，尾羽较长，喙较细长。","call":"其典型鸣声为短促的爆发声，开始时类似干涩的颤音，随后转为清脆的尖叫。","habits":"栖息于湿润森林，常加入混杂物种群落，活动于半落叶低山林、高大的次生林以及不同程度受干扰的残余森林中。","breeding":"关于繁殖行为的信息极为有限。","identification":"与灰顶窄嘴霸鹟相比，哥伦比亚须霸鹟体型更小，翼带更亮，面部图案对比度较低，且在海拔高度上有所不同。与眼斑须霸鹟的区别在于下体颜色、翼带明显度、眼环完整性以及冠羽色泽。","protection":"IUCN：VU（易危）","distribution":"分布于哥伦比亚西北部，特别是在中央安第斯山脉东坡和北坡，以及东部安第斯山脉西坡。","other":"由于其分布区域狭窄且持续遭受森林破坏，该物种的生存状况令人担忧。"},{"name":"南须霸鹟","english_name":"Southern Bristle Tyrant","scientific_name":"Pogonotriccus eximius","overview":"南须霸鹟（英文名：Southern Bristle Tyrant，学名：Pogonotriccus eximius），是雀形目霸鹟科须霸鹟属的小型鸟类，以独特的羽色著称。分布于南美洲的巴西东南部、巴拉圭东部和阿根廷东北部的亚热带森林地带，主要栖息于海拔800至1700米的山区森林，但在其分布区的南部边缘，如东南巴拉圭和东北阿根廷，亦可见于低至100米的高度。由于栖息地丧失，该物种数量稀少，被IUCN列为近危状态。","appearance":"南须霸鹟体型小巧，拥有橄榄黄色的背部和鲜亮的黄色腹部，上喉部为白色。最引人注目的是其头部的复杂图案：灰色的冠羽下方有一条宽阔的白眉纹，白眉纹后方有垂直的黑色新月形斑块。尾部长而突出，嘴型细长。雌雄外观相似，但幼鸟的羽色可能较为暗淡。","call":"其鸣唱为高音颤音，具有辨识度。","habits":"南须霸鹟主要栖息于山地森林中层，包括Araucaria森林，偏好在森林边缘活动。它们的活动范围和觅食方式尚未充分研究，但据观察，它们在树冠层中寻找昆虫等食物。","identification":"与同属其他物种如Phylloscartes属的种类相比，南须霸鹟有更直立的体态，不会翘起尾巴，觅食时较为不活跃。在同域分布的鸟类中，角侏霸鹟虽有类似的面部图案，但体型更小，尾部较短，且鸣声截然不同。","protection":"IUCN：NT（近危）","distribution":"南须霸鹟主要分布在南美的巴西东南部、巴拉圭东部和阿根廷东北部，尤其在亚热带森林中较为常见，包括山地森林和森林边缘。","other":"尽管南须霸鹟目前分类上归属于Pogonotriccus属，但过去曾归入Phylloscartes属。"},{"name":"圣保罗姬霸鹟","english_name":"Sao Paulo Bristle Tyrant","scientific_name":"Pogonotriccus paulista","overview":"圣保罗姬霸鹟（英文名：Sao Paulo Bristle Tyrant，学名：Pogonotriccus paulista），是雀形目霸鹟科须霸鹟属的鸟类。小型霸鹟科鸟类，体型小巧，橄榄色背部与胸部，黄色喉咙和腹部为其显著特征。常见于低地湿润森林的低至中层，活跃于混合物种群落中。与欧氏姬霸鹟相比，通常出现在较低海拔。","appearance":"体型极小，尾部细长，一般不翘起。上身及胸部橄榄色，喉部及腹部呈黄色。脸部淡黄色，眼后有宽大的暗色新月状斑纹，眉纹黄色。","call":"鸣唱为一系列高音急促的哨声。","habits":"栖息于低地湿润森林及边缘地带，活动积极，常与多种鸟类混群。以昆虫为主食。","breeding":"未提供具体繁殖信息。","identification":"与欧氏姬霸鹟相比，更偏好较低海拔环境。","protection":"IUCN：NT（近危）。全球数量可能不足10,000只。低地大西洋森林的破坏对其栖息地造成严重影响。","distribution":"分布于南美洲，包括巴西东南部（从马托格罗索州东南部至圣卡塔琳娜州）、巴拉圭东部（从卡宁德尤州南部至伊塔普阿州）和阿根廷东北部（米西奥内斯省）。","other":"在巴西的几个国家公园中相对常见，但在某些地区可能已局部灭绝，如自1942年后在埃斯皮里图桑托州未再有记录。"},{"name":"巴西姬霸鹟","english_name":"Serra do Mar Bristle Tyrant","scientific_name":"Pogonotriccus difficilis","overview":"巴西姬霸鹟（英文名：Serra do Mar Bristle Tyrant，学名：Pogonotriccus difficilis），是雀形目霸鹟科须霸鹟属的珍稀鸟类，分布于巴西东部和东南部的山地森林中。","appearance":"体长约11-11.5厘米，体重约7-8克。上体呈现明亮的橄榄绿色，具显著的白色眼环和眉纹，黑色耳羽斑块，翅膀与背部同色，略淡的边缘羽毛；尾部橄榄绿；整个下体为中灰色，喉部和尾下覆羽稍浅；虹膜棕色；喙短而尖，黑色，下颚基部较淡；腿灰粉色。雌雄相似，幼鸟未描述。","call":"发出快速的薄而略带刺耳音调的连续鸣叫。","habits":"单独或成对活动，偶尔加入混种群，栖息于湿润植被的林下层和茂密生长区。捕食昆虫，活动不如同类活跃，但保持水平姿态，尾巴常略高于水平线，翅膀下垂或远离身体；会悬停捕食密集叶丛中的昆虫。","breeding":"关于繁殖数据不足。推测繁殖季节为9月至次年1月。已记录到12月有幼鸟。","identification":"与其它须霸鹟属物种的区别在于上体鲜亮的橄榄绿色，下体灰色，暗色耳羽斑块，显著的白色眼环，以及粉红色而非深色的腿。","distribution":"分布在南美洲巴西的东部和东南部，具体位于海拔950至2150米的潮湿山地森林。"},{"name":"点颊姬霸鹟","english_name":"Mottle-cheeked Tyrannulet","scientific_name":"Phylloscartes ventralis","overview":"点颊姬霸鹟（英文名：Mottle-cheeked Tyrannulet，学名：Phylloscartes ventralis），是雀形目霸鹟科姬霸鹟属的小型鸟类。常见于南美洲。其特征为橄榄黄色的体羽，头部有浅色眉纹和白色颏部，两道淡色翼带显眼。分布于巴西东南部的山地大西洋森林、巴拉圭东部、阿根廷东北部和乌拉圭，以及秘鲁、玻利维亚和阿根廷西北部的安第斯山脉东坡森林。","appearance":"体长约12厘米，体重约9克。上体为暗橄榄色，眉纹和眼圈为灰白色，有时不太明显，眼先至耳羽呈深灰色，形成一浅弯月形。翅膀深色，带有两道淡黄色至黄色的翼带，飞羽边缘黄色，最内侧飞羽的外缘宽泛淡黄色。尾部深橄榄色。喉部白色，面部下部混杂白色；下体中黄色，胸部隐约带有橄榄色斑纹，腹部中黄色。虹膜深棕色，喙长而尖，黑色，下颚基部粉红色；腿灰色。雌雄相似，幼鸟较成鸟颜色暗淡。不同亚种色彩强度有差异：angustirostris亚种上体略呈深绿色，下体比指名亚种更黄；tucumanus亚种上体略淡橄榄色，下体更淡黄色。","call":"发出短促、高音调的鸣唱。","habits":"栖息于山地森林，包括Araucaria森林，在林中层活跃觅食，常与混合物种群一起活动。","identification":"与同属其他物种相比，点颊姬霸鹟具有独特的橄榄黄体色和两道翼带。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的两个不连续区域：一是巴西东南部、巴拉圭东部、阿根廷东北部和乌拉圭的山地大西洋森林；二是秘鲁东南部至阿根廷西北部的安第斯山脉东坡森林。"},{"name":"长尾姬霸鹟","english_name":"Alagoas Tyrannulet","scientific_name":"Phylloscartes ceciliae","overview":"长尾姬霸鹟（英文名：Alagoas Tyrannulet，学名：Phylloscartes ceciliae），是雀形目霸鹟科姬霸鹟属的小型鸟类，以长尾著称。分布于巴西东部的亚热带或热带湿润低地森林，属于特有种，面临栖息地丧失的威胁。","appearance":"体型小，尾部较长，上体呈深橄榄绿，下体白色，具白色眉纹。两翼有黄色翼带，眼周及耳羽有黑色边框，连接形成类似马鞍的图案。翅膀黑色橄榄色，边缘黄绿色，翼覆羽宽端黄绿色（两翼带），内侧飞羽边缘和尖端黄绿色。尾部黑色，边缘黄绿色；喉咙和胸部白色，胸侧略带暗绿色，其余下体白色，腹部和下尾覆羽淡黄色。虹膜栗棕色，喙尖黑，腿深蓝灰色。雌雄相似，幼鸟未详述。","call":"鸣唱为一系列快速高音的“dju”声，有时更尖锐、更快，‘ururut, ururut…’；发出柔和的‘thup’叫声。","habits":"栖息于残存的高地常绿森林和成熟的次生林，活跃于树冠中上层，常加入混群，与多种猛禽、鵙形目、蚁鵙目和蚁鸟共同活动。主要捕食昆虫，活动时尾巴保持水平或略高于水平，从树叶表面捕捉猎物。","breeding":"繁殖信息未详细记录，少数标本的换羽周期提示繁殖可能发生在9月至2月间。","identification":"与其他姬霸鹟属鸟类相比，长尾姬霸鹟具有独特的黄色翼带和白色眉纹，以及特定的栖息地选择。","protection":"IUCN：CR（极危）","distribution":"分布于巴西东北部的伯南布哥州和阿腊戈阿斯州的亚特兰大森林区域，主要集中在海拔400至550米之间。","other":"该物种于1983年首次在Murici附近的Pedra Branca山坡发现，当时被认为是较为常见的。"},{"name":"雷斯姬霸鹟","english_name":"Restinga Tyrannulet","scientific_name":"Phylloscartes kronei","overview":"雷斯姬霸鹟（英文名：Restinga Tyrannulet，学名：Phylloscartes kronei），是雀形目霸鹟科姬霸鹟属的鸟类。小型的橄榄绿色霸鹟，其尾部长而细，常上翘。这种鸟主要分布于巴西东南部，以南大西洋沿岸为中心，生活于约150公里宽的沿海地带，栖息于沿海沙丘植被及内陆山麓。全球受威胁的巴西特有种，于1990年代初被正式描述，纪念首次收集到标本的Ricardo Krone，他是19世纪末的采集人。","appearance":"雷斯姬霸鹟体长约12厘米，雄雌相似，背部呈绿橄榄色，头部略显棕色。眼眉和眼环黄色，眼上方有一条深色条纹，延伸至耳羽后方形成明显的深色新月状斑。脸面带有黄褐色斑点。翅膀暗色，具两道翼带，由较大型覆羽的黄色尖端构成；次级飞羽内侧边缘黄色；飞羽外缘淡黄色。尾羽橄榄色，边缘绿黄色。下脸和喉部淡黄色，腹部亮黄色，两侧和胸部有非常微弱的绿色斑点。大腿部有黄绿色横纹。","call":"其叫声为独特的双音节鸣叫和啾啾声的歌曲。","habits":"在小昆虫上觅食，通过短距离追逐和捕捉的方式，常伴随混合物种群。主要栖息于沿海沙丘植被及内陆山麓。","breeding":"关于其繁殖习性的具体信息尚未详述。","identification":"与点颊姬霸鹟相似，但雷斯姬霸鹟的脸部更黄，耳羽后方的新月形标记更暗，冠部和背羽更鲜绿色。叫声和歌声与点颊姬霸鹟明显不同。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东南部，南大西洋沿岸，从圣保罗州向南至里奥格兰德杜苏尔北部的150公里宽沿海地带。","other":"雷斯姬霸鹟的幼鸟颜色比成鸟浅，下颌有一个大的橙色区域。"},{"name":"巴伊姬霸鹟","english_name":"Bahia Tyrannulet","scientific_name":"Phylloscartes beckeri","overview":"巴伊姬霸鹟（英文名：Bahia Tyrannulet，学名：Phylloscartes beckeri），是雀形目霸鹟科姬霸鹟属的鸟类。小型的姬霸鹟。其特征在于橄榄绿的背部，灰白色的喉咙，以及黄色的腹部。该鸟种分布于巴西东部巴伊亚州的高海拔湿润森林中（750-1200米），常伴随混种群鸟活动。","appearance":"体长约12厘米，体重约7.5至9克。上体呈现明亮的橄榄绿色，头部中央的冠羽略带灰色。眼上有一条狭窄的黄褐色眉纹，眼周环绕着淡黄至奶油色的眼环，眼线暗淡，从鼻孔延伸到黄色耳羽的边缘，形成模糊的耳羽新月形。翅膀呈暗橄榄色，有两条淡黄色的翼斑，飞羽边缘同样泛黄；尾部为暗橄榄色。喉咙和胸部为脏白色，带有淡黄色斑点，其余腹部为中等黄色，胸部侧面隐约可见橄榄色斑纹。虹膜深棕色，喙长而尖，棕色，下颌基部三分之二为珍珠白色；腿为浅灰色。雌雄相似，幼鸟未详述。","call":"发出一系列短促而柔和的‘tik’音节作为联系叫声，以及变化多端但同样轻柔、啾啾的歌曲，包含短促的颤音。","habits":"栖息于原生林和老次生常绿林，活动于750至1200米的高海拔地区。它几乎总是与混种群鸟一起活跃于树冠层，积极觅食，扫描树叶表面，经常翘起尾巴至水平以上，甚至快速摆动至近乎垂直位置，以捕捉或悬停捕食树叶上的昆虫。","breeding":"繁殖季节可能在9月至次年2月，具体细节尚未记录。","identification":"与同属物种相比，巴伊姬霸鹟具有独特的橄榄绿色背部，黄白色的喉部和黄色腹部，以及其特有的鸣叫声。","protection":"IUCN：EN（濒危）","distribution":"仅见于巴西东部的巴伊亚州和米纳斯吉拉斯州东北部，分布范围极为有限。","other":"全球分布面积不超过约1500平方公里，受牧草地和农业扩张导致的森林快速清理威胁。"},{"name":"黄绿姬霸鹟","english_name":"Panama Tyrannulet","scientific_name":"Phylloscartes flavovirens","overview":"黄绿姬霸鹟（英文名：Panama Tyrannulet，学名：Phylloscartes flavovirens），是雀形目霸鹟科姬霸鹟属的小型鸟类。主要分布在中美洲的巴拿马东部地区，可能延伸至哥伦比亚边境。其最显著的特征是亮黄色橄榄色的下体、醒目的黄色翼带和白色眼环。","appearance":"这种小鸟拥有橄榄绿色的上体，而下体几乎呈均匀的黄色。它体态纤细，尾巴较长，喙部狭窄。性别间外观相似，具有水平的站立姿态，翅膀上有两条明显的黄色翼带。头部的耳羽部位没有强烈的图案，这是它与同属其他物种的不同之处。","call":"鸣叫特征为高音的喷嚏声，是辨识黄绿姬霸鹟的重要线索之一。","habits":"栖息于海拔约900至2000米的山麓森林中，常见于森林树冠层，通常以单个个体或成对的形式出现，跟随混种鸟群觅食。它们的活动范围主要集中在国家的太平洋斜坡。","breeding":"关于黄绿姬霸鹟的繁殖生态信息稀缺，但推测其繁殖习性与其他同科鸟类相似，包括营巢、产卵和育雏过程。","identification":"与黄绿姬霸鹟最相似的是林伊拉鹟，但后者有较暗的冠侧、灰白色的喉部和胸部，以及不那么鲜明的翼带。此外，黄绿姬霸鹟与黄顶小霸鹟、黄绿霸鹟和黄羽缘霸鹟在体型、行为和外观上也有明显区别。","protection":"IUCN状态未知，目前没有列入CITES或中国国家重点保护野生动物名录。","distribution":"主要分布于巴拿马东部，从运河区至Darién地区，可能延伸至邻近的哥伦比亚境内，主要在太平洋斜坡的山麓森林中。","other":"尽管黄绿姬霸鹟在部分地区较为常见，但有关其行为和生态的研究资料极为有限。"},{"name":"橄榄绿姬霸鹟","english_name":"Olive-green Tyrannulet","scientific_name":"Phylloscartes virescens","overview":"橄榄绿姬霸鹟（英文名：Olive-green Tyrannulet，学名：Phylloscartes virescens），是雀形目霸鹟科姬霸鹟属的小型雨林鸟类。分布于南美洲东北部的亚马逊雨林地带，包括圭亚那地区（苏里南、法属圭亚那、东圭亚那）以及巴西东北部的亚马逊盆地，特别是在帕拉州和阿马帕州。","appearance":"橄榄绿姬霸鹟体型小巧，外观平淡不起眼，常在高大的森林树冠层活动，偏好沙质土壤环境。其特征在于较长的喙和尾羽，尤其是尾羽常略向上翘起，翅膀上有明显的条纹。雌雄个体在羽毛颜色和大小上差异不大，幼鸟的细节特征可能有所不同。","call":"其叫声容易被忽视，为一连串尖锐且抑扬顿挫的吱吱声，有时会形成不规则的系列。","habits":"通常在混群中活动，活跃地以短距离飞扑的方式捕捉树叶丛中的昆虫为食。它在森林环境中较为活跃，常见于雨林的低海拔地区。","breeding":"关于其繁殖行为的详细资料有限，但通常在繁殖季节内，会在隐蔽处筑巢，雌雄共同参与育雏过程。","identification":"与灰冠姬霸鹟和黄缘姬霸鹟相比，橄榄绿姬霸鹟具有更窄的喙和更为活跃的行为特征，尽管它们在形状和姿态上相似，且经常在同一混群中出现。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要集中在南美洲东北部，包括苏里南、法属圭亚那、东圭亚那以及巴西东北部的亚马逊盆地，特别在帕拉州和阿马帕州的雨林中。","other":"尽管在混群中较为常见，但因其隐秘的生活习性和低调的外表，观察到它的机会相对较少。"},{"name":"厄瓜多尔姬霸鹟","english_name":"Ecuadorian Tyrannulet","scientific_name":"Phylloscartes gualaquizae","overview":"厄瓜多尔姬霸鹟（英文名：Ecuadorian Tyrannulet，学名：Phylloscartes gualaquizae），是雀形目霸鹟科姬霸鹟属的鸟类。小型的姬霸鹟，特征为灰顶冠、橄榄绿上体、两道淡色翼斑及绿色偏黄的下体。分布于南美洲的云雾森林，主要见于厄瓜多尔东部安第斯山脉斜坡，延伸至秘鲁北部和哥伦比亚南部。","appearance":"成鸟的上体主要呈橄榄绿色，头顶为灰色，翅膀带有两道淡色条纹。眼上方有一条不明显的白色线纹，耳羽区灰白相间，边缘有狭窄的黑色框边。喉部白色，胸腹部则为绿色偏黄色调。喙细长，尾较长，行为活跃。幼鸟的特征目前尚未有详细描述。","call":"频繁发出干燥、噼啪作响的颤音，这是识别它的重要线索。","habits":"偏好生活在高大森林的树冠层，以昆虫为食，通常单独或成对活动，常与混合物种群一起被观察到。活动范围位于海拔约700至1400米之间。","breeding":"关于繁殖的自然史信息尚待研究。已知偏好于在树冠层筑巢，但具体的繁殖行为细节未知。","identification":"与铅色顶小霸鹟、毛腿小霸鹟和眼斑须霸鹟相比，厄瓜多尔姬霸鹟在海拔、叫声、姿势和行为上有所不同，其头部侧面图案相对简单。","protection":"IUCN：LC（无危）。尽管常见，但因栖息地受到伐木、采矿和农业开垦的压力而易被忽视。","distribution":"分布于南美洲的云雾森林，主要在厄瓜多尔东部安第斯山脉斜坡，向北至哥伦比亚南部，向南至秘鲁北部。","other":"种名来源于其模式产地Gualaquiza，厄瓜多尔东南部的一个城镇。"},{"name":"黑额姬霸鹟","english_name":"Black-fronted Tyrannulet","scientific_name":"Phylloscartes nigrifrons","overview":"黑额姬霸鹟（英文名：Black-fronted Tyrannulet，学名：Phylloscartes nigrifrons），是雀形目霸鹟科姬霸鹟属的小型鸟类，1884年被命名。其最显著的特征是带有灰黑色的冠顶、黑色的额部和眼周，黑白相间的脸部以及几乎全白的下体，缺乏黄色调。该物种主要分布在南美洲特普伊山脉的湿润山地森林，海拔高度在800至1800米之间。","appearance":"黑额姬霸鹟的成鸟头部具有独特的灰黑色冠顶，黑色额部和眼周，橄榄色背部，翼上有黄白色翼带，下体呈现淡灰色，腹部呈淡黄白色。嘴喙细长，尾巴相对较长。雄雌外观相似。","call":"在觅食时通常发出模糊的短促叫声，偶尔会发出类似机关枪的断续颤音，这种叫声在它所处的范围内非常独特。","habits":"黑额姬霸鹟栖息于湿润的山地森林，常见于800至1800米的海拔，通常成对出现，活跃地捕食昆虫，常加入混合物种群落。它被认为除了以昆虫为食外，也可能食用小果实。","breeding":"具体繁殖细节未知，但基于同类物种的观察，预计黑额姬霸鹟会在繁殖季节形成稳定的配对关系，可能在树上筑巢。","identification":"最容易与查氏姬霸鹟混淆，但黑额姬霸鹟有明显暗色的眼周和灰黑色的冠顶，胸部和腹部没有黄色色调。","protection":"IUCN状态未列出。","distribution":"黑额姬霸鹟分布于南美洲最南部委内瑞拉和邻近圭亚那的特普伊山脉，繁殖区域与非繁殖区域一致，主要集中在800至1800米的高海拔湿润森林。","other":"与同属的其他物种如褐眼先姬霸鹟和棕脸姬霸鹟构成超物种群，显示了特普伊山脉特有种的复杂起源。"},{"name":"棕额姬霸鹟","english_name":"Rufous-browed Tyrannulet","scientific_name":"Phylloscartes superciliaris","overview":"棕额姬霸鹟（英文名：Rufous-browed Tyrannulet，学名：Phylloscartes superciliaris），是雀形目霸鹟科姬霸鹟属的鸟类。分布于中美洲的哥斯达黎加到巴拿马，以及南美洲从委内瑞拉西北部、哥伦比亚东部安第斯山脉东坡，到厄瓜多尔东南部和秘鲁极北端的山地森林。该鸟体型小巧，以昆虫为主食，偶尔也食用小果实。","appearance":"棕额姬霸鹟具有淡灰色或白色腹部，橄榄绿色背部，头部特征包括灰色顶冠、带有黑色边框的白色脸颊以及眼上方的细窄锈色条纹。成鸟两性相似，头顶珍珠灰，前额和眼先明亮的栗色，延展为狭窄的眉纹，耳羽白色，边缘明显黑色，后缘为栗色。上体鲜亮的橄榄色，翅膀和尾羽暗橄榄色，边缘黄绿色。头侧略带斑驳的白色。喉咙灰白色，胸腹白色，两侧和臀部微泛黄绿，腹部和尾下覆羽隐约黄色。幼鸟特征未详述。","habits":"栖息于海拔600-2000米的湿润山地森林，常在树冠层活动，单个或成对，有时家庭群体会加入混合物种群，以昆虫为主要食物来源，偶尔摄取小果实。","breeding":"关于棕额姬霸鹟的繁殖生态知之甚少。","identification":"通过其独特的头部标记和灰白色的腹部与其它小型树冠层霸鹟相区别，大多数同属物种下体为黄色，而棕额姬霸鹟为白色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加至巴拿马，南美洲的委内瑞拉西北部、哥伦比亚东部安第斯山脉东坡，至厄瓜多尔东南部和秘鲁极北端。"},{"name":"褐眼先姬霸鹟","english_name":"Rufous-lored Tyrannulet","scientific_name":"Phylloscartes flaviventris","overview":"褐眼先姬霸鹟（英文名：Rufous-lored Tyrannulet，学名：Phylloscartes flaviventris），是雀形目霸鹟科姬霸鹟属的小型鸟类。其显著特征包括红褐色的眉纹、黑色的眼罩、橄榄绿色的背部以及黄色的下体。这种鸟看起来像是棕额姬霸鹟的色彩更加丰富的版本。性别间外观相似。褐眼先姬霸鹟分布于委内瑞拉沿海山脉，是该地区的特有种。","appearance":"褐眼先姬霸鹟体型小巧，拥有醒目的红褐色眉纹，黑色的眼罩，橄榄绿色的背部，以及鲜明的黄色腹部。雌雄两性外观相似，没有明显区别。","call":"其典型鸣声由四声高音组成，类似于“teeup teeup teeup teeup”。","habits":"褐眼先姬霸鹟通常单独或成对出现，有时会加入混合物种的鸟群，在森林树冠层活动。它们栖息于潮湿的山地森林及其边缘。","identification":"在分布范围内没有与其相似的物种，因此辨识相对容易。","protection":"IUCN：NT（近危）","distribution":"褐眼先姬霸鹟主要分布在委内瑞拉北部的沿海山脉，具体包括Yaracuy和从西Carabobo向东至Distrito Federal，以及内陆Miranda（Cerro Negro）。过去也有报道在Mérida出现，但可能为误报。"},{"name":"棕脸姬霸鹟","english_name":"Cinnamon-faced Tyrannulet","scientific_name":"Phylloscartes parkeri","overview":"棕脸姬霸鹟（英文名：Cinnamon-faced Tyrannulet，学名：Phylloscartes parkeri），是雀形目霸鹟科姬霸鹟属的鸟类。小型霸鹟科姬霸鹟属鸟类，分布于南美的秘鲁中部至玻利维亚北部的湿润山地森林中。其独特的棕肉桂色面部斑纹和橄榄绿色的外表使其在野外辨识较为明显。","appearance":"棕脸姬霸鹟体型小，上体橄榄绿色，下体橄榄黄色，具有一条狭窄的肉桂红面部斑纹，靠近眼睛和前额冠部尤为显著。头部灰色，带有淡黄色绿色翼带，耳羽呈淡肉桂色，边缘有暗色条纹。成鸟两性相似，嘴黑色，脚趾中灰色。幼鸟羽毛较成鸟更为蓬松，颜色较浅，胸部略带绿斑点。","call":"鸣叫特征为一系列快速升降的高音吱吱声，歌声活泼；叫声为高音的‘pseet！’，通常重复两次。","habits":"棕脸姬霸鹟常以水平姿态栖息于湿润山地森林的中层和树冠，活动范围较小，通常成对出现，有时加入混合物种群。它们的活动范围限定在安第斯山脉东侧较低坡度的特定海拔地带。","breeding":"关于棕脸姬霸鹟的繁殖信息较少，但一般会在雨季之后开始繁殖，具体细节尚待研究。","identification":"最易与之混淆的是委内瑞拉的褐眼先姬霸鹟，但棕脸姬霸鹟的冠部更灰，肉桂红眼圈更深，耳羽大面积为肉桂色而非黑色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从秘鲁中部到玻利维亚北部的Yungas地区。","other":"该物种最初在1899年被发现，但直到1972年才再次被观察到，于1980年代初期才被确认为独立物种。"},{"name":"米州姬霸鹟","english_name":"Minas Gerais Tyrannulet","scientific_name":"Phylloscartes roquettei","overview":"米州姬霸鹟（英文名：Minas Gerais Tyrannulet，学名：Phylloscartes roquettei），是雀形目霸鹟科姬霸鹟属的小型鸟类，主要分布于南美巴西东部，包括巴伊亚州南部至米纳斯吉拉斯州中部。其显著特征为橄榄绿上体，黄色下体，两道黄色翼斑，以及锈色眉纹和超眼纹。偏好热带干燥森林、画廊森林和高大的落叶灌木丛。","appearance":"体长约12厘米，体重约8克。上体橄榄绿色，头部颜色与背部一致；具显著的赤褐色至橙褐色前额和超眼纹，薄而断续的淡色眼环，黑色侧冠纹，黄绿色耳羽边缘黑色；翅膀暗淡，两道黄色翼斑，飞羽边缘和尖端亮黄色；尾巴橄榄绿色；全身下体中等黄色；虹膜可能为棕色；嘴长而尖，黑色，下颚基部灰白色；腿灰色至棕色。雌雄相似，幼鸟与成鸟类似。","call":"鸣唱为一系列快速的高音谐音，起始音略大且更高；叫声是个别音符，类似于鸣唱中的音符。","habits":"栖息于热带干燥森林、画廊森林和高大的落叶灌木丛，尤其靠近河流的地带。通常成对或家庭群活动，很少加入混种群。主要在较高树冠层觅食，偶尔在离地面2-3米内的密集树叶中觅食。活跃且不安定，身体水平或呈45度角，尾巴稍高于水平并轻微上下摆动，翅膀有时张开或下垂；偶尔举起一只翅膀高于背部，随后可能抬起另一只翅膀（但从不同时）。通过短暂飞行捕捉树枝和树叶上的昆虫，偶尔从空中捕获。移动距离一般不超过1米，常涉及快速斜向下降然后返回低枝。","breeding":"繁殖期在10月和11月，已知有带羽毛的幼鸟出现在12月和2月。巢呈近似球形，高度约10厘米，宽6-7厘米（建造中），入口管短，由细根、枯枝、地衣、草质材料和少量枯叶构成，位于距地面约10米的小树枝尖端，在溪流旁的树上，且离白蚁丘不到1米处。两只成鸟积极收集材料，通常从地面或附近获取。","identification":"通过橄榄绿的上体、黄色的下体、两道黄色翼斑和锈色的面部特征进行辨识。与其他姬霸鹟属物种相比，其体型较小，且更倾向于在较高树冠层活动。","protection":"IUCN：EN（濒危）","distribution":"分布于巴西东部，从巴伊亚州南部至米纳斯吉拉斯州中部，以及戈亚斯州东部和巴伊亚州南部相邻地区。","other":"该物种曾一度被认为极度濒危，直到近年在新地点被重新发现，显示其潜在分布可能比先前认为的更广泛。"},{"name":"欧氏姬霸鹟","english_name":"Oustalet's Tyrannulet","scientific_name":"Phylloscartes oustaleti","overview":"欧氏姬霸鹟（英文名：Oustalet's Tyrannulet，学名：Phylloscartes oustaleti），是雀形目霸鹟科姬霸鹟属的小型鸟类。拥有橄榄绿色的体羽，黄色的喉部、腹部、眉纹、眼圈和颊斑，以及显著的黑色眼后斑。分布于巴西东部和东南部的亚热带或热带湿润低地森林，主要栖息于海拔500至900米的林冠层。","appearance":"成鸟体长约12厘米，体重9.4至10.5克。上体橄榄色，头顶与背部颜色一致；眼周黄色，与宽大的黄色眼圈相连；脸部近眼处鲜黄，耳羽黑褐色，边缘镶以亮黄；翅暗橄榄色，翼羽尖端微黄，飞羽边缘浅橄榄黄；尾部橄榄色；下体明亮黄色，胸处混杂橄榄色。虹膜棕色，喙长而尖，黑色；腿灰色。雌雄相似，幼鸟未详述。","call":"发出柔和的双音或三音节叫声，通常为\"ku-dut\"或\"ku-dut-dut\"。","habits":"常在成对或家庭群中活动，几乎总是与混合物种群一同，主要在森林树冠层和亚树冠层中水平姿态觅食，翅膀略垂，尾巴翘起，常颤动。以节肢动物为主食，包括昆虫、蜘蛛等。","breeding":"繁殖季节可能主要是9月至12月。已知巢穴位于地面以上2.3米的次生林边缘，巢由纤细的草色植物纤维与活苔藓交织而成，内衬柔软棉质材料，带有长挂饰结构。至少一成鸟照料巢中的未知数量雏鸟。","identification":"通过橄榄绿色上体、黄色下体、黑色眼后斑以及特有的叫声与其他姬霸鹟属成员区分开来。","protection":"IUCN：LC（无危）。在几个保护区如Augusto Ruschi Biological Reserve、Intervales State Park和Mata dos Godoy State Park中存在。由于农业开发、采矿、城市化和工业化威胁，其栖息地持续受到破坏。","distribution":"分布于南美巴西东部和东南部的亚热带或热带湿润低地森林。","other":"森林栖息地正因农业转化、采矿、城市化、工业化及道路建设而持续受威胁。"},{"name":"栗环姬霸鹟","english_name":"Bay-ringed Tyrannulet","scientific_name":"Phylloscartes sylviolus","overview":"栗环姬霸鹟（英文名：Bay-ringed Tyrannulet，学名：Phylloscartes sylviolus），是雀形目霸鹟科姬霸鹟属的鸟类。分布于南美洲的南部大西洋森林地带，包括巴拉圭东部、阿根廷东北部和巴西东南部。其显著特征为头部周围独特的肉桂色斑块，与绿色头部、淡色眼圈和黄色喉部形成鲜明对比。","appearance":"这种小鸟拥有细长的尾巴，通常保持翘起。上体呈现鲜艳的橄榄绿色，下体为浅色。眼周的肉桂色斑块是其最显著的特征，与绿色头部、淡色眼圈和黄色喉咙形成对比。雌雄鸟的羽毛颜色相似，幼鸟的特征可能略有不同。","call":"鸣叫声为快速下降的‘djeee-djeee’声。","habits":"栗环姬霸鹟栖息于湿润森林的树冠层，常见于混合物种群中。其活动范围、迁徙习性和食物偏好尚需更多研究。","breeding":"繁殖季节在阿根廷为8月至10月，巢穴悬挂于水平枝条下方，主要由苔藓构成，离地面高度约10至16米。卵为纯白色，具体数量未知。","identification":"通过眼周的肉桂色斑块、绿色头部和黄色喉咙可与其他种类区分开来。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的南部大西洋森林，包括巴西东南部、巴拉圭东部和阿根廷东北部，如伊瓜苏国家公园、马塔多斯戈多伊州立公园和伊瓜苏瀑布附近的森林。"},{"name":"纹颈霸鹟","english_name":"Streak-necked Flycatcher","scientific_name":"Mionectes striaticollis","overview":"纹颈霸鹟（英文名：Streak-necked Flycatcher，学名：Mionectes striaticollis），是雀形目霸鹟科绿纹霸鹟属的鸟类。小型霸鹟，在南美洲安第斯山脉的山麓和亚热带地区，从哥伦比亚至玻利维亚北部广泛分布。其上身呈橄榄色，腹部偏黄色，头部呈现独特的板条状灰色。喉部和胸部的条纹明显，与多数小型霸鹟有显著区别。下喙基部为苍白色，与橄榄绿纹霸鹟已删除相似，但通常栖息在较高海拔地区，头部颜色更偏向灰色。","appearance":"纹颈霸鹟长约13.5厘米，体重13-17克。上身暗橄榄色，头顶和颈背为板条状灰色；脸部和耳羽区深灰色，羽毛轴白色；眼后有微小白色斑点；翅膀橄榄色，有时可见淡橄榄色的模糊翼带；尾巴橄榄色；喉部和上胸板条状灰色，羽毛轴窄至宽白，形成细条纹；下胸和侧腹深橄榄色和黄色交错条纹，腹部中央黄色，大腿部橄榄色；虹膜深棕色；嘴长，暗褐色，下喙基部淡粉色；腿深灰色。两性外观相似，幼鸟与成鸟类似。不同亚种在颜色和条纹上有细微差异。","call":"非常安静，仅在繁殖季节据说发出细弱的金属音。同时，还可能产生轻微的翼颤声，推测由雄鸟的极度纤细的第九初级飞羽造成。","habits":"栖息于湿润的上层热带和下层温带山区森林，偶尔出现在次生林边界和相邻的开阔地带，尤其偏好孤立的挂果树木。活动高度通常在1300-2500米之间，局部地区可下降至600-900米，偶尔进入更高海拔的温带区域，最高记录到3400米。主要以节肢动物和浆果为食，通常独居，但在非繁殖季节会在树冠上大量采集浆果。偶尔加入混合鸟群或在果树上与其他鸟类聚集，但并非混群的固定成员。","breeding":"雄鸟在繁殖季条件成熟，时间在哥伦比亚为1月-4月，在秘鲁东南部为9月-12月；幼鸟和雏鸟在哥伦比亚5月和6月出现，厄瓜多尔东北部1月和2月，秘鲁4月和5月，玻利维亚3月、8月和12月。部分群聚繁殖，雄鸟在繁殖季进行展示，领地通常2-6个，直径10-30米，彼此相距不远。巢悬垂，梨形，侧面入口常有遮蔽，覆盖苔藓，内部衬有种子绒毛、干苔藓和浅色纤维。巢位于离地面0.8-3米的细藤、根或下垂枝条上，常处于植被纠缠中或较为暴露的位置，靠近小溪或河流。","identification":"与其他小型霸鹟相比，纹颈霸鹟的喉部和胸部有明显的条纹，下喙基部苍白色。与橄榄绿纹霸鹟已删除相似，但海拔分布更高，头部颜色更灰。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲，包括哥伦比亚、厄瓜多尔、秘鲁和玻利维亚北部。主要栖息于亚热带或热带湿润的山区森林，以及严重退化的人工林。"},{"name":"橄榄绿纹霸鹟","english_name":"Olive-streaked Flycatcher","scientific_name":"Mionectes olivaceus","overview":"橄榄绿纹霸鹟（英文名：Olive-striped Flycatcher，学名：Mionectes olivaceus），是雀形目霸鹟科绿纹霸鹟属的鸟类。小型果食性霸鹟，分布于中美洲至南美洲西北部潮湿山地森林。其黄色腹部、眼后白斑及颈侧纵纹为典型辨识特征。","appearance":"体长约13厘米。成鸟整体橄榄绿，头顶至背暗黄橄榄，翼尾深褐；眼后有醒目白斑，喉至上胸黄白并密被暗橄榄纵纹，下胸及两胁黄与橄榄纵纹相间，腹部中央鲜黄。雌雄同色，雄鸟第九枚初级飞羽末端略狭。幼鸟纵纹较淡，腹色暗并带赭黄，白斑不显。","call":"鸣声极高频（8–10 kHz），为持续数秒的颤哨或“W”形音符串，似虫鸣或蜂鸟歌；另有单声“tsew”叫。鸣唱主要在繁殖季黎明前后，自1–3 m高处浓密灌丛发出，极难目击。","habits":"栖息于潮湿山地及丘陵森林的中下层、次生林及林缘，海拔300–2150 米，局部可达3000 米。非繁殖季可垂直迁移至低地。主要悬停啄取浆果及小昆虫，偶尔倒挂枝条或随混合鸟群及行军蚁觅食。","breeding":"繁殖期2–7月因地而异。巢梨形侧口，悬于藤蔓或气根，距地0.4–2 米，外覆绿苔，内衬软纤维。每窝2–3枚纯白卵，双亲共同参与育雏。","identification":"与海拔更高的纹颈霸鹟相似，但纹颈头顶及头侧灰色明显，喉胸纵纹更细，腹黄色更纯且纵纹少。与赭腹霸鹟等下体黄褐种相比，本种下体偏黄绿且纵纹明显。","protection":"IUCN: LC（无危）","distribution":"繁殖与留居范围从哥斯达黎加东部、巴拿马经哥伦比亚西部至厄瓜多尔西南部；安第斯东坡自委内瑞拉、特立尼达向南至秘鲁及玻利维亚西北部。","other":"过去曾将不同鸣声型视为亚种，近年因鸣声及形态差异，橄榄绿纹霸鹟已删除被并入本种，未来仍可能发现隐存种级分化。"},{"name":"赭腹霸鹟","english_name":"Ochre-bellied Flycatcher","scientific_name":"Mionectes oleagineus","overview":"赭腹霸鹟（英文名：Ochre-bellied Flycatcher，学名：Mionectes oleagineus），是雀形目霸鹟科绿纹霸鹟属的鸟类。常见的小型霸鹟科鸟类，广泛分布于中美洲和南美洲东侧，从墨西哥南部至亚马逊雨林，乃至巴西东部。其以独特的赭色腹部而得名，常在湿润森林的低层植被中活动。","appearance":"赭腹霸鹟体长约12.7厘米，体重约11克。上体呈现橄榄绿色，头部及上胸同样为绿色，其余下体呈赭色。翼部具有两道淡色条纹，闭合时的翼羽边缘缀有淡色。雄鸟体型略大于雌鸟，但外观相似。","call":"雄性赭腹霸鹟的叫声包括高音的chip声和响亮的choo声。","habits":"这种鸟偏好在湿润森林环境中栖息，尤其是靠近水源的低层植被。它主要以种子和浆果为食，偶尔也会捕食昆虫和蜘蛛。","breeding":"繁殖季节，雌鸟会在树根或枝条上悬挂一个苔藓覆盖的球形巢，通常位于水面上方。一窝通常产2到3枚白色蛋，孵化期约为18至20天。幼鸟孵化出来时被灰色绒毛覆盖，再经过大约相同的时间就能离巢。","identification":"赭腹霸鹟与同属的纹颈霸鹟和橄榄绿纹霸鹟已删除在外形上相似，但后两者胸部有条纹，下体颜色为黄绿色而非赭色。此外，它还与麦氏霸鹟和灰冠霸鹟相像，但可通过翼部特征和头颈部颜色加以区分。","protection":"IUCN：LC（无危）","distribution":"赭腹霸鹟的分布范围包括中美洲的墨西哥南部，向南延伸至南美洲的亚马逊雨林地区，包括巴西东部，以及特立尼达和多巴哥岛。","other":"已描述多达12个亚种，主要在下体颜色和翼部图案上有差异，现代分类学仅承认其中7个亚种。"},{"name":"麦氏霸鹟","english_name":"McConnell's Flycatcher","scientific_name":"Mionectes macconnelli","overview":"麦氏霸鹟（英文名：McConnell's Flycatcher，学名：Mionectes macconnelli），是雀形目霸鹟科绿纹霸鹟属的鸟类。主要特征为橄榄色的上部和鲜明的红褐色腹部，常见于亚马逊雨林的东部和西南部地区的森林底层，以果实和昆虫为食，偶尔与食果鸟群共同活动。与赭腹霸鹟相似，但通常更暗，翼缘缺乏淡色，且在次生林和受干扰环境中较少见。","appearance":"麦氏霸鹟体长13至13.5厘米，体重8至18克。头部和背部为均匀的橄榄色，翅膀和尾巴呈暗淡的橄榄色，腹部为丰富的肉桂色，喉咙和上胸部分带深灰色橄榄色。眼睛棕色或深棕色，喙长而呈深褐色至黑色，有时下颌基部略显粉红色，脚腿为中等的灰褐色。幼鸟外观与成鸟相似。Peruanus亚种上部颜色更亮，泛橙色，翼盖边缘呈肉桂色，下部更浅更亮的肉桂橙色，下巴和喉部轻轻染有橄榄色。","call":"展示中的雄鸟会发出间隔较宽或重复的鼻音、类似鸫鸟的‘wiib’或‘trrr’音符，有时会连续发出长串，偶尔变调为快速的类似Nutcracker的‘rin-tin-tin-tin-tin-tin-tin-tintin’声，或者嘶哑粗糙的‘ruk’a-ruk’a-ruk’...’音符，由不定数量的不规则序列音符组成，间隔几秒至一分钟以上。还常发出单个的嗡嗡声‘qerrr’，随后是一连串持续约一秒的鼻音，音高略微上升然后平稳。","habits":"生活在湿润森林的低层植被中，主要在稳固的土地上，但也出现在森林种植园、次生林和河洪水或潮水淹没的森林中。通常在海拔500米以下，但在秘鲁中部可达1200米，玻利维亚可达2400米。以节肢动物和下层植被的果实（如茜草科和千屈菜科）为食，定期加入小昆虫食性的混合鸟群，但并非强制性参与者。觅食高度从地面1至25米，栖息于隐蔽的阴凉处，进行短暂的悬停觅食。","breeding":"繁殖季节在巴西北部为1月至3月，鸟巢建于1至1.5米高的藤蔓或细枝末端，靠近池塘或小溪，巢为带有侧面入口的叶片或纤维球状结构，倾斜的短入口隧道通向柔软材料制成的中央巢杯。一窝通常产三枚白色蛋，大小约为13至13.5毫米×19毫米，重量1.6至1.8克，孵化期约19天。雏鸟生长缓慢，从出生时的1.5克到12至13克需要十天，离巢发生在最后一只幼鸟孵化后的17至20天。成鸟不会主动保护巢穴，导致因恶劣天气（如大雨）而大量减少子代。","identification":"与极相似的部分共域物种M. oleaginous相比，麦氏霸鹟缺少翼尖的淡色，且在次生林和受干扰环境中较为少见。在野外，可以通过缺乏淡黄色的翼尖和无翼斑来区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊雨林的东部和西南部，包括委内瑞拉南部和东南部、圭亚那、巴西北部以及秘鲁东部和玻利维亚的部分地区。","other":"近年来，在巴西北部的Serra do Tapirapecó和Serra do Xamata（亚马逊州）也有记录，这两个地区都位于与委内瑞拉的边境附近。"},{"name":"暗胸麦氏霸鹟","english_name":"Sierra de Lema Flycatcher","scientific_name":"Mionectes roraimae","appearance":"体型较小，长度约为12.7至13.5厘米，体重约13克。上体橄榄绿色，下体较暗的肉桂色，翅膀和尾巴较短。雌雄相似，幼鸟与成鸟外观相仿。喙、眼和腿为深灰色至黑色。","call":"拥有两种主要的鸣叫声：一种是杂乱的喋喋不休声，由一系列不连贯的调音组成；另一种是金属质感的颤音，先降后升，伴有清晰的暂停。此外，还发出尖锐的‘chip’声。","habits":"生活在湿润森林内部，偏好有开阔林下空间的地带，常见于沙质土壤或岩石区域。通常加入混合物种群，活跃于清晨，觅食方式未知，推测以水果为主食。","breeding":"繁殖季节、求偶、筑巢等信息几乎未知。在委内瑞拉南部，于二月至三月期间处于繁殖状态，具体繁殖细节需进一步研究。","identification":"与McConnell’s霸鹟相比，声音不同，栖息地海拔更高。与Ochre-bellied霸鹟的区别在于缺乏翼带且声音不同。可通过声音和栖息环境识别。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉南部、圭亚那西部以及巴西北部的特普伊山脉地区。在委内瑞拉的Cerro de la Neblina和Serranía de Tapirapecó有记录，最近在巴西北部的Serra do Tapirapecó和Serra do Xamata也有发现。","other":"最近的研究将其从McConnell’s霸鹟中分离出来，主要基于声音和行为差异。"},{"name":"灰冠霸鹟","english_name":"Grey-hooded Flycatcher","scientific_name":"Mionectes rufiventris","overview":"灰冠霸鹟（英文名：Grey-hooded Flycatcher，学名：Mionectes rufiventris），是雀形目霸鹟科绿纹霸鹟属的小型鸟类。主要分布于南美洲的巴拉圭东部、阿根廷东北部以及巴西东南部的森林地带。","appearance":"灰冠霸鹟体型较小，上体呈橄榄色，下体为肉桂色，头部覆以灰色羽冠。其喙部双色，基部颜色较浅。","call":"雄性灰冠霸鹟在群体展示时会发出低沉鼻音的“bayo”歌声。","habits":"栖息于湿润森林的林下层、次生林及森林边缘。具体的食物习性和迁徙模式需进一步研究。","breeding":"关于繁殖行为的详细资料尚待收集，包括繁殖期、求偶、营巢等信息。","identification":"与同属其他物种相比，灰冠霸鹟的灰头和双色喙是其显著的识别特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的巴拉圭东部、阿根廷东北部（米西奥内斯省）以及巴西东南部，包括米纳斯吉拉斯州、埃斯皮里图圣多州至南马托格罗索州东南部和北里奥格兰德州。","other":"灰冠霸鹟的生态习性和保护状况需要更多的科学研究和关注。"},{"name":"棕顶窄嘴霸鹟","english_name":"Sepia-capped Flycatcher","scientific_name":"Leptopogon amaurocephalus","overview":"棕顶窄嘴霸鹟（英文名：Sepia-capped Flycatcher，学名：Leptopogon amaurocephalus），是雀形目霸鹟科窄嘴霸鹟属的鸟类。广泛分布于中美至南美的森林及边缘地带，自墨西哥至阿根廷北部。具有大头和长尾的霸鹟，以其独特的站立姿态和暗褐色的顶冠而著称。","appearance":"成年棕顶窄嘴霸鹟的头顶呈暗褐色，背部为橄榄绿色，翼羽边缘有淡黄色的条纹，形成两道明显的翼斑，尾羽边缘为浅棕色。脸部为灰色，带有白色的细纹，耳部后缘有黑色的轮廓。腹部为黄色至黄白色，胸部和两胁更偏橄榄色。雌雄相似，但雄鸟略大。","call":"发出断断续续的蛙鸣般的颤音，较为罕见。","habits":"栖息于湿润的热带森林内部中层及邻近的开阔地带，有时会在建筑物檐下悬挂巢穴，包括废墟。以昆虫为食，通过悬停捕食，常与混合群鸟一起活动。飞行时有独特的翅膀抬升动作。","breeding":"巢为草、苔藓和根制成的球状结构，侧面有入口，通常悬挂在河岸的树根下。繁殖信息未详。","identification":"在分布范围内独特，与其他低地暴君鹟的面部标记明显不同。与灰顶窄嘴霸鹟在高海拔地区有少量重叠，后者具有灰暗的顶冠和较淡的面部侧边。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，包括阿根廷、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、洪都拉斯、墨西哥、尼加拉瓜、巴拿马、秘鲁、苏里南、委内瑞拉等地的森林和边缘环境。"},{"name":"灰顶窄嘴霸鹟","english_name":"Slaty-capped Flycatcher","scientific_name":"Leptopogon superciliaris","overview":"灰顶窄嘴霸鹟（英文名：Slaty-capped Flycatcher，学名：Leptopogon superciliaris），是雀形目霸鹟科窄嘴霸鹟属的鸟类。分布于中美洲至南美洲，自哥斯达黎加至委内瑞拉北部和玻利维亚北部。其最显著的特征为暗灰色的冠羽，橄榄绿色背部，以及黄色翼条纹。体长约12.5厘米，体重约12克。","appearance":"成年灰顶窄嘴霸鹟具有暗灰色的头顶，脸部为灰色和白色相间，耳斑黑色呈新月形，上体橄榄绿，翅膀较暗，有两条黄褐色翼带。喉咙白色，胸部绿色泛黄至腹部黄色。喙长而粗壮，上部黑色，下部基部粉色。两性相似，但幼鸟的冠羽更偏橄榄色，脸纹较弱，翼带橙色，下体颜色较淡。","call":"具有尖锐的switch-choo叫声。","habits":"栖息于森林和林缘地带，活动于树冠下层至中间层。常单独或成对出现，停歇于开阔处，或在空中捕捉昆虫，亦会从树叶上取食。它们还经常食用浆果。","breeding":"巢呈球状，内衬细植物纤维，侧面入口，由根须悬挂，建于阴暗处，如岩石裂缝或河岸顶部的悬垂植被下。每窝通常产两枚白色卵。","identification":"与棕顶窄嘴霸鹟的区别在于后者具有棕色而非灰色的冠羽。与南美bristle-tyrants相似，但注意翼带为黄褐色，叫声独特。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，自哥斯达黎加至委内瑞拉北部和玻利维亚北部。","other":"在多个国家公园和保护区中有所记录，例如秘鲁的马丘比丘历史保护区和马努国家公园，玻利维亚的马迪迪国家公园和皮隆拉哈斯生物圈保护区。"},{"name":"棕胸窄嘴霸鹟","english_name":"Rufous-breasted Flycatcher","scientific_name":"Leptopogon rufipectus","overview":"棕胸窄嘴霸鹟（英文名：Rufous-breasted Flycatcher，学名：Leptopogon rufipectus），是雀形目霸鹟科窄嘴霸鹟属的鸟类。位于南美洲西北部山区的美丽小型飞禽，分布于委内瑞拉西部至秘鲁北部的安第斯山脉地带。具有橄榄褐色的上体，鲜明的锈色翼纹，脸部和胸部的红褐色，以及黄色腹部，通常在云雾森林较低层次中活动。","appearance":"成年棕胸窄嘴霸鹟的头部冠羽呈灰色，其余上体为橄榄绿色。翅膀有两道模糊的橙色翼纹，初级飞羽边缘橙色，次级飞羽边缘橄榄黄色。眼圈、耳羽和头部侧面为红褐色，耳羽有暗色后缘。喉部和胸部红褐色，腹部呈淡橄榄黄色。喙黑色或深棕色，脚灰或蓝灰色。","call":"其叫声尖锐而刺耳，通常在混群觅食时发出。","habits":"栖息于海拔1500-2400米的湿润山地森林，偏好在较低层次活动，常被其特有的尖锐叫声所吸引，与混合物种群一起觅食。","identification":"与华丽斑翅霸鹟有广泛的地理重叠，但后者体型更小，胸部颜色偏淡黄而非红褐色，喙较短，下颌有淡色，翼纹更为明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的委内瑞拉西南部和哥伦比亚东南部至秘鲁北部。"},{"name":"印加窄嘴霸鹟","english_name":"Inca Flycatcher","scientific_name":"Leptopogon taczanowskii","overview":"印加窄嘴霸鹟（英文名：Inca Flycatcher，学名：Leptopogon taczanowskii），是雀形目霸鹟科窄嘴霸鹟属的鸟类。仅见于秘鲁安第斯山脉东坡，海拔介于1700至2800米之间，栖息于山地森林较低层，以独特的橄榄褐色羽衣和黄色腹部著称。","appearance":"体型较小，体长约为12厘米，上身呈橄榄褐色，翼部有明显的锈色条纹，面部灰白相间，喉咙灰色，胸脯带有一种淡橄榄色，腹部则呈现黄色。头部具有狭窄的白色眼环，喙黑色，脚趾深灰色。成年个体与幼鸟相似，但幼鸟的翼羽边缘更宽且偏红。","habits":"通常单独活动，偶尔成对出现，有时会加入混合物种的鸟群。它有一个独特的习性，即快速地将一只翅膀抬高至背部。栖息于山地森林，飞行敏捷，以昆虫为食。","identification":"与同属的灰顶窄嘴霸鹟相比，印加窄嘴霸鹟的胸部带有暖色调，缺乏突出的耳斑，翼条更偏红，头部橄榄灰色而非石板灰色，易于区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在秘鲁的山地森林中，繁殖区域位于秘鲁东部的安第斯山脉，海拔高度在1700至2800米之间。"},{"name":"北灌丛霸鹟","english_name":"Northern Scrub Flycatcher","scientific_name":"Sublegatus arenarum","appearance":"北灌丛霸鹟体型小，长度约13-15厘米，体重10.5-15克。成鸟头部呈灰褐色，头顶和背部颜色一致，翼部较暗，翼条淡灰色至白色，尾羽深色，新羽尖端带白色。喉部白色，胸部浅灰色，腹部为中等黄色。虹膜深棕色，喙短而钝，黑色，腿灰色。雄雌相似，雌鸟平均比雄鸟小。幼鸟与成鸟外观相似。不同亚种间存在细微差异。","call":"其特有的鸣叫声为清晨响亮重复的'pfweéé'，以及稍后出现的间隔较大的'phew!-dit'声，接触叫声为类似挤压橡胶玩具发出的'peee'声，常与配偶成对发出。","habits":"北灌丛霸鹟栖息于红树林及其周边植被，包括次生灌木林。常见于低海拔至600米的开放干燥灌木丛、仙人掌和荆棘林地。它们全年留居于繁殖地，以昆虫为主要食物，包括蚂蚁、毛虫和小甲虫，也会食用小浆果。捕食时，它们会在灌木和小树上不显眼地站立，尾巴垂直向下，通过悬停啄食和短暂的空中追逐来获取食物。","breeding":"繁殖季节为3月至6月，雏鸟尾部短小，发现于8月的哥伦比亚。巢为简单的杯状，置于小树分叉处2-6米高，每窝产2枚卵，孵化期至少14天，雌鸟在巢中由雄鸟喂养，关于雏鸟期的信息未知。","identification":"与其他同类的区别在于较长的喙，胸部灰色与腹部明亮黄色的鲜明对比。不同亚种在颜色深浅和大小上有微小差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，从哥斯达黎加至圭亚那，包括巴西、哥伦比亚、法属圭亚那、苏里南、特立尼达和多巴哥、委内瑞拉等地。"},{"name":"亚马孙灌丛霸鹟","english_name":"Amazonian Scrub Flycatcher","scientific_name":"Sublegatus obscurior","appearance":"头部呈暗灰褐色，仅隐约可见一条比周围颜色稍浅的眼上纹。胸部为较淡的灰色，逐渐过渡到腹部的淡黄色。翅膀上有翼带，但并不显眼。体型比无须霸鹟略大且更为修长，外观与小型Myiarchus属霸鹟相似。与南方灌丛霸鹟极为相似，但在南半球冬季二者可能重叠分布，但亚马逊灌丛霸鹟整体色调更深。","call":"可通过其重复的两部分哨声来识别，发出响亮的含有2-3个音节的声音，具体为\"ch-we-deé ch-we-deé chu-weeé\"。","habits":"栖息于南美的亚热带或热带干燥森林以及亚热带或热带湿润低地森林。觅食时，它会从矮树和灌木中窥视，以垂直姿势站立，尾巴向下。采用捕食方法或从栖息处短暂出击捕捉猎物。","breeding":"在厄瓜多尔的亚马逊灌丛霸鹟，7月时会表现出更强烈的鸣唱和增大的睾丸，随后会在7月后期开始筑巢，巢位距地面约八米。而在圭亚那的同类，繁殖活动始于5月，同样在当月晚些时候开始筑巢。","identification":"与南方灌丛霸鹟相比，亚马逊灌丛霸鹟的整体色彩更为深沉，是区分二者的要点之一。","protection":"IUCN：LC（无危）","distribution":"分布于南美亚马逊雨林区域，范围从哥伦比亚东部、委内瑞拉南部和圭亚那地区向南至厄瓜多尔东部、秘鲁东部、玻利维亚北部和巴西东北部，最南可达马托格罗索北部，东至帕拉州Paragominas地区。"},{"name":"南灌丛霸鹟","english_name":"Southern Scrub Flycatcher","scientific_name":"Sublegatus modestus","overview":"南灌丛霸鹟（英文名：Southern Scrub Flycatcher，学名：Sublegatus modestus），是雀形目霸鹟科灌丛霸鹟属的小型鸟类。其分布于南美洲中南部、东部和东南部，常见于阿根廷、玻利维亚、巴西、巴拉圭、秘鲁和乌拉圭等地的干灌木丛和开阔林地。","appearance":"南灌丛霸鹟体型较小，羽毛颜色较为暗淡，全身呈中棕色，腹部显现出淡黄色，翅膀上有两道明显的白色翼带。与亚马逊灌丛霸鹟相比，南灌丛霸鹟腹部的黄色更加鲜亮，翼带白皙而醒目。","habits":"南灌丛霸鹟栖息于干燥的灌木丛和开放的森林地带，迁徙时会进入亚马逊地区的次生林和次生植被区。它们在南美洲南部繁殖，部分种群会向北迁徙至亚马逊河流域，表现出高度隐蔽的行为和羽色，使得它们在迁徙期间往往被忽视。","identification":"与亚马逊灌丛霸鹟的区别在于，南灌丛霸鹟具有更鲜亮的黄色腹部和更鲜明的白色翼带。","protection":"IUCN：LC（无危）。南灌丛霸鹟在全球范围内并不受到威胁，但在一些地区数量较少。在秘鲁的马努国家公园和生物圈保护区、坦博帕塔-坎达莫保留区，玻利维亚的诺埃尔·肯普夫·梅尔卡多国家公园以及巴西的塞拉达卡纳斯特拉国家公园等保护区内可见其踪迹。随着原始森林退化，第二生长林和开阔的干燥林地可能成为其受益环境。","distribution":"南灌丛霸鹟的分布范围覆盖南美洲中南部、东部和东南部，包括阿根廷、玻利维亚、巴西、巴拉圭、秘鲁和乌拉圭。在繁殖季节，它们主要分布在较干燥的区域，而在非繁殖季节，它们会迁徙到亚马逊河流域的次生植被区。"},{"name":"细嘴姬霸鹟","english_name":"Slender-billed Inezia","scientific_name":"Inezia tenuirostris","overview":"细嘴姬霸鹟（英文名：Slender-billed Inezia，学名：Inezia tenuirostris），是雀形目霸鹟科纯色姬霸鹟属的小型活跃鸟类。分布于南美洲的东北部哥伦比亚和西北部委内瑞拉，常见于干燥地带的灌木丛和小树林或红树林边缘。","appearance":"体长约9厘米，体重约5至6克。全身呈现绿褐色，下体偏黄色，具有一根细长如针的喙。眼圈狭窄，眉纹细白，头部和背部灰橄榄色，翅膀暗淡，有两道细白翼带和内飞羽外缘的淡白色。尾巴暗橄榄色，羽端略显淡色；脸部和喉咙白色，胸腹部呈污灰色，腹侧及臀下覆羽泛淡黄色。虹膜深棕色，喙短而细，黑色；腿灰色。雌雄相似，幼鸟未详述。","call":"发出长而干燥的颤音，尾音渐弱渐消；也会发出类似‘teer-téér-teer-terr-teer’的哨声。","habits":"常单独或成对觅食，领域性强，偏好干燥环境中的灌木丛和小树或红树林边缘。","identification":"与南无须小霸鹟相似，但后者具有更明显的冠羽，翼带对比度较低，喙较粗且弯曲。","protection":"IUCN：LC（无危）","distribution":"繁殖区与非繁殖区一致，主要分布于南美洲的东北部哥伦比亚和西北部委内瑞拉。"},{"name":"纯色姬霸鹟","english_name":"Plain Inezia","scientific_name":"Inezia inornata","overview":"纯色姬霸鹟（英文名：Plain Inezia，学名：Inezia inornata），是雀形目霸鹟科纯色姬霸鹟属的鸟类。分布于南美洲的阿根廷、玻利维亚、巴西、巴拉圭和秘鲁。其自然生境为亚热带或热带的干燥森林和湿润低地森林。","appearance":"体型小，整体呈灰褐色，具有微弱的眼眉纹。上体颜色从灰色至橄榄灰，翼部暗淡，有两道细白翼带，内侧飞羽边缘呈暗淡的白色；尾部暗色；面部、颏部和喉部白色，下体灰色，腹部下方略带淡黄色调；虹膜深棕色；嘴细长，黑色，下颌基部有时呈浅色；腿灰色。雌雄外观相似。幼鸟特征未详述。","call":"发出一系列带有强调引子音的较为悦耳的哨声，‘psee-tee-ee-ee-ee’。","habits":"通常单独或成对活动，偶尔加入混种群。在茂密的树叶中活跃觅食，常轻微翘起尾巴；主要在枝头捕捉昆虫，也会在树叶和树枝间悬停觅食。","identification":"与类似的小鼠色霸鹟相比，纯色姬霸鹟面部图案不那么明显（小鼠色霸鹟有强烈的眼眉纹），并且嘴更长更细，觅食更为活跃，频繁变换栖息点，快速在树枝间跳跃。","distribution":"主要分布于南美洲亚马孙雨林的西部和西南部，繁殖季节在南部南美洲，冬季迁徙至亚马孙地区。"},{"name":"亚马孙姬霸鹟","english_name":"Amazonian Inezia","scientific_name":"Inezia subflava","appearance":"体长约12厘米，体重约7至8克。成鸟具有宽大的白色眼环，延伸到鼻孔上方形成独特的“眼镜”状特征；头部和背部呈橄榄棕色，翅膀暗淡，翼上有两道细薄的白条纹，内侧初级飞羽边缘为淡白色至淡黄白色；尾巴较长，暗橄榄色，边缘和尖端明显呈白色至淡赭色；脸部和下巴为白色，喉咙和腹部为黄色，胸部侧面带有橄榄色或斑驳的橄榄色；眼睛为棕色，喙长而细，黑色；腿为灰色。雌雄相似，但雌鸟略小于雄鸟。幼鸟特征未详述。obscura亚种胸部中心有较强的橄榄色洗染，喙稍大。","call":"其鸣唱为一系列快速的高音“pit-chew”音符，间歇性地发出，常以二重唱形式呈现。","habits":"栖息于河流两岸的灌木植被、密集的沼泽森林和várzea，通常靠近水源，海拔从海平面到200米。它是留鸟，以昆虫为食，通常单独或成对活动，偶尔加入混群。觅食时活跃，一般在离地面1至3米的高度，在密集的灌木丛中寻找食物，尾巴几乎总是稍微翘起；它既能从树枝和叶子上觅食，也能悬停捕食。","breeding":"在巴西，巢是一个简单的杯状结构，目前关于繁殖行为的其他信息尚缺。","identification":"其最明显的识别特征是宽大的白色眼环和极其‘斑点’的双翼条纹，羽毛主要呈橄榄绿色至淡黄色。与同属的白眼姬霸鹟 相比，它们的叫声和形态差异明显。","protection":"IUCN：LC（无危）。在哥伦比亚的Puerto Inírida（东北Guainía）较为常见。在巴西的Jaú和Tapajós国家公园、Anavilhanas Zoological Station以及玻利维亚的Noel Kempff Mercado国家公园均有分布。","distribution":"分布在南美洲的亚马孙雨林中部和西南部，包括从委内瑞拉西南部和邻近的哥伦比亚东南部，向南穿过亚马逊地区到达玻利维亚北部。","other":"亚马逊姬霸鹟和异域分布的白眼姬霸鹟曾被认为属于同一物种，但通过叫声和形态学的差异现已明确区分为两个独立物种。"},{"name":"白眼姬霸鹟","english_name":"Pale-tipped Inezia","scientific_name":"Inezia caudata","overview":"白眼姬霸鹟（英文名：Pale-tipped Inezia，学名：Inezia caudata），是雀形目霸鹟科纯色姬霸鹟属的小型而不起眼的飞禽。广泛分布于南美洲，从哥伦比亚到巴西东北部，常见于沿海森林、画廊森林和红树林地带。","appearance":"具有较长的尾巴，眉纹呈白色，喙部粗壮，近距离观察时可见其淡色的眼睛。体型小巧，活跃于低处，偶尔会在地面觅食，穿梭于植被中追逐昆虫。","call":"鸣声丰富，包括一系列缓慢下降的哨音，声音响亮，对于其体型而言颇为独特；还有断续的接触叫声，一旦熟悉，这些叫声便很容易识别。","habits":"栖息于亚热带或热带的干燥森林、湿润低地森林、红树林以及严重退化的旧森林中。飞行时动作敏捷，善于在林间穿梭。","identification":"与其他姬霸鹟相比，白眼姬霸鹟的淡色眼睛和白色眉纹是显著的辨识特征。","distribution":"分布于南美洲，包括哥伦比亚、法属圭亚那、圭亚那、苏里南和委内瑞拉，以及巴西东北部。"},{"name":"黄斑翅霸鹟","english_name":"Flavescent Flycatcher","scientific_name":"Myiophobus flavicans","overview":"黄斑翅霸鹟（英文名：Flavescent Flycatcher，学名：Myiophobus flavicans），是雀形目霸鹟科斑翅霸鹟属的鸟类。其名称源自其特有的黄绿色调。分布于南美，自委内瑞拉至秘鲁的安第斯云雾森林，海拔约1,200至2,700米，常见于较低层森林地带。","appearance":"体长12-12.7厘米，体重10.2-12.9克。雄鸟具有橄榄色的冠羽，有时可见黄色或橙色的冠斑，眼上有一条显眼的黄色纹线和断续的眼环。背部橄榄色，翅膀和尾巴暗淡，有2-3条肉桂色的翼带，下部翼带更为明显，飞羽边缘呈肉桂色，三级飞羽边缘淡黄白色，尾羽边缘淡黄橄榄色。喉部和下体黄色，腹部颜色最鲜艳，胸部有轻微的橄榄色斑点。雌鸟无冠斑，幼鸟类似雌鸟。不同亚种在冠斑颜色、眼上纹线和眼环的颜色、胸部颜色和斑点程度、翼部标记以及下颚颜色上有差异。","call":"通常保持安静，叫声为尖锐的“tsink”或“chiyp”。偶尔听到的歌声，可能主要在黎明时发出，被描述为快速有节奏的5-8个“kawhik”音符组成的系列。","habits":"栖息于湿润森林的低层和中层，森林边缘和竹林缠结处，主要在海拔1500米以上。可能为留鸟。以昆虫为主食，如膜翅目、鞘翅目和革翅目昆虫，偶尔吃半翅目和鳞翅目幼虫。单独或成2-3只的小群觅食，通常不加入混种群。觅食时的姿态与Empidonax类霸鹟相似，通过短距离的跳跃从低矮、阴暗的栖木上捕捉叶、枝、空中或地面的猎物。","breeding":"筑巢记录显示在委内瑞拉东北部（Cueva de los Guácharos）和哥伦比亚南部（Huila）的二月，以及在委内瑞拉北部（Perijá Mts）的六月和哥伦比亚的三月（西南Huila）和十月（Boyacá）发现处于繁殖状态的个体。在哥伦比亚西部Nariño七月发现雏鸟，九月在Cundinamarca发现幼鸟，以及在厄瓜多尔西北部八月和东北部一月发现幼鸟。巢为由小枝和藤蔓制成的杯状结构，内衬羽毛。无更多信息。","identification":"与橙冠斑翅霸鹟相比，后者具有完整的细薄眼环。亚种间在颜色和标记上有细微差别，尤其是venezuelanus、caripensis、perijanus和superciliosus在冠斑、眼上纹线和眼环的颜色、胸部颜色和斑点程度、翼部标记以及下颚颜色上的区别。","protection":"IUCN：LC（无危）。在委内瑞拉的Choroní Pass、Henri Pittier国家公园和Cerro Negro以及Cueva del Guácharo国家公园、哥伦比亚的Tambito自然保护区和厄瓜多尔的Guandera生物保护区均有分布，总体数量不多至相当常见。","distribution":"分布于南美，从委内瑞拉至秘鲁的安第斯山脉云雾森林，主要栖息地为海拔1500米以上的森林区域。"},{"name":"橙冠斑翅霸鹟","english_name":"Orange-crested Flycatcher","scientific_name":"Myiophobus phoenicomitra","overview":"橙冠斑翅霸鹟（英文名：Orange-crested Flycatcher，学名：Myiophobus phoenicomitra），是雀形目霸鹟科斑翅霸鹟属的鸟类。栖息于亚热带或热带湿润山地森林中。","appearance":"体长约11.5至12厘米，重约10至11克。雄鸟具橄榄色头顶，橙红至金黄色冠羽通常隐藏，偶见狭窄黄色眼环；上身橄榄色，双翼黑色带2至3条赭色翼带，下部翼带更为显著，次级飞羽边缘呈肉桂色，覆羽具淡褐色边缘；尾羽暗色，羽缘泛黄橄榄色；喉部及下体黄色，腹部颜色最鲜艳，胸部有微弱的橄榄色细纹。雌鸟无明显冠羽。幼鸟似雌鸟，但上体更棕色，翼带呈肉桂色，覆羽边缘淡黄褐色。亚种litae较指名亚种体型小，腹部黄色稍亮，翼带更宽更深的赭色。","call":"典型鸣唱为高音的“sit-sweet!-sit”，有时随后跟着几声柔和的音符。","habits":"生活在安第斯山脉云雾林的下层，偏好亚热带或热带湿润山地森林。具体栖息地、迁徙、飞行特点、活动范围、觅食方式等细节待补充。","breeding":"繁殖季节、求偶、营巢、交配、产卵、孵化、育雏等信息待补充。","identification":"与黄斑翅霸鹟的区别在于后者具有断裂的眼环和黑色喙。雄鸟的橙色冠羽因常隐藏而不易作为野外辨识特征。","protection":"IUCN状态待更新。","distribution":"分布于南美安第斯山脉两侧，包括哥伦比亚西部至秘鲁北部，以及秘鲁Chachapoyas省附近的独立群体。","other":"历史分类学信息和其他有趣信息待补充。"},{"name":"纯色斑翅霸鹟","english_name":"Unadorned Flycatcher","scientific_name":"Myiophobus inornatus","overview":"纯色斑翅霸鹟（英文名：Unadorned Flycatcher，学名：Myiophobus inornatus），是雀形目霸鹟科斑翅霸鹟属的鸟类。主要分布于南美洲的秘鲁东南部至玻利维亚北部的中安第斯山脉地带。尽管其名为‘Unadorned’，即‘纯色’，但雄鸟个体的头顶隐藏着黄色或橙色的冠羽。在1000至2500米的海拔范围内栖息于湿润的山地森林中，较为常见。","appearance":"纯色斑翅霸鹟体型中等，上体呈橄榄绿色，翼缘带有淡红褐色，下体为黄橄榄色，胸部带有模糊的橄榄色条纹。雄鸟头部中央有一隐蔽或半隐蔽的黄色或橙色冠羽，而雌鸟则缺少这一特征。眼周有一圈明显的浅黄色眼环。","habits":"这种鸟通常在山地森林的中层栖息，以昆虫为食，常与其他物种混群。它倾向于在较低的海拔活动，特别是在与类似物种黄斑翅霸鹟的分布重叠区域。","identification":"与黄斑翅霸鹟相比，纯色斑翅霸鹟具有更为完整的圆形眼环而非断裂的眼线，整体更偏灰绿，且在重叠区域内，纯色斑翅霸鹟通常出现在更低的海拔。","protection":"IUCN状态未知。","distribution":"主要分布在南美洲秘鲁东南部至玻利维亚北部的山地森林中，具体范围包括安第斯山脉东坡的1000至2500米海拔地带。"},{"name":"巴西斑翅霸鹟","english_name":"Roraiman Flycatcher","scientific_name":"Myiophobus roraimae","overview":"巴西斑翅霸鹟（英文名：Roraiman Flycatcher，学名：Myiophobus roraimae），是雀形目霸鹟科斑翅霸鹟属的鸟类。分布于南美洲东部安第斯山脉的偏远山脊、特普伊山脉及其它几处孤立的高山地带。","appearance":"该鸟上体呈棕色，翼部有锈色条纹，下体淡黄色，带有微弱的纵纹，这一组合特征使其在同类中独树一帜。雄鸟头部有一片隐秘的红橙色冠羽，通常不显露。体型较小，具体尺寸待详。","call":"发出多样化的叫声，包括尖细的吱吱声和快速的颤音。","habits":"栖息于云雾森林，偏好沙质土壤区域。其分布范围横跨玻利维亚、巴西、哥伦比亚、厄瓜多尔、圭亚那、秘鲁和委内瑞拉。","breeding":"关于其繁殖习性的详细信息尚需更多研究。","identification":"通过其独特的上体颜色、翼部锈色条纹和下体的淡黄底色加以辨认，雄鸟的隐蔽红橙色冠羽也是关键识别点。","distribution":"分布于南美洲特普伊山脉，从哥伦比亚延伸至玻利维亚，自然生境为亚热带或热带湿润的山地森林。"},{"name":"绿胸斑翅霸鹟","english_name":"Olive-chested Flycatcher","scientific_name":"Myiophobus cryptoxanthus","overview":"绿胸斑翅霸鹟（英文名：Olive-chested Flycatcher，学名：Myiophobus cryptoxanthus），是雀形目霸鹟科斑翅霸鹟属的鸟类。分布于厄瓜多尔东部及秘鲁东北部的安第斯山脉东麓。栖息于亚热带或热带湿润山地森林，以其独特的橄榄色胸部羽毛而得名。","appearance":"体型小，约12厘米长，体重约11克。头部顶部呈暗橄榄褐色，冠部有一半隐藏的黄色斑块，面部两侧、颈背及上体为深橄榄色。翅膀和尾巴颜色较暗，有两条宽阔的淡白色翼带。喉部颜色较脏白，胸部有一条宽的灰橄榄色条纹，两胁模糊条纹，腹部及尾下覆羽呈淡黄色。虹膜深色，喙全黑，腿黑色。雌雄外观相似，幼鸟描述未知。","call":"发出柔和、快速的‘weee d’d’d’d’d’d’d’或‘weh-weh-weh-eh-eh-eh-eh’叫声，黎明时会重复一系列‘chwee’音符的歌唱，与浅褐斑翅霸鹟的声音相似。","habits":"偏好低矮的草地空地，周围散布着灌木丛和小树，不会进入森林内部。其栖息地选择是重要的识别线索。在厄瓜多尔较为常见至局部相当常见，而在秘鲁罕见。","breeding":"相关信息未提供。","identification":"与浅褐斑翅霸鹟相比，绿胸斑翅霸鹟具有更明显的橄榄色胸部和黄色冠斑，且栖息环境不同。","protection":"IUCN：LC（无危）。在厄瓜多尔常见至局部相当常见，秘鲁罕见。物种受益于森林清理，可能在厄瓜多尔东部数量增加。","distribution":"分布于厄瓜多尔东部（从苏库比奥斯南部到查莫拉钦奇佩）和秘鲁东北部（亚马逊州到圣马丁州），可能向北延伸至哥伦比亚南部相邻地区。","other":"在厄瓜多尔的Zumba地区和Archidona北部的Loreto公路沿线数量众多，但在东部低地逐渐稀少。"},{"name":"浅褐斑翅霸鹟","english_name":"Bran-colored Flycatcher","scientific_name":"Myiophobus fasciatus","overview":"浅褐斑翅霸鹟（英文名：Bran-colored Flycatcher，学名：Myiophobus fasciatus），是雀形目霸鹟科斑翅霸鹟属的小型鸟类。其分布广泛，从中美洲的哥斯达黎加西南部延伸至南美洲的阿根廷东北部和乌拉圭，也可见于特立尼达岛。该鸟种具有独特的暗红褐色头部和上体，冠部隐藏着黄色羽冠，两道淡黄褐色翼带，腹部呈白色渐变为淡黄色，胸侧有深色条纹。","appearance":"体长约12.7厘米，体重约10.5克。成年鸟头部和上体呈深红褐色，冠部有隐蔽的黄色羽冠，兴奋时会竖起。两道明显的淡黄褐色翼带，下体白色，腹部逐渐转为淡黄色，胸部和两侧有暗色条纹。喙部上方黑色，下方棕色。雌雄相似，但幼鸟缺乏冠羽片。雌鸟较雄鸟下体条纹较轻，冠羽片可能减少或缺失。","call":"鸣唱包括悠扬的哨音和上升的颤音，叫声有清晰的哨声和上升的颤音，有时呈现出笑声般的节奏。","habits":"栖息于开阔的森林和次生林中，偏好低矮的树枝作为栖息点。以小昆虫和浆果为食，独居或成对活动，常快速穿梭于灌木丛中寻觅食物。海拔分布从海平面至2800米。","breeding":"繁殖季节从2月到4月在厄瓜多尔西南部，巢由茎、树皮制成，内衬精细植物纤维，悬挂在树侧枝的低处。一窝通常产两枚奶油色带有赤褐色环的蛋，雌鸟孵卵17天，雏鸟再过15-17天离巢。繁殖期间受紫辉牛鹂寄生。","identification":"与其他斑翅霸鹟属物种相比，其冠羽颜色、上体色调、胸斑条纹和腹部颜色有显著差异。与灰褐斑翅霸鹟相比，颜色更暗淡、更偏灰，腹部明显呈黄色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加西南部至南美洲的阿根廷东北部和乌拉圭，特立尼达岛也有记录。在秘鲁西北生物圈保护区、厄瓜多尔的布埃纳文图拉生物保护区和尤恩吉拉生物保护区等多处保护区中均有发现。","other":"在部分地区的沙漠绿洲山谷中被认为是稀有种类。"},{"name":"灰褐斑翅霸鹟","english_name":"Mouse-grey Flycatcher","scientific_name":"Myiophobus crypterythrus","overview":"灰褐斑翅霸鹟（英文名：Mouse-grey Flycatcher，学名：Myiophobus crypterythrus），是雀形目霸鹟科斑翅霸鹟属的鸟类。小型、颜色较为暗淡的霸鹟，偏好轻度林木覆盖区、干燥草原及森林边缘地带。其特征在于褐色偏灰的羽毛、条纹状胸部及浅色翼带，这使其能从相似物种中区分出来。分布于南美洲的哥伦比亚西南部、厄瓜多尔西部和秘鲁西北部，尤其是安第斯山脉以西地区。","appearance":"灰褐斑翅霸鹟体长约为12至12.5厘米，体重介于9.5至12.2克之间。上身呈现冷灰褐色，腹部及喉咙为白色，带有灰色条纹。两翼具宽阔而明显的浅色翼带，翼缘略带锈色。头部两侧、颈项及背部主要为灰褐色；翅膀深褐色，翼盖上可见两条显著的浅色翼带，翼缘处呈淡黄色。尾巴亦为深褐色。雌鸟较雄鸟条纹较少，冠羽可能减小或缺失。","call":"灰褐斑翅霸鹟的鸣唱为快速的‘swee-ch-ch-ch-ch-ch…’声调，此外还发出一系列间隔均匀的哨音。","habits":"灰褐斑翅霸鹟通常独居或成对出现，喜欢安静地坐在低矮的栖木上。它主要生活在轻度林木覆盖区、干燥草原及森林边缘，其栖息地通常位于南美洲特定区域内。该物种被认为是留鸟，未见有迁徙行为。","identification":"灰褐斑翅霸鹟与浅褐斑翅霸鹟和绿胸斑翅霸鹟最为相似，但前者具有橙红色的冠羽斑点，上身呈冷灰褐色而非暖锈褐色，且下体更白。与灰胸纹霸鹟相比，后者下体无条纹，面部图案不同。","protection":"IUCN状态未知。","distribution":"灰褐斑翅霸鹟主要分布在南美洲的哥伦比亚西南部、厄瓜多尔西部和秘鲁西北部，尤其是在安第斯山脉以西的区域，但也出现在马兰翁谷地。","other":"该物种过去曾被认为是浅褐斑翅霸鹟的一个亚种，但现在已被确认为独立物种。"},{"name":"红褐斑翅霸鹟","english_name":"Rufescent Flycatcher","scientific_name":"Myiophobus rufescens","overview":"红褐斑翅霸鹟（英文名：Rufescent Flycatcher，学名：Myiophobus rufescens），是雀形目霸鹟科斑翅霸鹟属的鸟类。主要分布在南美洲西部的秘鲁和智利北部，栖息于亚热带或热带湿润的山地森林。其显著特征为锈褐色的外表，带有明显的翼带和淡色的眉纹。","appearance":"红褐斑翅霸鹟是一种体型较小的鸟类，全长约11.5至12.5厘米。上体呈温暖的棕色，冠部有一橙色的隐匿斑块（雌鸟中的斑块可能减小或消失）。两道浅色的翼带明显可见，下体一般为淡肉桂色或肉桂色，喉部颜色最浅。雄鸟的冠部为棕色，带有半隐藏的橙色斑块，眼上有一短而暖色调的眉纹，不到眼后方延伸过多。雌鸟和雄鸟相似，但冠部的橙色斑块可能减小或消失。","call":"红褐斑翅霸鹟的鸣声包括尖锐的金属般唧唧声和颤音。","habits":"这种鸟通常栖息在沙漠灌木丛、轻型林地和杂草丛生的田野中。它们经常静静地停在低矮的树枝或电线上。红褐斑翅霸鹟的食性为昆虫，通过短距离空中突袭和从停驻点捕食的方式获取食物。","breeding":"红褐斑翅霸鹟的繁殖生态尚未得到充分研究，但可能与近缘种浅褐斑翅霸鹟类似，后者以昆虫为食，采取空中短程突袭和停驻捕食的觅食方式。","identification":"红褐斑翅霸鹟与浅褐斑翅霸鹟和灰褐斑翅霸鹟曾被视为同一物种的不同亚种，但现已确认为独立物种。它具有无条纹的肉桂色下体，这是该物种复合体中最独特的特征。与其他潜在混淆种如桂红霸鹟相比，它们的分布范围和栖息地不重叠。","protection":"IUCN：LC（无危）","distribution":"红褐斑翅霸鹟的分布限于南美洲西部的秘鲁和智利北部，主要栖息在亚热带或热带湿润的山地森林中。","other":"历史上，红褐斑翅霸鹟与浅褐斑翅霸鹟和灰褐斑翅霸鹟被当作同一物种的一部分，但在近期的研究中，基于形态学和鸣声的差异，这三种鸟被重新分类为独立的物种。"},{"name":"华丽斑翅霸鹟","english_name":"Handsome Flycatcher","scientific_name":"Nephelomyias pulcher","overview":"华丽斑翅霸鹟（英文名：Handsome Flycatcher，学名：Nephelomyias pulcher），是雀形目霸鹟科华丽斑翅霸鹟属的鸟类。生活在南美山区森林中的小型亮丽飞鸟。其自然栖息地为哥伦比亚至秘鲁东南部的亚热带或热带湿润山地森林。","appearance":"华丽斑翅霸鹟的下体呈黄色，胸部尤其呈现出浓郁的橙色色调。其暗色翅膀上有着显眼的黄色翼纹。雄鸟和雌鸟在外表上相似。","call":"这种鸟会发出短促而快速的‘pip’声叫声。","habits":"它们通常成对出现，常跟随混合鸟群穿梭于云雾森林的中上层，活动高度大约在1,500至2,500米之间。","identification":"其独特的橙色胸部和黄色翼纹使其在同类中易于辨认。","distribution":"分布于南美地区的哥伦比亚至厄瓜多尔，以及秘鲁东南部。"},{"name":"橙斑翅霸鹟","english_name":"Orange-banded Flycatcher","scientific_name":"Nephelomyias lintoni","overview":"橙斑翅霸鹟（英文名：Orange-banded Flycatcher，学名：Nephelomyias lintoni），是雀形目霸鹟科华丽斑翅霸鹟属的鸟类。小型霸鹟科鸟类，仅限于南美洲安第斯山脉的高海拔云雾森林中，具体分布于厄瓜多尔南部和秘鲁东北部。拥有暗橄榄褐色的上体，黄色的下体，侧面带有橄榄色的洗涤，以及隐蔽的橙黄色冠带（雄鸟）。这种鸟的分布区域有限，栖息于海拔2250至2800米的湿润山地森林中。","appearance":"橙斑翅霸鹟的成年雄鸟上体为深棕色橄榄色，头部颜色最深，具有一条半隐蔽的黄色、橙色或赤褐色冠带。非常狭窄的淡黄色眼环。尾羽呈暗灰色。翅膀暗灰色，带有两道宽阔的肉桂色、黄褐色或淡黄色翼带；初级飞羽边缘窄而淡黄色或白色，次级飞羽外侧相似，但基部黑色。下体为黄色，胸侧带有橄榄色的洗涤。雌鸟的冠带为暗褐色，可能减弱或缺失。幼鸟缺乏冠带，翼带颜色更深的赤褐色，下体更淡。喙的下颌和上颌基部为黄色。","call":"橙斑翅霸鹟通常会在树顶发出连续柔和的‘tink’叫声。","habits":"橙斑翅霸鹟主要栖息于湿润的山地森林的树冠层和边缘，活动于海拔2250至2800米之间。它们的地理分布局限于厄瓜多尔南部和秘鲁东北部的特定区域。","breeding":"关于橙斑翅霸鹟的繁殖生态知之甚少，其详细繁殖习性仍待研究。","identification":"橙斑翅霸鹟与华丽斑翅霸鹟和赭胸斑翅霸鹟外观相似，但后者下方缺少赭色，虹膜颜色较深。这三种物种的地理分布并不重叠。","protection":"IUCN：LC（无危）","distribution":"橙斑翅霸鹟的分布限于南美洲安第斯山脉的南部厄瓜多尔和东北秘鲁，具体在海拔2250至2800米的湿润山地森林。","other":"橙斑翅霸鹟的种群数量疑似正在下降，其生存状况受到栖息地丧失的威胁。"},{"name":"赭胸斑翅霸鹟","english_name":"Ochraceous-breasted Flycatcher","scientific_name":"Nephelomyias ochraceiventris","overview":"赭胸斑翅霸鹟（英文名：Ochraceous-breasted Flycatcher，学名：Nephelomyias ochraceiventris），是雀形目霸鹟科华丽斑翅霸鹟属的鸟类。分布于南美洲秘鲁北部至玻利维亚西北部的高海拔山区，栖息于湿润的山地森林中，高度范围在2200-3700米。其显著特征为橄榄色的背部、黑褐色翅膀上的明显淡色翼带，以及橙黄色的冠纹和喉胸部。","appearance":"赭胸斑翅霸鹟体型较小，全身呈现暗橄榄色，翅膀黑色带有明显的淡色翼带和飞羽边缘，头部橄榄色，脸部呈土黄色，具有橙色的冠纹，喉部和胸部为赭黄色，腹部黄色。雌雄差异在于雌鸟的冠纹颜色较为暗淡，为橙红棕色。","habits":"通常成对或小群出现，常加入混合物种的鸟群。它们以昆虫为主食，通过短距离飞翔捕捉猎物，偶尔也会从树上啄食果实。","identification":"与华丽斑翅霸鹟相比，赭胸斑翅霸鹟的尾更长，色彩更鲜艳，生活在更高的海拔。华丽斑翅霸鹟体型较小，喙更短，胸腹部颜色偏黄绿，而非赭黄色，且头部侧面和冠部灰色较多，上身颜色更偏向橄榄色。","distribution":"分布于南美洲的秘鲁北部至玻利维亚西北部，主要栖息于安第斯山脉东坡的高海拔湿润山地森林中。"},{"name":"华丽霸鹟","english_name":"Ornate Flycatcher","scientific_name":"Myiotriccus ornatus","overview":"华丽霸鹟（英文名：Ornate Flycatcher，学名：Myiotriccus ornatus），是雀形目霸鹟科华丽霸鹟属的鸟类。体型较小的飞禽，长约12厘米，重约13.5克。其最显著的特征是明亮的黄色腹部、白色眼后斑点、深色头部以及显眼的黄色臀部。分布于南美洲的哥伦比亚至秘鲁一带，常见于亚热带或热带湿润山地森林。","appearance":"华丽霸鹟具有独特的外观，头部为灰色，面部和冠部有黑色，明显的白色半月形眼先斑，隐藏着亮黄色的冠羽；背部为深橄榄色，臀部呈鲜亮的金黄色；翅膀暗黑，尾巴基部呈锈色或赤褐色，尖端暗黑；胸部为丰富的橄榄色，腹部为亮金色；虹膜深棕色，喙和腿均为黑色或棕色。雌雄外观相似，雌鸟略小于雄鸟。幼鸟描述未知。部分亚种如stellatus，尾巴基部呈黄色，体型更小，眼先的半月形斑纹更为局限，有时中间会中断。","call":"发出响亮而清脆的单音节‘peek’或‘wheep’声，当积极觅食或停歇时频繁重复，偶尔快速连串发声。","habits":"主要栖息于潮湿的山地森林和较老的次生林，尤其偏爱树倒隙地、阴湿苔藓覆盖的溪谷和溪流边缘，海拔高度主要在600至2500米之间，局部低至300米。通常单独或成对活动，很少加入混群觅食。觅食时，常在深荫处的开阔枝头直立停歇，长时间静止，头部活动搜索空中猎物，然后从停歇处出击捕食昆虫，经常返回同一或附近位置。高度定居，日复一日在同一觅食区域内活动。","breeding":"繁殖期在3月至4月中旬，5月在哥伦比亚可见处于繁殖状态的个体。筑巢于陡峭土壁上，高度约1.3米，巢呈圆顶状，由根须构成，隐蔽性好。在厄瓜多尔发现的活跃巢穴为附着在固体基底上的球形苔藓巢，侧向入口，高3至5米，内部有紧密的草纤维杯。蛋呈奶油色或象牙白，表面散布少量肉桂色斑点，大小约为16.9至17毫米×12.8至13.4毫米。雏鸟眼睛紧闭，皮肤粉红，仅有稀疏的出生绒毛。","identification":"与其他霸鹟科鸟类相比，华丽霸鹟的黄色腹部和臀部，以及白色的“头灯”状眼后斑点极为醒目，使其在野外容易识别。与M. phoenicurus的区别在于地理分布无重叠，裸露部位颜色、眼部颜色、跗蹠颜色以及喙基颜色有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚至秘鲁，主要在亚热带或热带湿润山地森林，海拔范围为700至2200米，在秘鲁东部和厄瓜多尔东部，局部可低至500米。","other":"在多个保护区中存在，包括哥伦比亚的Tambito自然保护区和Tatamá国家公园，以及厄瓜多尔的Río Palenque科学中心和其他众多保护区。"},{"name":"多色苇霸鹟","english_name":"Many-colored Rush Tyrant","scientific_name":"Tachuris rubrigastra","overview":"多色苇霸鹟（英文名：Many-colored Rush Tyrant，学名：Tachuris rubrigastra），是雀形目霸鹟科苇霸鹟属的鸟类。色彩斑斓，主要栖息于湿地和芦苇丛中，尤其偏好Scirpus芦苇群落。拥有独特的七彩羽衣，是Tachuris属的唯一成员，有时被归类为单独的科。分布于南美的西部、南部和东南部。","appearance":"雄鸟成鸟的冠羽为黑色，有金色眉纹，隐蔽的红色顶冠和轻微的冠状突起；面颊和耳羽蓝黑光泽，呈现出面具般的外观；颈背赭色，过渡至鲜绿色背部；翅膀黑色，翼盖和三级飞羽边缘形成显著的白色翼带；尾巴黑色，外侧尾羽白色；上喉部白色；胸腹亮黄色，靠近翼弯处有黑色横斑（几乎在中央相遇），下体红至橙红色，有时呈现淡玫瑰粉色；虹膜淡蓝；喙黑色；跗跖长而黑。雌鸟色彩稍暗淡，冠斑较小。幼鸟面部无蓝色，上体可能带有黄色鳞片，胸腹黄淡，无胸斑。","call":"发出奇特快速的一系列类似昆虫的‘tic’音符，以及富有音乐性的‘piwup bzzzzt’或‘piwup piwuprrrrp’声，具有咕噜质感和嗡嗡声元素。","habits":"栖息于广阔的芦苇床、沼泽和湖边草甸，极少离开芦苇区。迁徙模式尚不明确；南端种群在南半球冬季向北移动。以昆虫为主食，单独或家族小群在密集的芦苇中觅食，通常隐藏得很好。主要从芦苇边缘或浮游植被上捕食，常倒挂或紧贴芦苇茎，有时空中捕食或水面掠食昆虫；偶尔在地面、泥滩或浮游植被上奔跑或跳跃寻找猎物。","breeding":"在秘鲁，10月产卵，9月有雏鸟，2月有离巢幼鸟；在巴西东南部，9月和10月处于繁殖状态，2月有离巢幼鸟。巢呈深锥形杯状，侧挂于单根芦苇上，通常位于水面上方，使用湿润的芦苇叶制作，干燥后质地似硬纸板。每窝3枚卵，罕见4枚；孵化和离巢期信息未知。","identification":"鲜明的色彩和独特的白翼带、白色尾缘使其在良好观察条件下易于识别。与其他霸鹟科鸟类明显不同。","protection":"IUCN：LC（无危）。在部分地区常见，形成松散的群落，如秘鲁的L Junín、玻利维亚的L Titicaca和L Poopó，以及阿根廷的Costanera Sur生态保护区。","distribution":"分布于南美西部、南部和东南部，包括秘鲁、玻利维亚、阿根廷、智利等地。","other":"DNA研究显示，多色苇霸鹟属于一个隔离的谱系，与其它鸣禽分离约2500万年，曾被提议归入独立的Tachurisidae科。"},{"name":"尖尾霸鹟","english_name":"Sharp-tailed Grass Tyrant","scientific_name":"Culicivora caudacuta","overview":"尖尾霸鹟（英文名：Sharp-tailed Grass Tyrant，学名：Culicivora caudacuta），是雀形目霸鹟科尖尾霸鹟属的小型鸟类。其显著特征为细长的尖尾和宽阔的白色眉纹，以及白色的下巴。分布于南美洲的玻利维亚西部至巴西中部，南部至阿根廷东北部。","appearance":"该鸟体型小巧，拥有引人注目的长而尖锐的尾巴。头部具有明显的宽白眉纹和白下巴，背部呈现黑色与棕色的条纹，两侧呈锈色。雄鸟、雌鸟和幼鸟的羽毛颜色相似，但幼鸟的羽色可能较为暗淡。","call":"鸣声微弱，由一系列短暂的“tweee tweee tweee”音符组成。","habits":"栖息于低地的高草丛中，偏好极少被打扰的环境。在高植被中难以被发现。飞行特点和活动范围未详述。","breeding":"关于其繁殖习性的具体信息未提供。","identification":"通过其独特的长尖尾、白色眉纹和下巴来识别。与同属其他物种的区别在于上述特征的组合。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的玻利维亚中东部及东部、巴西中南部、阿根廷东北部、巴拉圭东部以及乌拉圭。在玻利维亚东部可能是最丰富和分布最广的。","other":"尖尾霸鹟的生存受到栖息地丧失的严重威胁，尤其是由于农业扩张和森林砍伐导致的生境破坏。"},{"name":"淡褐胸侏霸鹟","english_name":"Drab-breasted Bamboo Tyrant","scientific_name":"Hemitriccus diops","overview":"淡褐胸侏霸鹟（英文名：Drab-breasted Bamboo Tyrant，学名：Hemitriccus diops），是雀形目霸鹟科侏哑霸鹟属的小型鸟类。主要分布在南美洲的巴拉圭东部、阿根廷东北部以及巴西东南部的森林地带。","appearance":"这种小型飞鸟在森林下层竹林中可见，上体橄榄褐色，下体淡黄色。面部有一白色斑点，虹膜呈红褐色。与相似的褐胸侏霸鹟相比，其面部斑点为淡色，通常在海拔低于1200米的地区发现。","call":"叫声为短暂的‘trrii-trrii trri tii’颤音。","habits":"栖息于森林下层，偏好有竹子的环境。具体栖息地和分布信息包括南美的低地森林和山地森林。","breeding":"筑巢于树枝末端，巢呈袋状，侧面开口，悬挂式。已知的巢位于地面1.8米高处，由绿色苔藓、植物纤维构成，偶尔混有枯叶和竹叶。巢中蛋主要为白色，有少量棕色斑点，集中在蛋的宽端。","identification":"与褐胸侏霸鹟的区别在于面部斑点的颜色和海拔分布差异。","protection":"IUCN：LC（无危）。在特定保护区如Estancia Itabó Private Nature Reserve（Paraguay）、Itatiaia和Serra dos Órgãos National Parks（Brazil）中较为常见。","distribution":"主要分布在南美洲，包括巴拉圭东部、阿根廷东北部和巴西东南部的森林区域。"},{"name":"褐胸侏霸鹟","english_name":"Brown-breasted Bamboo Tyrant","scientific_name":"Hemitriccus obsoletus","overview":"褐胸侏霸鹟（英文名：Brown-breasted Bamboo Tyrant，学名：Hemitriccus obsoletus），是雀形目霸鹟科侏哑霸鹟属的鸟类。小型霸鹟科鸟类，广泛分布于南美洲的巴西东南部和南部以及阿根廷东北部的亚热带或热带湿润山地森林中。","appearance":"体型微小，整体呈现橄榄褐色，上部颜色较深，腹部为淡黄色。其显著特征是眼前方有一块淡黄色斑点。与之相似的淡褐胸侏霸鹟的区别在于后者的眼前斑点为白色而非淡黄色，且淡褐胸侏霸鹟栖息于较低海拔地区。","call":"鸣声为一连串的“tic-tic-tic”音节，形成其特有的歌曲。","habits":"栖息于森林的林下层，尤其偏好有竹子的环境。分布于亚热带或热带湿润的山地森林。","identification":"与淡褐胸侏霸鹟的主要区别在于眼前斑点的颜色和栖息地的海拔高度。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的巴西东南部和南部，以及阿根廷东北部。"},{"name":"红侏霸鹟","english_name":"Flammulated Bamboo Tyrant","scientific_name":"Hemitriccus flammulatus","overview":"红侏霸鹟（英文名：Flammulated Bamboo Tyrant，学名：Hemitriccus flammulatus），是雀形目霸鹟科侏哑霸鹟属的的小型鸟类。又称红侏霸鹟，外观并不起眼，以橄榄色为主，分布于南美洲亚马逊雨林的西南部，特别是茂密的Guadua竹林中。","appearance":"红侏霸鹟体型小巧，全长约11厘米，重8.8至11.7克。上体呈单调的橄榄绿色，冠、颈背、背部、臀部及耳羽颜色一致。眼上方有一淡灰色斑点和窄眼环。喉咙通常被描述为灰白色带褐色条纹，但实际上显得暗淡的棕灰色，条纹微弱。上胸略深于喉咙，逐渐变白至腹部。翅膀和覆羽较上体稍暗，翼下有橄榄色边缘。尾巴上表面橄榄色，下表面较暗。","call":"红侏霸鹟最常通过声音被发现，发出一系列空洞的“pip”音节。","habits":"红侏霸鹟主要栖息于亚马逊地区的湿润低地森林，偏好大型竹林和森林边缘的藤蔓丛。它通过快速跳跃和短距离飞行来捕食叶面和枝条上的节肢动物。","breeding":"关于红侏霸鹟的繁殖信息尚未详细记载。","identification":"红侏霸鹟与巴西东南部的两种‘竹霸鹟’，淡褐胸侏霸鹟和褐胸侏霸鹟亲缘关系最近，但它们之间没有地理重叠。在分布区域内，可通过羽毛颜色、眼睛颜色和叫声将其与其他相似的tody-tyrant区分开。","protection":"IUCN：LC（无危）","distribution":"红侏霸鹟分布于亚马逊盆地的上游地区，包括秘鲁东南部、玻利维亚北部以及巴西西北部邻近的Acre、Rondônia和Mato Grosso州。","other":"红侏霸鹟是研究资源分割、生态位特化以及亚马逊鸟类多样性形成机制的理想对象。"},{"name":"小哑霸鹟","english_name":"Snethlage's Tody-Tyrant","scientific_name":"Hemitriccus minor","overview":"小哑霸鹟（英文名：Snethlage's Tody-Tyrant，学名：Hemitriccus minor），是雀形目霸鹟科侏哑霸鹟属的鸟类。包括玻利维亚、巴西和委内瑞拉。","appearance":"小哑霸鹟体型微小，背部呈橄榄绿色，腹部颜色依亚种而异，可能是黄色或接近白色。翅膀上的条纹比白眼哑霸鹟或奇氏哑霸鹟更为模糊，且头部无盔状突起，区别于盔侏霸鹟。","call":"不同亚种的鸣叫和歌声有所差异，许多亚种会发出快速的鼻音颤音和‘tic’音符。","habits":"栖息于热带湿润低地森林的林下层，西部亚种偏好黑水泛滥森林（igapo）。活动于亚马逊雨林的特定生境中。","identification":"与白眼哑霸鹟、奇氏哑霸鹟相比，小哑霸鹟的翼带不那么明显，且头部缺乏盔状突起，区别于盔侏霸鹟。","protection":"IUCN：LC（无危）","distribution":"分布于南美的亚马逊雨林南部，具体包括玻利维亚、巴西和委内瑞拉的热带湿润低地森林。"},{"name":"玻利维亚哑霸鹟","english_name":"Yungas Tody-Tyrant","scientific_name":"Hemitriccus spodiops","overview":"玻利维亚哑霸鹟（英文名：Yungas Tody-Tyrant，学名：Hemitriccus spodiops），是雀形目霸鹟科侏哑霸鹟属的鸟类。体型小巧、外观朴素，主要分布在玻利维亚的Yungas地区，偶尔在秘鲁东南部边境附近也能发现其踪迹。该鸟具有橄榄绿色的背部和淡黄色的腹部，喉咙和胸部可能带有轻微的条纹。","appearance":"体长约11厘米，体重介于6.9至7.5克之间。嘴基宽大，鼻孔异常大且呈圆形。头部和上体为深橄榄绿，头顶长有形成短冠的延长羽毛；眼周呈灰褐色；翅膀上有两道不明显的黄橄榄色翼带；喉咙和胸部为灰橄榄色，有不清晰的白色条纹，下腹部为清澈的黄白色；虹膜为淡黄色；喙黑色；跗跖粉灰色至粉红色。雄雌相似。","call":"典型鸣唱为下滑式的粗糙颤音。","habits":"栖息于安第斯山脉东坡的湿润森林中，偏好亚热带或热带湿润山地森林环境。","identification":"通过苍白的眼色和声音将其与Flammulated Pygmy-Tyrant区分开来，后者通常在较低海拔处被发现。","distribution":"分布于南美洲，主要集中在玻利维亚中部，以及秘鲁最东南部（S Puno）。"},{"name":"阿克雷哑霸鹟","english_name":"Acre Tody-Tyrant","scientific_name":"Hemitriccus cohnhafti","overview":"阿克雷哑霸鹟（英文名：Acre Tody-Tyrant，学名：Hemitriccus cohnhafti），是雀形目霸鹟科侏哑霸鹟属的小型鸟类。其背部呈橄榄绿色，喉部和胸部带有橄榄色条纹，腹部下方呈淡黄色。最显著的特征是其青铜色的翼带和赭色的眼纹。该物种主要分布于南美洲的亚马逊盆地，包括巴西阿克里州及秘鲁马德雷德迪奥斯地区，可能也延伸至临近的玻利维亚潘多地区。","appearance":"阿克雷哑霸鹟体型小巧，整体色调较为暗淡。成鸟拥有橄榄绿的背部，喉部和胸部可见橄榄色的条纹，而腹部下方则呈现黄色。翅膀上具有两道明显的青铜色翼带，头部两侧眼周区域为赭色。雄雌外观相似，幼鸟特征未详。","call":"鸣声为蛙鸣般的颤音，通常间隔规律但间隔较长，有时会连续发出2到4个快速的颤音，尤其是在回应播放声音时，其鸣唱有时会延长成更长的颤音，由多达38个音符组成。","habits":"栖息于次生林和退化的竹林中，偏好高地上排水良好、营养贫瘠的土壤。在巴西阿克里州，此类森林的树冠高度不超过约12米，植被以Guadua竹子为主，偶尔低至5米。活动范围在海拔300米以下的低地，通常在离地面1至4米的下层林中觅食，主要以昆虫为食，通过短暂的向上跳跃捕捉叶底下的猎物。","breeding":"关于繁殖行为的信息尚不充分，但根据其生态习性推测，繁殖期可能与雨季相关联。","identification":"与近缘种玻利维亚哑霸鹟相比，阿克雷哑霸鹟的鸣唱更短，平均音符数量较少，峰值频率更低，节奏较慢，但有重叠部分。此外，它的单音节‘skep’或‘keek’叫声频率在2.5至3.2千赫兹之间，或较低频率的‘kup’叫声约2千赫兹，这些叫声有时会连成一系列，例如‘kup keek’或‘kup keek keek’。","protection":"IUCN：NT（近危）。由于其分布范围较小，且面临森林砍伐的威胁，未来可能会上升至Vulnerable（易危）。","distribution":"主要分布在巴西阿克里州东南部及邻近秘鲁东南部的巴西-玻利维亚边境，可能也存在于相邻的玻利维亚西北极地区域。","other":"该物种于2013年首次被描述为新种，其历史在鸟类学领域知之甚少。"},{"name":"阔嘴哑霸鹟","english_name":"Boat-billed Tody-Tyrant","scientific_name":"Hemitriccus josephinae","overview":"阔嘴哑霸鹟（英文名：Boat-billed Tody-Tyrant，学名：Hemitriccus josephinae），是雀形目霸鹟科侏哑霸鹟属的鸟类。以独特的宽大喙部著称。该鸟主要栖息于南美洲的圭亚那和巴西中北部的热带雨林，偏好植被密集的藤蔓地带。","appearance":"体长约11厘米，体重介于10.2至10.8克之间。头顶至背部呈现均匀的暗橄榄色，面部两侧和耳羽呈淡灰色。翅膀为纯橄榄色，尾部则是暗褐色橄榄色调。喉咙部位为暗淡的灰白色，胸腹部则显现明亮的淡黄色，下腹部略带肉桂色。虹膜呈红棕色，喙部为灰色，下颚基部颜色较浅。腿脚为浅灰色。雄雌外观相似。","call":"叫声为一系列两到三个短促而空洞的音符，音乐般且音调递减，最常听到的是单独的短促‘pic’声，亦会发出7至15个快速膨胀后下降的‘pic’音符串。","habits":"通常独居或成对出现，偶尔加入混种鸟群。在森林中层的密集区域觅食，高度约6至9米，长时间停歇后做短暂上冲动作捕食昆虫，常侧身跳跃于水平枝条间。","identification":"其显著的大喙是辨认的关键，声音与佩氏哑霸鹟类似但更深沉且音符较少。生境与佩氏哑霸鹟完全不同。","protection":"IUCN：LC（无危）；在苏里南的Raleigh Falls-Voltzberg国家公园和Sipaliwini Savanna自然保护区有所分布，总体而言较为罕见。","distribution":"分布于圭亚那地区和巴西东北部，包括法国属圭亚那、苏里南、东盖亚纳，以及巴西亚马逊盆地的帕拉州、阿马帕州和东北部亚马逊州。"},{"name":"白眼哑霸鹟","english_name":"White-eyed Tody-Tyrant","scientific_name":"Hemitriccus zosterops","overview":"白眼哑霸鹟（英文名：White-eyed Tody-Tyrant，学名：Hemitriccus zosterops），是雀形目霸鹟科侏哑霸鹟属的鸟类。小型、不起眼，拥有橄榄绿色的上部羽毛和淡黄色的腹部，最显著的特征是白色的眼环和白色的眼睛，但在野外环境下，白色的眼睛可能并不明显。其自然栖息地为南美洲亚马逊盆地以北的热带湿润森林和干燥灌木丛。","appearance":"白眼哑霸鹟体型小，约11厘米长，体重介于7.8至10克之间。头部和上身呈橄榄绿色，眼上方有白色的区域，眼环模糊可见；翅膀暗色，带有两道较为明显的黄绿色翼带，飞羽边缘亮橄榄黄色；尾巴暗橄榄色；喉咙灰色，有暗色条纹，胸部和两侧橄榄色，点缀着黄色斑点，腹部清晰的淡黄色；虹膜浅灰色或稻草黄色（有时为红棕色）；喙黑色，下颌基部粉红色；腿深灰色。雌雄相似。flaviviridis亚种比指名亚种更鲜亮，上部更偏黄绿色，下部黄色斑点更为强烈；naumburgae亚种上部颜色更淡，黄绿色，腹部近白色。","call":"白眼哑霸鹟的叫声是其最佳识别特征之一，通常在被看到之前先被听到。指名亚种的叫声为一种干燥的1秒颤音，音调先升后降，逐渐放慢，由一个独特的单音开始；flaviviridis亚种的叫声类似昆虫的断续音符，金属质感，音调一致，有时以单独的高音开头或结尾；naumburgae亚种的主要叫声为'kwidíp'或'kwididíp'，与白腹哑霸鹟的叫声类似。","habits":"白眼哑霸鹟常独居，偶尔成对出现，很少跟随混合物种群。它在森林下层和中层的隐蔽位置栖息，但经常在非常开放的位置停歇，从森林冠层下方的植被中短距离向上捕捉猎物。","breeding":"关于白眼哑霸鹟的繁殖信息尚未发表。已知其巢穴为悬挂式。","identification":"与各种侏霸鹟在外貌和行为上有相似之处，但缺少羽冠，叫声不同。具体亚种间的辨识要点涉及颜色的细微差异。","protection":"IUCN：LC（无危）。白眼哑霸鹟在全球范围内不构成威胁，但在某些地区如厄瓜多尔的Serranías Cofán和巴西的Jaú国家公园相对常见。NE巴西的naumburgae亚种较为罕见，仅在Mata Estrela私人保护区、Murici生态保护区和Pedra Branca/Fazenda Bananeira保护区有记录。","distribution":"白眼哑霸鹟主要分布在南美洲亚马逊雨林北部，包括巴西、法属圭亚那、苏里南、圭亚那东南部、哥伦比亚、委内瑞拉、厄瓜多尔和秘鲁的亚马逊盆地。在亚马逊盆地，仅出现在亚马逊河以北；在委内瑞拉，则位于奥里诺科河上游南部。"},{"name":"白腹哑霸鹟","english_name":"White-bellied Tody-Tyrant","scientific_name":"Hemitriccus griseipectus","overview":"白腹哑霸鹟（英文名：White-bellied Tody-Tyrant，学名：Hemitriccus griseipectus），是雀形目霸鹟科侏哑霸鹟属的鸟类。主要栖息于南美洲亚马孙雨林的低地森林，常见于秘鲁东南部及邻近地区。其最显著的特征是轻橄榄绿色的上体与灰白色的下体，以及独特的苍白虹膜。","appearance":"白腹哑霸鹟拥有短小的尾巴，橄榄灰色的背部，腹部呈灰白色，翼羽边缘有淡黄色的尖端，形成两道翼带，眼睛周围有不显眼的白色羽毛。成年鸟的性别相似，喉部略带灰色条纹，胸部非常浅灰色，侧边微泛黄色，腹部白色，两翼内侧飞羽的外缘呈黄白色。","call":"白腹哑霸鹟以特有的短促打嗝声的鸣叫著称，声音清晰可辨，通常为‘ta-teek’。","habits":"这种鸟主要在森林的下层和中层活动，以昆虫为食，通过短暂的飞行捕捉猎物。它倾向于静静地停在枝头，然后突然飞向新的位置。","breeding":"关于白腹哑霸鹟的繁殖习性的具体信息较少，但一般而言，霸鹟科的鸟类会筑巢繁殖，有特定的繁殖季节。","identification":"与其他Hemitriccus属的物种相比，白腹哑霸鹟的翼部没有明显的斑纹，虹膜颜色较浅，且叫声独特。与Flammulated Pygmy-Tyrant、小哑霸鹟和奇氏哑霸鹟的区别在于翼部图案、虹膜颜色以及栖息环境。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊流域的低地森林，主要在秘鲁东南部、巴西东部以及玻利维亚的部分地区。","other":"白腹哑霸鹟曾与北部亚马逊地区的白眼哑霸鹟归为同一物种。"},{"name":"奇氏哑霸鹟","english_name":"Zimmer's Tody-Tyrant","scientific_name":"Hemitriccus minimus","overview":"奇氏哑霸鹟（英文名：Zimmer's Tody-Tyrant，学名：Hemitriccus minimus），是雀形目霸鹟科侏哑霸鹟属的小型鸟类。以美国鸟类学家John Todd Zimmer命名，以其非常细长的喙和黄色的眼睛为显著特征。广泛分布于南美的亚马逊雨林地区。","appearance":"奇氏哑霸鹟是一种极小的捕虫鸟，拥有细长的喙和黄色的眼睛。其上部羽毛呈橄榄褐色，下部为橄榄色带微暗的条纹，翼上有两道明显的黄色翼杠。雌雄羽色相似，幼鸟的特征可能略有差异。","call":"其鸣唱为清脆的颤音“Triieee”，在森林中回响。","habits":"奇氏哑霸鹟主要栖息在森林地带，尤其是贫瘠土壤上的白砂森林中。它们活跃于树冠层，善于捕食昆虫。","breeding":"关于奇氏哑霸鹟的繁殖习性的具体信息较少，但一般而言，这类鸟会在繁殖季节进行求偶、筑巢、交配、产卵等一系列繁殖行为。","identification":"与小哑霸鹟相似，但奇氏哑霸鹟具有更为明显的翼杠，且其鸣声截然不同。","protection":"IUCN状态未知。目前没有列入华盛顿公约(CITES)附录或中国国家重点保护野生动物名录。","distribution":"分布于南美洲亚马逊雨林的局部地区，包括厄瓜多尔东南部（Kapawi）、秘鲁东部（伊基托斯附近，上乌卡亚利河）、巴西（阿克雷州西北部至帕拉州东部，南至托坎廷斯和马托格罗索）、玻利维亚东北部（潘多东部、贝尼东部、圣克鲁斯北部）。在适宜的生境中，预计在更广泛的亚马逊地区也有分布。","other":"奇氏哑霸鹟的分类学历史中没有提及合并或分拆的情况。"},{"name":"橄榄色哑霸鹟","english_name":"Eye-ringed Tody-Tyrant","scientific_name":"Hemitriccus orbitatus","overview":"橄榄色哑霸鹟（英文名：Eye-ringed Tody-Tyrant，学名：Hemitriccus orbitatus），是雀形目霸鹟科侏哑霸鹟属的小型鸟类，仅见于巴西东南部的热带低地森林。其最显著的特征是白色的环眼圈和眼下的淡色斑点。","appearance":"该鸟体长约11.5厘米，体重介于9至10.5克之间。头部和背部呈深橄榄色，无花纹，具有明显的白色眉纹和眼圈；翅膀为橄榄色，内侧飞羽边缘有显眼的白色边界；尾巴暗橄榄色；喉咙灰白色，胸部带有橄榄色，且有深橄榄色的条纹，其余腹部黄色；虹膜深棕色；上喙灰色，下喙浅色；腿为浅灰色。雄雌相似。","call":"发出快速的吱吱声颤音，类似‘tr-r-r-r-r-r-r-r-r’或‘tirrit, tirririt’。","habits":"单独或成对在森林的低层和中层活动，通常在森林内部远离边缘地带。垂直停栖在树冠下的暴露枝干上；做短暂的向上冲击动作，从叶片下表面捕获猎物。","identification":"以其独特的白色眼圈和眼下的淡色斑点易于识别。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲巴西东南部的热带低地森林。"},{"name":"乔氏哑霸鹟","english_name":"Johannes's Tody-Tyrant","scientific_name":"Hemitriccus iohannis","overview":"乔氏哑霸鹟（英文名：Johannes's Tody-Tyrant，学名：Hemitriccus iohannis），是雀形目霸鹟科侏哑霸鹟属的鸟类。体型小巧、色泽暗淡的飞禽。分布于南美洲的亚马孙雨林西部，包括巴西、哥伦比亚、厄瓜多尔、秘鲁和玻利维亚等地，主要栖息于热带湿润低地森林和严重退化的次生森林。","appearance":"乔氏哑霸鹟长约11厘米，体重介于9.2至12.7克之间。头部至背部呈均匀亮丽的橄榄色，眉区和眼周为褐色，有时可见白色眉纹。翅膀为深橄榄色，翼羽边缘微黄，形成两道模糊的黄色翼带。喉咙呈白色，有非常细小的黑色条纹，腹部为淡黄色，胸部两侧和胁部略带橄榄色斑点。虹膜颜色从白色到浅稻草黄色不等，喙呈深灰色至黑褐色，腿脚为淡黄色、粉红色或浅灰色。雌雄鸟外观相似。","call":"其鸣声独特，快速而断续的颤音前有一单独的起始音符，音调逐渐升高，如同‘tik-trrrrrrrrrrrrrrree’。","habits":"乔氏哑霸鹟常在茂密的次生植被中直立停栖，包括河边的再生植被和竹林丛。它们的活动范围涵盖了亚马孙雨林西部的热带湿润低地森林，以及严重退化后的森林环境。","identification":"乔氏哑霸鹟与同属物种相比，其亮橄榄色的头部至背部，以及独特的鸣声，是重要的识别特征。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马孙雨林西部，包括巴西、哥伦比亚、厄瓜多尔、秘鲁和玻利维亚等地。"},{"name":"纹颈哑霸鹟","english_name":"Stripe-necked Tody-Tyrant","scientific_name":"Hemitriccus striaticollis","overview":"纹颈哑霸鹟（英文名：Stripe-necked Tody-Tyrant，学名：Hemitriccus striaticollis），是雀形目霸鹟科侏哑霸鹟属的小型鸟类。其分布于南美洲亚马逊雨林西部和南部，常见于半湿润的灌木丛生环境。","appearance":"纹颈哑霸鹟体型较小，羽毛主要呈淡黄色调，腹部色彩最为鲜艳。喉部白色，饰有强烈的灰色条纹，逐渐融入胸部较为模糊的斑纹。与近似种乔氏哑霸鹟相比，纹颈哑霸鹟具有更为明显的喉部标记和整体更明亮的色泽。","habits":"纹颈哑霸鹟偏好栖息于半湿润的灌木丛生环境，尤其是藤蔓交织的复杂地带。它们的活动范围和觅食习惯尚待详细研究。","breeding":"繁殖季节，纹颈哑霸鹟会在低至地面约1米的树冠水平枝上建造巢穴，巢材包括植物纤维、细草和绿色苔藓，有时也会混入枯黄的叶子和小块树皮。每窝产卵2枚，除此之外的繁殖细节尚不明确。","identification":"与乔氏哑霸鹟的区别在于纹颈哑霸鹟更强的喉部条纹和整体更加鲜艳的羽毛颜色。","protection":"IUCN：LC（无危）。在Tambopata-Candamo保护区（秘鲁）、Beni生物圈保护区和Noel Kempff Mercado国家公园（玻利维亚）、Pantanal Mato-grossense和Tapajós国家公园（巴西）等地有分布。哥伦比亚东部和秘鲁东北部两个孤立小群体的状况未知。","distribution":"纹颈哑霸鹟分布于南美洲亚马逊雨林的西部和南部区域，包括巴西、玻利维亚、哥伦比亚和秘鲁的部分地区。"},{"name":"悬巢哑霸鹟","english_name":"Hangnest Tody-Tyrant","scientific_name":"Hemitriccus nidipendulus","overview":"悬巢哑霸鹟（英文名：Hangnest Tody-Tyrant，学名：Hemitriccus nidipendulus），是雀形目霸鹟科侏哑霸鹟属的鸟类，体型微小，栖息于南美洲巴西的密集林地、森林边缘及沿海森林。其最显著的特征是头部及上体呈现亮橄榄绿色，喉部至腹部白色，略带淡灰橄榄色条纹，眼虹膜呈奶油白色。","appearance":"体长约9.5-10厘米，体重约7.2-8克。头部、面部及上体亮橄榄绿色，眼周稍显黄绿色；翅膀和尾巴橄榄色，翼羽缘明显黄色；喉部及腹部白色，胸及两侧具淡灰橄榄色细条纹；眼虹膜奶油白色；喙棕色，下颌基部灰色粉红；跗蹠浅灰色。雄雌相似。亚种paulistus略大，尾较长。","call":"鸣唱为一系列高音‘prre-prrew-prrew’音符。","habits":"偏好居住于密林地带，如森林边缘和沿海森林，自然生境为亚热带或热带湿润低地森林及重度退化旧森林。","breeding":"繁殖期间，会建造独特的长形袋状悬挂巢。","identification":"识别特征包括两色外观，亮橄榄绿背部，无翼纹，下体白色，喉部轻微条纹。与近缘物种相比，巢型独特。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲巴西东部和东南部，主要栖息于亚热带或热带湿润低地森林。"},{"name":"斑臀哑霸鹟","english_name":"Pearly-vented Tody-Tyrant","scientific_name":"Hemitriccus margaritaceiventer","overview":"斑臀哑霸鹟（英文名：Pearly-vented Tody-Tyrant，学名：Hemitriccus margaritaceiventer），是雀形目霸鹟科侏哑霸鹟属的鸟类，体型非常小，具有橄榄褐色上部和白色的翼纹，腹部颜色和背部色调因亚种而异，通常为灰色或黄色，背部为暗灰色或棕色。广泛分布在南美的北部、中南部和东部地区。","appearance":"斑臀哑霸鹟长约10至10.5厘米，体重7至10克。全身呈现灰褐色或棕橄榄色，冠部稍显灰色，眼圈和鼻纹白色。翅膀深色，翼纹从淡黄至白色，尾羽深色。喉部及下体白色，带有模糊的灰色条纹。虹膜颜色从淡稻草色到血橙色或浅榛色不等。喙色从红棕色到黑色，下颚粉棕色至粉色。腿粉色至浅灰粉色。不同亚种在色彩上有显著差异，如背部颜色、翼纹对比度、喉咙条纹和侧腹的黄色调。","call":"斑臀哑霸鹟的鸣声为一系列尖锐的断音，随后是一段短暂至长的、音乐般的颤音，音高可能上升或下降，典型声音为“tick-tick-tr’r’r’r’r’r’r’r”。同时也会发出短促的鼻音颤音或柔和的机械式蛙鸣声。在觅食时，会发出响亮、尖锐的叫声，如‘tuk, tuk, quéek, quéek’，或连续两至四个音节，每个音节比前一个音节更高。","habits":"栖息于干燥至半干燥的灌木丛、低矮的落叶林下层和有灌木的牛牧场，偶尔出现在茂密的河岸植被中。海拔范围从海平面至2000米，多数情况下低于1000米。主要以昆虫为食，单独或成对在灌木和低树的低至中层活动，有时接近地面几厘米处，主要在眼睛高度范围内停留短暂时间，快速向上出击以捕获叶子背面的昆虫。","breeding":"繁殖季节在哥伦比亚为1月至6月，在秘鲁、玻利维亚和阿根廷为10月至12月。巢穴呈悬挂的长袋状，穹顶形状，侧面入口靠近底部，上方有小檐，由干草叶、细植物纤维和不同程度的植物绒毛构成，内部铺满白色至深锈色的植物绒毛。巢悬挂在离地面0.5至3米高的树木、灌木或草本植物的下垂枝条上。每窝产卵2至3枚，常见2枚，偶尔1枚。孵化期未知，雏鸟期13至14天。","identification":"斑臀哑霸鹟与其他侏哑霸鹟属物种的区别在于其特定的色彩模式，尤其是腹部颜色、背部色调、翼纹的对比度以及喉咙上的条纹。亚种之间在这些特征上存在差异，如impiger亚种的冠部和背部颜色更深，chiribiquetensis亚种的喉咙条纹更明显且黑色，duidae亚种的腹部颜色从淡黄色到橙黄色。","protection":"IUCN：LC（无危）。在玻利维亚的Beni生物圈保护区、Madidi国家公园和Noel Kempff Mercado国家公园，以及巴拉圭的Caaguazú、San Rafael、San Luis和Ybycuí国家公园均有分布。阿根廷的San Juan de Poriahú私人保护区（位于Iberá省级保护区）也有其踪迹。巴西的Mata dos Godoy州立公园（Paraná）、Brasília和Serra da Canastra国家公园也有记录，同时在里约格兰德诺特省的Mata Estrela私人保护区有报道。在乌拉圭的Cerro Corá国家公园可能也有分布。","distribution":"分布于南美的北部、中南部和东部，具体包括阿根廷、玻利维亚、巴西、哥伦比亚、巴拉圭、秘鲁、乌拉圭和委内瑞拉。"},{"name":"佩氏哑霸鹟","english_name":"Pelzeln's Tody-Tyrant","scientific_name":"Hemitriccus inornatus","overview":"佩氏哑霸鹟（英文名：Pelzeln's Tody-Tyrant，学名：Hemitriccus inornatus），是雀形目霸鹟科侏哑霸鹟属的鸟类。分布于南美洲巴西西北部低矮的白沙滩森林中。","appearance":"佩氏哑霸鹟体型非常小，背部呈橄榄绿色，腹部白色并带有细薄的灰色条纹。翼上有白色翼斑，这一特征有助于识别。","call":"其鸣声容易被忽视，是一种低沉而短促的颤音，表现为“tid-dip, tid, te, de”的反复。","habits":"栖息于低矮的白沙滩森林，活动范围受限，具体的生活习性细节尚待更多研究。","breeding":"关于佩氏哑霸鹟的繁殖行为与生长周期的具体信息目前记录有限。","identification":"与其他同类物种相比，佩氏哑霸鹟的橄榄绿色背部和白色腹部带灰色条纹的特征较为独特，同时其特有的鸣声也是重要的辨识点。","protection":"IUCN状态未知，需进一步关注其保护状况。","distribution":"分布于巴西的亚马逊河流域（包括R Negro和R Branco流域）、Roraima州、Pará州以及苏里南中部的Tafelberg地区，可能也存在于邻近的委内瑞拉和哥伦比亚。","other":"尽管在特定区域内分布，但具体的生态习性和生存威胁尚需进一步研究以制定有效的保护措施。"},{"name":"黑喉哑霸鹟","english_name":"Black-throated Tody-Tyrant","scientific_name":"Hemitriccus granadensis","overview":"黑喉哑霸鹟（英文名：Black-throated Tody-Tyrant，学名：Hemitriccus granadensis），是雀形目霸鹟科侏哑霸鹟属的鸟类。小型鸟类，分布于南美洲从委内瑞拉至秘鲁的安第斯山脉地区。其最显著的特征是黑色的上喉部和灰白色的下喉部，以及橄榄色的背部和灰白色的腹部。","appearance":"体长8.5至10.5厘米，体重6.5至8.5克。头部和上体呈暗橄榄色，眼周白色形成宽阔的眼环，类似眼镜的外观。翅膀暗橄榄色，翼弯亮黄色，尾部深灰色。上喉部和下颊部黑色，下喉部白色，两旁略带灰色。胸部有淡灰色的带状图案，向下渐变为白色，两侧泛黄。虹膜颜色从栗色到浅橙色不等，喙黑色，腿灰色至粉灰色。雌雄相似，幼鸟虹膜为深棕色。","call":"发出沙哑的“dut't't”声，鼻音的“tip-buuuuu”和尖锐的“pik, peet, peet”。黎明时的歌曲以“kee kee kee krrrrrrrt”开始，以急促的颤音结束。巡逻时会发出短促的颤音“krrrt”。报警时重复“keep keep”的叫声，类似Synallaxis spinetail的声音。飞行时有翅膀振动的声音。","habits":"栖息于潮湿的苔藓山地森林、矮化的上层云雾林、灌木丛生的次生林和云雾林边缘，常出现在过长的滑坡和其他较开阔的区域附近，海拔高度在1800至3300米之间，主要在2000至3000米。有时跟随混合物种群觅食。","breeding":"繁殖季节在哥伦比亚为3月至7月，在秘鲁为12月。已知三种巢穴类型，分别位于哥伦比亚的两个地方和秘鲁的一个地方。巢穴通常为一个隐蔽的袋状结构，悬挂在小树枝上，入口侧开并被植被遮蔽。已观察到的两个巢穴中只有一个蛋，平均大小为18.1毫米×12.9毫米，重量为1.55克，颜色从淡褐色到明亮的白色，带有零散的红色斑点。孵化期为19天，巢的看守率为77.5%。","identification":"与其他同属物种相比，黑喉哑霸鹟的黑色上喉部和眼周的白色环是其独特之处。不同亚种在羽色上有细微差异，如lehmmani亚种的上体更黄绿，lores和眼区更浅色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的委内瑞拉至秘鲁，主要在安第斯山脉的潮湿山地森林中。在哥伦比亚的Tambito自然保护区、厄瓜多尔的Podocarpus国家公园以及秘鲁的Río Abiseo国家公园和Machu Picchu历史保护区都有记录。","other":"种族andinus了解甚少，最近仅在秘鲁东南部（普诺）的模式产地有确切记录，也在玻利维亚（拉巴斯）发现，但在那里较为罕见且局部分布。"},{"name":"黄胸哑霸鹟","english_name":"Buff-breasted Tody-Tyrant","scientific_name":"Hemitriccus mirandae","overview":"黄胸哑霸鹟（英文名：Buff-breasted Tody-Tyrant，学名：Hemitriccus mirandae），是雀形目霸鹟科侏哑霸鹟属的鸟类，体型小巧，色泽暗淡。头部相对较大，上体橄榄色，下体呈浅色，最显著的特点是淡黄色的眼纹和眼圈。主要分布于巴西东北部，生活在海拔较高的湿润森林残余地带。","appearance":"身长10厘米左右，冠部及背部呈深橄榄色，翅膀与尾巴为暗橄榄色，内侧次级飞羽边缘宽阔且颜色较浅；眼纹、眼周、脸颊、喉部和胸部均为均匀的浅奶油色，腹部更接近白色，逐渐过渡至臀部的淡黄色；虹膜橙色；喙灰色，下颚颜色较淡；腿灰至淡粉色。雌雄外观相似。","call":"鸣唱为一系列尖锐的‘kit-kit-kit-kiit-kiit-kiiit-kit’音节，音调急促。","habits":"栖息于巴西东北部孤立山脊的高海拔湿润森林残留区。全球数量估计为几千只，分布范围严重碎片化，约1800平方公里，栖息地正遭受大规模森林砍伐的持续威胁。","breeding":"关于繁殖行为的具体信息缺失。","identification":"其独特的头部比例、眼纹和眼圈颜色，以及特有的鸣叫声是与其他物种区分的关键特征。","protection":"IUCN：VU（易危）。物种受到严格限制，仅存于大西洋坡的阿拉戈斯和伯南布哥生态区。全球种群数量稀少，栖息地极度破碎，正面临快速丧失的风险。","distribution":"局部分布于巴西东北部，包括塞阿拉州、帕拉伊巴州、伯南布哥州和阿拉戈斯州的孤立山脊。","other":"在巴西的某些特定地点，如Fazenda Gameleira、Serra da Ibiapaba和Serra do Baturité州立环境保护区等地有所记录，但保护效果尚不明朗。"},{"name":"棕胸哑霸鹟","english_name":"Cinnamon-breasted Tody-Tyrant","scientific_name":"Hemitriccus cinnamomeipectus","overview":"棕胸哑霸鹟（英文名：Cinnamon-breasted Tody-Tyrant，学名：Hemitriccus cinnamomeipectus），是雀形目霸鹟科侏哑霸鹟属的鸟类。分布于南美厄瓜多尔东南部至秘鲁北部的偏远山地。其最显著的特征是亮棕色的胸部，耳羽盖和眼圈呈较暗的棕色，腹部黄色，上体橄榄绿色。","appearance":"成年棕胸哑霸鹟的上体为橄榄绿色，头部和颈背带有褐色调。脸部和耳羽盖为肉桂色，下巴至喉部渐变为温暖的淡黄色，胸部呈现亮丽的暖棕色，腹部颜色最为鲜艳，接近硫磺黄。两翼和尾巴为深灰色，翼羽和尾羽边缘有橄榄黄色。幼鸟的喉部和胸部为浅沙色，全身下体被这种颜色覆盖，上体普遍带褐色调，翅膀和尾巴类似成鸟。","call":"其叫声包括短暂的下滑颤音和连续三到七个尖锐的吱吱声。","habits":"栖息于低矮的云雾林较低至中层，通常在昏暗的环境中快速移动，难以观察。分布于海拔1700至2200米的密集苔藓覆盖的山地森林下层。","breeding":"具体繁殖信息未详述。","identification":"与同属其他物种如黄喉哑霸鹟和棕胸窄嘴霸鹟有明显的区分点，包括颜色模式和生境差异。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲厄瓜多尔东南部及秘鲁北部的几个孤立山脉，主要栖息于海拔1700至2200米的山地森林。","other":"由于其有限的分布范围，棕胸哑霸鹟目前面临栖息地丧失的威胁。"},{"name":"凯氏哑霸鹟","english_name":"Kaempfer's Tody-Tyrant","scientific_name":"Hemitriccus kaempferi","overview":"凯氏哑霸鹟（英文名：Kaempfer's Tody-Tyrant，学名：Hemitriccus kaempferi），是雀形目霸鹟科侏哑霸鹟属的鸟类。为巴西东南部大西洋森林所特有，其发现历史充满神秘色彩，直至1990年代才首次被观察到活体。体长约10厘米，橄榄绿色，眼周环绕着淡色圈环。","appearance":"凯氏哑霸鹟体型小巧，通体橄榄绿色，背部暗橄榄色，翼缘黄色明显，具宽阔的黄边。头部冠羽呈淡橄榄色，脸颊及眼区为淡黄色，上身深橄榄色，翼部橄榄色带淡黄色边缘。尾巴暗橄榄色，尖端稍淡，外侧尾羽稍长并向外弯曲。喉部与胸部为暗赭色，带有绿橄榄色调，腹部均匀淡黄色。虹膜棕色至暖赭棕色，喙灰色，下颚较浅，腿深灰色。雌雄外观相似。","call":"其叫声为一系列高音鼻音、沙哑的“kuít-kuít”或“kwit-kwit”音符，有时会发出“kwit kwit-kwit kwit-kwit kwit-kwit”的重复声，与橄榄色哑霸鹟的叫声相似。","habits":"凯氏哑霸鹟栖息于低地热带常绿林及次生灌木丛，偏好低矮、荫蔽的植被，常伴有Cecropia和heliconias等丰富的地面植物，通常靠近河流。海拔高度从海平面至150米。它们以昆虫为食，如鳞翅目幼虫。通常单独或成对在密林中觅食，离地0.5至3米高，长时间停顿后快速向上击打或悬停捕食叶片下的昆虫。","identification":"与其他地理隔离的棕胸哑霸鹟相似，但通过其独特的冠羽颜色、翼缘黄色、腹部颜色等特征可以区分。","protection":"IUCN：VU（易危）。全球估计成熟个体数量为6000-12000只。栖息地因森林砍伐、农业转化、城市化及道路建设而严重破碎。受巴西法律保护，被列入美国濒危物种名单。","distribution":"分布于巴西东南部，具体在SE Paraná和NE Santa Catarina地区。","other":"凯氏哑霸鹟首次发现于1929年，但直到很久以后才正式命名。自1991年后，多次在Salto do Piraí附近被重新发现，部分栖息地现已在Bracinho生态站得到保护，尽管尚未记录到物种在保护区内的存在。"},{"name":"黄喉哑霸鹟","english_name":"Buff-throated Tody-Tyrant","scientific_name":"Hemitriccus rufigularis","overview":"黄喉哑霸鹟（英文名：Buff-throated Tody-Tyrant，学名：Hemitriccus rufigularis），是雀形目霸鹟科侏哑霸鹟属的鸟类。体型小巧、数量稀少，分布于南美洲安第斯山脉东侧的云雾森林，从厄瓜多尔到玻利维亚北部。其生境通常位于海拔800至1500米之间，偏好潮湿山麓森林，以丰富的藤蔓缠绕为特色。","appearance":"这种小型的鸟拥有橄榄绿色的背部和翅膀，头部和胸部呈现淡黄色，腹部则是淡淡的灰色，有时在南方分布区可见轻微的下部条纹。成年鸟的头部冠部和颈背为灰黄色，上体橄榄绿，翼羽和尾羽边缘带有黄绿色，翼弯和下翼覆羽黄色。眼圈不明显，呈淡黄色。头侧、喉部和上胸为淡肉桂色，隐约带有灰色条纹，其余下体白色，腹部略带黄色，尾下覆羽淡黄色。幼鸟特征尚未详细描述。","call":"发出尖锐的‘weep’叫声，要么以悠闲的方式连续出现，要么快速连发，其叫声在整个白天持续，有助于观察者定位这一容易被忽视的物种。","habits":"主要栖息于南美安第斯山脉东部的云雾森林，海拔高度介于800至1500米。活动范围在较低至中层的森林中，通常单独或成对出现，偶尔加入混合物种群。它会持续地发出鼻音的kik-keek-keek keek kéék叫声。","breeding":"关于黄喉哑霸鹟的繁殖生态知之甚少，但据观察，它们似乎占据非常小的领地。","identification":"与棕胸哑霸鹟在地理上有所重叠，但后者通常出现在更高的海拔（1700至2200米）。黄喉哑霸鹟的喉咙颜色更浅，头部两侧无橘色，腹部为白色而非黄色。与棕胸窄嘴霸鹟相比，后者体型更大，尾巴更长，具有灰色的头部顶部，翼羽和覆羽边缘较浅，胸部红色更深，脸部侧面为灰色，带有肉桂色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从厄瓜多尔南部至玻利维亚北部，主要栖息于安第斯山脉东侧的潮湿山麓森林。","other":"全球近危物种，生活在特定海拔范围内的云雾森林中，对于其自然历史了解甚少。"},{"name":"叉尾哑霸鹟","english_name":"Fork-tailed Tody-Tyrant","scientific_name":"Hemitriccus furcatus","overview":"叉尾哑霸鹟（英文名：Fork-tailed Tody-Tyrant，学名：Hemitriccus furcatus），是雀形目霸鹟科侏哑霸鹟属的鸟类。主要分布于巴西东南部的亚热带或热带湿润森林中，包括低地森林和山地森林。该鸟种因独特的头部图案和叉尾而著名。","appearance":"叉尾哑霸鹟体长约11厘米，头部前额亮肉桂棕色，逐渐变为橄榄褐色至后颈和头顶；面部呈可可棕色至肉桂色，眼眶周围和眉纹淡肉桂色；上体鲜亮橄榄绿；翅膀鲜亮橄榄绿，内飞羽边缘具明显肉桂色，最内侧次级飞羽外缘宽大乳白色；尾部特征鲜明，非常长，外侧尾羽最长且略向内弯曲，主要为橄榄绿色，带有显著的白色尖端和黑色次端带；喉咙可可棕色，下方有清晰的白色带或胸中心斑点；胸部和两胁淡灰，微具火焰状斑纹，腹部更白；虹膜橙棕色；喙灰色，下颚较浅，粉红至黄；跗跖灰至粉红色。雌雄相似，雄鸟尾部叉状更为突出。","call":"其鸣唱为一系列快速而高音的音符。","habits":"该鸟种栖息于森林边界和次生林，尤其偏好竹林和藤蔓丛生的环境。","identification":"与其他物种的区别在于其独特的头型和尾部特征，尤其是长叉尾和肉桂色头部。","protection":"IUCN：VU（易危）","distribution":"分布于巴西东南部，包括巴伊亚州、米纳斯吉拉斯州南部、里约热内卢州和圣保罗州东部。"},{"name":"角侏霸鹟","english_name":"Eared Pygmy Tyrant","scientific_name":"Myiornis auricularis","overview":"角侏霸鹟（英文名：Eared Pygmy Tyrant，学名：Myiornis auricularis），是雀形目霸鹟科侏霸鹟属的小型鸟类。其显著特征包括栗色眼斑和黑色新月形耳斑，橄榄黄背部，以及独特的‘prrii-priii-prii’歌声。分布于巴西、巴拉圭和阿根廷东北部的湿润森林地带。","appearance":"体长7厘米，体重仅5克，身材圆胖，头部较大。眼周具淡肉桂色区域，耳羽呈白色，眼下方有黑色斑块，耳羽后缘有黑色新月形斑点形成类似耳朵的外观。上体鲜橄榄绿色，头顶微带棕色，颈背灰色；翅膀暗色，边缘亮橄榄黄色，有两道不明显翼纹；尾部暗色；喉部和上胸部白色，细密黑纹，其余下体鲜黄色，橄榄色条纹；虹膜橙色；喙黑色；跗跖粉红色。雄雌相似。幼鸟未详述。亚种emcinereicollis/em变异大，耳羽通常较淡，灰于指名亚种。","call":"发出一系列‘pic’音节后接音乐般的颤音，‘pic-pic-pic-pree-ee-ee-ee-ee’；飞行时翅膀产生嗡嗡声。","habits":"栖息于湿润森林及边缘地带，常在浓密灌木丛中活动，偶尔会扩展至草地低矮树木。海拔高度可达1250米。以昆虫为食，主要在低层和中层植被中觅食，高度约2-3米；在开阔处停栖，频繁变换停歇位置。飞行时做嗡嗡响的捕食动作。","breeding":"筑巢期在10月至12月间。巢呈钱包状，侧向入口，由枝条、茎和干叶构成，有时带有悬挂的‘尾巴’，悬挂在距地面1-3米的灌木水平枝上。每窝产卵2或3枚。双亲共同喂养雏鸟，但似乎只有雌鸟孵卵。巢穴曾被小雉鹃寄生。","identification":"与同属物种相比，角侏霸鹟的耳斑和眼下的黑色新月形斑块是其独特标志。","protection":"IUCN：LC（无危）。相当常见，尽管其适宜栖息地受到破坏或严重退化，但在其分布范围内仍能在多个国家公园和其他保护区找到。","distribution":"南美洲东南部，包括巴西、巴拉圭和阿根廷东北部的湿润森林和边缘地带。","other":"无"},{"name":"白胸侏霸鹟","english_name":"White-bellied Pygmy Tyrant","scientific_name":"Myiornis albiventris","overview":"白胸侏霸鹟（英文名：White-bellied Pygmy Tyrant，学名：Myiornis albiventris），是雀形目霸鹟科侏霸鹟属的小型鸟类。体型极小，羽毛密集，外观如同一团小巧的绒球，色彩上似蜜蜂与羽绒枕头的结合。分布于南美洲的特定区域，包括厄瓜多尔东南部、秘鲁中东部和玻利维亚北部，栖息于次生林和原始湿润森林。","appearance":"成鸟体长约7厘米，体重仅5-6克。具有圆胖的身体和较大的头部比例。眼周有淡白色区域，耳羽处有灰色新月形斑块；背部呈亮橄榄色，头冠微带棕色；翅膀深色，边缘和两翼条纹隐约可见亮橄榄黄色；尾巴深色；喉咙和上胸部白色，轻微带有灰色斑点，其余下体白色，侧身和臀部略带黄橄榄色；虹膜红色；喙黑色；跗蹠粉色。雌雄外观相似，幼鸟特征未详述。","call":"其鸣唱为一段容易被忽视的、类似昆虫发出的短促快速颤音，逐渐加速至嗡嗡声。","habits":"栖息于高大树木的树冠层，因体型小且活动于树梢，观察较为困难。偏好湿润森林环境，既见于次生林也见于原始林。","breeding":"关于繁殖习性的具体信息尚不明确。","identification":"与角侏霸鹟的主要区别在于前者耳羽新月形斑较不明显，下体颜色更浅，尾巴略短。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的特定区域，包括厄瓜多尔东南部、秘鲁中东部和玻利维亚北部，主要栖息在次生林和原始湿润森林。","other":"在玻利维亚，该物种出现在Pilón Lajas生物圈保护区和Madidi国家公园，常见于Cochabamba的Villa Tunari路下段附近。"},{"name":"黑顶侏霸鹟","english_name":"Black-capped Pygmy Tyrant","scientific_name":"Myiornis atricapillus","overview":"黑顶侏霸鹟（英文名：Black-capped Pygmy Tyrant，学名：Myiornis atricapillus），是雀形目霸鹟科侏霸鹟属的小鸟，为中美洲至南美洲西北部的居民。以全球最小的鸣禽之一而闻名，体型如同高尔夫球般大小，黑顶绿背，腹部呈污白色，具有独特的白色眼圈。其分布范围自尼加拉瓜南至哥伦比亚西部和厄瓜多尔西北部，常见于海拔900米以下的湿润森林边缘。","appearance":"黑顶侏霸鹟是一种极为小巧的飞禽，身长仅约6.5厘米，尾部极短。头部顶部黑色，后部渐变为灰色，背部橄榄绿色，下体淡灰或近白色。雄鸟拥有醒目的黑色冠羽，而雌鸟的头部主要为灰色。两者在羽毛颜色上基本一致，与近缘种短尾侏霸鹟相似。","call":"它的叫声为细薄的ttseep声，有时难以分辨，可能被误认为昆虫或青蛙的声音。家庭群体会以柔和的哨声和颤音进行交流。","habits":"偏好湿润森林的低层和中层，偶尔亦见于树冠层，活动范围包括森林边缘和次生林。以单独、成对或家庭小群体的形式，通过快速冲刺的方式捕食小型昆虫。","breeding":"雌鸟会建造一个长约15厘米的袋状巢，带有侧面入口，悬挂在树上离地1-7米的细枝上。孵化期为15-16天，由雌鸟负责，每窝产两枚带有棕色斑点的白色蛋。","identification":"与短尾侏霸鹟非常相似，但分布区域完全不同，后者位于亚马逊盆地东侧的安第斯山脉东侧。黑顶侏霸鹟是中美洲最小的鸣禽，比黑头哑霸鹟更小，下体颜色为淡灰色而非黄色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域与非繁殖区域一致，主要分布在中美洲的哥斯达黎加至南美洲的厄瓜多尔西北部。","other":"尽管与短尾侏霸鹟有时被视为同一种，但它们的分布区是完全不重叠的。"},{"name":"短尾侏霸鹟","english_name":"Short-tailed Pygmy Tyrant","scientific_name":"Myiornis ecaudatus","overview":"短尾侏霸鹟（英文名：Short-tailed Pygmy Tyrant，学名：Myiornis ecaudatus），是雀形目霸鹟科侏霸鹟属的鸟类。全球最小的雀形目鸟类之一，体长约6.5厘米，体重仅4.2克。头部灰暗，具独特的白色眼圈，背部亮橄榄绿，翅膀和极短的尾巴呈黑色，下体泛黄白色。广泛分布于南美洲亚马逊雨林，从低地至海拔950米处。","appearance":"体型极小，几乎无尾。头部灰暗，眼圈和上眼睑白色明显，形成“眼镜”状外观；背部鲜亮橄榄绿，翅膀边缘黄亮，尾羽短小，多黑色；喉部与腹部白中带淡黄色，虹膜深色，喙长，黑色，腿粉红。雌雄相似，幼鸟与成鸟相近。亚种miserabilis背部较暗绿，头顶和颈背更暗，胸部偏灰，腿部颜色更深。","call":"发出高音调而微弱的声音，类似昆虫或青蛙，常被误认为非鸟类声音。叫声通常为柔和的颤音，有时连续发出短促的‘creek’声，起始缓慢后加速。","habits":"栖息于湿润森林，偶尔出现在树倒区和开阔林地，高度在750米以下。独居或成对活动，偶尔加入混合物种群。主要在树冠层觅食，利用快速、嗡嗡的飞行捕捉叶片上的昆虫，偶尔悬停。飞行时产生的嗡嗡声由翅膀造成。","breeding":"繁殖季节在巴西亚马逊地区为6月中旬至9月中旬，筑袋状侧入口巢，用绿色苔藓、细草、枯叶碎片和根须构成，巢内铺满毛发或细植物纤维。每窝产卵2枚，可能仅雌鸟孵卵，双亲喂养雏鸟并清理粪便囊。","identification":"与同属的黑顶侏霸鹟相比，体型略大，头部具独特白色眼圈，背部颜色更亮。在野外，其外形和行为更易被误认为大型昆虫。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲亚马逊盆地，包括巴西、哥伦比亚、秘鲁、委内瑞拉和苏里南等地的低地和丘陵地带。"},{"name":"北弯嘴霸鹟","english_name":"Northern Bentbill","scientific_name":"Oncostoma cinereigulare","overview":"北弯嘴霸鹟（英文名：Northern Bentbill，学名：Oncostoma cinereigulare），是雀形目霸鹟科嘴霸鹟属的鸟类。体型微小，活跃于中美洲热带低地的湿润森林和林地中。其特征在于独特的向下弯曲的喙，以及灰橄榄色的上体和淡黄色的翼缘。","appearance":"体长9.5至10.5厘米，体重4.5至7克。喙显著向下弯曲，灰色的冠羽与橄榄色的背部形成鲜明对比；翅膀暗淡，边缘呈柠檬黄色；面部、喉部和胸部为淡灰色，带有橄榄色条纹；下腹部和臀部泛着淡柠檬黄色，两胁略带橄榄色；虹膜淡黄色；喙基部粉色；腿粉色。雌雄相似。幼鸟具有橄榄色的冠羽，窄淡黄色的翼斑和飞羽边缘，喙色暗淡。","call":"常见叫声为低沉的，类似蛙鸣的churr声。","habits":"主要在森林内部和边缘的低至中层活动，从一个栖木飞向另一个，然后静坐不动。栖息于热带低地的湿润森林和林地。","breeding":"具体繁殖信息未提及。","identification":"与南弯嘴霸鹟最明显的区别在于喉咙和胸部的底色为灰白色，而非黄白色。","protection":"IUCN状态未提及。","distribution":"分布于中美洲，从墨西哥南部至巴拿马。在墨西哥南部（南韦拉克鲁斯，北瓦哈卡）至巴拿马西部（加勒比海沿岸东至科隆省和太平洋沿岸西至奇里基省）；哥伦比亚西北部（安蒂奥基亚省西北部）可能有标本记录。","other":"未提及其他重要信息。"},{"name":"南弯嘴霸鹟","english_name":"Southern Bentbill","scientific_name":"Oncostoma olivaceum","overview":"南弯嘴霸鹟（英文名：Southern Bentbill，学名：Oncostoma olivaceum），是雀形目霸鹟科嘴霸鹟属的小型鸟类。其最显著特征为向下弯曲的喙，如同折断的鼻子。体色上部橄榄绿，下部淡黄色，眼睛呈浅灰色。常单独出现在低地森林的林下层，边缘地带及次生林，通过颤音鸣叫最容易被发现。分布于巴拿马至哥伦比亚，与相似的北弯嘴霸鹟无地理重叠。","appearance":"体型微小，长约9厘米，体重仅6至7克。喙独特，具有向下弯曲的鼻脊。羽毛上部橄榄绿色，眼上区域白色；翅膀暗淡，有两道不明显的黄绿色翼带和柠檬黄色边缘，尾巴暗橄榄色；喉部和胸部黄白色，有橄榄色条纹，其余下部橄榄黄色，腹部黄色；虹膜浅黄色到暗色；喙灰色；腿粉红色偏暗。与北弯嘴霸鹟的主要区别在于喉部和胸部基色为黄白色而非灰白色。雌雄外观相似，幼鸟特征未详述。","call":"通过颤音鸣叫最容易被发现。","habits":"栖息于低地森林的林下层，边缘地带及次生林。关于其飞行特点、活动范围、觅食方式方法、食物、捕食者等具体生活习性信息未提供。","breeding":"在巴拿马，单个巢穴在4月底和8月初被记录；在哥伦比亚，鸟类在2月至6月处于繁殖状态。巢呈小型圆形穹顶状，侧面入口靠近顶部，带有小檐篷，悬挂在离地面1至4米的细树枝上。一窝通常产2枚卵；孵化期平均为19.4天，对于雏鸟离巢时间信息未知。","identification":"与北弯嘴霸鹟的主要区别在于喉部和胸部的颜色，前者为黄白色，后者为灰白色。","protection":"IUCN状态未提及。","distribution":"分布于中美洲的巴拿马（加勒比海斜坡自北科克莱省起，太平洋斜坡自运河区域开始）和南美洲西北部的哥伦比亚（自乔科省向东至马格达莱纳和北昆迪纳马卡）。"},{"name":"鳞冠侏霸鹟","english_name":"Scale-crested Pygmy Tyrant","scientific_name":"Lophotriccus pileatus","overview":"鳞冠侏霸鹟（英文名：Scale-crested Pygmy Tyrant，学名：Lophotriccus pileatus），是雀形目霸鹟科冠侏霸鹟属的鸟类。该羽冠在吸引配偶或受惊吓时会竖立起来，使鸟显得更大。分布于中美洲和南美洲，包括哥伦比亚、哥斯达黎加、厄瓜多尔、巴拿马、秘鲁、委内瑞拉，可能还有洪都拉斯。","appearance":"体长9.7厘米，体重7-8克。最显著的特征是淡色的眼睛和带黑色斑点的红褐色冠羽，当冠羽竖起时形成独特的羽冠，即使在不竖起时，冠羽也显得蓬松。整体呈橄榄棕色，腹部白色带有模糊的条纹，翼上有两道模糊的淡色翼带。雄鸟与雌鸟的外观相似，但雄鸟的冠羽更加发达。幼鸟的描述不详。","call":"发出尖锐的叫声和短暂的昆虫般的颤音。","habits":"通常单独或成对出现在森林边缘、次生林或有时在森林内部。偏好竹林环境，特别是在安第斯山脉东坡的山脚和较低山坡，海拔高度在700-2100米之间，局部可达300-2300米，偶尔低至100米。主要以甲虫、膜翅目昆虫（如黄蜂和蚂蚁）、半翅目昆虫、同翅目昆虫和蛛形纲动物为食。","breeding":"繁殖季节在哥伦比亚为3月至6月。筑巢于离地面约3.5米高的树枝上，巢呈袋状，顶部有侧入口和小檐，由细小的浅色纤维构成，巢口上方有小篷遮盖，巢边有细长的垂挂物。一窝产2枚卵，仅雌鸟参与孵卵。","identification":"与其它小型鵙鸟相比，其体型、羽冠图案以及特殊的叫声有助于区分。不同亚种在羽冠颜色、翼羽边缘颜色和喉部颜色上有细微差别。","protection":"IUCN：LC（无危）。在整个分布范围内相当常见，出现在多个国家公园和其他保护区中。由于其能容忍退化和孤立的栖息地，且分布范围相对较大，因此被认为不太可能受到威胁。","distribution":"分布于中美洲和南美洲，从哥斯达黎加到委内瑞拉北部和秘鲁东南部。在中美洲，已知分布于巴拿马、哥斯达黎加。在南美洲，分布于哥伦比亚、厄瓜多尔、秘鲁、委内瑞拉，可能还包括洪都拉斯。","other":"在2009年，首次在尼加拉瓜北部的Bosawás和El Jaguar保护区被记录。"},{"name":"长冠侏霸鹟","english_name":"Long-crested Pygmy Tyrant","scientific_name":"Lophotriccus eulophotes","overview":"长冠侏霸鹟（英文名：Long-crested Pygmy Tyrant，学名：Lophotriccus eulophotes），是雀形目霸鹟科冠侏霸鹟属的鸟类。分布于南美洲亚马孙盆地西部的巴西、秘鲁和玻利维亚低地雨林。","appearance":"长冠侏霸鹟体长约10厘米，体重介于6.5至8克之间。其显著特征为黑色的长冠羽毛，边缘呈灰色，形成独特的羽冠，有时会竖立并展开，即使平躺时也会延伸至后脑部位。上体橄榄色，翅膀和尾巴暗淡；喉咙和腹部白色，带有灰色条纹。虹膜为黄白色，喙灰色，腿呈淡粉色。雄鸟和雌鸟外观相似。幼鸟特征未详细描述。","call":"长冠侏霸鹟的鸣唱由一系列短暂的‘pit’声组成，这些声音逐渐加速，最终形成一段短促的下降颤音。","habits":"长冠侏霸鹟栖息于低地热带雨林，常见于竹林或茂密的次生林中，偶尔加入混合物种的鸟群。它们直立停栖，通过快速飞行在不同停栖点间捕食飞行中的昆虫。","breeding":"关于长冠侏霸鹟的繁殖行为信息尚不详尽。","identification":"长冠侏霸鹟的长冠羽毛和灰边黑羽是其显著的识别特征。","protection":"IUCN状态未提及。","distribution":"分布于南美洲亚马孙雨林西南部，具体包括巴西（阿马孙河上游普鲁斯河流域）、秘鲁（乌卡亚利南部，马德雷德迪奥斯）和玻利维亚（潘多西北部）。"},{"name":"双斑侏霸鹟","english_name":"Double-banded Pygmy Tyrant","scientific_name":"Lophotriccus vitiosus","overview":"双斑侏霸鹟（英文名：Double-banded Pygmy Tyrant，学名：Lophotriccus vitiosus），是雀形目霸鹟科冠侏霸鹟属的鸟类。偏好砂土森林环境。","appearance":"体长约10厘米，体重6至8.5克。成鸟具有黑色的长冠羽，边缘灰色，形成一个不常竖立的冠状结构；眼先呈灰白色；上体橄榄色；翅膀暗淡，有两条较为明显的绿黄色翼带和边缘，翼弯处黄色（通常隐藏）；尾部暗色；喉部和上胸部白色，有暗橄榄色条纹，两胁和臀部泛淡黄色。雄雌外观相似，但雌鸟的冠羽不如雄鸟发达。幼鸟未详述。不同亚种间，下体颜色和冠羽边缘色彩有差异。","call":"鸣唱为连续重复的尖锐、嗡嗡声的颤音，几乎无地域变异性。","habits":"通常单独或成对活动，栖息于茂密植被内部，偏好较低层，偶尔到达次冠层。静止时突然向上飞扑至树叶中捕食昆虫。主要以昆虫为食，是典型的飞虫捕食者。","breeding":"具体繁殖细节未详。","identification":"与盔侏霸鹟相似，主要通过鸣叫声辨别，若能近距离观察，则可通过清晰的淡色下体（无橄榄色斑点）区分。","protection":"IUCN：LC（无危）","distribution":"分布于巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁和苏里南。自然栖息地为亚热带或热带湿润低地森林及亚热带或热带沼泽地。","other":"系统学历史未详。"},{"name":"盔侏霸鹟","english_name":"Helmeted Pygmy Tyrant","scientific_name":"Lophotriccus galeatus","overview":"盔侏霸鹟（英文名：Helmeted Pygmy Tyrant，学名：Lophotriccus galeatus），是雀形目霸鹟科冠侏霸鹟属的小型鸟类。常见于南美洲亚马逊雨林北部和东南部，以其独特的锤头外观和稀少的目击而闻名。头部具有一簇延长的黑色冠羽，形成显眼的冠饰。","appearance":"体长约10.2厘米，体重约6至7克。头部有长长的黑冠羽，边缘灰橄榄色，形成一个有时竖立并扇形展开的冠饰。上体橄榄色，翅膀暗淡，有两个几乎看不见的橄榄色翼带和窄边，最外侧三个初级飞羽缩短且狭窄。尾巴暗淡，边缘橄榄色。喉咙和下体白色，有灰色细纹。虹膜黄至橙白色，喙灰色，下颚基部粉红色，腿灰粉色。性别相似，幼鸟特征未详述。","call":"鸣唱为一系列不规则的滴答声，有时演变成颤音，经常在白天长时间连续发出。","habits":"栖息于湿润森林下层、次生林及草原林地。常在树隙和藤蔓丛附近安静地坐着，然后向上飞掠，从树叶上捕食昆虫。","identification":"与双斑侏霸鹟相似，但其叫声更为清脆，冠羽更细长，使得冠饰不太显眼，尾巴较长。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉东部（苏克雷、莫纳加斯、玻利瓦尔、阿马索尼）、圭亚那、哥伦比亚东部、秘鲁东北部（洛雷托）和巴西北部（亚马逊州东至阿帕帕州，亚马逊河以南，从塔帕霍斯河向东至马拉尼昂）。","other":"由法国博物学家乔治-路易·勒克莱克，布丰伯爵在1780年首次描述，现属Lophotriccus属，该属结合了古希腊语'lophos'（意为'冠饰'）与'trikkos'（指一种未识别的小鸟，在鸟类学中用于表示霸鹟）。"},{"name":"淡眼侏霸鹟","english_name":"Pale-eyed Pygmy Tyrant","scientific_name":"Atalotriccus pilaris","overview":"淡眼侏霸鹟（英文名：Pale-eyed Pygmy Tyrant，学名：Atalotriccus pilaris），是雀形目霸鹟科淡眼侏霸鹟属的小型鸟类。主要分布在中美洲的巴拿马和南美洲北部的巴西、哥伦比亚、圭亚那、委内瑞拉等地。这种鸟以其独特的淡黄色眼睛和红褐色眼环而著称。","appearance":"淡眼侏霸鹟体型小巧，身长仅约9.7厘米，体重约为6克。上体呈橄榄色，头部侧面带有浅黄褐色，眉纹处接近白色；翅膀暗淡，有两道黄色的翼带，飞羽边缘略显黄色，最外侧四枚初级飞羽显著缩小且变窄；尾巴暗色；喉咙和下体呈灰白色，有棕色条纹，两侧和臀部带有黄色；虹膜为淡黄白色，眼圈狭窄呈黄褐色；喙小，灰色，下颚基部粉红色；腿脚粉红色。雌雄相似，雌鸟的初级飞羽比雄鸟稍少缩短。幼鸟虹膜颜色较深。","call":"它们通常通过响亮的喷溅式颤音和滴答声的叫声被发现。","habits":"淡眼侏霸鹟栖息于低地至海拔2,000米的林地、边缘地带和灌木丛生的次生植被中。常单独或成对出现在林下层至中层，偏好在较为隐蔽的环境中活动。","breeding":"关于淡眼侏霸鹟的繁殖生态信息有限。","identification":"其独特的眼部特征和叫声有助于与其它类似物种区分开来。","protection":"IUCN：LC（无危）","distribution":"淡眼侏霸鹟分布于中美洲的巴拿马以及南美洲北部，包括巴西、哥伦比亚、圭亚那和委内瑞拉。"},{"name":"棕顶哑霸鹟","english_name":"Rufous-crowned Tody-Flycatcher","scientific_name":"Poecilotriccus ruficeps","overview":"棕顶哑霸鹟（英文名：Rufous-crowned Tody-Flycatcher，学名：Poecilotriccus ruficeps），是雀形目霸鹟科哑霸鹟属的鸟类。黑色线条勾勒，黄色腹部和白色的喉部。分布于南美洲安第斯山脉的委内瑞拉至秘鲁北部，偏好竹林和次生林地带。","appearance":"体型微小而丰满，体长约9-10.2厘米，体重约6.6克。头部特征明显，具亮棕色的冠羽，颈部灰色，两者由黑色线条相连。面部有细薄的黑色颊纹，眼上有一白色或淡黄色区域。上体橄榄色，翅膀黑色，有两道较窄的黄色翼带，飞羽和三级飞羽边缘呈黄白色。尾巴橄榄褐色，喉咙和上胸部淡黄色，下体明亮黄色。虹膜深棕色，喙黑色，腿灰色。雌雄相似，幼鸟喉部颜色较浅。","call":"发出低沉的‘chak’、‘tttrew’、‘patreer-pít’或‘pip-prrrrrr’等声音，有时会省略最后一音节；觅食时发出‘tick-trrrrt’声。歌声通常是一系列喷溅声，例如‘pa-treer-pit-pit-pit’。","habits":"主要以昆虫为食，单独、成对或家族群体觅食，偶尔出现在混合物种的鸟群中。在接近地面的茂密植被中做短暂前向或向上飞行以捕获昆虫。","identification":"与其他Tyrannidae家族成员相比，其独特的棕色冠羽和黄色腹部是辨识关键。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的安第斯山脉区域，从委内瑞拉至秘鲁北部。"},{"name":"红头哑霸鹟","english_name":"Lulu's Tody-Flycatcher","scientific_name":"Poecilotriccus luluae","appearance":"红头哑霸鹟体长约9.5厘米，体重约7克。头部红褐色，下颌白色，颈部两侧灰色，背部橄榄色，腹部橙黄色至黄赭色。翅膀主要是黑色，有两条窄黄翼带，初级和次级飞羽边缘黄白色。雄雌相似，尚未描述幼鸟和换羽状态。","call":"鸣声为一系列短促的颤音，常以二重奏形式发出。","habits":"栖息于山地湿润森林边缘的密丛和竹林，常沿道路活动。以昆虫为主食，活动范围有限，尚未详细记录其生态习性和迁徙模式。","breeding":"关于繁殖生物学的资料稀缺，具体繁殖期、筑巢、交配等细节尚待研究。","identification":"与棕头侏霸鹟的区别在于后者下体橄榄色而非亮黄，翅膀红褐色，无白色下颌和灰色颈侧。与棕顶哑霸鹟的分布区不重叠，且后者耳羽淡色，喉部白色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲秘鲁北部，主要在亚马逊斯和圣马丁地区的云雾森林。","other":"由于其小范围内的持续森林损失，被一些人认为处于濒危状态。"},{"name":"白颊哑霸鹟","english_name":"White-cheeked Tody-Flycatcher","scientific_name":"Poecilotriccus albifacies","overview":"白颊哑霸鹟（英文名：White-cheeked Tody-Flycatcher，学名：Poecilotriccus albifacies），是雀形目霸鹟科哑霸鹟属的鸟类。原属Todirostrum属，现归于哑霸鹟属。分布于南美洲秘鲁东南部的竹林中，偶见于玻利维亚西北部及巴西极西部。其独特的羽色和鸣声使其成为竹林中的独特存在。","appearance":"体型小巧，羽毛装饰华丽，下身白色，上身黑色，脸部具一大块白色颊斑，头顶橙色，前额有橙色斑块，背部黄色。雄雌相似，幼鸟的色彩可能较为暗淡。","call":"鸣声为一连串清脆悦耳的音符，呈‘pur pep-pep-pep-pep’的节奏，是寻找它的重要线索。","habits":"偏好纯竹林环境，常单独或成对在竹冠层活动。其分布局限于高大竹林的特定区域，以昆虫为主要食物来源。","identification":"通过其特有的白色颊斑、橙色头部标记和黄色背部，以及清脆的鸣叫声，可与同属其他物种相区分。","protection":"IUCN：LC（无危）。虽然常见度不高且分布局部，但在南美低地森林仍有相对完整的栖息地。然而，采矿、石油/天然气开采及道路建设等开发活动对其生存构成威胁。","distribution":"主要分布于秘鲁东南部的亚马逊地区，包括库斯科地区的亚马逊小屋、马努国家公园及坦博帕塔-坎达莫保护区。此外，也在玻利维亚的潘多省及巴西阿克雷州发现其踪迹。","other":"尽管目前全球状况稳定，但其分布区域内的保护压力不容忽视。"},{"name":"黑白哑霸鹟","english_name":"Black-and-white Tody-Flycatcher","scientific_name":"Poecilotriccus capitalis","overview":"黑白哑霸鹟（英文名：Black-and-white Tody-Flycatcher，学名：Poecilotriccus capitalis），是雀形目霸鹟科哑霸鹟属的小型鸟类。拥有引人注目的黑白相间羽毛，分布于南美洲的低地和山麓雨林中，尤其偏好竹林和密集的藤蔓灌木丛。","appearance":"雄鸟个体上体呈光泽黑色，除眼上方有白色斑点和眼圈，肩部边缘有黄色镶边，有时可见外侧翼羽末端呈浅色（'三色'特征）；腹部全白，仅喉咙侧面和上胸部有黑色侵入，形成不完整的胸带，两胁和臀部有淡黄色调。雌鸟具有独特的栗色帽状羽冠，脸颊和眼圈淡黄，背部和翅膀橄榄色，尾羽深黑，翼缘橄榄色，胸侧灰色，其余下体白色，两胁和臀部淡黄色。嘴上颚黑色，下颚橙黄色，腿灰色或黄橄榄色。","call":"发出快速而尖锐的‘tik, t-r-r-r-r-r-r-ew’声，当受到惊扰时，声音更为爆炸性，表现为连续的‘tk, tk, tk, whey-whey-whey-whuh’。","habits":"栖息于低地和山麓森林中的竹林和藤蔓灌木丛，偶尔出现在湿润的次生林中。常在靠近地面的浓密植被中单独或成对活动，以昆虫为食，采用短距离向前或向上突袭的方式觅食。","breeding":"已知繁殖数据有限，巢呈倒挂的卵圆形，由一对伴侣共同构建，位于旧树倒伏的空隙中，离地面约1.3米高，悬挂在细枝上，巢材包括细条状树皮、暗色根须、活死叶碎片和菌丝，巢体总长143毫米，底部延伸的植被‘尾巴’另加120毫米，横跨133毫米，蛋室尺寸为47.5毫米x55毫米。","identification":"与同属其他物种相比，黑白哑霸鹟的黑白分明的羽毛和特定的鸣叫声是其显著的识别特征。","protection":"IUCN：LC（无危）。总体上被认为是稀有到少见的种类，可能经常被忽视。在厄瓜多尔的卡帕维洛奇和提普蒂尼生物多样性中心附近较为常见。在巴西西南部的状况需进一步调查。","distribution":"分布于南美洲的亚马逊雨林西部和西南部，具体包括哥伦比亚南部（纳里奥省东南部、普图马约省西南部）、厄瓜多尔东部、秘鲁东北部和东部（南至帕斯科省）以及巴西西部（亚马逊州西南部、朗多尼亚州、马托格罗索州西北部）。"},{"name":"黄颊哑霸鹟","english_name":"Buff-cheeked Tody-Flycatcher","scientific_name":"Poecilotriccus senex","overview":"黄颊哑霸鹟（英文名：Buff-cheeked Tody-Flycatcher，学名：Poecilotriccus senex），是雀形目霸鹟科哑霸鹟属的鸟类。体型非常小，分布于巴西中北部的亚马逊地区，属于濒危物种，被列入《世界自然保护联盟》红色目录。其自然生境主要是热带或亚热带的沼泽地带。","appearance":"黄颊哑霸鹟具有独特的外观特征，最显著的是其淡黄色的脸颊和条纹状的喉部。头部上方呈灰色，背部橄榄色，腹部白色。这种鸟的体型极小，是典型的Tyrannidae家族成员。","call":"其鸣叫声为一段深沉的颤音“djrrrt”，通常由几个“chup”音符作为前奏，有时会发出一系列约十五个短促的“djrrrt”音符，音调略降。","habits":"黄颊哑霸鹟栖息于湿润森林边缘，偏好沿黑色水域河流及低矮的白砂森林。它们在特定的地理环境中活动，包括巴西的R Madeira流域、Borba区域以及R Roosevelt和R Madeirinha周边。","identification":"黄颊哑霸鹟通过其独特的淡黄色脸颊和条纹喉部与其他同类相区分。在行为上，其特有的鸣叫声也是辨识的重要依据。","protection":"IUCN：LC（无危）","distribution":"黄颊哑霸鹟主要分布在南美洲的巴西中北部，具体包括亚马逊地区的R Madeira流域、Borba区域、Rondônia的Taquaras一带。"},{"name":"赤黄哑霸鹟","english_name":"Ruddy Tody-Flycatcher","scientific_name":"Poecilotriccus russatus","overview":"赤黄哑霸鹟（英文名：Ruddy Tody-Flycatcher，学名：Poecilotriccus russatus），是雀形目霸鹟科哑霸鹟属的独特鸟类，分布于南美的特普伊山脉地区，包括委内瑞拉东南部、圭亚那西部及巴西北部。其显著特征为橙红色的脸部和胸部，以及短小的尾巴。","appearance":"赤黄哑霸鹟是一种小型而富有魅力的鸟，拥有橙红至赤褐色的脸部和胸部，短尾，以及明显的翼条纹。成鸟与幼鸟的羽毛颜色相似，但在亮度和鲜艳度上有所差异。","call":"其叫声为一种空洞、滚动式的咕噜声，音调逐渐下降，通常由一两个短促的音符引出；这种声音间歇性地发出，常由一对伴侣鸟共同鸣唱。","habits":"赤黄哑霸鹟栖息于海拔1000米以上的湿润森林中层，偏好生长茂盛苔藓和附生植物的环境。它们通常成对活动，有时会加入混杂物种群，但更多时候独立行动。以昆虫为食，捕食时动作谨慎，短暂飞行后停驻于枝头，四处窥探猎物。","identification":"在有限的分布范围内，赤黄哑霸鹟的橙红脸部和胸部以及独特的叫声使其易于与其他物种区分开来。","protection":"IUCN：LC（无危）","distribution":"赤黄哑霸鹟的分布限于南美洲的特普伊山脉，包括委内瑞拉的东南部（玻利瓦尔州东南部）、邻近的圭亚那西部和巴西北部地区。"},{"name":"赭脸哑霸鹟","english_name":"Ochre-faced Tody-Flycatcher","scientific_name":"Poecilotriccus plumbeiceps","overview":"赭脸哑霸鹟（英文名：Ochre-faced Tody-Flycatcher，学名：Poecilotriccus plumbeiceps），是雀形目霸鹟科哑霸鹟属的小型鸟类，分布于南美洲，从秘鲁至阿根廷北部、东部及东南部。其独特外观包括灰色的冠羽和肉桂色的脸颊，环绕着较暗的耳斑。","appearance":"赭脸哑霸鹟是一种体型极小的哑霸鹟，栖息于密集的藤蔓缠绕、木质化的生境，包括森林边缘和次生林，容易被忽视。其独特的羽毛色彩，头部以灰色为主，脸部呈肉桂色，环绕着深色的耳斑。上身橄榄绿色，下身颜色更淡，双翼上有两道黄色的翼条。","call":"它的鸣唱是一种低沉而尖锐的‘trrrp’声，极易被误认为是青蛙或昆虫的叫声。","habits":"赭脸哑霸鹟栖息于亚热带或热带湿润的低地森林，以及山地森林，也能适应严重退化后的森林环境。这种鸟在乌拉圭的首次发现是在1997年，具体地点为Yaguarón河沿岸的画廊森林，位于Cerro Largo省。","identification":"赭脸哑霸鹟的独特之处在于其灰顶肉桂面的外观，以及特有的叫声，使其与同属的其他物种区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的阿根廷、玻利维亚、巴西、巴拉圭、秘鲁和乌拉圭。在乌拉圭，它首次于1997年在Cerro Largo省的Yaguarón河画廊森林被发现。"},{"name":"灰额哑霸鹟","english_name":"Smoky-fronted Tody-Flycatcher","scientific_name":"Poecilotriccus fumifrons","overview":"灰额哑霸鹟（英文名：Smoky-fronted Tody-Flycatcher，学名：Poecilotriccus fumifrons），是雀形目霸鹟科哑霸鹟属的小型鸟类，分布于南美的亚马逊雨林东部及巴西东部。不起眼的霸鹟，以其小体型、相对较大的喙和浓密灌木丛的栖息环境而著称。","appearance":"灰额哑霸鹟具有小巧的身形，喙部相对较大型，身上羽毛颜色较为暗淡，脸部有浅色的眼圈，翼上有黄色的翼斑。雌雄羽色相似，幼鸟的特征不详。","call":"其叫声为类似其他Poecilotriccus属的鸟类，是一种带空洞音质的颤音，常在被发现前先听到其声音。","habits":"栖息于密集的灌木丛和灌丛，尤其偏好沙质土壤的地区。也可在森林边缘和受扰动的生境中找到，通常在有限的范围内不太常见，但可能被低估。以昆虫为主要食物。","breeding":"繁殖季节在巴西托坎廷斯州，巢为封闭袋状，侧入口，悬挂在树枝尖端约1米高的地方。巢中的幼鸟曾被子弹蚁（Paraponera clavata）捕食。","identification":"与Slate-headed Tody-Flycatcher相比，灰额哑霸鹟的羽毛色彩更加暗淡。通过大小、喙型和栖息环境可以区分。","protection":"IUCN：LC（无危）。在苏里南，沿雷利瀑布自然公园的飞机跑道附近较为常见，也在锡帕利温尼草原自然保护区出现。在巴西的EMBRAPA实验站和佩德拉布拉恩卡/香蕉种植园保护区也有记录。","distribution":"分布于巴西东部、法属圭亚那和苏里南的亚马逊雨林东部，主要栖息于亚热带或热带的干燥森林和湿润低地森林。","other":"关于灰额哑霸鹟的系统学历史和详细生态习性的研究仍在进行中。"},{"name":"锈额哑霸鹟","english_name":"Rusty-fronted Tody-Flycatcher","scientific_name":"Poecilotriccus latirostris","overview":"锈额哑霸鹟（英文名：Rusty-fronted Tody-Flycatcher，学名：Poecilotriccus latirostris），是雀形目霸鹟科哑霸鹟属的鸟类。北至哥伦比亚东部，南达玻利维亚北部和巴西南部，东至巴西亚马逊地区的帕拉州。该物种常见于低地潮湿环境中的密集植被，如森林边缘、竹丛、河岸植被和农业区。","appearance":"锈额哑霸鹟体型小巧，外观朴素，头部较大，尾巴短小，整体呈灰褐色，面部和嘴基部附近有红褐色斑纹，翼羽边缘略带黄色。上体橄榄色，下体灰白色，眼环淡黄，翅膀覆羽有赭色边缘，翼下覆羽和翼羽尖端有黄色边线。","call":"发出类似‘ti-trrrrrr’的音乐性颤音和‘tuck’的坚实叫声。","habits":"偏好生活在密集植被中，通常单独或成对活动，很少加入混合物种群。以昆虫为主食，飞行技巧高超，能够迅速捕捉飞虫。","breeding":"关于其繁殖生态学的信息尚未发表。","identification":"与灰额哑霸鹟相似，但后者腹部更黄，面部淡色区域较小，通过面部红褐色斑纹和翼下覆羽的黄色边线容易区分。","protection":"IUCN状态未知。","distribution":"主要分布在南美洲的亚马逊雨林西部、中部以及巴西中部。","other":"与灰额哑霸鹟在巴西中部有狭窄的分布重叠区域。"},{"name":"蓝灰头哑霸鹟","english_name":"Slaty-headed Tody-Flycatcher","scientific_name":"Poecilotriccus sylvia","overview":"蓝灰头哑霸鹟（英文名：Slaty-headed Tody-Flycatcher，学名：Poecilotriccus sylvia），是雀形目霸鹟科哑霸鹟属的鸟类。分布广泛，自墨西哥南部延伸至巴西东北部，栖息于中美洲和南美洲的热带低地森林。","appearance":"体型极小，行动隐秘，常穿梭于茂密的灌木丛和林下植被中。头部呈灰蓝色，上体橄榄色，翼缘泛黄，腹部淡黄色。具较长的喙，眼色较浅。其跳跃式的移动方式类似慵懒的莺鸟，时常长时间保持静止不动。","habits":"偏好湿润的热带低地森林环境，常见于亚热带或热带干燥森林，以及严重退化的前森林区域。生活方式及迁徙模式尚需进一步研究。","identification":"与北弯嘴霸鹟相似，但后者更倾向于开放的森林下层，站立姿势更为直立，且具有弯曲的喙。","distribution":"分布于中美洲至南美洲，具体包括墨西哥南部至巴西东北部，覆盖了中美洲和南美洲的多个国家和地区。"},{"name":"金翅哑霸鹟","english_name":"Golden-winged Tody-Flycatcher","scientific_name":"Poecilotriccus calopterus","overview":"金翅哑霸鹟（英文名：Golden-winged Tody-Flycatcher，学名：Poecilotriccus calopterus），是雀形目霸鹟科哑霸鹟属的鸟类。小型、色彩斑斓的霸鹟。其分布范围相对较小，主要集中在南美洲东部厄瓜多尔，同时延伸至哥伦比亚南部和秘鲁东北部，完全位于亚马逊以北。黑头、白喉、大黄翼条、栗肩斑和鲜黄色下体使它在众多鸟类中脱颖而出，美丽而易于识别。","appearance":"成鸟具有黑色头部、白色喉咙、橄榄绿色背部、亮黄色胸部和腹部，以及独特的栗色小翼覆羽和宽大的黄色翼条，覆盖在中间翼覆羽上。两性相似。幼鸟的描述目前尚缺。","call":"其叫声为短促、干燥的颤音，常由一对中的双方反复发出。","habits":"金翅哑霸鹟通常成对出现，偏好隐蔽于雨林边缘的纠缠植被或过度生长的空地中。它们的活动范围包括低地森林的密集下层植被和边缘地带，偶尔出现在过度生长的牧场或大型花园中。","breeding":"关于其生态习性的具体细节知之甚少，包括繁殖行为。","identification":"与黑背哑霸鹟最为相似，但后者背部全黑，眼后有小白斑点，须纹白色。两者分布区不重叠，黑背哑霸鹟限于秘鲁南部。与哑霸鹟的区别在于后者缺乏鲜明的翼纹，冠羽与背部颜色对比不明显，虹膜较淡，且不局限于密林下层。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚东南部、厄瓜多尔东部和秘鲁东北部，主要栖息于亚热带或热带湿润的低地森林。","other":"金翅哑霸鹟的生态学细节仍有待研究。"},{"name":"黑背哑霸鹟","english_name":"Black-backed Tody-Flycatcher","scientific_name":"Poecilotriccus pulchellus","overview":"黑背哑霸鹟（英文名：Black-backed Tody-Flycatcher，学名：Poecilotriccus pulchellus），是雀形目霸鹟科哑霸鹟属的小型鸟类，拥有鲜明的色彩对比。其特征在于白色的喉咙与黑色背部形成强烈对比，腹部呈亮黄色。该物种仅分布于秘鲁东南部的安第斯山脉山脚地带。","appearance":"黑背哑霸鹟体型紧凑，尾巴短小，上身黑色，下身鲜黄，喉部白色，有一条白色髭纹和眼后小白斑，雄鸟肩部有小红斑，雌鸟背部为暗橄榄色而非黑色。翼部大部分黑色，带有淡栗色的小翼羽和宽阔的黄色中翼羽条纹。","call":"黑背哑霸鹟的鸣唱为快速下降的丰富‘churr’声，常以二重唱形式呈现，伴随着翅膀的闪动。","habits":"栖息于秘鲁东南部的次生森林，尤其是高大的竹林附近，偏好湿润低地和山脚森林边缘的密集灌木区。通常成对活动，以昆虫为食，在树冠下层觅食。","breeding":"关于其繁殖生物学信息目前未知，是未来研究的空白领域。","identification":"与金翅哑霸鹟最为相似，但两者地理分布完全不重叠。金翅哑霸鹟两性均有橄榄色背部，缺乏黑背哑霸鹟眼后的小白点和狭窄的黑色侧喉线。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲秘鲁东南部，特别是在安第斯山脉的山脚地带。","other":"尽管分布范围极其有限，但黑背哑霸鹟的种群被认为保持稳定，不属于受威胁物种。"},{"name":"黑胸霸鹟","english_name":"Black-chested Tyrant","scientific_name":"Taeniotriccus andrei","overview":"黑胸霸鹟（英文名：Black-chested Tyrant，学名：Taeniotriccus andrei），是雀形目霸鹟科黑胸霸鹟属的独特小型鹟。其显著的黑、红、黄三色羽毛和罕见的特性，使其成为亚马逊地区多年来备受追求的鸟种之一。在北亚马逊和东南亚马逊地区，从委内瑞拉东北部向南，穿过巴西至马拉尼昂、帕拉和马托格罗索北部，分布虽零散但相对广泛。","appearance":"雄鸟头部、喉咙、脸颊和颈侧呈红栗色，大部分被长而黑色的顶冠遮盖。背部、翅膀和尾巴为黑色，翼羽基部显眼的黄色边缘延伸至三级飞羽。胸部有一条宽广的深色带，腹部呈淡灰色，侧翼和下尾覆羽带有绿黄色调。雌鸟顶冠较短，背部为橄榄棕色，头部色彩较暗淡，胸部为青铜橄榄灰，腹部白色，翼羽边缘为棕褐色。","call":"其叫声为一系列低沉的‘chewp’音符，间杂着双音节‘chewp-chewp’音符，极易被误认为蛙鸣或昆虫声。","habits":"栖息于湿润森林的下层，密集的次生林和季节性洪水区，偏好密集藤蔓或竹林的环境。可能受益于适度的生态扰动，因为这能创造其偏好的低矮密集植被。","breeding":"目前关于其繁殖习性的信息有限。","identification":"高度独特的黑胸霸鹟，黑色的身体，红色头部，白色腹部和翼覆羽上醒目的白色条纹，若观察条件良好，实为无可混淆之物种。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马逊雨林中北部和东部，具体包括巴西、苏里南和委内瑞拉。"},{"name":"斑哑霸鹟","english_name":"Spotted Tody-Flycatcher","scientific_name":"Todirostrum maculatum","overview":"斑哑霸鹟（英文名：Spotted Tody-Flycatcher，学名：Todirostrum maculatum），是雀形目霸鹟科黑头哑霸鹟属的小型鸟类，主要分布在南美的亚马逊盆地国家和圭亚那地区，包括巴西、哥伦比亚、秘鲁等地。常栖息于亚马逊雨林及周边环境。","appearance":"体长8.9至10.2厘米，体重6.4至8.3克。头部大而呈灰色，具黑色和白色细纹，有小块白色眉纹。上体橄榄色，翅膀棕色带黑色，翼羽边缘和尖端泛黄，形成模糊的翼纹。尾部棕色带黑色，外侧羽毛边缘带有黄色。喉咙和上胸部白色，有独特的较窄黑色条纹，其余下体黄色，两侧有深橄榄色条纹。虹膜橙黄色，有时为灰或棕色。喙黑色，下颚基部有白色。腿粉灰色。雌雄相似，幼鸟条纹更细更淡。不同亚种差异不大，emamacurense/em和emsignatum/em的前额为烟黑色。","call":"发出清晰、尖锐而响亮的‘tee’或‘peek’声，重复多达12次，每秒2次，经常立即得到配偶的回应，听起来像是‘peek-peek’的双音节。","habits":"通常与湿润环境相关联，如茂密的灌木丛、红树林边缘的次生林、牛轭湖、溪流、河流和河岛旁，也出现在废弃牧场和开阔地带的次生灌木丛中，甚至在城市花园或住宅周围的高树中。主要在低地至海拔500米处活动。以蜘蛛、苍蝇、白蚁和蝴蝶为食，常成对活动，不参与混合群。在接近地面的密集植被中觅食，也会在较高的树冠中较为开放的植被中觅食，以短暂的向前和向上的突袭捕捉猎物。","breeding":"繁殖期全年，雏鸟在8月与成鸟一同出现。巢由双方共同建造，大约需两周时间，为一个不规则的长袋状结构，顶部有盖，侧面有入口，用枯草和其他植物材料制成，用蛛网固定，内部铺垫植物纤维，悬挂于下垂的树枝上，通常低于3米，靠近黄蜂巢（如Polybia occidentalis和Nectarina bilineolata）。产卵1-2枚，仅由雌鸟孵化，孵化期16-21天；幼鸟由双方喂养，巢期约15-19天。","identification":"与彩哑霸鹟在东北亚马逊盆地的圭亚那盾地有地理隔离，可通过分布区域和叫声辨识。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲亚马逊盆地，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南、特立尼达和多巴哥、委内瑞拉。"},{"name":"灰头哑霸鹟","english_name":"Yellow-lored Tody-Flycatcher","scientific_name":"Todirostrum poliocephalum","overview":"灰头哑霸鹟（英文名：Yellow-lored Tody-Flycatcher，学名：Todirostrum poliocephalum），是雀形目霸鹟科黑头哑霸鹟属的鸟类。体型小巧、色彩鲜艳，以其独特的灰黑色头部与醒目的黄色眼斑而闻名。分布于巴西东南部，从巴伊亚南部至圣卡塔琳娜州，常栖息于森林边缘、次生林、花园及城市公园。","appearance":"灰头哑霸鹟体长约8.8厘米，体重平均6.8克。头部以灰黑色为主，额部深色，头顶灰色，具有显著的亮黄色眼斑。上体绿色或橄榄色，下体鲜黄色，翅膀黑色带有黄色边缘，尾部暗灰褐色。喙呈扁平状，长而尖，腿脚蓝灰色。雄雌外观相似，幼鸟的黄色眼斑较淡。","call":"其鸣叫声为尖锐的‘tchip-tchip-tchip’。","habits":"该物种栖息于森林边缘、次生林、花园和城市公园。主要以小型节肢动物为食，活动于低矮密集的植被中，常在树叶背面捕捉昆虫。飞行敏捷，善于在枝叶间穿梭。","breeding":"灰头哑霸鹟筑巢于树枝上，离地面不高，巢由草和叶子构成，侧面有入口，通常每季产卵2到3枚，仅由雌鸟孵卵。","identification":"与哑霸鹟相比，灰头哑霸鹟的黄色眼斑更为醒目，尾部颜色更深，腿脚颜色不同，且幼鸟的黄色眼斑较淡。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲巴西东南部，从巴伊亚南部至圣卡塔琳娜州。","other":"在巴西葡萄牙语中，该鸟被称为Teque-teque。"},{"name":"哑霸鹟","english_name":"Common Tody-Flycatcher","scientific_name":"Todirostrum cinereum","overview":"哑霸鹟（英文名：Common Tody-Flycatcher，学名：Todirostrum cinereum），是雀形目霸鹟科黑头哑霸鹟属的小型鸟类。体型小巧，头部较大，拥有长而扁平的黑色喙。分布于中美洲至南美洲东北部，自墨西哥南部至阿根廷东北部。常见于花园、阴凉的种植园、次生林及森林边缘和空地，避免成熟森林的密集内部和干旱地带。","appearance":"哑霸鹟长约9.5-10.2厘米，重约6.5-6.8克。上头部为黑色，逐渐变为暗灰色至颈背，其余背部呈深橄榄绿色。尾羽通常翘起，黑色，尖端白色。翅膀黑色，带有两道黄色翼带和黄色边缘。下体全为黄色。性别相似，但幼鸟的上头部更偏灰色，翼部标记呈淡褐色，下体颜色较浅。","call":"哑霸鹟的雄鸟具有快速类似蚱蜢的‘te’e’e’e’e’t’叫声，类似于热带王鹟的鸣声，以及黎明时由高速高音的‘tic’音组成的歌曲，每分钟重复高达110次。","habits":"常在花园、阴凉的种植园、次生林和森林边缘的开放区域活动，避免成熟森林的密闭环境和干旱区。通常成对出现，以快速的突进或悬停的方式从植被上捕食小型节肢动物，常常边移动边摇摆尾巴。","breeding":"繁殖高度从海平面至1,150米，局部可达1,500米。巢为袋状，具侧向遮蔽的入口，通常悬挂在树上1-5米高的细枝或藤蔓上，偶尔高达30米。雌鸟单独孵化两个通常无斑点的白色蛋，孵化期约为15-16天。","identification":"哑霸鹟以其特有的黑色面罩、白色眼圈和白色尾尖为辨识要点，与同属其他物种的区别在于其独特的头部色彩模式和体型大小。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲东北部，从墨西哥南部至阿根廷东北部，包括中美洲大部分地区、哥伦比亚、委内瑞拉、圭亚那、苏里南、法属圭亚那、巴西东北部、玻利维亚东部和秘鲁西北部。","other":"已知在多个国家公园和其他保护区中普遍存在，适应转化和次生栖息地，受益于森林砍伐，扩散到新开垦地和种植园，在这些地方通常数量众多。"},{"name":"短尾哑霸鹟","english_name":"Maracaibo Tody-Flycatcher","scientific_name":"Todirostrum viridanum","overview":"短尾哑霸鹟（英文名：Maracaibo Tody-Flycatcher，学名：Todirostrum viridanum），是雀形目霸鹟科黑头哑霸鹟属的鸟类。体型微小、色彩淡雅，主要分布于委内瑞拉西北部近Lake Maracaibo地区的干旱灌木丛。该物种曾被视为普通哑霸鹟的一个亚种。","appearance":"体长9至10.2厘米，头部灰色，前额及眼周黑色，具隐蔽的黄白色冠纹；上体橄榄色，翅膀黑色，翼羽边缘及尖端呈宽幅的黄白色；尾巴短小，黑色并带白边；下体淡黄色，两胁泛肉桂色；虹膜深色，有时略显黄白色；上喙黑色，下喙粉红色；腿灰色。雌雄同型，幼鸟特征未详述。","habits":"栖息于半干旱及干旱的灌木丛、林地（常伴有Acacia、Cercidium、Cardon和Opuntia等植物），也见于热带落叶森林和河岸森林，海拔高度不超过200米。","breeding":"繁殖季节主要在5月至6月及1月至3月。巢由双亲共建，结构类似于其他Todirostrum种类，如哑霸鹟和斑哑霸鹟。巢置于距地面约3.5米的树干靠近干涸溪流处，每窝产卵2至3枚。","identification":"与普通哑霸鹟相比，短尾哑霸鹟颜色更淡，更显褪色，具有独特的前额和眼上区黄白色斑点。","protection":"IUCN：LC（无危）。尽管在小范围内仍存在大量适宜栖息地，但Lake Maracaibo周边的大量生境已因过度放牧、砍伐木柴、旅游开发和污染而被破坏。该物种在Médanos de Coro国家公园、Sierra de San Luis国家公园和Ciénaga de Los Olivitos野生动物保护区等几个保护区内有分布。","distribution":"南美洲委内瑞拉西北部，主要分布在Lake Maracaibo周边地区。"},{"name":"彩哑霸鹟","english_name":"Painted Tody-Flycatcher","scientific_name":"Todirostrum pictum","overview":"彩哑霸鹟（英文名：Painted Tody-Flycatcher，学名：Todirostrum pictum），是雀形目霸鹟科黑头哑霸鹟属的小型林鸟。其最显著的特征是亮丽的硫磺黄色胸羽和小巧的黑白侧翼斑块。分布于南美洲的亚马孙雨林东北部，包括法属圭亚那、圭亚那、苏里南以及委内瑞拉和巴西东北部的部分地区。","appearance":"体型极小，约9至10.2厘米长，重6至8克。头部呈光泽黑色，拥有白色眼上斑点和长长的白色颊纹；颈部有一圈小黄带，背部和臀部为橄榄绿色；翅膀黑色，带有两道黄色翼带，边缘黄色；尾巴黑色，外缘橄榄色；喉部白色带黑色条纹，下体鲜亮黄色，上胸部有黑色条纹；虹膜深棕色或黄色；喙和腿黑色。雌雄外观相似，幼鸟未详述。","call":"发出清脆的‘chevik’或‘pi-pik’叫声；歌曲由8至12个尖锐刺耳的‘peek’音符组成，每秒约2个音符；还有一种穿透性的哨声‘teeng-teeng-teeng-teeng’。","habits":"栖息于高大的低地森林，通常成对出现，很少加入混杂物种的群落。它们在树冠的高处和森林边缘觅食，以昆虫为主食，如双翅目的蝇类。捕食时会做短距离的前冲和向上突袭。","breeding":"在苏里南，繁殖季节始于10月。巢由双方共同建造，呈不规则的长袋状，带下垂的‘尾巴’和侧面入口，曾观察到悬挂在花园树上的枝条末端靠近黄蜂巢附近。巢通常建得比同类鸟的巢更高。","identification":"与同类相比，彩哑霸鹟的体型更小，胸部的黑色条纹有限，且具有较大的喙。在森林中较为隐蔽，听到的次数多于见到的次数。","distribution":"分布于南美洲的东北亚马逊盆地，包括法属圭亚那、圭亚那、苏里南、委内瑞拉东部和巴西东北部亚马逊地区的部分地带。在亚马逊河口至大西洋的范围内，物种的分布涵盖了整个巴西东北部的阿马帕州以及相邻的法属圭亚那和大西洋。"},{"name":"黄眉哑霸鹟","english_name":"Yellow-browed Tody-Flycatcher","scientific_name":"Todirostrum chrysocrotaphum","overview":"黄眉哑霸鹟（英文名：Yellow-browed Tody-Flycatcher，学名：Todirostrum chrysocrotaphum），是雀形目霸鹟科黑头哑霸鹟属的鸟类。小型、色彩鲜明，主要分布在南美洲亚马逊盆地的热带雨林中，从哥伦比亚东南部至玻利维亚北部，横跨巴西直至马兰豪州亚马逊河口附近。与彩哑霸鹟及黑头哑霸鹟形成超物种群。","appearance":"体型微小，以黑色、黄色为主色调，搭配绿色背部。头部两侧黑色，具宽阔的黄色眉纹，自眼后延伸至颈背。背部橄榄绿，翅膀黑色，翼羽边缘和尖端呈黄色。下体鲜黄，部分亚种胸腹部有细窄的黑色条纹。喙形似船首，长度适中且扁平。","call":"其鸣唱为一连串高亢、金属质感的连续音符，节奏略快于一秒一音，持续时间较长。","habits":"栖息于成熟的低地雨林树冠层，偶尔出现在森林边缘，甚至花园和人类居住区附近。偏好单独或成对活动，不常加入混合物种群。食性以昆虫为主，觅食时偏好独行或与伴侣一同。","breeding":"巢穴为悬挂式球状结构，筑于离地面高达35米处。有关繁殖行为的详细研究尚待开展。","identification":"与哑霸鹟相比，黄眉哑霸鹟具有显著的黄色眉纹，上体颜色更深，尾较短，且下体有黑色条纹。斑哑霸鹟虽也有黄色下体和黑色标记，但冠部灰色，缺乏黄色眉纹。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲亚马逊盆地的南部，包括亚马逊雨林的低地森林，从哥伦比亚东南部到玻利维亚北部，以及巴西至马兰豪州的亚马逊河口。","other":"黄眉哑霸鹟通常数量不多，若不熟悉其鸣叫，容易被忽视。"},{"name":"黑头哑霸鹟","english_name":"Black-headed Tody-Flycatcher","scientific_name":"Todirostrum nigriceps","overview":"黑头哑霸鹟（英文名：Black-headed Tody-Flycatcher，学名：Todirostrum nigriceps），是雀形目霸鹟科黑头哑霸鹟属的鸟类。体型微小，主要栖息于中美洲和南美洲的低地森林中，分布区域包括哥斯达黎加至委内瑞拉北部和厄瓜多尔。其头部呈现光泽的黑色，与白色的喉部和橄榄色的背部形成鲜明对比。","appearance":"体长约8-10.2厘米，体重约6-6.5克。具有醒目的特征，包括亮黑色的冠羽和头部侧面，与白色喉部和黄橄榄色上体形成强烈对比；有时可见狭窄的白色眉纹；翅膀黑色，带有两条黄色的翼带和黄色边缘；尾巴较短，呈黑色；下体鲜黄色；眼睛深棕色；喙黑色；腿蓝灰色至黑色。雄雌外观相似。幼鸟的头部颜色较为暗淡，喉部略带黄色，下体颜色较浅，翅膀上的标记带有橄榄色调。","call":"发出活泼的单声或双声‘chip’、‘peep’或‘pik’的叫声；歌声通常由5-8个（最多可达12个）高音尖锐的‘tsip’或‘jyip’音符组成，首个音符稍低，最后几个音符加速并略微增加音量；孵卵中的雌鸟会发出柔和的颤音。","habits":"倾向于栖息在树冠较高处，难以被发现。生活在亚热带或热带湿润的低地森林中。","breeding":"繁殖季节在哥伦比亚记录到6月和2月，巴拿马记录到8月。巢穴是一个杂乱的短袋状结构，带有悬挂的‘尾巴’和遮阳的侧入口，由植物纤维制成，内衬种子绒毛，悬挂在3-15米高的垂枝上，几乎总是在黄蜂巢附近。每次产卵1枚。","identification":"与哑霸鹟非常相似，但通常在较高的森林中发现。辨识要点包括黑色头部、白色喉部、黄橄榄色背部以及活跃的鸣叫声。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，从哥斯达黎加至委内瑞拉北部和厄瓜多尔。"},{"name":"褐霸鹟","english_name":"Brownish Twistwing","scientific_name":"Cnipodectes subbrunneus","overview":"褐霸鹟（英文名：Brownish Twistwing，学名：Cnipodectes subbrunneus），是雀形目霸鹟科褐霸鹟属的鸟类。在中美洲和南美洲，从巴拿马至亚马逊盆地的巴西和秘鲁，分布广泛。其外观为上部棕色，下部淡黄白色，外表较为普通，但翅膀和尾巴边缘呈现锈色，眼圈淡棕色，飞行时会定期抬起翅膀。","appearance":"体型中等的飞虫捕食者，长度介于14至18厘米，头部、背部呈暗棕色，翼羽和尾羽边缘有明亮的锈色，喉部和胸部颜色较深，腹部灰白或带黄色，臀部和长尾比背部更红棕色。雄鸟具有独特的外侧初级飞羽，硬化并扭曲的轴。雌鸟较小，无明显初级飞羽形态改变，幼鸟同样如此。","call":"鸣叫声为尖锐而略带鼻音的哨声“kuuuu-wit”，通常重复两到三次；歌曲为独特且强调的“kuheer”，常被重复为“kuheer kuheer-quer”，有时伴有1至2次响亮的喙击声。","habits":"偏好低地和山脚森林的底层植被，常见于湿度高和落叶森林的低矮植被中，喜欢阴凉地带，多藤蔓和杂草的下层，接近溪流，有时与竹子相关联。主要分布在低地，偶尔在安第斯山脉上升至1200米高度。通常为居民，很少迁徙。","breeding":"在哥伦比亚，繁殖季节为1月至4月（北部安蒂奥基亚，乔科）和6月（西部卡奎塔）。可能形成分散的领地，但关于独特改变的初级飞羽用途未知，可能在求偶展示中发挥作用。巢穴类似皇霸鹟，悬垂式，由纤维构成，侧入口，离地面2米。","identification":"与相似的拟鸫希夫霸鹟的区别在于后者翅膀边缘无锈色。可通过鸣叫和特定的行为特征识别。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的巴拿马至南美洲的亚马逊雨林区域，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、巴拿马和秘鲁。在厄瓜多尔东部和巴拿马的某些地区较为常见。","other":"尽管在西厄瓜多尔因森林砍伐数量下降，但该物种可能能在孤立的森林碎片中存活。"},{"name":"棕霸鹟","english_name":"Rufous Twistwing","scientific_name":"Cnipodectes superrufus","overview":"棕霸鹟（英文名：Rufous Twistwing，学名：Cnipodectes superrufus），是雀形目霸鹟科褐霸鹟属的鸟类。全身羽毛呈亮丽的肉桂色。栖息于南美洲秘鲁东南部、玻利维亚西北部以及巴西远西部（仅阿克雷州）的湿润森林中，偏好生长着高大竹林的环境。棕霸鹟的发现充满神秘色彩，直至2007年才被科学界正式描述。","appearance":"棕霸鹟是一种体型较大的飞禽，站立时姿态挺拔，喙宽而扁平，口角须发达，全身羽毛呈现出浓密的肉桂色。头部顶部有较长的肉桂色羽毛，中心较暗，形成一个通常不竖立的冠羽。身体和覆羽普遍呈现明亮的肉桂色，腹部颜色更鲜艳。翅膀的飞羽呈暗色，雄鸟的初级飞羽扭曲，展现出独特的结构。","call":"其鸣唱是一系列下降的音乐性哨声，\"pew-pur-pur-pur-pur\"，极具辨识度。","habits":"棕霸鹟栖息于湿润森林中的竹林地带，偏好Guadua竹林生境。它们的活动范围广泛，能在亚马逊西南部的广大森林中找到它们的踪迹。","breeding":"关于棕霸鹟的繁殖信息尚不详尽，需要更多研究。","identification":"与同属的褐霸鹟相比，棕霸鹟体型更大，羽毛颜色更为鲜亮的肉桂色，且偏好竹林环境。此外，两者的叫声也截然不同。","protection":"IUCN：VU（易危）","distribution":"棕霸鹟主要分布在南美洲的秘鲁东南部、玻利维亚西北部以及巴西的阿克雷州，这些地区多为偏远的湿润森林。","other":"棕霸鹟的发现历史充满传奇色彩，直到2007年才被正式科学描述，显示了对于生活在竹林中的鸟类仍有大量未知领域等待探索。"},{"name":"眼环扁嘴霸鹟","english_name":"Eye-ringed Flatbill","scientific_name":"Rhynchocyclus brevirostris","overview":"眼环扁嘴霸鹟（英文名：Eye-ringed Flatbill，学名：Rhynchocyclus brevirostris），是雀形目霸鹟科扁嘴霸鹟属的鸟类。这种体型较大的霸鹟，头部明显，全身呈现绿色调，主要分布在中美洲，从墨西哥南部到哥伦比亚西北部的热带及亚热带湿润森林中。","appearance":"成年眼环扁嘴霸鹟约15至17厘米长，重21至23克。雄鸟具有橄榄绿的头部和上体，特征性的白色眼环，眼睛下方隐约可见暗色斑点，脸颊和耳羽区域呈灰白色，翼和尾部颜色较暗，边缘带有黄橄榄色，喉部和胸部为暗橄榄绿色，下胸至腹部逐渐变为淡黄色。雌鸟与雄鸟相似，但外侧初级飞羽缺少梳状突起。幼鸟的腹部更亮黄，翼羽边缘更鲜明，侧身条纹更粗，胸侧条纹减少或消失，耳羽区域颜色偏暗。不同亚种差异不大。","call":"发出多种声音，包括尖锐的‘zweeip’或‘sweeip’声，蝉鸣般的‘zzrrip’声，尖细的‘siiir’或‘ssssi’音，以及较长的‘weeep weeep wip-wip-wip’声，带有喷溅质感。","habits":"眼环扁嘴霸鹟通常在森林内部中层安静地站立，很少出现在边缘地带，不常摆动翅膀或尾巴。它们偏好栖息于亚热带或热带湿润的低地森林和山地森林，偶尔会侵入哥伦比亚南部地区。","identification":"与绿扁嘴霸鹟相比，眼环扁嘴霸鹟拥有更显眼的白色眼环和翼部更鲜艳的黄色。雌鸟与雄鸟外观相似，但外侧初级飞羽缺乏梳状突起。","protection":"IUCN状态未提及。","distribution":"分布于中美洲，具体包括墨西哥南部至哥伦比亚西北部，以及中美洲国家如伯利兹、哥斯达黎加、萨尔瓦多、危地马拉、洪都拉斯、尼加拉瓜和巴拿马。","other":"太平洋扁嘴霸鹟有时仍被视作眼环扁嘴霸鹟的亚种。"},{"name":"绿扁嘴霸鹟","english_name":"Eastern Olivaceous Flatbill","scientific_name":"Rhynchocyclus olivaceus","overview":"绿扁嘴霸鹟（英文名：Eastern Olivaceous Flatbill，学名：Rhynchocyclus olivaceus），是雀形目霸鹟科扁嘴霸鹟属的鸟类。主要分布在南美洲东北部，包括委内瑞拉东部、圭亚那、亚马逊雨林北部和巴西东部。其最显著的特征是橄榄绿色的外表和环绕大黑眼的白色眼环。绿扁嘴霸鹟通常单独或成对活动，栖息于低地和山脚森林的下层和中层。","appearance":"绿扁嘴霸鹟拥有圆头和较长的尾巴，全身呈暗橄榄色，翼部带有两道淡褐色或黄褐色的翼带，尾羽边缘泛白。腹部呈现淡黄色，胸腹部橄榄灰，两侧有橄榄色条纹。喙宽而扁平，眼周有白色眼环。幼鸟颜色较淡，背部橄榄色更深，下体更偏黄色。","call":"绿扁嘴霸鹟的叫声主要是在黎明时发出一系列快速下降的嗡嗡声，由大约10个音符组成，开始时有一两个较长的音符，随后是较短的音符，音调可能上升也可能下降，有时仅发出初始的长音符或仅一两个短音符。","habits":"绿扁嘴霸鹟主要栖息于湿润森林的较低层次，如terra firme和várzea森林，常在混合物种群中跟随，以捕食节肢动物为主。它们在白天多数时间保持安静，偶尔在清晨鸣叫，捕食时会从栖木上迅速飞出，进行空中捕猎或悬停捕食。","breeding":"绿扁嘴霸鹟在6月底至7月中旬进入繁殖期，巢为梨形，长约16厘米，宽约18厘米，由黑色根状菌丝、枝条、树叶和腐烂的叶脉构成，内部衬以叶子和腐烂的叶脉。巢悬挂在树的细枝上，离地面高度约为1.6米至3米。每窝产2枚近椭圆形的白色蛋，孵化和育雏期不详，但据观察，幼鸟大约在21天左右离巢。","identification":"绿扁嘴霸鹟与西绿扁嘴霸鹟的区别在于其叫声和羽毛颜色的差异。绿扁嘴霸鹟的叫声更偏向于嗡嗡声，而西绿扁嘴霸鹟的叫声有所不同。此外，绿扁嘴霸鹟的羽毛颜色较为暗淡，而西绿扁嘴霸鹟的颜色可能更加鲜艳。","protection":"IUCN：LC（无危）","distribution":"绿扁嘴霸鹟广泛分布于南美洲东北部，包括委内瑞拉南部、圭亚那、亚马逊雨林北部以及巴西东部，从海平面至海拔500米的亚马逊地区，或在巴西东南部高达600米。它在多个国家公园和保护区中均有分布，如巴西的塔帕若斯国家公园、穆里奇生态保护区、Córrego do Veado生物保护区和Sooretama生物保护区。","other":"绿扁嘴霸鹟过去被认为与西绿扁嘴霸鹟同种，但基于叫声和羽毛颜色的差异，现已将其分类为独立物种。"},{"name":"太平洋扁嘴霸鹟","english_name":"Pacific Flatbill","scientific_name":"Rhynchocyclus pacificus","overview":"太平洋扁嘴霸鹟（英文名：Pacific Flatbill，学名：Rhynchocyclus pacificus），是雀形目霸鹟科扁嘴霸鹟属的鸟类。主要分布于南美洲的哥伦比亚西部和厄瓜多尔西北部低地和山脚雨林。其显著特征为橄榄色的羽毛，带黄色条纹的下体，灰色眼环，以及翼上的棕色斑块。喙基部宽阔，侧面观察时可能不明显。","appearance":"体长约15厘米，体重23.5至26.5克。头部较大，上体呈深橄榄色，眼环模糊的灰色，翅膀和尾巴为暗褐色，翼覆羽边缘有显眼的土黄色或赭色，初级飞羽和次级飞羽边缘为橄榄色，三级飞羽边缘淡黄色；喉咙和胸部为橄榄色并带有微弱的黄色条纹，腹部和两胁为黄色，两胁有橄榄色条纹；虹膜深色；喙大而宽扁，上颌黑色，下颌浅色；腿为蓝灰色。雄雌相似。幼鸟未详述。","call":"鸣唱为一连串快速下降的清晰至模糊音符，'tchwee-tee-te-tu-tu-tu'；叫声为嘶嘶声'scheeeuw'。","habits":"以节肢动物为食。通常单独或成对觅食，常出现在下层混合物种群中，包括furnariids、Myrmotherula蚁鵙和蚁鵙（Thamnophilidae）。直立静坐于低矮的栖木，如开阔的树枝或藤蔓，转动头部向上窥视中层或下层森林；迅速向空中或悬停捕捉叶底和枝梢下的猎物，然后降落到新的栖木；极少向空中掠食。","breeding":"在哥伦比亚，3月发现处于繁殖状态的个体。其他繁殖信息未知。","identification":"与锈胸扁嘴霸鹟相似，但太平洋扁嘴霸鹟缺乏褐胸特征，且通常在较低海拔发现。与橄榄色扁嘴霸鹟相比，翼上有棕色而非黄色。","protection":"IUCN状态未知。","distribution":"分布于南美的哥伦比亚西部和厄瓜多尔西北部。"},{"name":"锈胸扁嘴霸鹟","english_name":"Fulvous-breasted Flatbill","scientific_name":"Rhynchocyclus fulvipectus","overview":"锈胸扁嘴霸鹟（英文名：Fulvous-breasted Flatbill，学名：Rhynchocyclus fulvipectus），是雀形目霸鹟科扁嘴霸鹟属的鸟类。罕见而不起眼的霸鹟科鸟类，1860年首次被命名。在安第斯山脉的云雾森林中栖息，拥有橄榄绿色上体、淡褐色胸部、黄色腹部，以及灰色眼圈和翼上的棕色斑块。其喙基部宽大，尽管侧面观察可能不易察觉这一特征。与太平洋和橄榄色扁嘴霸鹟相似，但可通过淡褐色胸部和较高的海拔分布区来区分。","appearance":"体型略大，头部显得较大，体长约15厘米，体重11.4至27.5克。头部和上体呈深橄榄色，眼圈淡灰色，翼和尾较暗，翼覆羽和飞羽边缘有明显的淡黄褐色或赭色。下巴灰色，下喉和胸部独特地呈现暗淡的锈褐色；腹部、胁部和臀部黄色，胁部有橄榄色条纹。虹膜深色，喙大而扁平，上颌黑色，下颌浅色，腿灰色。两性相似，幼鸟特征未详述。","habits":"主要以节肢动物为食，常单独觅食，有时加入底层混群。静立于低矮枝头（1至4米高），头部转动向上窥视中层或底层林木。迅速向上掠飞或悬停捕食叶底或枝梢的猎物，然后飞向新栖处；偶尔空中捕食。","breeding":"繁殖期在哥伦比亚为5月，秘鲁东北部为8月末。巢为梨形，约8厘米×3厘米，侧下方有向下延伸的入口，由根须、粗纤维和枯叶构成，悬挂于细枝或藤蔓末端，位于空地或小溪旁。产卵1至3枚，白色，有时大端有小红或肉桂色斑点，平均尺寸约为24.4毫米×18.8毫米，平均新鲜重量3.5克，孵化期24天。雏鸟出生时皮肤粉橙色，背部和翅膀有少量灰绒毛，体重约3克，巢期至少29天。","identification":"通过淡褐色胸部和较高海拔的分布，可将其与太平洋和橄榄色扁嘴霸鹟区分开来。此外，观察其独特的喙形和颜色模式也是辨识要点。","protection":"IUCN：LC（无危）。在其分布边缘较为罕见，如委内瑞拉，但在厄瓜多尔则较为常见。在哥伦比亚的Tambito自然保护区和厄瓜多尔的Podocarpus国家公园中可以找到。","distribution":"分布于南美洲，自委内瑞拉西部至玻利维亚西北部，包括哥伦比亚、厄瓜多尔、秘鲁等地。"},{"name":"西绿扁嘴霸鹟","english_name":"Western Olivaceous Flatbill","scientific_name":"Rhynchocyclus aequinoctialis","overview":"西绿扁嘴霸鹟（英文名：Western Olivaceous Flatbill，学名：Rhynchocyclus aequinoctialis），是雀形目霸鹟科扁嘴霸鹟属的鸟类。中型的霸鹟，分布于中美洲和南美洲，从巴拿马东部到哥伦比亚北部，委内瑞拉东北部南部至亚马逊雨林西部，直至秘鲁东部和玻利维亚北部。其橄榄绿色的羽毛与苍白的黄色下腹部构成了主要的外部特征，最引人注目的是环绕大而深色眼睛的白色眼环。","appearance":"这种鸟拥有中等体型，长尾巴和圆头。整体呈暗淡的橄榄棕色，缺乏显著特征，除了隐约可见的苍白眼环和非常宽大的喙。头部和上身呈现深橄榄色，翅膀颜色较暗，翼盖和次级飞羽边缘呈黄绿色，形成两个模糊的翼纹，尾羽颜色较暗，边缘较浅。下喉部呈浅灰色或淡黄色，胸部为灰橄榄色，腹部至臀部及两胁为淡黄色，胸部和两胁带有橄榄色斑点或条纹。虹膜为褐色至黑色。喙宽而扁平，上喙为黑色，下喙为淡角质色、黄色、粉红色或淡白色。腿蓝色灰色。性别相似，幼鸟色泽较淡，腹面更黄，尾上覆羽更加橙橄榄色。","call":"鸣唱为一系列通常5至10个哨音，起初平缓且沙哑，逐渐变为响亮纯净的哨音，加速并音调上升，赋予整体上升的质感。有时以结巴的连续声结束，可能在兴奋时或播放后发生。","habits":"栖息于低地和山麓森林的下层和中层，高度可达约1000米。常跟随混合物种群。主要食物为节肢动物，单独觅食或偶尔加入混合物种群，主要由蚁鸟和烤箱鸟组成。在树冠中层的细枝上发出声音。","breeding":"繁殖期在2月至6月间，筑巢于地面2至7米处，构造为大型梨形结构，长度15厘米，侧面下方有向下延伸的入口。巢穴与黄羽缘霸鹟的形状和结构相似，但本物种会在巢壁中融入大型枯叶。一窝通常产2至3枚蛋，蛋壳白色带紫色斑点和线条。平均年存活率约为57%。","identification":"与绿扁嘴霸鹟的区别在于鸣唱和外观细节上的差异，如明亮的黄色飞行羽边缘和黄色或橙色更大的翼盖，以及腹部更多淡黄色。","protection":"IUCN：LC（无危）。在大部分分布范围内从罕见到常见不等，但在厄瓜多尔和哥伦比亚部分地区较为稀少，甚至在一些看似适宜的低地森林中缺失。在多个国家公园和其他保护区出现，如巴拿马的Darién国家公园、哥伦比亚的Tinigua国家公园和Río Claro保护区、委内瑞拉的Henri Pittier和Yacambú国家公园、秘鲁的Manu生物圈保护区和Tambopata-Candamo保留区、玻利维亚的Madidi国家公园和Pilón Lajas生物圈保护区。能够忍受转化的栖息地，短期内不太可能面临风险。","distribution":"分布于中美洲的巴拿马东部，以及南美洲的哥伦比亚、委内瑞拉、巴西、秘鲁、玻利维亚等地，具体范围从哥伦比亚中南部至秘鲁东部和玻利维亚北部，沿安第斯山脉东侧至南至玻利维亚，再向东进入巴西中央地带，位于亚马逊河以南。","other":"西绿扁嘴霸鹟曾被视为绿扁嘴霸鹟的同种，但基于歌声的明显差异，现在被确认为独立物种。"},{"name":"黄绿霸鹟","english_name":"Yellow-olive Flatbill","scientific_name":"Tolmomyias sulphurescens","overview":"黄绿霸鹟（英文名：Yellow-olive Flatbill，学名：Tolmomyias sulphurescens），是雀形目霸鹟科黄绿霸鹟属的鸟类。广泛分布于中美洲和南美洲热带及亚热带森林和林地，从墨西哥南部延伸至巴西东南部。其羽毛呈绿色偏黄，头部有灰白色斑纹，翼缘淡黄色，翼上有两道黄绿色的翼带，下体从浅绿灰色到亮黄色渐变。","appearance":"黄绿霸鹟体型介于13至15.5厘米，体重约14.5至15.2克。成鸟头部为暗橄榄色，上体橄榄绿色，翼黑或暗色，翼缘黄绿色，下体从喉咙的浅绿灰色至腹部的鲜黄色。幼鸟颜色较淡，眼环不完整，虹膜随成熟变为棕或橄榄色。","call":"发出高音、尖锐的鸣叫，类似于昆虫声或小鸟的哀鸣。声音在不同地区有显著差异，例如在委内瑞拉北部，叫声为连续的‘ps ps psst psst PSST’，而在河的南部，则为‘spik spik’，中间有短暂停顿。","habits":"栖息于各种干燥至湿润的森林环境，包括雨林边缘、落叶林、画廊林、孤立的树林、阴凉的种植园和较高的次生林。常在河流岛屿和亚马逊与委内瑞拉的河岸地带活动。主要在低地生活，偶尔出现在安第斯山脉斜坡，高度可达1800米。","breeding":"繁殖期在4月至6月（哥斯达黎加）、4月至7月（特立尼达岛）和1月至6月（北哥伦比亚）。雄鸟通过展翅颤抖进行求偶展示。巢为梨形袋状，由黑色根须和真菌菌丝构成，通常悬挂在树枝或藤蔓上，高1.5至11米。每次产卵2至3枚，由雌鸟孵化，孵化期17至18天，雏鸟由雌鸟照料，双亲共同喂养，离巢期22至24天。","identification":"与黄边扁嘴鸟相似，但不同于灰顶霸鹟。可通过声音、虹膜颜色和羽毛细节进行辨识。南美南部亚种（pallescens和grisescens）的头部橄榄色比北方亚种更深。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，从墨西哥南部至巴西东南部。在哥斯达黎加、特立尼达岛、北哥伦比亚等地均有记录。","other":"物种分类学尚需进一步研究，不同地区存在声音、羽毛和虹膜颜色的变化，暗示可能包含多个物种。"},{"name":"黄眼霸鹟","english_name":"Orange-eyed Flatbill","scientific_name":"Tolmomyias traylori","overview":"黄眼霸鹟（英文名：Orange-eyed Flatbill，学名：Tolmomyias traylori），是雀形目霸鹟科黄绿霸鹟属的鸟类。以其独特的橙色眼睛和灰褐色冠部著称。分布于南美洲亚马孙雨林西部，自哥伦比亚东南至秘鲁东北部。该鸟种是在1997年被正式描述，以纪念美国鸟类学家Melvin Alvah Traylor Jr。","appearance":"黄眼霸鹟体型小，上体橄榄色，下体呈淡黄色，无翼带但翼羽缘以黄绿色。最显著的特征是其面部、耳羽和胸部的淡黄色调以及橙色的眼睛。成鸟两性相似，头部前冠部肉桂色，边缘橄榄灰色；面部淡黄色，边缘暗色；背部和翅膀覆羽淡橄榄绿色。幼鸟的特征目前尚未描述。","call":"其叫声为一系列有力而沙哑的吱吱声，比黄胸霸鹟的鸣叫更为延长且粗糙。","habits":"栖息于亚马逊地区相对成熟的季洪森林中层，通常单独或成对出现，较少加入混合物种群。食物以昆虫为主，偶尔参与混群觅食。","breeding":"关于其繁殖生态的信息尚少，已知的是它们会在靠近黄蜂巢的地方建造袋状巢穴，巢入口位于底部附近。","identification":"通过其面部和胸部的淡黄色调以及橙色眼睛，可以与同属其他物种区分开来。相较于黄胸霸鹟，它拥有灰褐色的冠部。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊河流域，包括哥伦比亚东南部、厄瓜多尔东部及秘鲁东北部。偏好中层季节性洪水泛滥的成熟瓦尔泽亚森林。","other":"尽管在亚马逊地区分布广泛，但黄眼霸鹟属于罕见物种，其数量可能因当地森林砍伐而逐渐减少。"},{"name":"黄羽缘霸鹟","english_name":"Yellow-margined Flatbill","scientific_name":"Tolmomyias assimilis","appearance":"体型小，长度约13至13.5厘米，体重介于12至17.5克之间。头部顶部、颈背和头部两侧呈深灰色，眼圈白色。上身大部分橄榄绿色，翅膀暗淡，许多羽毛边缘黄色。喉部和胸部淡灰色，带微黄色或条纹，腹部和下尾覆羽黄色。喙宽而扁平，上喙黑色，下喙棕色、灰色或角质色，尖端较暗；腿灰色。雄雌相似。幼鸟与成鸟相比，翅膀羽毛边缘黄色不明显，头部灰度较低。","call":"发出一系列4到5个相似的音符，较为粗糙和嗡嗡声，首音较长，随后3到4个音符音调逐渐升高，节奏相同且几乎一致，如‘zhweyk, zhwek-zhwek-zhwek-zhwek’（厄瓜多尔西部），‘tsew, tseep tseep tseep’（哥斯达黎加）或‘tsish, tsish tsish tsish’（巴拿马），通常重复前会有一两分钟的停顿。","habits":"栖息于湿润的常绿森林的树冠和中层，偶尔在边缘较低处活动，亦见于种植园和高大的次生林，以及巴拿马的沼泽森林；通常在中美洲海拔低于1000米的地方发现，但在厄瓜多尔西北部仅限于海拔500米以下。更偏好成熟的森林，而非森林边缘。","breeding":"繁殖季节在哥斯达黎加为4月至6月；在巴拿马中部，4月上半月开始筑巢；哥伦比亚5月观察到处于繁殖状态的配对。巢为类似细长梨形的袋子，由细黑纤维和真菌根状菌丝构成，离地面高度9至21米，常靠近黄蜂巢。关于繁殖的其他信息未知。","identification":"与黄橄榄霸鹟（Yellow-olive Flycatcher）极为相似，通常通过声音来区分。与灰冠霸鹟的区别在于后者眼睛颜色更深。与绿脸霸鹟和黄胸霸鹟的区别在于喉咙颜色（前者白色而非黄色）。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲南部，自尼加拉瓜南部至哥斯达黎加，向南至哥伦比亚西部（东至玻利瓦尔西南部和考卡河谷下部）和厄瓜多尔西北部（主要分布在皮钦查以北地区，至少在过去更南）。在南美洲，主要栖息于亚马逊雨林。","other":"黄羽缘霸鹟在安第斯山脉东西两侧的种群存在显著差异，尤其是声音上的不同，导致有人提议将其视为两个独立的物种。"},{"name":"黄翅霸鹟","english_name":"Yellow-winged Flatbill","scientific_name":"Tolmomyias flavotectus","overview":"黄翅霸鹟（英文名：Yellow-winged Flatbill，学名：Tolmomyias flavotectus），是雀形目霸鹟科黄绿霸鹟属的小型霸鹟。分布于中美洲和南美洲，自哥斯达黎加至厄瓜多尔西北部的湿润森林地带。","appearance":"具有宽大的喙和鲜明黄色边缘的翼羽，这与多数其他物种区分开来。其头部呈较深的灰色，眼睛为暗色，与绿脸霸鹟极为相似，但通过这些特征可加以区分。曾经被认为是黄羽缘霸鹟的一个亚种。","call":"典型的鸣声是一系列四到五个尖锐的吱吱声。","habits":"通常栖息在树冠层较高处，常见于混合物种的鸟群中。偏好低地和较低的山麓地带。","breeding":"关于其繁殖行为的具体信息未详述。","identification":"与绿脸霸鹟非常相似，但可通过其深灰的头部和暗色的眼睛加以区分。","protection":"IUCN状态未知。","distribution":"分布于中美洲至南美洲，具体包括哥斯达黎加至厄瓜多尔西北部，主要栖息于安第斯山脉以西的湿润森林。","other":"历史上曾被视为黄羽缘霸鹟的亚种，后独立为种。"},{"name":"灰顶霸鹟","english_name":"Grey-crowned Flatbill","scientific_name":"Tolmomyias poliocephalus","overview":"灰顶霸鹟（英文名：Grey-crowned Flatbill，学名：Tolmomyias poliocephalus），是雀形目霸鹟科黄绿霸鹟属的鸟类。最显著的外部特征为灰色的头顶和颈背，与橄榄色的上体形成鲜明对比。广泛分布于南美洲的亚马逊雨林及巴西东部，常出现在湿润森林的树冠层和次生高大植被中。","appearance":"灰顶霸鹟体型小巧而健壮，长约12厘米，体重约11克。头部具有小而白的眉纹和模糊的眼环；头顶和颈背呈灰色，与橄榄色的背部形成对比；翅膀黑色，翼羽边缘黄色明显，形成两条黄色的翼带；尾部暗橄榄色；喉部绿色，胸部和两肋橄榄色，腹部和臀部淡黄色。虹膜颜色浅，上喙黑色，下喙暗色基部带有淡橙粉色；腿灰色。雌雄外观相似，幼鸟描述未详。不同亚种间差异细微。","call":"其鸣叫特征为一连串音调逐渐升高的哨声，最后的哨音颤动，类似“tuee? tuee? TUEE? tuEEuEE? tuEEuEE?”。叫声比类似物种如褐霸鹟和蓝背娇鹟更为尖锐清脆，但不如紫喉歌雀的‘twee-twee’声高。","habits":"灰顶霸鹟主要栖息在亚马逊和大西洋森林的湿润地带，常见于森林边缘、花园和高大的次生林中。它们占据着森林的树冠和中层，活跃于低海拔地区，最高可达1,000米。它们的飞行特点和活动范围尚待详细描述，但已知它们在寻找食物时会表现出特定的行为模式。","breeding":"繁殖期间，灰顶霸鹟会在靠近黄蜂巢的地方建造袋状的巢，入口管状，接近底部。关于其求偶、交配、产卵和育雏的具体细节有待进一步研究。","identification":"与黄色边缘和黄色橄榄色的扁嘴鸟非常相似，但可通过下颌暗色、基部淡色这一特征以及声音加以区分。其姿态比同属的其他物种更水平，有时会抬起尾巴。","protection":"IUCN：LC（无危）。灰顶霸鹟拥有广泛的分布区域，且数量相对较多，尽管其种群可能略有下降，但并不引起重大担忧。","distribution":"分布于南美洲的亚马逊雨林区域，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。在巴西东部也有分布记录。"}];
